window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["ja"]={"ICON-0001":{"nm":"足あと","on":"足あと","de":"床に残った土色のしるしひとつ。長いことためらった末に、結局もう一歩を踏み出した人がいたんだね。足あとが刻むのは留まった時間ではなく、去ろうと心に決めたその一瞬だ。"},"ICON-0002":{"nm":"灯火","on":"灯火","de":"芯に火が触れると、闇がひと幅ずつ静かに退いていく。指先を温める小さなぬくもりに、昔の人は願いを書いて流したという。灯火は照らすためではなく、そばにいてあげるために灯すもの。"},"ICON-0003":{"nm":"リボン","on":"リボン","de":"結び目ひとつで心がきれいに包まれる。贈る手はほどきやすく、受け取る手はゆっくりほどきたくなるように。リボンが結んでおくのは箱ではなく、手渡す直前にときめいていたあの胸の高鳴りだ。"},"ICON-0004":{"nm":"ポスト","on":"ポスト","de":"赤い口を開けたまま路地の入り口に立っている。手紙が貴重になった時代にも、この小さな箱は誰かの便りを最後まで待っている。空になる瞬間に最も明るく輝く、やさしい器。"},"ICON-0005":{"nm":"マイ島ミニマップ","on":"ミニマップ","de":"畳めばポケットの中、広げれば海と稜線が並んで横たわる一枚の紙。初めて訪れる者には、どの曲がり角もまだ開いていない約束だ。広げた瞬間、小さな島も広い世界になる。"},"ICON-0006":{"nm":"マイク","on":"マイク","de":"最初の音を出す直前、息を整える半拍。客席の眼差しが自分のひと言を待っていると知ると、指先が震えてくる。マイクは音を大きくするのではなく、その震えを最後まで届ける仕事だ。"},"ICON-0007":{"nm":"時計","on":"時計","de":"秒針は休まないけれど、誰も君をせかしたりしない。デビューまで何夜、ステージまで何分——文字盤の上では待ちとときめきが同じ速さで回る。時間を見ることは、心をなだめること。"},"ICON-0008":{"nm":"ノート","on":"ノート","de":"余白が最も多い物。振り付けの動線も、夜明けの決意も、ついに送れなかった言葉も、ここに積もる。開いた瞬間、昨日の自分が今日の自分にそっと語りかける。"},"ICON-0009":{"nm":"ハンコ","on":"ハンコ","de":"赤い朱肉を含んでぐっと一度押すと、約束がくっきりと刻まれる。文字より重く、言葉より明確な痕跡。書類の終わりごとに人は名前の代わりに、この小さなハンコに心を託した。"},"ICON-0010":{"nm":"台座","on":"台座","de":"自分の身を精一杯低くして他のものを支える。上に置かれたものが揺れないよう、最も下で黙々と耐える場所。輝かなくても、崩れないようにするやさしさがここにある。"},"ICON-0011":{"nm":"切手","on":"切手","de":"片隅に唾をつけてぐっと貼った小さな絵。遠くへ送る思いにつける、最も正直な値だ。四角い風景一枚が海を越えて手紙の手を取って行く。"},"ICON-0012":{"nm":"旗ピン","on":"ピン","de":"地図の上にちょんと刺せば「私ここまで来たよ」になる。征服ではなく記録であり、次に来る誰かへの応援だ。この旗を見てもう一歩だけ、と言葉なく背中を押すしるし。"},"ICON-0013":{"nm":"木の枝","on":"木の枝","de":"一度しなった枝は折れることを忘れる。風の前で曲がった場所ごとに節がしっかり刻まれ、本当の強さはよく耐え抜いた痕跡から来ると、古い森が風にのせて教えてくれる。"},"ICON-0014":{"nm":"ボタン","on":"ボタン","de":"外れてはまた留められるのを繰り返しながら襟を合わせる。小さな円ひとつが夜明けの寒さも、ふと差した恥ずかしさも、そっと防いでくれる。ぽろっと取れてみて、ようやくその場所が大きかったと知る。"},"ICON-0015":{"nm":"封筒","on":"封筒","de":"口を封じる瞬間、ようやく秘密になる。中に何が入っているかは受け取る人だけが知る。紙一枚が心と世界の間に置かれる、最も薄くてやさしい扉ひとつ。"},"ICON-0016":{"nm":"箱","on":"箱","de":"四隅がまっすぐで何でも寛大に抱きとめる。引っ越しの時期には思い出を、節句には贈り物を、普段はがらくたを。閉じた蓋の内側はいつも誰かの「あとで」でいっぱいだ。"},"ICON-0017":{"nm":"取っ手","on":"取っ手","de":"扉と人の間で、最初に手を差し出す物。一度引っ張ってこそ、ようやく内と外がつながる。入っていくのも出ていくのも、すべての決心はこの冷たい手を一度握ってから。"},"ICON-0018":{"nm":"スプーン","on":"スプーン","de":"くぼんだ口で温かい汁をそっとすくい上げる。母がふうふう冷まして先に差し出した一さじのぬくもりを覚えている道具。食卓で最もよく口に触れる、最もやさしい手だ。"},"ICON-0019":{"nm":"スリッパ","on":"スリッパ","de":"敷居をまたぐ瞬間、足がまず一息つく。カツカツだった一日を脱いで、ぺたぺた歩く夕方の音。玄関にきちんと並んだ一足が、「もう家だよ」と言ってくれる。"},"ICON-0020":{"nm":"鍵","on":"鍵","de":"閉める方法より開ける方法を先に学ぶ。手のひらの中で温まり、ある日見知らぬ新しい扉の前でそっと止まる小さな金属。去る者のぬくもりを最も長く宿す物。"},"ICON-0021":{"nm":"グラス","on":"グラス","de":"空っぽの時はきちんとしていて、満たされる時はこの上なく温かい。向き合って掲げたふたつがチンとぶつかる澄んだ音に、言葉なき約束が宿る。ひとりよりふたりの時に輝くために生まれた器。"},"ICON-0022":{"nm":"皿","on":"皿","de":"丸い縁の中に一日分の真心がいっぱいに盛られる。空にして洗ってまた満たすのを一生——最もよく輝き、最もよく忘れられる暮らしの道具。食卓の舞台はいつもこの上に整えられる。"},"ICON-0023":{"nm":"照明","on":"照明","de":"スイッチひとつで部屋の表情が変わる。明るければ日常、ほのかなら慰め。遅く帰る誰かのために最後まで灯しておいた一点の光が、世界で最も温かい出迎えになる。"},"ICON-0024":{"nm":"ティースプーン","on":"ティースプーン","de":"茶の上をひと回りゆっくり回すと、葉と水が互いに染み込んでいく。急ぐことのない手つき、香りが広がるまでの小さな待ち。銀色の手ひとつが午後の速度をやさしく緩める。"},"ICON-0025":{"nm":"しおり","on":"しおり","de":"読みかけの場所にそっと挟んでおく約束。「ここで止めたから必ず戻ってくるね」という誓いが紙の間で眠る。物語は閉じても、心はその一行にくっきりと印されている。"},"ICON-0026":{"nm":"クッション","on":"クッション","de":"寄りかかる場所が必要な背中とひざを、言葉なく受け止めてくれる。ぺしゃんこにへこんではゆっくり膨らみ、今日一日の疲れを吸い込む。最も怠けた姿勢を、最も寛大に許してくれる物。"},"ICON-0027":{"nm":"フレーム","on":"フレーム","de":"四角い縁が風景ひとつを永遠に結びつける。その中に入った瞬間だけは、時が経っても色あせない。何を入れるかより、何を残そうと決めたかというやさしい選択。"},"ICON-0028":{"nm":"地図","on":"地図","de":"折り目ごとに道に迷っては再び見つけた痕跡が染みついている。広げれば行ったことのない場所も指先で先に歩いてみることができる。すべての冒険は、この一枚を広げる小さな勇気から始まる。"},"ICON-0029":{"nm":"絵はがき","on":"絵はがき","de":"裏面の半分は写真、半分は空白。遠くへ旅立った人が「元気だよ」の五文字に、その地の風景を添えて送る。封筒なしでも便りが恥ずかしくない、最も率直な一枚の紙。"},"ICON-0030":{"nm":"入館証","on":"入館証","de":"首にかける瞬間、ようやく内側の世界へ入っていく。小さなカードに記された自分の名前が「ここ、君の席だよ」とそっと許してくれる。通過の資格ではなく、どこかに属しているというしるしだ。"},"ICON-0031":{"nm":"アルファベットB","on":"アルファベットB","de":"単語の真ん中で最もよく呼び出される文字。唇を一度閉じてからぽんと弾いてこそ、ようやく音が出る。始まりでも終わりでもないけれど、拍子を取ってくれる頼もしい二番目の席。"},"ICON-0032":{"nm":"名刺","on":"名刺","de":"渡す時は両手で、受け取る時は目を合わせて。紙一枚にひとりの一日と誇りがそっと圧縮される。名前と肩書きの間の狭い余白に、その日の第一印象がそっと宿る。"},"ICON-0033":{"nm":"表紙","on":"表紙","de":"物語の最も外側で、雨風を先に受けてくれる。中の文字を守るために自分の角から擦り切れていく。開く直前のしばしのときめきは、いつもこの一枚から先に始まる。"},"ICON-0034":{"nm":"教材","on":"教材","de":"下線と蛍光ペンでひとりの奮闘がぎっしり記されている。新しい本の時は途方に暮れるが、読み終えれば最も頼もしい友になる。知らなかったことを知った痕跡が、ページごとにきれいに折られている。"},"ICON-0035":{"nm":"ダンスパス","on":"ダンスパス","de":"この一枚が練習室の扉を大きく開く。鏡だらけの部屋、足を踏み鳴らす音、初めて習う8拍。踊りがまだ下手でも大丈夫だと、小さな紙一枚が震える背中をそっと押す。"},"ICON-0036":{"nm":"ファイル","on":"ファイル","de":"ばらばらに漂っていた紙が一本の背骨にきちんと綴じられ、ようやく順序を得る。順序ができれば物語になり、厚くなるほど誰かがそれだけ着実に生きてきたというやさしい証拠になる。"},"ICON-0037":{"nm":"試験用紙","on":"試験用紙","de":"空欄の上でしばし震える指先。正解より怖いのは、知らないことと正面から向き合うことだ。採点が終われば間違えた場所ごとに、次に育つ余白がそっと残る。"},"ICON-0038":{"nm":"アルファベットA","on":"アルファベットA","de":"口を大きく開けてこそようやく出る最初の音。列の一番前、名前の一番初めによく立っている。何かを始める時はこの文字からだから——だからいつも少しだけ勇敢だ。"},"ICON-0039":{"nm":"アルファベットD","on":"アルファベットD","de":"なめらかに曲がった背中で単語をそっと支える。丸い片側が誰かの名前の終わりにきちんとぶら下がる。華やかではなくても抜けると寂しい、アルファベットの中の静かなそばひとつ。"},"ICON-0040":{"nm":"練習用紙","on":"練習用紙","de":"間違えても大丈夫な、世界にただひとつの紙。同じ動作を、同じ文章を、何十回も書き直させてくれる。くしゃくしゃに丸めて捨てた枚数だけ、誰かは確かにもっと良くなっていた。"},"ICON-0041":{"nm":"作曲用紙","on":"作曲用紙","de":"夜中二時、鼻歌ひとつが眠りを覚ます。鉛筆が五線譜の上でためらうのはメロディが手より速いから。消しては書いた痕跡ごとに、まだ名もない歌が少しずつ育っている。"},"ICON-0042":{"nm":"バックステージパス","on":"バックステージパス","de":"首にかける瞬間、平凡な廊下が別世界に変わる。ケーブルが闇の中を蛇のように横切り、ステージの向こうでは聞こえないカウントダウンが始まる。ここに入る資格は、この一枚が代わりに語ってくれる。"},"ICON-0043":{"nm":"コンタクトシート","on":"シート","de":"小さなマスごとに違う表情が止まって立っている。笑い、振り返り、目を閉じる。一コマずつたどっていくと、シャッターを切ったあの日のときめきが指先に戻ってくる。一枚を選ぶことさえ、すでに記録だ。"},"ICON-0044":{"nm":"香盤表","on":"シート","de":"明日何時、どこで、何を。紙一枚が一日分の動線を前もって描いておく。分単位でびっしりのマスの間、誰かはここに記された順序に従って一歩ずつ夢のほうへ歩いていく。"},"ICON-0045":{"nm":"タグ","on":"タグ","de":"値札の裏には作った人の時間が静かにぶら下がっている。ちょんと取り外すその短い手つきでようやく自分のものになる小さな紙。切られた跡に残るのは新品の匂いと、ときめきひとつかみだ。"},"ICON-0046":{"nm":"ポートフォリオ","on":"ポートフォリオ","de":"表紙をめくると歩んできた道が一度に広がる。自信のある一枚の隣に、不器用だった初めての挑戦が恥ずかしそうに並んで。誰かに自分を初めて差し出す時、これほど率直な自己紹介はない。"},"ICON-0047":{"nm":"プランナー","on":"プランナー","de":"今日を書き、来週を描き、時には一マスを真っ黒に塗る。計画通りにいったことはなくても、マスを埋める手は止まらない。未来を一度先に生きてみる、小さな儀式のようなもの。"},"ICON-0048":{"nm":"プレイリスト","on":"プレイリスト","de":"遅い曲と速い拍子の間、その日の心の天気に合わせて歌を一列に並べる。誰かの一日がちょうどこの順序通りに流れていくと思うと、曲の間の静寂さえやさしくなる。"},"ICON-0049":{"nm":"学生証","on":"学生証","de":"名前と写真、そしていくつかの数字。教室と練習室の間を行き来した日々を証明する一枚。角が擦り切れるほどポケットを出入りしたカードには、二度と来ないみずみずしい毎日が刻まれている。"},"ICON-0050":{"nm":"ブレスレット","on":"ブレスレット","de":"その日の色を手首に結んだ瞬間を覚えてる? 一緒に叫んだ掛け声、共に濡れたコンサートの夜。紐が擦れて色があせてもほどかないのは、あの夏を手首の上で生かし続けたいから。"},"ICON-0051":{"nm":"腕章","on":"腕章","de":"腕に巻く瞬間、責任という重さがそっと加わる。列の一番前に立ち、場所を最も遅く去る人のしるし。布一切れが誰かをひと回り成長させる。"},"ICON-0052":{"nm":"リング","on":"リング","de":"途切れることなく丸くつながった一本。始まりと終わりが触れ合っていて、人々はここに永遠の形を見る。両手をそっと重ね合わせると言葉より先に、約束が形として残る。"},"ICON-0053":{"nm":"勲章","on":"勲章","de":"胸につけた小さな金属片には耐え抜いた日々が刻まれている。輝くのは金属ではなく、その後ろに隠れた数多くの練習の夜。誇りより先にこみ上げるのは、なぜか感謝の気持ちだ。"},"ICON-0054":{"nm":"エプロン","on":"エプロン","de":"首に紐を結べば両手が自由になる。小麦粉でも絵の具でも、何かに夢中になる準備ができたという合図。しみがひとつずつ増えるほど、その日注いだ真心も共に濃くなる。"},"ICON-0055":{"nm":"耳フード","on":"耳フード","de":"耳をすっぽり包むと外の音がひと足遠ざかる。木枯らし吹く登校路、ふんわりした内側にそっと隠れる小さな避難所。冬の温かさは時々、こうして耳先から始まる。"},"ICON-0056":{"nm":"衣装","on":"衣装","de":"幕が上がる前、ハンガーにかかったまま息を潜める一着。縫い目ひとつひとつに振り付けが折りたたまれている。腕を通す瞬間、人は役柄になり、ステージはその服の二番目の肌になる。"},"ICON-0057":{"nm":"王冠","on":"王冠","de":"頭に載せる瞬間、曲がっていた背中がひとりでにまっすぐ伸びる。黄金色は権力より責任を先にささやく。額に触れるひんやりした重さが教えてくれる。輝く席ほどより重いと。"},"ICON-0058":{"nm":"マント","on":"マント","de":"肩に羽織ると背中の後ろで風がはためく。走るたびに一幅の裾が後を追ってくるあの気分。英雄のしるしというより、ただかっこよくなりたかった幼い心により近い。"},"ICON-0059":{"nm":"仮面","on":"仮面","de":"顔を隠すとかえって率直になる。面の後ろで思う存分笑い泣いた昔の村芝居のように。隠した表情の向こうで、普段は飲み込んでいた本当の声がより大きく漏れ出る。"},"ICON-0060":{"nm":"口紅","on":"口紅","de":"蓋を回して一筆引くと口元に小さな決意が立つ。鏡の前の最後の確認、ためらいの上に塗り重ねる赤い一本。色が乗るその短い瞬間、恐れはそっと席を譲る。"},"ICON-0061":{"nm":"ジャケット","on":"ジャケット","de":"肩のラインがぴたりと合う時、人は少し凛とする。袖をまくれば働く心、襟を立てれば出かける心。一着がその日一日の姿勢をそっと決めてくれる。"},"ICON-0062":{"nm":"テコンドー帯","on":"帯","de":"色が一段階変わるたびに、その下に積もった汗の量も変わる。結び目をきつく締めてお辞儀をした道場の朝。帯を結ぶ指先で、散らばっていた精神が再び集まる。"},"ICON-0063":{"nm":"ゴーグル","on":"ゴーグル","de":"目の前にかけると世界がワントーンくっきりする。風もほこりも防いでくれる丸い盾の向こうで、いつも歩く平凡な道さえなぜかスタートラインのように輝いて見える。"},"ICON-0064":{"nm":"グローブ","on":"グローブ","de":"手にはめると何でもしっかりつかむ勇気が湧く。落とすかと縮こまっていた指が、ようやく大きく開く。守るのは手だけれど、本当に守られるのは、その次に来る挑戦だ。"},"ICON-0065":{"nm":"マスク","on":"マスク","de":"口元を覆うと目がより多くを語る。人がごった返す通りで、少し隠したまま味わう小さな匿名の自由。だからすべて外した跡に残る笑顔が、より明るく広がる。"},"ICON-0066":{"nm":"帽子","on":"帽子","de":"つばを少し下げると日差しも視線もひと幅それる。頭に載せた小さな屋根の下、今日だけは楽な表情で歩いてもいい。最も軽い変身はいつもここから始まる。"},"ICON-0067":{"nm":"シャツ","on":"シャツ","de":"かさっ、ちょうどアイロンをかけた襟から朝の匂いがする。ボタンを上から順に留める間、こんがらがっていた心もひとマスずつきちんとしていく。白い一枚が一日の最初の文章を開く。"},"ICON-0068":{"nm":"スカーフ","on":"スカーフ","de":"首にひと回り巻くと風の通り道がふさがれる。裾が肩でそよぐ間、寒さはもう内側まで届かない。おしゃれと温かさ、その間のどこかに置かれた一幅。"},"ICON-0069":{"nm":"手袋","on":"手袋","de":"指先まですっぽり包まれると冷たいものも怖くない。はあはあ息を吹いていた手がそっとほっこりする、冬の小さな贅沢。脱いで差し出した片方が誰かの手を温めることもある。"},"ICON-0070":{"nm":"認識票","on":"票","de":"薄い二枚の札が互いをそっと見つめ合う。名前の三文字といくつかの番号、それが誰かを最後まで覚えさせる。冷たい金属なのになぜか、最も温かい約束に似ている。"},"ICON-0071":{"nm":"グリップリング","on":"リング","de":"指を通すと落とす心配がするりと消える。片手でも十分に持って振れる小さな安心。写真一枚残そうと腕を長く伸ばす時、静かに手のひらを支えてくれる。"},"ICON-0072":{"nm":"花冠","on":"花冠","de":"頭に載せると春がひと抱えついてくる。野で摘んで丸く編んだ花々が額をそっと囲む。写真の中の明るい笑顔の上に、淡い草の匂いが長く残る。"},"ICON-0073":{"nm":"アイマスク","on":"アイマスク","de":"目を覆うと灯りも騒音も一度に遠ざかる。見えないから聞こえるのは自分の息だけ。しばし世界を消して内側の静寂へ入っていくと、背中の後ろで小さな扉がそっと閉まる。"},"ICON-0074":{"nm":"マフラー","on":"マフラー","de":"ひと回り、ふた回り、首に巻くたびに冬が少しずつ穏やかになる。毛糸の間のどこかには誰かが編んでくれた心が混じっているかも。鼻先まで埋めると世界がいっそうほっこりする。"},"ICON-0075":{"nm":"半月仮面","on":"半月仮面","de":"顔の半分だけ隠したまま舞踏会の夜が始まる。あらわになった唇は笑い、隠した目は秘密を抱く。誰だか分かりそうで分からないその狭い隙間が、真夜中の空気をときめかせる。"},"ICON-0076":{"nm":"ベレー帽","on":"ベレー帽","de":"斜めに載せると平凡な一日にそっと趣が宿る。丸くて平たい布一枚が、肩の上に芸術家の真似をそっと着せてくれる。鏡の前で角度を選ぶそのしばしさえ楽しい。"},"ICON-0077":{"nm":"チョーカー","on":"チョーカー","de":"首にぴったり巻くと視線が自然に上に集まる。細い紐ひとつが雰囲気をまるごと変えてしまう。小さいけれど確かな、今日一日の自信を満たす留め具のようなもの。"},"ICON-0078":{"nm":"パーカー","on":"パーカー","de":"ジッパーを最後まで上げると吹雪もひと足退く。分厚い内側に手を深く入れると、世界中の騒がしさが静まる。荒い風の中でもついに温かい、一軒の小さな家。"},"ICON-0079":{"nm":"パンツ","on":"パンツ","de":"足を通して腰を締めると、ようやく出かける準備が終わる。一歩踏み出すたびに布が織り目に沿ってなめらかに動く。快適さときちんとした感じ、その間のどこかで一日が始まる。"},"ICON-0080":{"nm":"ピアス","on":"ピアス","de":"小さな一点を加えるのにも少しの勇気がいる。輝く金属ひとつが平凡な耳元にくっきりした句点を打つ。とても小さいけれど、確かに変わった今日の自分を映す光。"},"ICON-0081":{"nm":"波形","on":"波形","de":"エンジニアにとって歌は聞こえるものではなく見えるものだ。画面の上で上下する稜線から、その日息がどこで震えたかを読み取る。見えなかった声が山脈のように横たわり、一曲の地形を広げて見せる。"},"ICON-0082":{"nm":"チューナー","on":"チューナー","de":"公演直前、弦六本を順になでて、乱れた音を元の場所に座らせる。0.5度だけずれても客席は鬼のように気づく。誰も分からないほど正確に合わせておくこと——それがステージへのやさしさだ。"},"ICON-0083":{"nm":"ストラップ","on":"ストラップ","de":"手首にひと巻きすると落とす心配がするりとほどける。ステージの上で最も怖いのは手から何かを落とすことだから、この小さな紐ひとつにようやく心が落ち着く。"},"ICON-0084":{"nm":"シンバル","on":"シンバル","de":"ただ一度ぶつかる瞬間、曲の最後の文章にくっきりした句点が打たれる。金色の円盤は最も短く鳴り、最も長く余韻を残す方法を知っている。終わりはこうして明るく閉じられるべきだと。"},"ICON-0085":{"nm":"ギター","on":"ギター","de":"六本の弦の上を指が滑ると、狭い部屋がまるごとステージになる。誰かの最初のメロディも、眠れぬ夜明けの独り言も、この丸い木の胴の中で最初に息を得た。"},"ICON-0086":{"nm":"サウンド雲","on":"サウンド雲","de":"空の片側に音符たちが綿のように固まってふわふわ漂う。風が一度撫でて通り過ぎると雨粒の代わりにメロディが降ると、島の子どもたちは傘も持たずに迎えに出る。"},"ICON-0087":{"nm":"ステップ","on":"ステップ","de":"ステージの動線はつま先で解く算数だ。ここで一歩、あそこで半拍——間違えてもいいからゆっくり。何百回も踏んで体に刻んだマスが集まって、ようやく一曲の地図が完成する。"},"ICON-0088":{"nm":"アンプ","on":"アンプ","de":"ささやきを歓声に変えてくれる箱。それでもボリュームをひとマス上げる前にはいつも手を止める。より大きな音よりもより正確な音が客席の最後列まで届くと、この箱は知っている。"},"ICON-0089":{"nm":"音符わた","on":"音符わた","de":"おたまじゃくしの頭たちが集まって綿玉になると、枕のようにふかふかだ。そっと枕にして横になると聞こえるか聞こえないかの子守唄が流れ出るという、島で最もやさしい噂ひとつ。"},"ICON-0090":{"nm":"カセット","on":"カセット","de":"巻き戻しボタンを押すとキィッ、テープがあの夏の最初の曲へゆっくり戻る。ひと時代がまるごと巻かれた小さな箱の中に、もう二度と触れられない時間がそのまま眠っている。"},"ICON-0091":{"nm":"音叉","on":"音叉","de":"二股の鉄を軽く打つと宙に基準音ひとつが生まれる。この小さな震えにすべての楽器がそっと頭を合わせる。何であれ始まりはこうして弱い振動から来る。"},"ICON-0092":{"nm":"波形チップ","on":"チップ","de":"音のひと切れを爪ほどのチップの中にそっと閉じ込める。わざと録音したことのない合いの手、消えたと思っていた誰かの笑い声が、この中で今も温かく生き続けている。"},"ICON-0093":{"nm":"LP","on":"LP","de":"針が溝に沿って最初の一歩を踏み出すと、ジジッとかすかな息遣いがまず聞こえる。その小さな雑音さえ好きで、ある人は最後までこの黒い円盤を手放せない。"},"ICON-0094":{"nm":"ポケット","on":"ポケット","de":"最も大切なものはいつも胸から最も近い場所に置く。手のひらほどの布袋ひとつがある日は手温めに、ある日はお守りに、またある日は秘密の保管箱になってくれる。"},"ICON-0095":{"nm":"ばんそうこう","on":"ばんそうこう","de":"練習が長引いた夜にはかかとごとに小さな勲章がひとつずつ貼られる。痛いという言葉を飲み込もうと貼った一枚——明日も必ず踊るという、誰も知らない静かな約束だ。"},"ICON-0096":{"nm":"枕","on":"枕","de":"一日分のステージをすべて下ろす場所は結局このふかふかした四角一枚だ。頭をそっと横たえると耳元に残っていた拍手の音がゆっくり静まり、島にもようやく夜が降りる。"},"ICON-0097":{"nm":"ベル","on":"ベル","de":"チリン、短い音一度で誰かが扉を押して入ってくる。お客さんが来たという合図であり、一日が開いたという挨拶。小さな金属ひとつが一日中うれしさだけを引き受けて鳴る。"},"ICON-0098":{"nm":"ケース","on":"ケース","de":"大切なものほど丈夫な家を別に建ててやる。開け閉めする手つきが毎回慎重になるのは、その中に入っているのがただの物ではなく、どうしても失いたくない心だからだ。"},"ICON-0099":{"nm":"ブラシ","on":"ブラシ","de":"毛一本まで織り目に沿って掃き下ろすと、隅にこびりついたほこりがそっと退いていく。見えない場所まで厭わない手つきがあるから、部屋は毎日新しい朝を迎える。"},"ICON-0100":{"nm":"スケッチ","on":"スケッチ","de":"完成する前の線はためらいをあえて隠さない。消してはまた引いた跡ごとに、何になりたかったかが偽りなく残る。不器用な始まりほど最も率直だ。"},"ICON-0101":{"nm":"ぬいぐるみ","on":"ぬいぐるみ","de":"言葉なく胸に抱かれるだけで慰めになる存在がいる。ステージの後ろで手が震えた夜、枕元で一緒に震えてくれた綿玉の友を——誰もが心の中にひとつくらい抱いて生きる。"},"ICON-0102":{"nm":"鐘","on":"鐘","de":"山寺の鐘は一度鳴って谷をまるごと渡る。遠く、もっと遠く届きたい鉄の心が長く鳴くものだから、その音は聞く人の胸のあたりでゆっくり沈んでいく。"},"ICON-0103":{"nm":"傘","on":"傘","de":"一緒に差すとどちらか片方の肩は必ず濡れるものだ。そっと傾いた傘の下、濡れた肩こそやさしさの最も確かな証拠だ。ひとつ屋根を分け合った短い道が長く心に残る。"},"ICON-0104":{"nm":"マット","on":"マット","de":"素の床に一枚広げればそこがすぐ練習室になる。転がっても倒れても言葉なく受け止めてくれる場所——数多くの動作がこの上で初めて自分の体に道をつけた。"},"ICON-0105":{"nm":"鈴","on":"鈴","de":"そっと振るとコロロと、澄んだ音が手の中で転がり出る。昔の子どもたちが色とりどりの上着の裾につけて庭を駆け回った、小さくて丸い楽しさが手のひらの上で再び目を覚ます。"},"ICON-0106":{"nm":"ヘビおもちゃ","on":"ヘビおもちゃ","de":"細長く伸びた形がいたずらっぽく人をびっくりさせる。怖くて逃げてついにけらけら笑ってしまう——こんないたずらも結局は互いへのやさしさのひとつの枝だ。"},"ICON-0107":{"nm":"おもちゃ","on":"おもちゃ","de":"大人になっても捨てられない箱が誰にでもひとつくらいある。その中には最も輝いていた時代の笑い声が、ほどけていないぜんまいのように今もしっかり巻かれている。"},"ICON-0108":{"nm":"ちゃぶ台","on":"ちゃぶ台","de":"折りたたまれた脚を広げればどこでもすぐ家族の席になる。囲んで座ってスプーンがぶつかる音、その素朴な合奏が一日中で最も温かく響く一曲だ。"},"ICON-0109":{"nm":"石けん","on":"石けん","de":"手の中で少しずつ小さくなりながら黙々と誰かをきれいにする。自分の身をすり減らして他人を洗う仕事——泡がすべて消えてしばらく後にようやく、その静かな心が見えてくる。"},"ICON-0110":{"nm":"くし","on":"くし","de":"もつれた髪を一筋ずつほどくように、こんがらがった一日も次第に整っていく。鏡の前で差し出した短い手つきひとつが、髪の毛の向こうの心の身だしなみまでそっと直してくれる。"},"ICON-0111":{"nm":"鳥かご","on":"鳥かご","de":"扉が大きく開いていても去らずに歌う鳥がいる。閉じ込められているからではなく留まりたくて残る心——その微妙な違いを、この鳥かごは誰よりも先に気づく。"},"ICON-0112":{"nm":"カイロ","on":"カイロ","de":"冬の公演会場の待機列、ポケットの中の小さなぬくもりがかじかんだ指をそっと温める。寒さに震える君を思い浮かべて誰かが前もって振って温めておいた、手のひらほどのやさしさだ。"},"ICON-0113":{"nm":"ハンカチ","on":"ハンカチ","de":"涙も汗も文句なく受け止めてくれる一枚の布。角に小さく刺された刺繍は、先に見送った人が残した、忘れるなという最後の挨拶のようにそこにきれいに留まる。"},"ICON-0114":{"nm":"スプレー","on":"スプレー","de":"一度シュッと吹きかけると空気の織り目が瞬く間に変わる。ステージの上に広がる霧も、朝の窓辺の草花も、この細い水滴の中でしばし別世界になって輝く。"},"ICON-0115":{"nm":"試香紙","on":"試香紙","de":"香りを選ぶことはなぜか記憶を選ぶことにそっくりだ。細い紙の端にそっとついたひと筋の匂いが、忘れたと思っていたある季節をそっと鼻先へ連れてくる。"},"ICON-0116":{"nm":"食卓","on":"食卓","de":"擦れた木目ごとに共に分け合った食事の数がそっと刻まれている。にぎやかだった夕方も、ひとりで迎えた夜更けも——この四角は言葉なくすべて受け止めて艶が出た。"},"ICON-0117":{"nm":"糸玉","on":"糸玉","de":"一端をそっと引くとするする解け、ひと針あればまたつながる。途切れたものをつなぐことはいつもこうして細い糸一筋から静かに始まる。"},"ICON-0118":{"nm":"レインコート","on":"レインコート","de":"降りしきる日にもどうしても外へ出かけさせるのはこの一着だ。雨の中をぴちゃぴちゃ歩く楽しさを知る人だけが、雨を口実に家に留まらない。"},"ICON-0119":{"nm":"巾着","on":"巾着","de":"口を丸くすぼめるとその中のものがようやく安全になる。手垢のついた小さな袋ひとつにコインも、ある日の思い出も、ついに言えなかった言葉も共に入って揺れる。"},"ICON-0120":{"nm":"本棚","on":"本棚","de":"差し込まれた背表紙に沿って指をゆっくりなでると、過ぎてきた季節が指先に触れられる。読み終えた本をどうしても捨てられないのは、そこにあの時の自分がまだ生きているからだ。"},"ICON-0121":{"nm":"本の塔","on":"本の塔","de":"読んだ本は横に寝かせ、読めなかった本は上に積み上げる。いつか全部読むという約束が天井近くで少しずつ揺れても、その揺れさえ好きで今日もまた一冊を載せる。"},"ICON-0122":{"nm":"回し車","on":"回し車","de":"一生懸命走っても同じ場所のようだけれど、小さな足はつま先のリズムを先に覚えている最中だ。止まらなかった昨日たちが集まって、ある日本当の道の上で明るく輝く。"},"ICON-0123":{"nm":"カバー","on":"カバー","de":"ほこりがつかないよう、日差しに色あせないよう——覆っておくことにも指先の真心がいる。大切なものほど、見えない場所でよりやさしく守られている。"},"ICON-0124":{"nm":"毛糸","on":"毛糸","de":"おばあちゃんのひざの上でコロロと解け出た一筋。もつれて見えても端を見つけてそっと引けばきまって従ってくる。冬の夜はそうしてひと目ひと目長くなった。"},"ICON-0125":{"nm":"ポーチ","on":"ポーチ","de":"リップ、ヘアゴム、きれいに折られた手紙一枚——小さく見えてもその中には一日分の心が入っている。ジッパーを閉める音とともに、大切ながらくたがまるごと安全になる。"},"ICON-0126":{"nm":"ひじ掛け","on":"ひじ掛け","de":"本を読みながら眠った午後、電話しながら歩き回った夕方。長く座るほど手垢が深くなる場所に、ひじが覚えているすべての休息がひと幅分静かにたまった。"},"ICON-0127":{"nm":"パック","on":"パック","de":"破る前まではまだ誰のものでもない。封印されたひと袋には開けていない期待がいっぱいで、角をつかんだ指先が軽く震えてくる。それが開封のときめきだ。"},"ICON-0128":{"nm":"包装紙","on":"包装紙","de":"贈り物よりひと足先に届く心。角を合わせて折りリボンで結ぶ間、受け取る人の笑う顔が手の中で前もって明るく広がる。"},"ICON-0129":{"nm":"ゲームパッド","on":"パッド","de":"親指が頭より先に覚えるボタンたち。負けてもあと一回だけ——その一回が結局夜を明かす。手にぴったり合う重さが今夜の冒険をそっと持ち上げる。"},"ICON-0130":{"nm":"信号","on":"信号","de":"赤はしばし止まれ、緑はもう行ってもいい。単純な約束ひとつで数多くの道がもつれずに流れる。待つことにも順番があると、点滅する灯りがやさしく教えてくれる。"},"ICON-0131":{"nm":"矢印","on":"印","de":"道に迷った人に最もやさしい図形。どこへ行くべきか途方に暮れた時、誰かが先に引いておいた方向ひとつが、止まった足どりを再びしっかりさせる。"},"ICON-0132":{"nm":"座標","on":"座標","de":"数字ふたつあれば世界のどこでもちょんと指せる。会うことにした場所、宝を埋めておいた砂浜。約束が道に迷わないよう、小さな点ひとつが最後まで引き止めてくれる。"},"ICON-0133":{"nm":"タイル","on":"タイル","de":"ひとつではただ四角い一片。肩を合わせて並んで横たわる瞬間、床になり壁になる。小さなものが集まって、誰かが心置きなく足を踏み入れる場所を作る。"},"ICON-0134":{"nm":"砂時計","on":"砂時計","de":"上の段が空けば下の段がゆっくり満たされる。さらさら流れ落ちる砂を見ながら、私たちは時が流れると信じる。ひっくり返せばまた最初——それが砂のやさしい嘘だ。"},"ICON-0135":{"nm":"ボール","on":"ボール","de":"投げれば戻り、蹴れば転がっていく。丸いからどこへ跳ねるか分からないのが最大の魅力だ。運動場の真ん中、笑い声はいつもこの小さな球から丸く始まった。"},"ICON-0136":{"nm":"スイッチ","on":"スイッチ","de":"カチッ、一度でつき、一度で消える。暗い部屋に入りながら押すその小さな音が、散らばっていた一日の始まりと終わりをくっきりした一本の線で分けてくれる。"},"ICON-0137":{"nm":"はてなマーク","on":"マーク","de":"答えを知らないことは恥ずかしいことではない。好奇心がまだ生きているといううれしい証拠だから。この小さなかぎが頭の中をとんとんたたく時、学びはようやく第一歩を踏み出す。"},"ICON-0138":{"nm":"マッチ","on":"マッチ","de":"自分の身をすって火を渡す一本。短く燃えて静かに消えるけれど、そのしばしの間にろうそくがつき、かまどが温まる。小さな差し出しがぬくもりの最初のボタンになる。"},"ICON-0139":{"nm":"踏み台","on":"台","de":"一歩だけ上がれば届かなかった棚にも手が届く。誰かの背を少し伸ばすこと。低くうつ伏せて私たちをそっと高くしてくれるやさしい場所がここにある。"},"ICON-0140":{"nm":"腕時計","on":"腕時計","de":"運動を決意した日、手首に最初につけたもの。心拍と歩数を数えてくれる小さなコーチが、今日は昨日より少し多く歩いたと、とんとんたたいて知らせてくれる。"},"ICON-0141":{"nm":"アラーム","on":"アラーム","de":"毎朝憎まれる最も誠実な友。布団の中の5分の誘惑と毎回代わりに戦ってくれるおかげで、約束も夢も遅れない。つれなく鳴るその音が実は応援だ。"},"ICON-0142":{"nm":"芯","on":"芯","de":"外をすべて剥がして最後まで残る最も内側。りんごの種、心の真心——何であれその真ん中には最も固いものが入っている。揺れてもついに残る一点だ。"},"ICON-0143":{"nm":"ペン","on":"ペン","de":"インクが乾く前に手の側面にそっとにじんだ跡。よく書けても書けなくても、白い紙の前で最初に引く一画にはいつも小さな勇気がいる。考えが指先へ渡る橋だ。"},"ICON-0144":{"nm":"筆","on":"筆","de":"墨を含んで和紙の上を通る時、ためらった震えひとつまでそのまま残る。早く書こうと欲張ればたちまちばれる。筆は指先に宿った正直さを最も先に知る。"},"ICON-0145":{"nm":"吹き出し","on":"吹き出し","de":"言葉がまだ口の外に出る前、頭の上に先に丸く浮かび上がる場所。言いたいひと言がここに入る。空っぽの時は、どんな言葉を満たそうか選んでいる最中だ。"},"ICON-0146":{"nm":"チェックボックス","on":"チェックボックス","de":"空っぽの四角に二本の線を引くと心がいっそう軽くなる。終えたことに自分で授ける小さな勲章。一日の終わり、満たされたマスを見ながら、私たちは今日もよく生きたと安心する。"},"ICON-0147":{"nm":"タブレット","on":"タブレット","de":"指が触れるままに絵がにじみ文字が流れる。ひざの上にそっと載せると世界ひとつが明るくつく。軽いけれど、その中に入った可能性は決して薄くない。"},"ICON-0148":{"nm":"リモコン","on":"リモコン","de":"ソファの隙間に隠れることには天賦の才を持っている。チャンネルを回す権力はいつもこれを握った人のもの。家族の間の最も小さく愛おしい争いが、このひと幅の上で繰り広げられる。"},"ICON-0149":{"nm":"おもり","on":"おもり","de":"揺れるものをつかんでやろうと最も低い場所まで自ら降りた重さ。上が揺れ動いても下がずっしりしていればついに倒れない。均衡はいつも見えない場所で耐える。"},"ICON-0150":{"nm":"パズル","on":"パズル","de":"最後の一片を探してソファの下まで手探りした夜。ぴたりとはまる瞬間の音なきあの快感。散らばっていたものが元の場所を見つける時、ついに絵が完成する。"},"ICON-0151":{"nm":"ものさし","on":"ものさし","de":"長さを測るということは、約束を守ることでもある。ひと目盛りが誰にとっても同じであるように、目盛りは正直に並んでいる。まっすぐな一本の線が、ずれた心まできちんと整えてくれる。"},"ICON-0152":{"nm":"キャンバス","on":"キャンバス","de":"何もない白い面が一番こわくて、そして一番ときめく。最初の一点を打つまでは、何にだってなれるのだから。空っぽであることは終わりではなく、始まりのもう一つの名前だ。"},"ICON-0153":{"nm":"キューブ","on":"キューブ","de":"六つの面をそろえようとして徹夜した人は、一人や二人ではない。回して、また回す指先の執念。入り混じった色がそれぞれの場所に収まる瞬間、小さな宇宙がきちんと整う。"},"ICON-0154":{"nm":"ゲーム機","on":"ゲーム機","de":"休みのたびにいとこたちと頭を突き合わせてのぞき込んだ小さな画面。手のひらにすっぽり収まる冒険の世界。電源を入れるメロディの一節を聞くだけで、あの頃の夏がまるごと戻ってくる。"},"ICON-0155":{"nm":"グリップ","on":"グリップ","de":"ぎゅっと握ると手にぴたりと馴染むその感覚が、そっと自信を渡してくれる。滑らないように、取りこぼさないように。一番大切な瞬間、手と道具をしっかり一つに結びつける接点だ。"},"ICON-0156":{"nm":"万年筆","on":"万年筆","de":"インクを満たして書いているあいだは、字までも少し端正になる。さらさらと走るペン先の音に心を整えながら、手紙の一行目をゆっくり書き出したあの真心に、そっとよく似ている。"},"ICON-0157":{"nm":"パレット","on":"パレット","de":"赤の隣に青、黄色の上に緑。色がきちんと並んだこの小さな板の上で、絵はようやく表情を得る。混ぜて重ね塗るすべての冒険が、ここで最初の一歩を踏み出す。"},"ICON-0158":{"nm":"セット","on":"セット","de":"一つひとつは平凡でも、並んで集まれば一編の物語になる。欠けた欠片もなくそろったときの、あの頼もしさ。散らばったものを一か所に集めることには、小さな完成の喜びが宿る。"},"ICON-0159":{"nm":"シャトル","on":"シャトル","de":"ラケットに当たって舞い上がるとき、羽根が立てるやわらかな風の音。軽いから遠くまで飛べなさそうだけれど、本気で打てばコートの端までまっすぐ飛んでいく。軽さもまた、立派な一つの力だ。"},"ICON-0160":{"nm":"アンテナ","on":"アンテナ","de":"見えない信号をつかまえようと、じっと空に向かって立つ。遠くにある声さえも最後には引き寄せる、その忍耐。よく聞こえない日には、角度を少し変えてやれば、また鮮明になる。"},"ICON-0161":{"nm":"聴診器","on":"聴診器","de":"胸に冷たく触れる丸い先端、そしてしばし止まる息。小さな太鼓の音に耳を澄ませば、生きているという一番古いリズムが指先に伝わってくる。聴くことが先になる道具。"},"ICON-0162":{"nm":"チェスの駒","on":"チェスの駒","de":"ゆっくり、一マスずつだけ歩いた小さな駒。それでも一番奥の列に届いた瞬間、何にだってなれる。鈍い歩みで盤全体をひっくり返すその一手を、古びたチェス盤は静かに見守ってくれる。"},"ICON-0163":{"nm":"コントローラー","on":"コントローラー","de":"二本の親指で宇宙を駆けめぐった夜、覚えてる？負けたと投げ出して、ばつが悪そうにまた拾い上げた手垢のついたグリップ。画面の向こうの誰かと言葉なく交わした、一番長くて温かい会話。"},"ICON-0164":{"nm":"コンソール","on":"コンソール","de":"電源を入れると小さな起動音が挨拶のように鳴る。休みのあいだじゅう布団の中でつけたり消したりした四角い箱、幼い日の最初の冒険はいつもこの画面の灯りから始まった。"},"ICON-0165":{"nm":"タイムライン","on":"タイムライン","de":"左の端は始まり、右の端はまだ来ていない日。その間のどこにでも一つの点を引き寄せれば、忘れたと思っていた瞬間がまた広がる。時間を一本に横たえておく場所。"},"ICON-0166":{"nm":"プリズム","on":"プリズム","de":"澄んでいるだけだった光が、実は七つの色を秘めていたなんて。ガラス一片を通る瞬間、虹となってほどけ出す秘密。端正なものほど、その内側にはもっと多くの色が隠れている。"},"ICON-0167":{"nm":"ゴルフティー","on":"ゴルフティー","de":"ボールをそっと載せる小さな受け台一つ。遠くへ送りたいほど、まずしっかり支えてくれる何かが必要だ。芝の上のこの小さな杭が、最初の一歩を支える。"},"ICON-0168":{"nm":"編み針","on":"編み針","de":"一目、また一目。一つ落とせば全部ほどいて最初に戻らなければならない。冬のひと季節、膝の上でゆっくり長くなっていったマフラー、指先の忍耐が温かさに編まれていった場所。"},"ICON-0169":{"nm":"メロディライン","on":"ライン","de":"歌詞が乗る前に、口元でふんふんと漏れていた一節。まだ文字のついていないそのおぼろげな旋律の中に、歌の一番素直な最初の顔が宿っている。"},"ICON-0170":{"nm":"レーダー","on":"レーダー","de":"見えない闇に向かって信号を放ち、返ってくる一つの点をじっと待つ。何も見えなくても、そこに何かがあると信じる、丸い緑色の忍耐。"},"ICON-0171":{"nm":"リズムパッド","on":"パッド","de":"トントン、軽く叩けば光と音が同時に跳ね上がる。リズムを頭より先に手が覚える場所。手のひらの上に広がった、一番小さくてやさしい舞台。"},"ICON-0172":{"nm":"絵の具","on":"絵の具","de":"昔の絵師は石や土をすりつぶして色を得た。藍色は草から、赤色は土から。今、指先で絞り出されるこの一滴にも、自然をそっと移し取った古い真心が流れている。"},"ICON-0173":{"nm":"線","on":"線","de":"点と点をつなごうと心に決めた瞬間、ようやく生まれるもの。短くても長くても、曲がっていてもまっすぐでも、どこかへ行ってみようという気持ちが一番素朴に残した痕跡。すべての絵の始まり。"},"ICON-0174":{"nm":"シャッター","on":"シャッター","de":"カシャッ、その短い一度の暗闇が、一つの場面を永遠に捕らえる。まばたきの合間に流してしまいそうだった表情一つまで、光をそっと切り取って思い出に固めてくれる小さな刃。"},"ICON-0175":{"nm":"命綱","on":"綱","de":"高い所に登る人より一歩先にしっかり結ばれる綱。落ちるのではと気を揉む心を代わりに支え、見えないところでそばを守ってくれる約束の紐。いつも背中の後ろにいる。"},"ICON-0176":{"nm":"錠前","on":"錠前","de":"蔵に掛けた重たい鉄の錠前。何かを閉じ込めようとするのではなく、大切なものを安心して置いておこうとする気持ちだった。掛ける手つきにも真心が宿っていた、昔の家の頼もしさ。"},"ICON-0177":{"nm":"天秤","on":"天秤","de":"片方が重くなれば、もう片方は自然と軽くなる。何をどれだけ載せようかとためらうその瞬間、人は公平を学ぶ。傾きながら均衡を教えてくれる二本の腕。"},"ICON-0178":{"nm":"わりわり","on":"わりわり","de":"固くくっついたものも、目に沿っていけば結局は割れる。何でも二つに分けて中をのぞき込む小さな道具。合わさったものをまたほどいて見てみたい、好奇心いっぱいの指先。"},"ICON-0179":{"nm":"カウンター","on":"カウンター","de":"一、二、三。指の代わりに黙々と数を数えてくれる小さな友。落とすのではと気を揉む心を、カチカチと安心に変えてくれる勘定のやさしい伴侶。"},"ICON-0180":{"nm":"カーソル","on":"カーソル","de":"画面のどこかで点滅しながら、次の命令を待つ小さな矢。ためらっているあいだもその場所を離れず、さあ始めてみようと静かに手招きする光の先。"},"ICON-0181":{"nm":"ホールド","on":"ホールド","de":"指先の力が抜けきる直前、最後につかむその一点。離さないという気持ちひとつで耐える瞬間があるのだと、壁の上の小さな突起がそっと教えてくれる。"},"ICON-0182":{"nm":"小石","on":"小石","de":"小川で長いあいだ転がり、角をすべて手放した石。丸くなるということは、削られていった時間のもう一つの名前。手のひらにそっと握れば、流れていた川の忍耐が触れられる。"},"ICON-0183":{"nm":"紋章","on":"紋章","de":"昔の家門は一枚の旗に獣や星を刻んで自らを名乗った。言葉より先に心を渡していた絵。一人の誇りを小さな一枠にそっと凝縮した、古い印。"},"ICON-0184":{"nm":"盾","on":"盾","de":"立ちはだかるということは、いつも背中の後ろにいる人のためのことだった。飛んでくる矢を代わりに受け止めて、誰かの平凡な一日を守った、重たくもやさしい壁。"},"ICON-0185":{"nm":"復活","on":"復活","de":"消えてからまた灯る心がある。一度倒れてみてはじめて分かる、また立ち上がる方法。終わりだと思った場所で静かに満ちてくる、二度目の息。"},"ICON-0186":{"nm":"弓","on":"弓","de":"遠くへ送ろうとする手は、まず弦を限界まで引き絞る。送り出すにはそのぶん近くに抱きしめなければならないと、ぴんと撓んだ弓が静かに言葉なく教えてくれる。"},"ICON-0187":{"nm":"ハート","on":"ハート","de":"好きという言葉は、いつしか小さな形に縮んでいく。応援棒の先にも、向かい合わせた指の間にも、そっと描かれるこの形。心の一番ありふれた正直な略字。"},"ICON-0188":{"nm":"雲","on":"雲","de":"風の吹く方へゆっくり流れながら、そのたびに違う顔になる。うさぎだったり綿だったり、何も長くは抱え込まず流していく、空の一番軽やかな心。"},"ICON-0189":{"nm":"迷路","on":"迷路","de":"行き止まりの壁の前で引き返す術を学ぶ場所。さまよっているあいだも足取りは少しずつ出口へと育っていく。一度くらい道に迷ってみてこそ、道を見る目が開ける。"},"ICON-0190":{"nm":"歯","on":"歯","de":"抜けた歯を屋根の上に投げる風習があった。新しい歯がまっすぐ生えるようにという小さな祈り。育つうちに一度くらい失ってみてこそ、もっと丈夫なものを得るという、幼い日のやさしい約束。"},"ICON-0191":{"nm":"惑星","on":"惑星","de":"自らの軌道を一度も外れることなく星を巡る丸い体。孤独に見えても、いつもそばに何かを一緒に巡らせる重力。黙々と場所を守ることが、やがて一つの世界になる。"},"ICON-0192":{"nm":"星","on":"星","de":"道に迷った夜、人々は一番明るい点を見上げた。届かないほど遠くても、方向だけははっきり示してくれる光。遠くにあるという理由で、いっそう揺るがなくなる約束。"},"ICON-0193":{"nm":"シルエット","on":"シルエット","de":"光を背にして立つと、人は輪郭だけが残る。名前も表情も消えた黒い形一つ。空っぽだからこそ、かえってもっと多くを想像させる、満たさない余白。"},"ICON-0194":{"nm":"耳","on":"耳","de":"うまく歌うには、まずうまく聴かなければならない。リズムも心も、結局は聴くことから始まる。世のあらゆる音が一番先に届いて留まる、丸く開いた小さな扉。"},"ICON-0195":{"nm":"落ち葉","on":"落ち葉","de":"落ちるその瞬間が一番美しく輝く葉がある。ひと季節青々と茂ったことを赤く燃やしきって、そっと手放す軽やかさ。終わりもこんなに美しくありうるのだと、秋が見せてくれる。"},"ICON-0196":{"nm":"月","on":"月","de":"中秋の丸い光の下、両手を合わせて願いをかけた夜があった。満ち欠けを繰り返し、一度も同じだったことのない顔。変わりながらも、いつもその場所を照らす灯火。"},"ICON-0197":{"nm":"心臓","on":"心臓","de":"舞台の上でも一番正直なのは、結局この鼓動だ。震えても止まらず、込み上げればもっと大きく打つ。言葉で言い尽くせなかった応援を代わりにときめいてくれる、赤くて小さな太鼓。"},"ICON-0198":{"nm":"影","on":"影","de":"光がある限り、決して離れない同行者。明るいほど濃くなり、ぼやけるほど淡くなる、私を一番長く追ってきてくれたもう一人の私。ひとりの日にも、そばに立つ一人。"},"ICON-0199":{"nm":"しっぽ","on":"しっぽ","de":"嬉しければ自然と揺れ、こわければそっと丸まる。口はぐっと閉じても、ついに心を隠せない正直な端っこ。体が先に漏らしてしまう本音。"},"ICON-0200":{"nm":"しっぽ紐","on":"紐","de":"リボンのように端に結んで仕上げる小さな紐。ほどけないようにもう一度しっかり結び目を作った気持ち。散らばりやすいものを一か所に集めてなだめておく、やさしい締めくくり。"},"ICON-0201":{"nm":"瞳","on":"瞳","de":"言葉は選べても、眼差しは隠せない。見破られた心が一番先に漏れ出す場所、あの黒い丸の内側。好きという言葉を飲み込んでも、瞳はもう君に向かって揺れている。"},"ICON-0202":{"nm":"蹄鉄","on":"蹄鉄","de":"遠い道を駆けてきた足先がすり減るほど、いっそう丈夫になった鉄の一片。扉の上に逆さに掛けておけば、行き交う福がその中に溜まると言った。誰かの無事な帰宅を静かに支えている。"},"ICON-0203":{"nm":"紋章石","on":"紋章石","de":"雨風が文字をおぼろげにすり減らしても、指先でなぞれば刻まれた目がはっきりとよみがえる。忘れられたくなかったある心の重み。石はそうして一つの名前を長く抱いている。"},"ICON-0204":{"nm":"水かき","on":"水かき","de":"指の間をつなぐ薄い膜一つで、水をかく術を学ぶ。泳ぎが苦手なものに自然がそっと握らせた小さな櫂。遅くても結局は川向こうに届かせる、やさしい設計だ。"},"ICON-0205":{"nm":"ラメ","on":"ラメ","de":"手につくと何日もついて回ると皆こぼしながら、祭りの日には真っ先にこの光の粒を探す。星屑をひとつかみ振りまけば、平凡な紙もきらり、今日が特別になる。"},"ICON-0206":{"nm":"爪","on":"爪","de":"森の獣は爪で土を掻いて自らの道を残す。脅しではなく痕跡——ここを通ったという静かな署名。鋭い先端が、誰かにとってはやさしい道しるべになることもある。"},"ICON-0207":{"nm":"稲妻","on":"稲妻","de":"空がしばし手相を広げて見せる刹那、光が雷鳴より先に届く。大きな音が届く前に、ひと息整えろとでもいうように。恐れと驚嘆は、いつも同じ光から共に生まれる。"},"ICON-0208":{"nm":"お守り","on":"お守り","de":"赤い紙に墨でぎゅっと押し込めた願いの一行。枕の下に置けば悪い夢が避けて通ると信じた。誰かの無事を祈る心は、薄い紙一枚でもこんなに温かい。"},"ICON-0209":{"nm":"筆の翼","on":"筆の翼","de":"筆先が翼になる瞬間がある。一画引くとき、紙の上を滑るあの軽やかさ。字を書くことがすなわち飛ぶことであると、墨をすった昔の手はおぼろげに分かっていただろう。"},"ICON-0210":{"nm":"骨","on":"骨","de":"肉がすべて朽ちた後にようやく残るもの。一番丈夫だったからこそ最後まで耐え抜いた白い骨格だ。時間がすべて連れ去っても、ついに形だけは記憶する、静かな証一つ。"},"ICON-0211":{"nm":"鼻","on":"鼻","de":"匂いは記憶へ向かう一番の近道だ。祝祭の台所の油の匂い、初雪の降りた朝の冷たい空気——鼻先が先に気づいて、心がひと拍遅れて追いかける。"},"ICON-0212":{"nm":"トースト","on":"トースト","de":"忙しい朝、一番早く手に取る一食。こんがり焼けた面を噛みしめれば、一日分の勇気がサクッと砕ける。大げさでなくても頼もしいものが、人をまた立ち上がらせる。"},"ICON-0213":{"nm":"クッキー","on":"クッキー","de":"オーブンの前で一番長く待った人が、最初の一口を得る。焼きたての縁の温かさ、つかの間の甘さ。誰かを思い浮かべて焼いたものほど、不思議ともっと甘い。"},"ICON-0214":{"nm":"おやつ","on":"おやつ","de":"練習が長引く午後、かばんの奥から取り出す小さな袋。半分に分ければ、頼もしさは不思議と二倍になる。空腹より先に心を満たしてくれる、ひとつかみのやさしさ。"},"ICON-0215":{"nm":"カプセル","on":"カプセル","de":"回して開けてみるまでは、誰にも分からない。丸い殻の中に入っているのは、いつも同じときめき。小さな偶然を売り買いする、世界で一番正直なときめきだ。"},"ICON-0216":{"nm":"ドアノブ","on":"ノブ","de":"扉を開け閉めする無数の手が、一番先に触れる場所。冷たく始まって手のひらで温まる、家の最初の挨拶だ。手垢が積もるほど、その部屋は少しずつ誰かの家になっていく。"},"ICON-0217":{"nm":"散歩","on":"散歩","de":"目的地もなく歩くことにも理由はある。絡まった考えを足取りに一筋ずつほどいていく時間。ひと回りして帰れば、答えはそのままでも、心だけはずっと軽くなっている。"},"ICON-0218":{"nm":"スクーター","on":"スクーター","de":"狭い路地を切り裂いて走る二輪。速くなくても、風だけは全身で受ける。遠くまで行けなくてもいいから、今日はただ爽やかに走ってみたい、そんな日がある。"},"ICON-0219":{"nm":"安全バー","on":"安全バー","de":"乗り込む前、胸の前にしっかり下りてくる横棒一つ。こわい区間を最後まで一緒に耐えてくれる、頼もしい約束だ。ぎゅっとつかんでも大丈夫だと、冷たく言葉なく教えてくれる。"},"ICON-0220":{"nm":"階段","on":"階段","de":"一段ずつ登っていくと、いつのまにか風景が変わっている。一息で届く高さなどないと、足の裏が先に学ぶ。上り下りそれ自体が、誰かにとっては一日分の歩みだった。"},"ICON-0221":{"nm":"テラリウム","on":"テラリウム","de":"ガラスの中に森を閉じ込めたのではなく、一つの世界を丹精込めて育てることだ。苔が広がり水滴が結ぶ、手のひらほどの宇宙。のぞき込むほど、心が緑色にゆっくり染まっていく。"},"ICON-0222":{"nm":"壇上","on":"壇上","de":"ひと回り高い場所に登れば、見える風景が変わる。恐れと自負が同じ高さで出会う場所。誰が立つかによって、その一段は毎回違う舞台になる。"},"ICON-0223":{"nm":"飛行機","on":"飛行機","de":"雲が足元に広がる瞬間、離れてきた場所がようやく恋しくなる。遠ざかるのではなく、世界がもっと広くなること。小さな島で育った夢も、こうして空を渡っていく。"},"ICON-0224":{"nm":"スケートボード","on":"スケートボード","de":"転び方からまず学ばなければ、ようやく乗れる物。膝をすりむくたびに、バランスが少しずつ体に刻まれる。うまく転んだぶんだけ、もっと遠くへ転がる、正直な四つの車輪。"},"ICON-0225":{"nm":"パスポート","on":"パスポート","de":"表紙をめくれば、空白のページがいっぱいだ。満たされていくスタンプの一つひとつが、やがて生きてみた証になる。どこまで行ったかよりも、どこへでも行けるという可能性を秘めた小さな本。"},"ICON-0226":{"nm":"手描き地図","on":"略図","de":"正確な距離も比率もないけれど、手で描いてくれた道だから、まず迷う心配がない。路地と店の名前が親しげに絡み合った紙。心のこもった案内は、いつも道より先に温かい。"},"ICON-0227":{"nm":"動線図","on":"動線図","de":"舞台の上の足取り一つひとつが線で描かれた紙。どこで止まり、どこで回るか、矢印があらかじめ約束しておく。自由に見えるダンスも、実はこの一枚から始まる。"},"ICON-0228":{"nm":"座席案内紙","on":"座席案内紙","de":"見知らぬ空間で一番先に手探りで探すのは、自分の席だ。列と番号をたどって、ついに届いたその一枠。紙一枚が、何千ものときめきを一つひとつ、それぞれの場所に座らせる。"},"ICON-0229":{"nm":"路地案内カード","on":"カード","de":"迷路のような路地で道に迷う人のために、誰かが手ずから書いておいた案内。何番目の角で曲がれというやさしい字。町の人情が、小さなカード一枚にきっちり詰まっている。"},"ICON-0230":{"nm":"セキュリティカード","on":"カード","de":"このカードを首に掛けてようやく、内側の世界の扉が開く。出入りを許す小さな権限であり、ここに属しているという静かな証。手に入れるまでにかけた時間を知る人だけが、その重みを知る。"},"ICON-0231":{"nm":"仮入場バンド","on":"バンド","de":"手首に一度巻けば、外すまではその日の一員だ。紙のバンド一つが内と外を分け、同じ一日を共に過ごしたという印になる。切ってしまった後も、その跡はしばらく残る。"},"ICON-0232":{"nm":"ゲストラベル","on":"ラベル","de":"胸に貼る小さな名札一つで、見知らぬ場所が自分の居場所になる。歓迎するという言葉が紙一枚に乗せて手渡されるとき、初めて来た人もようやく客になる。"},"ICON-0233":{"nm":"ポスターチューブ","on":"ポスターチューブ","de":"くるくる巻いたポスターを、しわ一つなく守ってくれる丈夫な円筒。大切な絵ほど、まっすぐ伸ばして送らなければならないから。中は見えなくても、誰かの真心を抱いて旅立つ。"},"ICON-0234":{"nm":"資料集カバー","on":"カバー","de":"分厚い資料の束を包む最初の一枚。中身より先に手に触れる顔だ。表紙が端正なら、その中の心構えまで端正に見えるもの、小さな格式のやさしい始まり。"},"ICON-0235":{"nm":"記念ポストカード","on":"カード","de":"遠い場所の風景の一片に近況をしたためて送る。届く頃には、送った心も一緒に少し古びて、いっそう親しげになる。画面の中のメッセージがついに追いつけない、手紙の遅い温もり。"},"ICON-0236":{"nm":"ギフトタグ","on":"タグ","de":"贈り物の上に結ぶ小さな紙一枚。「あなたへ」という言葉だけで、包装はもう完成する。何を贈るかよりも、誰を思い浮かべたかを書く、世界で一番短い手紙。"},"ICON-0237":{"nm":"ラッピングシールロール","on":"ラッピングシールロール","de":"一枚ずつちぎって使うたびに、仕上げがいっそう美しくなる。ほどけそうな端を端正に押さえる小さな結び目。丹精込めて包んだ包装の最後の一手は、いつもこのくるくる巻いた帯から生まれる。"},"ICON-0238":{"nm":"透明レタースリーブ","on":"透明レタースリーブ","de":"手紙が歳月に色あせないよう包む、透明な一枚。字はそのまま見えるけれど、手垢だけは触れないように。誰かが大切にする心を、見えない膜が静かに守ってくれる。"},"ICON-0239":{"nm":"カラー封印シール","on":"カラー封印シール","de":"封筒を閉じる最後の一点、色が鮮やかなほど心が漏れ出さない。開ける前までは誰の手も触れていないという約束。秘密にも、こんなにきれいな結び目が必要だ。"},"ICON-0240":{"nm":"メッセージタグブック","on":"メッセージタグブック","de":"短いメモを一つにまとめて持った小さな本。一枚一枚が、誰かに渡す一言だ。言えなかった言葉をきちんと集めておけば、いつか必ず伝える勇気が育つ。"},"ICON-0241":{"nm":"折りたたみ案内板","on":"板","de":"広げれば「こちらです」、たためば「今日はここまで」。路地の入り口に脚を広げて立ったまま、道に迷う誰かのために一日じゅう立っている。たたまれる夕方が、私には一番やさしい休息だ。"},"ICON-0242":{"nm":"郵便整理帯","on":"帯","de":"はがきの一山を腰に巻いて抱えれば、散らばろうとしていた近況がようやくひと束の心になる。軽い帯一つが遠くまで行く言葉を端正に束ね、旅立つ背中をそっと見送る。"},"ICON-0243":{"nm":"感謝メモ束","on":"感謝メモ束","de":"ありがとうという言葉は口から何度も滑り落ちるから、手のひらほどの紙に書いてそっと束ねておく。束が分厚くなるほど、誰かに負った心の厚みも並んで育っている。"},"ICON-0244":{"nm":"応援文句サンプル紙","on":"応援文句サンプル紙","de":"「こう叫んでください」と書かれた見本一枚。まだ声がまとっていない応援は、最初の拍子を待つ空っぽの楽譜のように、静かにときめきだけを含んでいる。"},"ICON-0245":{"nm":"事前収録申請メモ","on":"メモ","de":"事前収録を取ってほしいと書いたメモは、いつも明け方五時の欄に留まる。眠りを削って場所を確保しようとする心を、小さな紙はすべて分かっているかのように、黙って書き留めておく。"},"ICON-0246":{"nm":"ファンサ順番券","on":"券","de":"何番目に挨拶を交わすかを決めてくれる一枚。列に並ぶのは順番を待つことではなく、好きな気持ちに番号をつけられなくて、しばし順序を借りることだ。"},"ICON-0247":{"nm":"待機番号ブレス","on":"待機番号ブレス","de":"数字一つで今日列に並ぶ順番が分かれる。前でも後ろでも、この小さくて軽い帯を手首に巻いた人たちは、結局同じ舞台を見に集まった一心同体の同志たちだ。"},"ICON-0248":{"nm":"フォトカード整理表","on":"表","de":"同じ顔なのに全部違うと、マスごとに分けて書く。表がびっしり埋まるほど心は端正になり、空いて残った一マスが、今日埋めたいときめきとなって胸をどきどきさせる。"},"ICON-0249":{"nm":"アルバムチェック紙","on":"アルバムチェック紙","de":"バージョン、フォトカード、封印の有無まで——数字で書き下ろした愛情のリストだ。すべて埋める日の誇らしさを前もって思い描きながら、今日も一行に丸をきれいに描き入れる。"},"ICON-0250":{"nm":"応援法メモ","on":"応援法メモ","de":"手の形、叫ぶ拍子、息を整える地点まで。初めて来た人もすぐに一つの声に混ざれるよう、小さなメモは親切な道案内となって手から手へ渡っていく。"},"ICON-0251":{"nm":"非公開メモパッド","on":"パッド","de":"誰にも見せない文章だけを選んでここに書く。開いたことのないページが一番素直だということを、このパッドは表紙を閉じたまま黙々と守ってくれる。"},"ICON-0252":{"nm":"記念日スタンプ紙","on":"記念日スタンプ紙","de":"押す、また一日が特別になる。平凡な日付の上にぽんと押される小さなスタンプ一つで、「今日」が記憶しておきたい日々の名簿に、そっと名前を載せる。"},"ICON-0253":{"nm":"クリップボードカバー","on":"カバー","de":"風が吹いても、雨が吹き込んでも、挟んでおいた紙だけは最後まで守る。ボードの鎧を買って出た私は、書かれた字たちの頼もしいボディガードだ。"},"ICON-0254":{"nm":"ファイルインデックス","on":"ファイルインデックス","de":"分厚い資料の中で道に迷わないよう、小さな舌をちょこんと出して「ここ」と知らせる。色とりどりの一枚の表が、百枚のページをひと目で治める。"},"ICON-0255":{"nm":"分類タブラベル","on":"ラベル","de":"これはこのマス、あれはあのマス。世の散らかりを一行ずつきちんと整理するのが私の仕事だ。ラベルが貼られる瞬間、ぐちゃぐちゃだったものがようやく自分の場所を見つける。"},"ICON-0256":{"nm":"ミニ決裁板","on":"板","de":"ハンコをぽんと押す瞬間、なぜか本当に大人になったような気分になる。大きさは小さくてもしっかりした権威で、通過印一つで積み上がった仕事がてきぱきと片づく。"},"ICON-0257":{"nm":"透明資料袋","on":"袋","de":"中が透けて見えて隠すものがない。大切な紙を抱いたまま、雨に濡れないか、しわにならないかと、透明な我が身で包み込んで約束の場所まで連れていってくれる。"},"ICON-0258":{"nm":"出席チェック帯","on":"帯","de":"来た、また一マスを埋める。毎日の足跡が帯に沿って並んで積もれば、見えなかった誠実さがようやくひと目で見える模様になる。"},"ICON-0259":{"nm":"間違い直しノート","on":"間違い直しノート","de":"間違えたものを書いておくことは、恥ずかしさを集めておくことではない。同じ場所で二度転ばないよう、昨日の失敗を今日の道案内に書き直すことだ。"},"ICON-0260":{"nm":"スケジュールスタンプ板","on":"板","de":"空っぽの予定表にスタンプ一つ押せば「約束」が生まれる。手首のスナップ一つで一日が決まる魔法——その魔法は実は、早め早めに備える勤勉さのもう一つの名前だ。"},"ICON-0261":{"nm":"背表紙ラベル","on":"ラベル","de":"本棚に背を向けて立つ本たちの名札。狭い背中に書かれた短い字が、何百冊の隙間から探していたその一冊を、一発で手招きして呼び出す。"},"ICON-0262":{"nm":"写真保護紙","on":"写真保護紙","de":"素手はお断り。指紋一つも残すなと、大切な一枚の上にそっと我が身を覆う。好きな気持ちは、こんな慎重な手つきで長く長く続く。"},"ICON-0263":{"nm":"フィルムインデックス紙","on":"フィルムインデックス紙","de":"フィルムの一列一列に番号をつけておけば、散らばっていた瞬間がまた物語の順番を取り戻す。光で記された記憶を取り違えないよう世話する、小さな案内者だ。"},"ICON-0264":{"nm":"フォトスリーブ袋","on":"フォトスリーブ袋","de":"四角い幸せを一枚ずつお迎えしておく透明な家。角が潰れる心配なく、一番大切にする顔がこの中で四季のあいだじゅう端正に輝く。"},"ICON-0265":{"nm":"ミニ現像封筒","on":"封筒","de":"焼きたての写真の温もりがまだ冷めないうちに、小さな封筒が両腕を広げて受け止める。手のひらほどの入り口から入った一枚は、いつのまにか誰かのかばんの中の宝物になる。"},"ICON-0266":{"nm":"レンチキュラーカバー","on":"カバー","de":"傾けると表情が変わる手のかかる写真を、傷一つなく守るのが私の任務。角度ごとに違う顔をすべて保護しようとなると、私もそれなりに勤勉でなければならない。"},"ICON-0267":{"nm":"カット分類ラベル","on":"ラベル","de":"四カットのうちどのカットがベストか、ラベルが代わりに指してくれる。よく撮れたものと面白いものを並べて分けておくこの小さな仕事が、思い出を二度楽しむ秘訣だ。"},"ICON-0268":{"nm":"四カット保管帯","on":"帯","de":"細長い四マス分の思い出をきちんと巻いて束ねる。舞い散ろうとするあの日の笑いをひと束にしっかり抱いて、かばんの奥まで無事に連れていく。"},"ICON-0269":{"nm":"写真コーナーシール","on":"写真コーナーシール","de":"アルバムに写真を貼るとき、四隅をそっとつかんでくれる小さな手。のりでべたべたにしなくても落ちないように——繊細さとは、こうして角から始まる。"},"ICON-0270":{"nm":"プリント補正表","on":"表","de":"もう少し温かく、ほんの少し暗く。気に入った色合いが出るまで数字をいじる表一枚が、ありふれた一枚をそっと作品に変えてしまう。"},"ICON-0271":{"nm":"レシートクリップ","on":"クリップ","de":"くしゃくしゃになったレシートを端正にくわえて離さない。小さな口で一日分の支出をしっかり預かってくれるから、月末の精算がいっそう軽やかになる。"},"ICON-0272":{"nm":"予約確認表","on":"表","de":"「予約されました」の一行に心がすっと安らぐ。紙一枚が約束の証となって、待つその日まで、ときめきをきちんと保管してくれる。"},"ICON-0273":{"nm":"返却確認証","on":"返却確認証","de":"借りたものを元の場所に戻したという、小さくとも堂々とした証。この紙が手に握られる瞬間、心の片隅に乗っかっていた借り一つが軽やかに消える。"},"ICON-0274":{"nm":"預かり証ホルダー","on":"ホルダー","de":"預けた物を受け取る引換券をなくさないよう、私が代わりにしっかり握っているよ。小さな紙一枚の行方が、誰かの一日の終わりを左右することもあるから。"},"ICON-0275":{"nm":"貸出表タグ","on":"貸出表タグ","de":"借りていった物ごとにひらひら揺れる小さなタグ。このタグをたどれば、誰が何を持っていったか一発で明らかになるから、紛失のミステリーもすぐに解けてしまう。"},"ICON-0276":{"nm":"検収チェック紙","on":"検収チェック紙","de":"一つひとつ目で手探りして、抜けたところがないか調べる。チェック印が並んで埋まるとき、見えなかった几帳面さがようやく信頼という名前を得る。"},"ICON-0277":{"nm":"精算メモ袋","on":"袋","de":"入ってきた金と出ていった金を封筒の上に書いておけば、散らかっていた数字が静かに並ぶ。精算の終わりは、いつもこの小さなメモがじっと終止符を打ってくれる。"},"ICON-0278":{"nm":"配送ラベル紙","on":"配送ラベル紙","de":"どこへ行くか、誰に届くか、我が身に書いたまま旅立つ。このラベルが貼られる瞬間、箱は目的地を持った旅人となって、わくわくと出発する。"},"ICON-0279":{"nm":"受領確認帯","on":"帯","de":"ちゃんと受け取ったという一言を帯一つに束ねて送り返す。受け取った人の安堵と送った人の安心が、この小さな紐の上でそっと互いに手を握り合う。"},"ICON-0280":{"nm":"単語カードリング","on":"リング","de":"ばらばらに散らばればなくしてしまう単語たちを、小さなリング一つが一つに貫いてつかまえる。めくって、まためくっていくうちに、見慣れなかった言葉がいつのまにか口に馴染んだ友になっている。"},"ICON-0281":{"nm":"発音メモ帯","on":"帯","de":"舌先が何度も滑る場所に、小さな印を一つつけておく。口の中で道に迷っていた見知らぬ音も、このメモをたどればいつのまにか自分の発音を見つける。たどたどしい音を少しずつ慣らしていく最初のページ。"},"ICON-0282":{"nm":"翻訳メモ箱","on":"翻訳メモ箱","de":"言葉と言葉のあいだを渡る小さな橋たちが、一マスずつきれいに折り畳まれて入っている。苦労して選んだ一言を書いてそっと渡せば、通じなかった心も、メモ一枚を間に挟んで近づく。"},"ICON-0283":{"nm":"文章スクラップ紙","on":"文章スクラップ紙","de":"心にこつんと触れた文章は、手で書き写してこそ長く残るもの。本の隅から切り取った一行を机の前に貼っておけば、その字が沈んでいた今日一日をそっと支えてくれる。"},"ICON-0284":{"nm":"ノートインデックス","on":"ノートインデックス","de":"分厚い本の中で道に迷わないよう挟んでおいた、色とりどりの小さな旗。戻る場所を知ってこそもっと遠くまでさまよえると、ちょこんと飛び出したタブが本のページの間で静かに教えてくれる。"},"ICON-0285":{"nm":"暗記チェックチップ","on":"チップ","de":"覚えたもののそばにこつんと押しておく一点の印。頭の中にしばし立ち寄って消えようとするものをつなぎとめる小さな錨だから、黒く埋まったマスごとに、昨夜流した努力が静かににじんでいる。"},"ICON-0286":{"nm":"クイズ封筒パック","on":"クイズ封筒パック","de":"封筒を破るまでは、何が出るか誰も分からない。指先で封じた場所をいじるその数秒——問題一つがきれいに折り畳まれて入った、ときめきまで一緒に封じたときめきの包み。"},"ICON-0287":{"nm":"文法タブノート","on":"ノート","de":"規則は頭で覚えるのではなく、手に馴染ませるものだ。よく開く方の色タブから、すべすべに擦り減っていくノート、その擦れた角こそが、君が耐えた時間の年輪になる。"},"ICON-0288":{"nm":"スピーキング練習表","on":"表","de":"口を開くことが世界で一番難しい人のための表一枚。マスを指でなぞって下りていけば、喉の奥で震えていた最初の一言も、いつのまにか自分の声を見つける。勇気にも順番があるのだから。"},"ICON-0289":{"nm":"カラーラフ紙","on":"カラーラフ紙","de":"完成する前の色たちが荒々しく横たわって息を整える。正解ではなく、まだ可能性である状態——磨ききれていないこの一枚の上に、何よりも多くの明日が含まれて揺れる。"},"ICON-0290":{"nm":"ムードボードの欠片","on":"ムードボードの欠片","de":"ばらばらに散らばった印象を一か所に集めて貼れば、なかなか手につかめなかった雰囲気がおぼろげに輪郭を現す。まだ名前のないある感覚を、欠片たちが互いに寄りかかってそっと指し示す。"},"ICON-0291":{"nm":"パターンサンプル帳","on":"パターンサンプル帳","de":"風呂敷の格子と格子窓の組みが、一冊にきちんと整理されている。同じ模様が最後まで繰り返される場所には、怠けではなく約束が宿る——ひと筋を守り抜く、揺るがない心。"},"ICON-0292":{"nm":"衣装スウォッチ紙","on":"衣装スウォッチ紙","de":"同じ色なのに、布切れごとに肌合いと影が違ってにじむ。舞台衣装を選ぶ前、指先で何十回もなで、ためらったあの夜が、小さな見本一つにそっくり留められている。"},"ICON-0293":{"nm":"ロゴ禁止指示紙","on":"ロゴ禁止指示紙","de":"してはならないことを先にきっちり書いておいた紙。赤いバツ印が引かれた輪郭の中で、かえって自由がはっきりするから、行き止まりだと思った場所で、かえって新しい道が開ける。"},"ICON-0294":{"nm":"色味リファレンスチップ","on":"チップ","de":"色は言葉ではどうにも説明できなくて、別に作っておいた見本の欠片。夕焼けが一番赤かったある刹那を小さな手のひらの上に閉じ込めて、次の人に「まさにこの色だよ」と正確に渡せるようにした。"},"ICON-0295":{"nm":"配置ラフカード","on":"カード","de":"何をどこに置くか、軽く引いてみた最初の絵。場所を決めることがすなわち心を決めることだから、たどたどしく散らばった線の間で、全体の均衡がゆっくり目を覚ます。"},"ICON-0296":{"nm":"素材メモ板","on":"板","de":"木、土、石——触れられるものの名前がびっしり書かれている。目をまず手で読んでから始める人だけが知る秘密、何で作るかが、何になるかをすでに半分ほど決めている。"},"ICON-0297":{"nm":"図案トレーシング紙","on":"図案トレーシング紙","de":"下絵の上に薄い紙を載せて、じっと線をなぞって描く。他人の道をしばし借りるあいだに私の手がその道を覚え、なぞっていた線の間で、いつのまにか私だけの線がそっと育っていく。"},"ICON-0298":{"nm":"入場動線帯","on":"帯","de":"床に長く貼られた帯に沿って、人々が列をなして入っていく。浮き立った足取りが絡まないようそっと案内する一本——ときめきが崩れないように支えた、見えないやさしい手だ。"},"ICON-0299":{"nm":"イベント案内ピケット","on":"イベント案内ピケット","de":"「こちらです」の一言を代わりに掲げて立っている札。誰かが迷わないよう道筋ごとに立てておいた小さな親切が、初めて来た人の見知らぬ一日を、手を取るようにそっと連れて歩く。"},"ICON-0300":{"nm":"ブース番号ラベル","on":"ラベル","de":"ブースごとにつけられた番号一つが、その一マスの主をはっきり定めてくれる。小さな数字だけれど「ここは君の場所だよ」という約束だから、見知らぬ会場で帰ってこられる場所ができる。"},"ICON-0301":{"nm":"スタッフ同意書","on":"スタッフ同意書","de":"一緒に働こうと心を一つにした場所に残された一筆の署名。薄い紙一枚だけれど、その中には互いを信じてみようという重みが込められていて、イベントのすべての手仕事はまさにここから始まる。"},"ICON-0302":{"nm":"体験券の束","on":"体験券の束","de":"片手に握りやすいよう厚めに束ねられた体験券の束。ほどいて配るほど減るのではなく、誰かの「はじめて」をどんどん増やしてくれる、触れるほど温かくなる人情の束だ。"},"ICON-0303":{"nm":"待機列マーカー","on":"待機列マーカー","de":"ここからお並びください、と床がそっと語りかけてくる。順番を守る心が集まれば長い列も一つの風景になり、小さな目印一つがせかせかした気持ちを落ち着きへと変えてくれる。"},"ICON-0304":{"nm":"現場受取タグ","on":"現場受取タグ","de":"あらかじめ注文したものを直接受け取る場所でそっと添えられる小さなタグ。手に握った瞬間、肩からするりとほどける軽い安堵——長く待った気持ちがようやく形を得る結び目だ。"},"ICON-0305":{"nm":"ランダムボックス券","on":"券","de":"何が入っているか分からないまま一つを選ぶ楽しさ。振ると中でカタカタ鳴る音に胸が先に高鳴り、開ける直前のそのわずかな間が一日でいちばん膨らんだ時間になる。"},"ICON-0306":{"nm":"交換完了シール","on":"シール","de":"やり取りが無事に終わったことを知らせる小さくて丸い印。差し出した手と手の間に残るなめらかな終止符で、一度ぽんと貼られると、その取引はそこでようやく温かく丸くおさまる。"},"ICON-0307":{"nm":"記録封印バンド","on":"バンド","de":"大切な箱をバンドでぐるりと巻いてそっと封じる。むやみに開けないでほしいという頼みであり、中身をそれだけ大切に思っているという最も静かな礼儀が、一本のバンドに込められている。"},"ICON-0308":{"nm":"秘密メモカプセル","on":"秘密メモカプセル","de":"言いたかった一言を小さな筒の中にそっと閉じ込めて保管する。出せなかった気持ちを埋めるようにしっかり閉じておけば、いつかまた開ける日まで、手のひらの上の小さな金庫が時間を守ってくれる。"},"ICON-0309":{"nm":"ミニスクラップカード","on":"カード","de":"切り貼りした一片に、その日の気分がほのかに滲んでいる。日記より軽く写真より手触りのある——指の間からこぼれ落ちやすい一日を、手のひらほどの紙がしっかり留めておく。"},"ICON-0310":{"nm":"初訪問記録紙","on":"初訪問記録紙","de":"この島に初めて足を踏み入れた日のときめきが、短い一行に残る。見知らぬものが親しみに変わるその直前、最も澄んでいた最初の気持ちを、紙が代わりに抱いて長く守ってくれる。"},"ICON-0311":{"nm":"思い出分類表","on":"表","de":"思い出を筋道と種類ごとに丁寧に分けて書き留めた表。すべての記憶を一つの引き出しに乱雑に積めば、いちばん大切にしていた一日さえ埋もれてしまうから、大切なものほどきちんと居場所を定めておく。"},"ICON-0312":{"nm":"吹き出しメモチップ","on":"チップ","de":"言いたかった言葉が風船のように丸く膨らんで紙の上に浮かんでいる。口に出せなかった一言も、丸い縁の中ではそっと勇気を出す——気持ちが抜け出てくる小さくて温かい通り道。"},"ICON-0313":{"nm":"日付ホルダー","on":"ホルダー","de":"今日が何日かをまっすぐ立てて向き合わせる小さな台。次々と流れていく日々の中からたった一日を選んで正面に座らせれば、ただ平凡だった日付にも記念すべき温もりが宿る。"},"ICON-0314":{"nm":"所蔵番号タグ","on":"所蔵番号タグ","de":"大切なものごとに一つずつ付けた固有の番号。所蔵するということは、その一つを世界でただ一つとして呼んであげるという誓いなので、小さなタグの上の数字に心の重みがはっきりと刻まれる。"},"ICON-0315":{"nm":"アーカイブスリップ","on":"アーカイブスリップ","de":"長く取っておいて眺めるものを一枚ずつ挟み込む薄い中敷き。光と時間から一枚ぶんだけそっと遠ざけておくこと——何かを愛するとは、結局それをきちんと保管しきることだ。"},"ICON-0316":{"nm":"トレカトップローダー紐","on":"紐","de":"トップローダーを首に掛けられるようつなぐ細い紐。推しを胸元に置いて一日を歩くオタ活のやり方なので、この細い一本に一日中の優しい同行が結ばれている。"},"ICON-0317":{"nm":"トレカスタンドピン","on":"ピン","de":"小さなピン一つでトレカが机の上にまっすぐ立ち上がる。寝かせればただの一枚の紙だけれど、立てればようやく向き合う間柄になり、視線が長くとどまる場所をそっと作ってくれる。"},"ICON-0318":{"nm":"ホロトレカフィルム","on":"ホロトレカフィルム","de":"角度によって虹がするすると流れる薄い一枚のフィルム。光をそっと閉じ込めた膜が平凡なカードに星明かりをまとわせ、手首で振るたびに違う表情がきらりと目を覚ます小さな魔法だ。"},"ICON-0319":{"nm":"トレカ保護キャップ","on":"保護キャップ","de":"角が一度押されただけでも、大切にしていた気持ちまで一緒に折れてしまう気がする。大事な一枚をしっかり抱きしめる透明な鎧なので、本気で大切にすることには、いつもこんな慎重さがついて回る。"},"ICON-0320":{"nm":"トレカ整列トレー","on":"トレー","de":"何十枚ものトレカを筋目どおりに整えて寝かせる浅い盆。散らばればただの一山だけれど、列を揃えて寝かせればコレクションになり、整理する手つきごとに愛情の順番が一つずつ刻まれる。"},"ICON-0321":{"nm":"トレカ交換封筒","on":"封筒","de":"トレカ一枚を封筒に入れて差し出すとき、指先が一瞬ためらう。手放すのではなく、誰かの推しになってほしいという頼み。封筒の口を折るその瞬間、小さな縁が一つ、そっと手を変える。"},"ICON-0322":{"nm":"トレカ飾りペン","on":"ペン","de":"余白を埋めるのは文字ではなく心だ。ペン先が通った跡ごとに小さなハートと星が芽吹き、平凡な紙一枚が世界にただ一つの応援として目を覚ます。飾ることは、つまり告白の別の名前。"},"ICON-0323":{"nm":"トレカクリップリング","on":"リング","de":"カチッ、とクリップが噛む音。その小さな留め具一つで、散らばりかけたカードが一列に集まる。鞄の中で一日中揺れても角一つ傷つかないように。丈夫さとは、これほど静かなものだ。"},"ICON-0324":{"nm":"トレカ持ち運びポーチ","on":"ポーチ","de":"ファスナーを開け閉めする手つきに、いつしか習慣が染みついている。にわか雨に遭っても、人波に押されても、内側だけは乾いたまま。いちばん大切なものをいちばん奥に置く心、それが持ち運びという優しい労働だ。"},"ICON-0325":{"nm":"ファンミブレス紐","on":"紐","de":"手首に紐を結んでくれたスタッフの手が温かかったと、あるファンは長く覚えていた。結び目一つで、今日この場に属しているという目印。ほどけないようにと二度巻いたその紐が、一日ぶんのときめきを留めておく。"},"ICON-0326":{"nm":"入場リストバンド","on":"バンド","de":"入口を通るまさにその瞬間、ようやく内と外がはっきり分かれる。一日中つけているといつしか肌になじみ、外す頃には細い跡が残る。そこにとどまった場所の証のように。"},"ICON-0327":{"nm":"トークコーナーチップ","on":"チップ","de":"トークコーナーが始まると、チップが一つコロコロと転がる。誰が先に話すか、どの質問が引かれるか——その小さな偶然が雰囲気をまるごと変える。決められた台本より、チップ一粒の気まぐれのほうが愛おしい。"},"ICON-0328":{"nm":"サイン会待機券","on":"券","de":"番号の書かれた紙を手に握って列に並ぶ。142番。先の141人を数える間、心臓が先に順番を数える。待ち時間は長いけれど、この一枚のおかげでその時間さえときめきの一部になる。"},"ICON-0329":{"nm":"ハイタッチ手袋","on":"ハイタッチ手袋","de":"手のひらが触れ合う刹那、手袋がその短い温もりを代わりに受け止める。0.5秒の出会いのために一日中温めてきた手。布をはめていても、その震えだけは止められないと、誰もがそこで知る。"},"ICON-0330":{"nm":"記念撮影ピン","on":"ピン","de":"カシャ、という音一つで今日がそのまま標本になる。ピンで固定したフレームの中、ぎこちなく笑っていた表情さえ、後にはいちばん恋しい一場面になる。記録は、瞬間をとらえる最も優しい欲だ。"},"ICON-0331":{"nm":"座席リボンタグ","on":"座席リボンタグ","de":"座席の背もたれに垂れた小さなリボンが、風もないのにそよぐ。誰かが結んでおいた目印、ここに人がいたという痕跡。公演が終わった空席でも、リボンだけはまだ拍子を覚えているようだ。"},"ICON-0332":{"nm":"贈り物検品ラベル","on":"ラベル","de":"贈り物一つひとつにラベルが貼られる。届けたか、確認したか、抜けはないか。心を受け取ることにも切り盛りが要るから、この小さなシールが真心と真心の間を漏れなくつないでくれる。"},"ICON-0333":{"nm":"メモリアルスリップ","on":"メモリアルスリップ","de":"長く取っておいて眺めようと書き留めた紙一枚。その日の天気、座席番号、最後の曲名まで。記憶は薄れても、このスリップだけは薄れない。思い出を保管するにも、小さな様式が要るものだ。"},"ICON-0334":{"nm":"応援タオルフック","on":"フック","de":"タオルの端にフックを掛ければ、肩から滑り落ちない。汗を拭い、頭の上で回し、また首に掛ける動作の合間合間に。小さなつなぎ一つが、応援の身振りを途切れさせずにつないでくれる。"},"ICON-0335":{"nm":"スローガンクリップ","on":"クリップ","de":"スローガンの両端をクリップがしっかりとつかむ。両腕を高く上げても文字が折れたり翻ったりしないように。見えないところでメッセージをまっすぐ伸ばしてくれる、最も寡黙な脇役がここにいる。"},"ICON-0336":{"nm":"防音ポーチ","on":"ポーチ","de":"ファスナーがゆっくりと、音もなく滑る。静けさが約束された場所で、たった一つの雑音も漏れないよう設計された沈黙。気遣いとは時に、聞こえないようにすることだと、このポーチがそっと語る。"},"ICON-0337":{"nm":"拍手リズムチップ","on":"チップ","de":"手のひらを打ち合わせるたびにチップが拍子を数える。パン、パン、パン——散らばった拍手がある瞬間、一つのリズムに集まる。数千人の拍手が一つの呼吸になるその魔法を、小さなチップが静かに手伝う。"},"ICON-0338":{"nm":"応援法フォルダー","on":"応援法フォルダー","de":"広げると応援法が段階ごとに書かれている。どの小節でどの色を掲げ、いつ歓声を入れるか。初めて来た人もこのフォルダー一冊ですぐに一家になる。約束を分かち合う小さな案内書だ。"},"ICON-0339":{"nm":"座席うちわ紐","on":"紐","de":"うちわの取っ手に紐を結んでおけば、手から離しても落ちない。暑い日にあおいでいて、歓声に両手が自由になるとき、手首にぶらぶらと。紐一本が暑さと興奮を一度に冷ましてくれる。"},"ICON-0340":{"nm":"きらめきフィルム片","on":"きらめきフィルム片","de":"光を受けると一片ごとに違う角度で砕ける。手のひらの上に乗せれば小さな虹がちらつき、振るたびに色が生きて動く。きらめきとは、光を細かく分け合うことなのかもしれない。"},"ICON-0341":{"nm":"ミニバナー棒","on":"棒","de":"小さな棒を広げると布が風を受けてぴんと張る。両手で高く掲げれば文字が客席の向こうまで届き、たためば鞄の片隅にすっと。心の大きさは、棒の長さで測るものではない。"},"ICON-0342":{"nm":"応援シールパック","on":"応援シールパック","de":"シール一枚一枚に応援の言葉が刻まれている。手帳に、携帯に、ノートパソコンの角に——貼る場所ごとに日常が応援に染まる。好きという気持ちは、こうして至るところに痕跡を残す。"},"ICON-0343":{"nm":"アルバム保護カバー","on":"カバー","de":"アルバムをカバーで包む手つきが慎重だ。角が擦り減らないように、日に当たって色あせないように。音楽は耳で聴くけれど、この一枚は手が覚えている。大切なものを長く側に置こうとする心の鎧だ。"},"ICON-0344":{"nm":"ディスクスリーブリング","on":"リング","de":"ディスクをスリーブに入れてリングで束ねれば一冊の音盤帳になる。一枚ずつめくるときのカサカサという音が好きだ。散らばった音楽を手の中に整えて集めること、それが収集家の静かな幸せだ。"},"ICON-0345":{"nm":"グッズ収納仕切り","on":"グッズ収納仕切り","de":"仕切り一つで混ざりかけたグッズが居場所を見つける。ここはトレカ、あそこはキーリング、その隣はペンライト。整理とは物に家を建ててやること。仕切りが分かれた瞬間、雑然が秩序に変わる。"},"ICON-0346":{"nm":"ランダムパック封印紐","on":"紐","de":"ランダムパックの口を紐で縛れば、誰の運命もまだ決まっていない状態になる。ほどくまでは皆が期待の主人公。封を解く指先の震えこそ、この紐が守ってきた楽しさだ。"},"ICON-0347":{"nm":"特典整理ボックス","on":"特典整理ボックス","de":"特典がボックスの中で種類ごとに列をなす。ハガキはハガキ同士、しおりはしおり同士。増えるほどびっしりになる区画を見れば、これまで集めた時間が一目で目に入る。整理とは、つまり思い出の目録だ。"},"ICON-0348":{"nm":"バージョン区分ラベル","on":"ラベル","de":"同じに見えても同じではないものがある。ラベル一つがAバージョンとBバージョンを、初版と再版を分けてくれる。小さな目印のおかげで紛らわしさが消え、収集の世界にはっきりした名札が一つ付く。"},"ICON-0349":{"nm":"初動チェックメモ","on":"メモ","de":"発売初週、数字一つに心が揺れる。メモ用紙にきちんと書き留めたチェック印。数日の記録が集まれば、小さな応援の成績表になる。好きという気持ちを数字に翻訳する、心のこもった習慣。"},"ICON-0350":{"nm":"ポスター固定キャップ","on":"キャップ","de":"くるくると巻かれたポスターの端にキャップをはめれば、広がったままおとなしくなる。壁に掛けようか、額に入れようか迷う間も、しわにならないように。いちばん好きな場面をまっすぐ守ってくれる小さな栓だ。"},"ICON-0351":{"nm":"スタンディングフォト台","on":"台","de":"台の上に写真が斜めに立つ。机の片隅、目線にぴったり合う角度で。通り過ぎるたびに目が合うようにする発明。好きな顔を毎日の風景の中に迎え入れる、最も簡単な方法だ。"},"ICON-0352":{"nm":"リハーサルテープロール","on":"リハーサルテープロール","de":"床にテープを貼って立つべき位置を示す。一マス、二マス、正確にここ。同じ跡を何十回も踏みながら、動線が体に刻まれる。華やかな舞台の下には、この正直なテープの跡が敷かれている。"},"ICON-0353":{"nm":"舞台動線ピン","on":"ピン","de":"舞台の床にちょこんと刺さったピン一つが、次の一歩を教えてくれる。暗闇の中でも、つま先が先にその位置を見つけにいく。見えなくても正確な道、数えきれない練習が描いておいた見えない地図だ。"},"ICON-0354":{"nm":"スタッフイヤーキャップ","on":"キャップ","de":"イヤーキャップをはめると客席の歓声が一枚和らぎ、キューを伝える声だけがはっきりする。舞台裏のスタッフの耳は、いつも二つの世界を同時に聞いている。騒がしさの中から信号を選り分ける小さな道具だ。"},"ICON-0355":{"nm":"楽屋ハンガー札","on":"札","de":"ハンガーごとに名札が掛かっている。1番衣装、2番衣装、アンコール衣装。着替える順番がずらりと書かれたその札を見れば、一日の舞台が衣装の順番であらかじめ描かれる。慌ただしさを治める静かな秩序。"},"ICON-0356":{"nm":"小道具検品タグ","on":"タグ","de":"舞台に上がる前、小道具一つひとつにタグが付けられる。抜けはないか、無事か。客席は知らないけれど、この小さな点検が事故を防ぐ。完璧に見える舞台の裏には、いつも丁寧な手がある。"},"ICON-0357":{"nm":"キューサインチップ","on":"チップ","de":"キューサインのチップが手から手へと渡る。今、入って。言葉一つなくタイミングが伝わる瞬間。舞台脇の暗闇の中で、この小さな信号が皆の拍子を逃さないように留めておく。"},"ICON-0358":{"nm":"バックステージパッチ","on":"バックステージパッチ","de":"このパッチをつけた人だけが通れる扉がある。舞台裏、歓声が壁の向こうから聞こえてくる場所。小さな布切れ一つが、華やかな表と慌ただしい裏を分ける。舞台を支える人々の目印だ。"},"ICON-0359":{"nm":"プロンプター遮光板","on":"板","de":"遮光板がプロンプターの光を客席に漏らさないように抑える。舞台上の人だけが見て、見る人は知らないように。気づかれてはいけない助け一つを静かに隠してくれる、舞台の上品な秘密の番人だ。"},"ICON-0360":{"nm":"楽屋鏡カバー","on":"カバー","de":"公演が終わった楽屋、鏡を布で覆う。一日中数えきれない表情を映していたガラスがしばし目を閉じる。化粧を落とした素顔が最後に向き合うのは、鏡ではなく静かな暗闇だ。"},"ICON-0361":{"nm":"事前収録入場ブレス","on":"事前収録入場ブレス","de":"一度つければ切るまではほどけない小さなバンド。事前収録の客席に入るたった一つの資格のために、誰かは真っ暗な明け方の始発に身を乗せた。手首の重みが、その日一日ぶんのときめきになる。"},"ICON-0362":{"nm":"収録待機ラベル","on":"ラベル","de":"赤いランプが点く直前、皆の息を一列に束ねておくのが私の仕事だ。キューサインを待つ静寂の中で、私は最後まで静かに耐える。剥がされる瞬間、ようやく本番の幕が上がる。"},"ICON-0363":{"nm":"カメラ位置チップ","on":"チップ","de":"床に記された小さな目印一つが、六台のカメラの動線をきっちり定める。どこで捉えればいちばん明るく映るか、監督はリハーサル前から知っている。画面の外から画面の中をあらかじめ描いておく手つき。"},"ICON-0364":{"nm":"音響チェック下げ札","on":"札","de":"空の客席に向けてマイクをトントンと叩いてみる。響きが長ければ天井に吸音材をもう一枚。観客が知らないうちに音の質感を整える真心が、この小さな下げ札からそっと始まる。"},"ICON-0365":{"nm":"現場スタンプブック","on":"現場スタンプブック","de":"現場を通るたびに一マスずつスタンプを集める。インクが滲んだ跡ごとに、その日の天気とときめきが一緒に押された。すべて埋めたページは、誰にもまねできない、私だけの足跡の地図になる。"},"ICON-0366":{"nm":"放送局訪問証の紐","on":"紐","de":"この紐がなければロビーのゲートは開かない。首に掛けたまま廊下を一歩ずつ歩く間、昨日まで画面でしか見られなかった世界が、ゆっくりと手に届くほど近づいてくる。"},"ICON-0367":{"nm":"スタジオ足袋パック","on":"スタジオ足袋パック","de":"スタジオの床はいつも冷たくて滑る。靴を脱いで薄い足袋を履けば足音がするりと消える。カメラが収めるのはダンスであって足取りではないから、音を消すことも舞台への礼儀だ。"},"ICON-0368":{"nm":"楽屋おやつタグ","on":"楽屋おやつタグ","de":"リハーサルと本番の間、空腹は最も正直に訪れる。楽屋の片隅、おやつごとに誰のぶんか書かれた小さな名札。気にかけておくその優しさが、長い長い一日を最後まで持ちこたえさせる。"},"ICON-0369":{"nm":"モニタリングメモバンド","on":"バンド","de":"映像を巻き戻して見ながら書く。ここでは視線を、あそこでは半拍を。びっしりの文字は明日の自分に送る秘密の手紙。最後に付けたこのバンドは、昨日より一歩よくなろうという静かな約束だ。"},"ICON-0370":{"nm":"ショーケース招待スリップ","on":"ショーケース招待スリップ","de":"紙一枚が、誰かにとっては丸一年の待ち時間になることもある。ショーケースに招待するという短い一文、封筒を開ける指先の震えまで込めて、世界でいちばん小さな招待状として生まれた。"},"ICON-0371":{"nm":"プレス首掛け紐","on":"紐","de":"取材陣の首に掛かり、シャッター音の真ん中を駆け抜ける。いちばんいい角度を探して慌ただしく走る足取り、その速さがそのまま、舞台の熱を外の世界へ運ぶ通り道になる。"},"ICON-0372":{"nm":"舞台挨拶順序表","on":"表","de":"拍手がどっと降り注ぐ瞬間にも乱れないよう、誰が先で誰が次かを一列に書いておく。最後の挨拶の整列は、最初の登場と同じくらい丁寧に組まれるものだ。"},"ICON-0373":{"nm":"フォトウォール床目印","on":"フォトウォール床目印","de":"フォトウォールの前の床には、つま先を置く位置があらかじめ刻まれている。一歩でもずれると背景のロゴが切れるから。いちばん明るく収まるその位置の秘密は、足元に静かに示されている。"},"ICON-0374":{"nm":"試写会ブレス","on":"試写会ブレス","de":"劇場の灯りが消える直前に手首につけられる小さなバンド。幕が上がれば皆が同じ暗闇の中で、同じ場面を生まれて初めて出会う。その最初の瞬間に一緒にいたという、小さな立会の目印だ。"},"ICON-0375":{"nm":"記念カーテン片","on":"記念カーテン片","de":"千秋楽の日、最後の挨拶の後にカーテンがゆっくり下りてきた。その一幅を切って額に収めた一片。布には照明の熱と拍手の振動が、まだほんのり残ったまま冷めずにいる。"},"ICON-0376":{"nm":"初公開スタンプ","on":"初公開スタンプ","de":"世に初めて姿を現す日、その一度のために刻まれた印。二度目の初公開はないから、インクが乾く短い瞬間さえ、二度と戻らない時間だ。"},"ICON-0377":{"nm":"舞台ひとこまカード","on":"カード","de":"ある舞台でいちばん輝いていた一こまを切ってカードに収めた。音楽も照明も止まったけれど、手に握る瞬間、その日の歓声が耳元でまた膨らんでくる。止めておいた場面がよみがえる小さな魔法。"},"ICON-0378":{"nm":"エンディングポーズメモ","on":"メモ","de":"最後の音が終わる刹那、止めるべき指先と視線の角度を描いておいたメモ。エンディングの一こまが数日を左右すると知る人だけが、この小さな絵を大切に折りたたんでおく。"},"ICON-0379":{"nm":"ツアー都市ピン","on":"ピン","de":"地図の上、回った都市ごとにピンが一つずつ刺さる。釜山の潮風も光州の真昼も、この小さな釘先に刺さっている。点をそっとつなげば、ひと季節を横切った長い旅路の線が見える。"},"ICON-0380":{"nm":"座席エリアクリップ","on":"クリップ","de":"何万もの座席をエリアに分けて道を案内する。迷わないように、ぶつからないように。私についてくれば誰でも自分の席にたどり着く。秩序とは結局、みんなのための小さな親切なのだから。"},"ICON-0381":{"nm":"入場ゲートタグ","on":"入場ゲートタグ","de":"ゲートの前で一人ずつ順に確認を経る。券を握った手とときめく心を中へ通す最後の関門。私を通る瞬間、長かった待ち時間は終わり、今日の舞台が始まる。"},"ICON-0382":{"nm":"ブレス保管カプセル","on":"ブレス保管カプセル","de":"色があせても、その日の歓声だけはそのまま封じられる。手首のバンドをどうしても捨てられず、小さなカプセルにそっと巻いて入れる。大切な思い出にも、その身を横たえる一区画くらいは用意してあげたくて。"},"ICON-0383":{"nm":"現場交換棒","on":"棒","de":"ファンと舞台の間、手から手へと何かが渡る。手紙かもしれないし、小さな贈り物かもしれない。私はその気持ちが無事に届くよう道を開いてやる、現場で最も慌ただしい橋だ。"},"ICON-0384":{"nm":"公演日付シール","on":"公演日付シール","de":"その日の日付が丸いシールの中に刻まれて永遠に止まる。カレンダーはめくられても、この小さな円だけはその一日にそのままとどまる。忘れたくない日には、人はいつも何かを封じておく。"},"ICON-0385":{"nm":"ツアー鞄パッチ","on":"ツアー鞄パッチ","de":"一緒にツアーを回った鞄には、都市ごとにパッチが一枚ずつ増える。布の上に縫いつけた地名が、いつしか履歴書になる。擦り切れた角でさえ、どこへでも一緒に行ったという証として残る。"},"ICON-0386":{"nm":"チケットボード紐","on":"紐","de":"入場列の端で揺れるボード、その端をしっかり結んだ紐一本。券を高く掲げた手が長く連なる風景の中で、私はときめきが列をなす行列の先頭をそっと示す。"},"ICON-0387":{"nm":"アンコールリボン片","on":"アンコールリボン片","de":"アンコールを叫ぶ声がいちばん大きかった夜、舞台を飾ったリボンが一片落ちた。終わるのが惜しくてより長く歌った歌のように、この一片にも去りがたい気持ちが結ばれている。"},"ICON-0388":{"nm":"メッセージカプセル瓶","on":"瓶","de":"ガラス瓶の中にそっと折りたたんで入れた一言。いつか届くようにと浮かべた小さな船のように、私は気持ちを抱いて時間の上をゆっくりと漂う。開けて見るその日まで、約束は中で静かに眠る。"},"ICON-0389":{"nm":"小さな告白タグ","on":"小さな告白タグ","de":"どうしても口に出せなかった言葉を小さなタグに書いてそっと挟んでおく。文字は震えたけれど、真心だけははっきりしていた。最も小さな紙が、最も大きな勇気を抱くときがある。"},"ICON-0390":{"nm":"匿名応援メモ箱","on":"匿名応援メモ箱","de":"名前を書かなくても気持ちは伝わる。箱に入ってきたメモごとに、誰かの応援が匿名で一枚ずつ積もる。誰が書いたか分からなくても温もりだけははっきりした、顔のない優しさの集まりだ。"},"ICON-0391":{"nm":"心折り紙","on":"心折り紙","de":"四角い紙が指先に沿って鶴になり星になる。一度折るたびに願う気持ちも一枚ずつ重なる。心を込めて折った形には、言葉より長く残る真心が宿る。"},"ICON-0392":{"nm":"封印リボン蝋","on":"封印リボン蝋","de":"蝋を垂らして印をぐっと押せば、手紙はようやく封じられる。心をしっかり固めた古いやり方そのまま。冷めていく赤い蝋の上に、秘密が一つ静かに閉じ込められる。"},"ICON-0393":{"nm":"贈り物緩衝紙","on":"贈り物緩衝紙","de":"贈り物が傷つかないようにと、その周りを柔らかく包む。くしゃくしゃの折り目ごとに、壊れないでという願いが染み込んでいる。受け取る人は気づかず過ぎてしまう、見えないところのささやかな心遣い一枚。"},"ICON-0394":{"nm":"カラー手紙紐","on":"紐","de":"手紙を結ぶ紐にも色がある。黄色は応援、青は恋しさ。言葉では言い尽くせない感情を色で選んで結ぶ。ほどく前から、心の温度が指先に先に伝わる。"},"ICON-0395":{"nm":"手書き隠しバンド","on":"バンド","de":"手渡す直前まで文字を隠しておくバンド一つ。ばれるかとはらはらする告白を最後の瞬間まで守ってくれる。そっとめくれば現れる真心、その震えの重みを私はいちばん近くで知っている。"},"ICON-0396":{"nm":"応援文チップ","on":"チップ","de":"ペンライトが波打つ夜、一声で叫ぶ一文がチップの中に刻まれている。散らばった気持ちを一列に集める約束の言葉。みんなで一緒に叫ぶとき、その一文はいちばん大きく輝く。"},"ICON-0397":{"nm":"古い練習室キーリング","on":"リング","de":"練習室の扉を何百回も開け閉めしたキーリング。塗装は剥がれ、輪は緩んだけれど、そこにはいちばん不器用だった頃の汗が手垢として残った。古びたということは、それだけ長くとどまったということだ。"},"ICON-0398":{"nm":"舞台メイク片","on":"舞台メイク片","de":"舞台用の化粧は照明の下でようやく完成する。その濃い色の一片。汗にも滲まないようにしっかり施した跡には、遠く客席まで表情を伝えようとした真心がそのまま染み込んでいる。"},"ICON-0399":{"nm":"イヤーチップケース","on":"ケース","de":"舞台の上で自分の声を聞かせてくれた小さなイヤーチップ。公演が終わるとケースの中にそっと寝かせておく。いちばん近くで音楽を伝えてくれたものほど、より丁寧に保管してあげたくなる。"},"ICON-0400":{"nm":"個人ロッカーラベル","on":"ラベル","de":"宿舎の廊下の端、ロッカーごとに貼られた名札。誰の場所かを教えてくれる小さな文字が、見知らぬ空間を家に変える。自分の区画ができるということは、ここにとどまってもいいという優しい許しだ。"},"ICON-0401":{"nm":"携帯のど管理ボトル","on":"ボトル","de":"リハーサルの合間、ぬるい水を一口ゆっくり飲み下す。のどは歌手にとって借りて使う楽器だから、冷めないうちに満たしておくこの小さなボトルが、明日の最初の音をあらかじめ守ってくれる。大切に思う心は、いつもこんなに静かだ。"},"ICON-0402":{"nm":"スケジュール通知ピン","on":"ピン","de":"分刻みでびっしり詰まった一日の上に、ピン一つが次の枠を指す。その細かい行の間でいちばんうれしいのは、空いている一枠。少し窓の外を見てもいい時間が、そこに小さく隠れている。"},"ICON-0403":{"nm":"楽屋ブランケットクリップ","on":"クリップ","de":"化粧をすべて終えて椅子にもたれてうとうとしていた午後、誰かが肩にそっとブランケットを掛けてくれた。滑り落ちないように噛ませたこのクリップが、その手のぬくもりを舞台に上がるまでそっとつかんでいる。"},"ICON-0404":{"nm":"小さな香水サンプル","on":"小さな香水サンプル","de":"手首の内側にそっと叩けば、香りはちょうど一握りの範囲だけで咲く。遠くまで広がらなくてもいい。近づいてきた人だけが気づく痕跡だからより密やかで、だからこそより自分らしいのだから。"},"ICON-0405":{"nm":"練習着洗濯タグ","on":"練習着洗濯タグ","de":"何度洗っても布の奥深くに染みついた汗の匂いは、ついに完全には消えない。日に干してさらりと乾いた練習着をまた畳みながら思う——消えないその跡が、実はいちばん正直な痕跡なのだと。"},"ICON-0406":{"nm":"照明ジェルフィルム","on":"照明ジェルフィルム","de":"薄い色フィルム一枚を挟めば白い照明が夕焼け色に滲み、もう一枚重ねれば夜明けが降りる。舞台をどんな季節に染めるか、光にも服を着せる手が幕の裏で息をひそめている。"},"ICON-0407":{"nm":"スポットレンズキャップ","on":"キャップ","de":"カメラが消えている間も、誰かはこの小さな蓋を開けてレンズを拭く。まだ撮られていない次の場面のために。画面に収まらない時間の上で、最も慌ただしい手があらかじめピントを合わせておく。"},"ICON-0408":{"nm":"舞台反射板","on":"板","de":"自ら輝かなくても、受けた光を陰った顔へ返してやる板がある。舞台の真ん中があれほど明るいのは、端で黙々と角度を取って照らしてやる誰かの腕がそこにあるからだ。"},"ICON-0409":{"nm":"カラーフィルタースリーブ","on":"カラーフィルタースリーブ","de":"透明なスリーブに青い光を挟めば客席がまるごと海になり、赤い光に変えればその場に夕焼けが落ちる。同じ舞台が色一つで違う季節になる魔法は、この薄い一枚から始まる。"},"ICON-0410":{"nm":"ライト番号ピン","on":"ピン","de":"数多くの照明ごとに小さな番号が付いている。何番が点いて何番が眠るか、今夜の公演の流れがこの数字の順番であらかじめ組まれている。まばゆい幕の裏には、いつも丁寧な目録が広がっている。"},"ICON-0411":{"nm":"照明テープマーカー","on":"照明テープマーカー","de":"暗転した舞台の床、蛍光テープが足を止める位置を静かに照らす。客席からは見えないけれど、出演者のつま先はこのかすかな光を頼りに自分の位置を見つける。暗闇の中にも優しい道しるべがある。"},"ICON-0412":{"nm":"影遮断板","on":"板","de":"漏れ入る光を遮って影をはっきりと落とす板。暗闇を扱うことも結局は光を扱うことなので、何を見せるかは、何をそっと隠しておくかで先に決まる。"},"ICON-0413":{"nm":"照度チェックチップ","on":"チップ","de":"空間の明るさを測る小さなチップが手のひらの上で数字を読む。明るすぎても暗すぎても目が疲れるから。人が最も快適にとどまるその見えない適正線を、このチップが静かに守る。"},"ICON-0414":{"nm":"ピン照明遮り蓋","on":"ピン照明遮り蓋","de":"ピン照明が見当違いの場所に漏れないように添える遮り蓋。光をただ一人だけに集めるのは優しい集中だ。その丸い光の中へ足を踏み入れた瞬間、世界がしばしたった一人だけを見つめる。"},"ICON-0415":{"nm":"イヤーチップセット","on":"イヤーチップセット","de":"耳にぴったり噛み合うイヤーチップ一対。サイズが少しでもずれると音が漏れ、漏れた瞬間に拍子を逃す。舞台の上の一寸も揺れない歌が、実はこの小さなゴム一片から始まることもある。"},"ICON-0416":{"nm":"ケーブルベルクロ","on":"ケーブルベルクロ","de":"絡んだ線を一筋に整えて束ねるベルクロの紐。誰も見ていない舞台裏ほど、整頓はより輝く。ケーブル一束の端正さが、舞台の前で揺るぎなく流れる音をそっと支える。"},"ICON-0417":{"nm":"ラインチェックラベル","on":"ラベル","de":"数十本の線ごとに、どの楽器かを手書きで書いて貼った名札たち。たどたどしいその文字一つひとつが居場所を守ってこそ、ばらばらだった音がようやく一曲に流れ集まる。"},"ICON-0418":{"nm":"無音パッド","on":"パッド","de":"足音も震えも静かに飲み込む無音パッド一枚。静けさがどうしても必要な場所に敷かれる。いちばん澄んだ音は時に、どんな雑音も漏れ出ないこの静かな床の上でようやく生まれる。"},"ICON-0419":{"nm":"サウンドチェックトークン","on":"トークン","de":"公演前に音を合わせる間、手の中で温かくなるトークン。マイク一つ、スピーカー一つの点検を終えるたびに持ち替える。本番の完璧さは、この静かな予行の中で一歩ずつ作られる。"},"ICON-0420":{"nm":"マイクカバーキャップ","on":"キャップ","de":"数多くの声が触れた場所だから、マイクの先を包むこのキャップをより丁寧に拭く。歌を盛る器だから、歌手にとってはもう一つの手も同然。拭く間に明日の最初の一節をあらかじめ思い描く。"},"ICON-0421":{"nm":"ポップフィルタークリップ","on":"クリップ","de":"唇とマイクの間に垂れた薄い網一枚。その膜を留めておく小さなクリップのおかげで、荒く漏れていた息遣いがいつしか丸く柔らかな音声に整えられて流れ出る。"},"ICON-0422":{"nm":"音響ラックタグ","on":"タグ","de":"真っ暗な舞台裏、幾重にも積まれた機材棚の間で道を見失わないようにと吊るしておいた小さなタグ。客席を満たす華やかな音の源は、いつもこうして薄暗いところにきちんと整理されている。"},"ICON-0423":{"nm":"スピーカーグリルピン","on":"ピン","de":"スピーカーの網をしっかり固定するピン。音が抜け出る窓は最も先に埃を浴びる場所だから、薄い網一枚で音を守る。耳に触れるすべてのものには、見えない保護が一枚ずつ施されている。"},"ICON-0424":{"nm":"ステップマーカーシール","on":"シール","de":"床にちょこちょこ貼っておいた動線シールたち。群舞が刃のようにぴたりと合う秘密は、実は足元に隠れている。数十人が同じ点を踏んで散らばってはまた集まる、数えきれず約束した跡の上で。"},"ICON-0425":{"nm":"ターン練習円盤","on":"板","de":"その場でくるくる回る練習用の円盤。めまいに打ち勝つには、まず一点に視線を据える法から学ぶ。どんなに速く回ってもその一点だけは離さないように、体にゆっくり刻む均衡だ。"},"ICON-0426":{"nm":"膝テープロール","on":"膝テープロール","de":"膝をしっかり巻いてやるテープ一巻き。何千回も跳んで着地した関節はついに何も語らないけれど、この一枚がその沈黙をそっと受け止める。最後まで持ちこたえる体の裏には、いつも誰かのケアがある。"},"ICON-0427":{"nm":"つま先整列板","on":"板","de":"つま先の角度を揃えてやる板。ダンスは指先よりつま先で完成すると言うから。同じ方向へ伸びた数十のつま先が集まって、大勢が一人のように見える魔法を生み出す。"},"ICON-0428":{"nm":"練習室滑り止めパッド","on":"パッド","de":"練習室の床に敷く滑り止めパッド。思いきり跳ぶには、まず安全でなければならない。転ぶ心配なく安心して転がれる床の上でこそ、最も大胆で恐れ知らずの動作がようやく花開く。"},"ICON-0429":{"nm":"動作分解カード","on":"カード","de":"振付を一拍ずつ細かく刻んで描いておいたカード。どんなに難しい動作も一マスずつ分ければいつしか追えるようになる。舞台の上の水が流れるようになめらかな流れは、こうして区切って覚えた絵が集まって作られたものだ。"},"ICON-0430":{"nm":"鏡隠しカーテンピン","on":"ピン","de":"練習室の鏡をしばし隠すカーテンを留めておくピン。映る姿なく、ただ体の感覚だけで踊ってみる時間も必要だ。鏡を覆う瞬間、音楽がようやく肌まで染み込むことを知っている。"},"ICON-0431":{"nm":"拍子カウントビーズ","on":"拍子カウントビーズ","de":"コロッ、と一拍ごとにビーズを一つずつ指先で押して動かしながら拍子を数える。昔の数え方のように手に取れるように。音楽の骨組みである拍子は、こうして触れられるもので覚えてこそ、ようやく体にしっかり身につく。"},"ICON-0432":{"nm":"ウォームアップチェック紐","on":"紐","de":"体をすべてほぐしたか印をつけておくチェックの紐。本格的な練習の前には、いつも落ち着いた支度が先に来る。怪我をしてから後悔するより、紐一本結びながらゆっくり体を目覚めさせるほうが、結局はより長く踊らせてくれる。"},"ICON-0433":{"nm":"衣装番号クリップ","on":"クリップ","de":"何着もの衣装が混ざらないように番号を噛ませておくクリップ。息せき切る着替えの合間には、たった一着でも紛らわしくなれば大ごとだから、衣装ごとに自分の順番がはっきり書かれている。慌ただしさも秩序が支えてこそ優雅だ。"},"ICON-0434":{"nm":"修繕室ピンクッション","on":"修繕室ピンクッション","de":"修繕室の片隅に置かれたピンクッション。ほつれた縫い目、取れたボタンを黙って埋めてきた手がここにとどまる。舞台の上の乱れない着こなしの裏には、舞台を一度も見たことのない針目の真心が隠れている。"},"ICON-0435":{"nm":"生地端切れリング","on":"リング","de":"余りの生地の端切れを一つに通したリング。本番の服が傷むときに備えて同じ布をあらかじめ残しておく。何事もないことを願って用意したこの小さな備えが、いざ大ごとが起きた瞬間に舞台衣装を救い出す。"},"ICON-0436":{"nm":"急速ボタンパック","on":"急速ボタンパック","de":"急ぐときにすぐ付けられるボタン一パック。公演直前にボタン一つがぽろりと取れると、楽屋中が一気にざわめく。その短くひやりとした非常事態を一発で鎮める、小さいけれどこの上なく頼もしい救急箱だ。"},"ICON-0437":{"nm":"舞台ベルトホルダー","on":"ホルダー","de":"舞台衣装のベルトをしっかり留めてくれるホルダー。激しく跳んで回っても服が乱れないように。舞台の上で思いきり味わうその自由は、見えないところをきっちり締めておいたところからようやく生まれる。"},"ICON-0438":{"nm":"羽根ぼうき","on":"羽根ぼうき","de":"照明の下では小さな毛玉一つも際立つから、羽根ぼうきで衣装の上をそっと払い下ろす。舞台へ足を踏み出す直前、服を最後に整えるその優しい手つきは、いつもこの柔らかな羽根の役目だ。"},"ICON-0439":{"nm":"楽屋スリッパタグ","on":"楽屋スリッパタグ","de":"楽屋のスリッパごとに貼られた名前タグ。誰のものか書かれた小さな札一つに、私たちが同じチームだという安堵がそっと込められる。靴を脱いで足を伸ばすその部屋が、舞台裏でいちばん心安らぐ家になる。"},"ICON-0440":{"nm":"スタイリングクリップ板","on":"板","de":"髪をいじる間、束を留めておくクリップ板。一筋一筋整える合間、指は散らばろうとする髪をしばしこのクリップに預けておく。端正さとは結局、こんな小さな立ち止まりが集まって成り立つ。"},"ICON-0441":{"nm":"安全ピン整理カプセル","on":"安全ピン整理カプセル","de":"縫い目がほつれた明け方、カプセルの蓋を開けると小さく冷たい銀色がきちんと横たわっている。見えない内側で衣装を最も固く留める手——安全ピンはいつも舞台の裏で静かに働く。"},"ICON-0442":{"nm":"レンズ清掃布","on":"レンズ清掃布","de":"ふっ、と息を一度吹いて円を描きながら拭けば、ぼやけていた世界がはっきりする。その短い刹那が好きで、つい何度もレンズを拭く。誰かの視界を代わりに澄ませてあげる、小さな春の日差し一枚。"},"ICON-0443":{"nm":"三脚ゴム足","on":"三脚ゴム足","de":"三本の足先にゴムをはめると、床がもう悲鳴を上げなくなる。小さな一点が揺れを飲み込む間、画面の中の風景は嘘のように静かになる。安定はいつも足元から静かに始まる。"},"ICON-0444":{"nm":"カメラレインカバー","on":"カバー","de":"雨粒がつつっと流れ落ちても、レンズは乾いたまま世界を収める。野外撮影の曇った午後、カメラの上に透明な雨具がそっとかぶせられる。大切なものは濡れる前にまず包むものだと。"},"ICON-0445":{"nm":"撮影目印テープ","on":"撮影目印テープ","de":"ここに立て、あそこへ回れ——色とりどりの短い跡が一言もなく行く道をきちんと指し示す。舞台が終われば未練なく剥がしても、慣れたつま先はその位置を長く長く覚えている。"},"ICON-0446":{"nm":"カット分けクリップ","on":"クリップ","de":"散らばろうとする紙を一口で噛む小さなクリップ。カチッ、軽やかな音一つで昨日と今日がきちんと束ねられる。整理とは、失いかけたものをそっとつかむ優しい手癖だ。"},"ICON-0447":{"nm":"ホワイトバランス板","on":"板","de":"白い板を画面に映せば、色たちがそっと自分の位置を見つけていく。黄ばんだ夕焼けも、青い夜明けも偽りなく。本物の白い光を知る板一つが、残りの色を正直に語らせる。"},"ICON-0448":{"nm":"メモリー保管缶","on":"メモリー保管缶","de":"小さなブリキの缶の中に思い出のチップがぐっすり眠っている。蓋を開ければカチャッ、過ぎた季節の場面が手のひらにこぼれ落ちる。記憶はこうして、丈夫な缶一つにそっと収まってとどまる。"},"ICON-0449":{"nm":"モニターフードキャップ","on":"キャップ","de":"モニターの周りに黒いひさしを巡らせると、光の反射がぴたりと止まる。日差しが降り注ぐ窓辺でも画面は自分の色を失わない。よく見るには、まず雑光から遮らなければと、フードがそっと教えてくれる。"},"ICON-0450":{"nm":"撮影現場防音ピン","on":"ピン","de":"扉の隙間に挟んだ小さなピン一つが、外の騒音をそっと断ち切る。廊下の足音も、隣室の笑い声も、ここまでは届かない。澄んだ音を収めるには、まず沈黙から作らなければならないから。"},"ICON-0451":{"nm":"メイクスポンジパック","on":"メイクスポンジパック","de":"ふわふわのスポンジがきちんと重なった一束。指先でトントンとパウダーをはたけば、顔色がワントーン明るくなる。ステージの上の輝く笑顔の裏には、いつもこの柔らかな手間が隠れている。"},"ICON-0452":{"nm":"ヘアピンケース","on":"ケース","de":"なくしやすい小さなピンたちのきちんとした家。ふたを開ければ銀色が一列に並んで出迎える。散らばると見えなくても集めておけば心強い、小さなものにも自分の居場所は必要だ。"},"ICON-0453":{"nm":"ブラシ除菌ケース","on":"ケース","de":"一日中色を含んだ筆たちがケースの中で紫外線シャワーを浴びる。見えない光が古いものを洗い流す間に、明日の筆先は初めてのようにふんわり整う。清潔さも真心のひとすじだ。"},"ICON-0454":{"nm":"パウダーパフネット","on":"パウダーパフネット","de":"まるいパフたちがネットの中でそっと息を整える。網の隙間を風が出入りすれば、ふんわり感が長持ちする。よく乾いたパフひとつに、明日の朝の華やかさがあらかじめ宿る。"},"ICON-0455":{"nm":"スタイルキープスプレーキャップ","on":"キャップ","de":"シュッと一度ふきかければ、風にも乱れない。手間をかけた髪型を一晩中支える小さなふた。しっかり固定された髪の上に、まぶしい照明が砕けるように降りそそぐ。"},"ICON-0456":{"nm":"リップブラシカバー","on":"カバー","de":"細い筆先をそっと包む小さなふた。かばんの中であちこち揺れても、筆はまっすぐ清潔に守られる。小さな筆ひとつを大切にする心が、唇の上の一筆の色を仕上げる。"},"ICON-0457":{"nm":"順番待ちミラー","on":"ミラー","de":"自分の番を告げる数字の横に、小さな鏡がそっと付いている。ステージに上がる直前、乱れた前髪を最後に整える場所。緊張も一度映してみれば、少しだけ軽くなる。"},"ICON-0458":{"nm":"リストバンドタオル","on":"リストバンドタオル","de":"額の汗を手首でさっと拭きとる柔らかな帯。振付が激しくなるほど、より頻繁に手が伸びる。息が上がる瞬間ごとにそばを守ってくれる、手首の上の小さな慰めのひとすじ。"},"ICON-0459":{"nm":"小道具バッグラベル","on":"ラベル","de":"楽屋に同じバッグが10個並んでも、迷うことはない。バッグごとに付いた名札が持ち主をはっきり示してくれるから。「自分のもの」と書いておくことは、小さくても優しい印だ。"},"ICON-0460":{"nm":"練習室予約ピン","on":"ピン","de":"今日は誰がこの練習室を使うのだろう。ドアの前のボードにちょこんと刺さった小さなピンが、黙って時間を分けてくれる。次の番を待つ気持ちが、このピンひとつにそっと列をなす。"},"ICON-0461":{"nm":"壁時計カバーリング","on":"リング","de":"壁時計の上に透明なカバーがそっと降りてほこりを防ぐ。カチカチと刻む針はかすまず、時間は澄んで流れていく。大切なものの上には、見えない保護の一枚がいつも必要だ。"},"ICON-0462":{"nm":"床保護パッド","on":"パッド","de":"椅子の脚の下に貼られた薄いパッドが、フローリングの傷をあらかじめ防ぐ。引きずっても傷つかず、動かしても跡ひとつ残らない。見えないところで床をいたわる心、それが長く使う秘訣だ。"},"ICON-0463":{"nm":"飲料禁止サインチップ","on":"チップ","de":"ここではしばらく飲み物を置いておこうと、小さなチップが優しくお願いする。楽譜も機材も濡れたら困るから。「禁止」という言葉も、こうして伝えればいつしか温かな思いやりになる。"},"ICON-0464":{"nm":"換気ボタンラベル","on":"ラベル","de":"息苦しい空気を変えたいときはここを押してと、ボタンの横の小さなラベルが道を案内する。息が楽になることは、意外とこんなささやかな印ひとつから、そっと始まる。"},"ICON-0465":{"nm":"スピーカー台ゴム","on":"スピーカー台ゴム","de":"スピーカーの下に敷かれたゴムの台が、鈍い震えをそっと飲みこむ。低音が床を伝って広がらないので、音は一段とはっきりする。よい響きは、しっかりした足場の上でようやく澄んでいく。"},"ICON-0466":{"nm":"ロッカー番号マグネット","on":"マグネット","de":"ロッカーの扉にぴたりと付く小さな数字マグネット。今日の私の荷物は何番の枠で眠るのだろう。毎日場所が変わっても、マグネットひとつあればすぐに自分の枠ができる。所属とは、こんな軽い印から来るものだ。"},"ICON-0467":{"nm":"ミラー拭きワイパー","on":"ミラー拭きワイパー","de":"鏡の上をさっと一度なでれば、くもりがすっきり晴れる。ぼやけていた自分の顔がはっきり浮かび上がる瞬間。自分をちゃんと見るには、まず曇ったものからそっと拭きとらなければならない。"},"ICON-0468":{"nm":"ドア緩衝パッド","on":"パッド","de":"強く閉まるドアの隙間にはさんだふかふかの緩衝材。バタンという音も、指のはさまりも、やわらかく受けとめる。荒い衝突の間に、優しさを一枚そっと挟みこむ小さな安全だ。"},"ICON-0469":{"nm":"ケーブルカバーブロック","on":"ケーブルカバーブロック","de":"床を横切るケーブルの上に、頑丈なカバーがしっかり橋をかける。足に引っかかることも、線が踏まれることもない。道をふさがずに道を守る、一ブロックの黙々とした働き。"},"ICON-0470":{"nm":"滑り注意コーン","on":"滑り注意コーン","de":"濡れた床の上に黄色いコーンがひとり立って、そっと警告する。気をつけて、ゆっくり踏みなさいと。まぶしいステージの裏側には、こうして黙々と足どりを守る小さな見張りが立っている。"},"ICON-0471":{"nm":"緊急ライト棒","on":"棒","de":"停電した廊下にぱっと灯る一筋の光。暗闇の中でも道に迷わないようにと、緊急の明かりが手に握られる。最も暗い瞬間に最も明るくなるものが、この世には確かにある。"},"ICON-0472":{"nm":"手すり保護キャップ","on":"保護キャップ","de":"階段の手すりの端にかぶせた丸いキャップが、とがった角をやわらかく包む。うっかり手がかすめてもけがをしない。鋭さをそっと覆っておくこと、それも誰かへの思いやりだ。"},"ICON-0473":{"nm":"ステージ角クッション","on":"ステージ角クッション","de":"ステージの端の角にふかふかのクッションが巻かれる。激しい振付でつま先が当たっても、あざにならないように。輝く動きひとつひとつの裏側で、見えない保護がともに踊っている。"},"ICON-0474":{"nm":"床マーク円盤","on":"盤","de":"床に置かれた丸い円盤が「ここに立ってください」と静かに語る。列に並ぶ人も、場所を探す人も、この一点を見てそっと立ち止まる。秩序とは、小さな印から育つものだ。"},"ICON-0475":{"nm":"懐中電灯ストラップ","on":"ストラップ","de":"懐中電灯の端に下がった紐を手首にひと巻きすれば、暗闇の中でも光を見失わない。落とす心配なく両手が自由になる、小さくても心強いひと巻きの結び目だ。"},"ICON-0476":{"nm":"動線遮断ロープ","on":"ロープ","de":"ここまでは入らないでと、一本のロープがやわらかく線を引く。危険な場所と安全な場所をそっと分ける優しい境界。さえぎることも、誰かを守るひとつの方法だ。"},"ICON-0477":{"nm":"安全確認ピン","on":"ピン","de":"点検が終わった場所ごとに、小さなピンが「確認」を残す。見落としなく見回った心の印鑑のような一点。安全とは大げさなものではなく、こうしてひとつひとつ確かめた跡の積み重ねだ。"},"ICON-0478":{"nm":"ミニカチンコ","on":"ミニカチンコ","de":"カチッと最初の拍を切る軽快な音に、現場に立つ全員の呼吸がいっぺんに合わさる。大きさは小さくても、すべてのシーンのスタートラインはいつもこの一拍。撮影の心おどる始まりがここで開かれる。"},"ICON-0479":{"nm":"デスクマイクカバー","on":"カバー","de":"机の上のマイクにふんわりカバーがそっとかぶせられる。息づかいが荒く飛び出しても、雑音なくきれいに伝わる。声をいちばん温かく包むのは、この小さくて柔らかな一枚だ。"},"ICON-0480":{"nm":"吸音パネル片","on":"吸音パネル片","de":"壁にはめこまれた吸音パネルの一片が、こだまを静かに収めていく。音がぶつかって散らないので、歌は一段と澄んでたまる。よい響きは、沈黙を丁寧に整えることから生まれる。"},"ICON-0481":{"nm":"ヘッドホン掛けキャップ","on":"キャップ","de":"ヘッドホンをここに掛けておくのは、小さな約束だ。次の人がすぐ取って使えるように、コードをほどいてきちんと。フックひとつが、慌ただしいブースに静かな秩序をもたらす。"},"ICON-0482":{"nm":"録音中サインランプ","on":"録音中サインランプ","de":"赤いランプが灯る瞬間、ブースの中のすべての息が止まる。ドアの外の足音さえ止まるその合図。音を収めることは、この深い沈黙を守ることから始まる。"},"ICON-0483":{"nm":"ピック整理ケース","on":"ケース","de":"色別に枠を分けて挿しておいたピックたち。太さと重さが指先のくせを作る。ステージ直前、見なくても一発で取り出せるその正確さが、ここで育つ。"},"ICON-0484":{"nm":"ケーブルラベラー","on":"ケーブルラベラー","de":"数十本がもつれた床でも道に迷わないためには、両端に名前を書いておかなければならない。どこから来てどこへ行くのか書いた人だけが、暗闇の中でも手が迷わない。"},"ICON-0485":{"nm":"小型ミキサーノブ","on":"小型ミキサーノブ","de":"指一節ぶん回せば、声の質感が変わる。上げれば荒く下げれば埋もれる、その間のただ一点を手探りすること。最もかすかな手つきが、最も大きな変化を生み出す。"},"ICON-0486":{"nm":"スタンド固定ワッシャー","on":"ワッシャー","de":"ステージを支えるのは華やかな照明ではなく、この小さな輪だ。揺れをしっかり押さえつけたまま、誰の目にも留まらず自分の場所で黙々と耐える。"},"ICON-0487":{"nm":"セット解体ラベル","on":"ラベル","de":"立てたすべてのものを再び慎重に倒すのにも、はっきりとした順序がある。どこからほどきどこへ運ぶか書いた一枚。組み立てる手と同じく、片付ける手もしっかりしている。"},"ICON-0488":{"nm":"落とし物袋チップ","on":"チップ","de":"誰かが落としていったものには、それぞれ事情が宿る。小さな袋に入れて持ち主の名を待つことは、なくした人の心までしばらく預かる優しさだ。"},"ICON-0489":{"nm":"清掃動線マーク","on":"清掃動線マーク","de":"床に引いておいた矢印をたどれば、すきまなく拭ける。ほうきも道があってこそ空回りしない。最も輝く場所は、最もよく描かれた足どりの先にある。"},"ICON-0490":{"nm":"退場誘導棒","on":"棒","de":"最後の拍手が静まると、この棒が道を開く。まだ高ぶった気持ちを傷つけないように、ゆっくり流していく手。締めくくりを案内することにも、温かな思いやりが込められる。"},"ICON-0491":{"nm":"残りテープボール","on":"残りテープボール","de":"使い残した切れ端を丸く固めれば、もう一度使い道が生まれる。捨てられかけた端が集まって固い玉になるように、いとおしむ心は小さな指先から育つ。"},"ICON-0492":{"nm":"椅子番号キャップ","on":"キャップ","de":"客席の椅子ごとに数字が刻まれていてこそ、誰も迷わない。席を決めてくれる小さな帽子ひとつが、初めて来た人のときめきを安らかな安心へと変えてくれる。"},"ICON-0493":{"nm":"ゴミ分別ピン","on":"ピン","de":"紙とプラスチックを分けて挿す小さなピン。混ざればただのゴミだが、分ければ再び使われる資源になる。分別とは、ものに二度目の命を返す優しい仕事だ。"},"ICON-0494":{"nm":"機材返却タグ","on":"機材返却タグ","de":"借りたものは必ず元の場所に戻らなければならない。タグを付けて返す指先ごとに、信頼が一枚ずつ積み重なる。きちんと返す人が、次も気持ちよく借りられる。"},"ICON-0495":{"nm":"控室チェックアウトキー","on":"控室チェックアウトキー","de":"今日のメイクと衣装をすべて脱いで、最後にこのキーを返す。入るときに受け取ったものを出るときに戻すこと。一日の始まりと終わりが、同じ手の中に収まる。"},"ICON-0496":{"nm":"クッションパフケース","on":"ケース","de":"ふんわりしたパフは、つぶれると自分の質を失う。丸い家ひとつにそっと寝かせておく理由がそこにある。柔らかさを長く保つには、柔らかく扱うことからだ。"},"ICON-0497":{"nm":"アイシャドウチップ","on":"チップ","de":"まぶたに乗せる色ひとつが、表情をまるごと変える。小さなチップに眠る色は照明の下でようやく目覚め、ステージへ向かうまなざしに深みを添える。"},"ICON-0498":{"nm":"チークブラシキャップ","on":"キャップ","de":"筆先が傷めば発色も一緒に崩れる。小さな帽子をかぶせてその質を守ることは、よい道具を長くそばに置こうとする人の静かな習慣だ。"},"ICON-0499":{"nm":"リップパレットスリム","on":"リップパレットスリム","de":"分厚いパレットはかばんの中で場所をすべて取る。薄く削った一列で十分だと知っている手。減らすことがそのまま備えることになる瞬間だ。"},"ICON-0500":{"nm":"マスカラガード","on":"マスカラガード","de":"一本一本立てたまつ毛がにじまないように、小さなガードがその曲線をそっと守ってくれる。丁寧に上げたものは丁寧に守らなければと、鏡の前の時間が教えてくれる。"},"ICON-0501":{"nm":"綿棒ケース","on":"ケース","de":"白い綿棒が四方に散らばらないように入れておく小さな家。最後のひと修正のために、いつも近くに置いておく手つき。細々とした準備が、大きなステージの隙間を埋める。"},"ICON-0502":{"nm":"ビューラーゴムパック","on":"ビューラーゴムパック","de":"ゴムが固まると、まつ毛をはさむときにちくっと痛い。取り替える予備をあらかじめ用意しておく心は、小さな痛みまで気づかう優しさから生まれる。"},"ICON-0503":{"nm":"コンシーラーブラシ","on":"ブラシ","de":"細い筆先で影をそっと消していく。光の届かなかった場所に明るさを入れること。欠点を覆うより光を足す手が、一段ときれいに仕上げる。"},"ICON-0504":{"nm":"パウダーシフター","on":"パウダーシフター","de":"細かな粉を一度こせば、ダマなくきれいに乗る。もう一度ふるいにかけるその手間。真心とは結局、もう一段階を経る指先からにじむものだ。"},"ICON-0505":{"nm":"前髪ロールクリップ","on":"クリップ","de":"前髪を丸く巻いてしばらく留めておくクリップ。待つ間に形が落ち着いていく。急がず待つことを知る場所から、端正さが咲く。"},"ICON-0506":{"nm":"ヘアワックススプーン","on":"スプーン","de":"ワックスは手に取る前に、この小さなスプーンですくう。ちょうど必要なぶんだけ取り分ける節度。あふれずに使える手が、最も自然な質感を作る。"},"ICON-0507":{"nm":"ヘアアイロン置きマット","on":"マット","de":"熱く焼けたヘアアイロンを、むやみに置くわけにはいかない。受けとめるマット一枚が、机も手も守る。熱を扱う場所には、いつも安全な憩いの場が必要だ。"},"ICON-0508":{"nm":"ヘアオイルサンプル","on":"ヘアオイルサンプル","de":"一滴で十分なつやを小さなサンプル瓶にきれいに入れて、かばんの片隅にそっと忍ばせておく。大きな瓶より小さな一本のほうが、かえってよく手に届く。"},"ICON-0509":{"nm":"ブラシ掃除コーム","on":"ブラシ掃除コーム","de":"ブラシに絡んだ髪の毛をコームでゆっくりすいて落とす。道具を手入れする時間は、仕事を終えた後の静かな儀式。よく手入れされたブラシが、明日の質感をきれいに描く。"},"ICON-0510":{"nm":"ヘアゴムボビン","on":"ヘアゴムボビン","de":"ボビンにくるくる巻いておくだけで、ひと目でぱっと目に入る。丸く整ったこの小さな束は、ゴムが四方にころころ転がっていた慌ただしい朝に差し出す、優しいゆとりだ。"},"ICON-0511":{"nm":"毛染め手袋パック","on":"毛染め手袋パック","de":"色を入れる手が染まらないようにはめる薄い手袋。仕事が終わった後もきれいな手で次を迎えようとする心。保護とは、つまりそんな準備の別の名だ。"},"ICON-0512":{"nm":"ヘアネットポーチ","on":"ポーチ","de":"髪型を守ってくれるネットをきれいに畳んで入れる小さな袋。かさのないものほど居場所を失いやすいから、自分の家を決めてあげる心づかいがありがたい。"},"ICON-0513":{"nm":"おくれ毛フィクサーペン","on":"ペン","de":"はみ出たおくれ毛をちょんと押さえてきちんと整えるペン。大きな手入れをすべて終えた後の最後のひと押し。仕上げとは、いつも最も小さなところを撫でることだ。"},"ICON-0514":{"nm":"香水試香キャップ","on":"キャップ","de":"香りを選ぶときは鼻先に直接つけない。小さなキャップに含ませて空気中に振りまいてこそ、本当の質感が現れる。香りも一歩離れて嗅ぐとき、ようやく正直になる。"},"ICON-0515":{"nm":"ロールオン香水瓶","on":"瓶","de":"丸いボールがころころ転がって手首に香りを描く。ちょんとつける昔の香水瓶と違い、滑るように広がるひとすじ。香りは触れる方法ごとに、違う物語を残す。"},"ICON-0516":{"nm":"ボディミストふた","on":"ふた","de":"霧のように広がる香りを閉じこめる小さなふた。開ければ舞い散るものを閉じて守ること。少し惜しんでおく心が、その香りをより長くそばに留めてくれる。"},"ICON-0517":{"nm":"ハンドクリームキーリング","on":"リング","de":"手に塗る小さなクリームにリングを付ければ、どこへでも一緒に行ける。かばんの外にぶら下がってゆらゆら揺れる道連れが、乾いた指先に差し出す優しい便りになる。"},"ICON-0518":{"nm":"シャワーボール掛け","on":"シャワーボール掛け","de":"もこもこと泡を作った後は、よく乾かさなければならない。浴室の片隅のフックに掛けておいた網の球は、ぽたぽたと水気を切りながら、次の朝をさわやかに待つ。"},"ICON-0519":{"nm":"マッサージボールポーチ","on":"ポーチ","de":"凝った肩をほぐしてくれる固い球を小さな袋に入れる。ステージ裏の短い休息、こわばった体を静かに撫でる時間。ケアとは、いつも自分自身から始まる。"},"ICON-0520":{"nm":"クーリングパッチケース","on":"ケース","de":"貼ればひんやり冷えていくパッチを集めておいたケース。熱を帯びたステージが終わった夜、熱くなった体と心をゆっくり鎮める小さな慰めが、その中で眠っている。"},"ICON-0521":{"nm":"ネイルオイルペン","on":"ペン","de":"押して、こすって、きらり。乾いた指先にたった一滴で十分だ。華やかな処方なんて必要なく、小さなペン先から広がるほのかなつやが、爪の上にきれいに漂う。ケアはこんな小さな一滴から始まる。"},"ICON-0522":{"nm":"サシェクリップ","on":"クリップ","de":"紙の上に香りを結んでおく小さな結び目。引き出しを開けるたびに、ほのかなひと握りが手より先にあいさつを送ってくる。見えなくてもそばに留まる優しさ——クリップひとつが一日ぶんの慰めを静かに抱いている。"},"ICON-0523":{"nm":"ネイルチップトレー","on":"トレー","de":"十本の指の色をあらかじめ広げておく小さな舞台。どのトーンが今日に似合うか、トレーの上で静かなオーディションが開かれる。選ぶそのひとときがなぜかときめいて、指先の一日はここから始まる。"},"ICON-0524":{"nm":"キューティクルプッシャーキャップ","on":"キャップ","de":"押し出す仕事にも優しさがある。ささくれひとつを丸い先でそっと、急がずに。急ぐ手はいつも何かを見落とすから、整えるとはゆっくり見つめる心により近い。"},"ICON-0525":{"nm":"ミニファイルバッファー","on":"ミニファイルバッファー","de":"粗い面と細かい面、二つの顔をひとつの手に握る。とがったところをそっと削ってなめらかに整えることはささやかだが、完成はいつもこんなささやかな手つきから来る。最後は結局、柔らかさのものだ。"},"ICON-0526":{"nm":"ネイルシール板","on":"板","de":"星、花、ハート——今日の気分にぴったりの一枚をちょんと選んで貼ればいい。爪ほどの小さな絵が並んだ板の上で、シールひとつが指先に残す優しいサインのようにきらめく。"},"ICON-0527":{"nm":"ジェルランプ覆い板","on":"板","de":"光をしばらく閉じこめておく薄い膜。固める間、目は休み、指先だけが静かに固まる。待つことにも一片の陰が必要なもの——急がない時間の中で、今日の指先が完成する。"},"ICON-0528":{"nm":"ネイルパーツケース","on":"ケース","de":"きらめく欠片が仕切りごとに眠っている。ラインストーン、パール、星くず——名札のない宝石箱を開けるときめきでふたを開ける。どんな光を爪に乗せようか、選ぶその瞬間が最もきらめく。"},"ICON-0529":{"nm":"ハンドケア手袋パック","on":"ハンドケア手袋パック","de":"眠る間に手が受ける短い休暇。手袋の中で乾いた肌が一晩かけてゆっくり潤っていく。ケアとは結局、見えないところで起こること——朝になれば指先が真っ先にその優しさを知る。"},"ICON-0530":{"nm":"リムーバーポンプ瓶","on":"瓶","de":"一度押せばちょうど必要なぶんだけ。コットンにしみて広がるひんやりした香りが、爪の上の昨日をすっきり消す。空けることにもリズムがあって、ひと押しが新しく塗る場所をそっと空けてくれる。"},"ICON-0531":{"nm":"ラインストーンピンセット","on":"ピンセット","de":"指先より細い宝石をつまむには、もっと細い手が必要だ。震えなく一点を移すピンセットの先——繊細さは心と同じくらい、道具のものでもある。小さな光ひとつが自分の場所を見つける。"},"ICON-0532":{"nm":"ピアス収納板","on":"板","de":"片割れをなくしたピアスが、もう引き出しの中で迷子にならないように。一対ずつ自分の場所に挿しておけば、慌ただしい朝に選ぶ時間が一段と軽くなる。整理とは、未来の自分に差し出す小さな親切だ。"},"ICON-0533":{"nm":"指輪サイザーリング","on":"リング","de":"指の周りを数字に変えてくれる小さな輪の一束。合う枠をひとつずつはめてみることは、自分にぴったり合う何かをゆっくり知っていくことに似ている。ぴったり合うときのあの安心感のように。"},"ICON-0534":{"nm":"時計ベルトピン","on":"ピン","de":"時計のベルトが緩んだとき、この小さなピンひとつが時間を再び手首につなぎとめる。最も深く隠れた部品が最も長く耐えるということを——長く着けてきた時計は黙って知っている。"},"ICON-0535":{"nm":"ネックレス絡み防止板","on":"板","de":"細い鎖たちが互いに絡まないように、仕切りを分けておく。絡みのない朝は、昨夜あらかじめ分けておいた小さな仕切りから始まる。ゆとりとは結局、手が触れる前に整えておいた心だ。"},"ICON-0536":{"nm":"ブローチ裏ふた","on":"ブローチ裏ふた","de":"前が華やかなほど、裏は黙々としている。服の裾に挿したブローチをしっかり支える小さなふた——表に出る光の裏には、いつも名もなく耐えてくれる手がある。見えないからこそ頼もしい場所だ。"},"ICON-0537":{"nm":"サングラスポーチ","on":"ポーチ","de":"夏の光を防いでくれたレンズを、柔らかな布がそっと包む。かばんの中の衝突から一組の視界を守る小さな袋。何かをいとおしむ心は、いつもこうして柔らかな一枚で来る。"},"ICON-0538":{"nm":"ベルト穴パンチ","on":"パンチ","de":"一目盛り減った腰にも、一目盛り増えた季節にも。穴をひとつだけ増やせば、ベルトは再び体に合う。変わるのはいつも私で、黙々と合わせてくれるのはこの小さな道具の仕事だ。"},"ICON-0539":{"nm":"スカーフリングクリップ","on":"クリップ","de":"ずり落ちるスカーフを一点にまとめて押さえるクリップ。風にほどけていた装いがようやく落ち着く。優雅さもときにはこの小さな留め具に寄りかかって、乱れかけた一日を端正に締める。"},"ICON-0540":{"nm":"チャームリングセット","on":"チャームリングセット","de":"かばんの片側に下げる小さなリングが一セットで来た。好きなものをそばに下げて持ち歩く心——チャームひとつにその日の気分を掛けることは、自分だけが知るささやかな儀式のようで、なぜか楽しい。"},"ICON-0541":{"nm":"毛玉取り器ケース","on":"ケース","de":"セーターが一晩で老けたように毛玉が立てば、このケースをそっと転がして再び新品の表情に。古びを取り除く軽いウィーンという音が、なぜか頼もしい。いとおしむ服はそうしてもう一度よみがえる。"},"ICON-0542":{"nm":"繊維フレグランスカード","on":"カード","de":"クローゼットの奥深くに挟んでおけば、何日も香りで静かに満たす。文字の代わりに香りで書かれた手紙——開かなくても読める一枚だ。服を取り出す朝ごとに、昨日書いておいた優しさが真っ先に広がる。"},"ICON-0543":{"nm":"静電気防止ピン","on":"ピン","de":"スカートの裾が足にまとわりつく冬の朝、ピンひとつがそのまとわりつきをそっとほどいてくれる。見えない摩擦まで和らげる小さな平和——ささやかないらだちひとつが消えれば、一日が一段となめらかだ。"},"ICON-0544":{"nm":"携帯洋服ブラシ","on":"ブラシ","de":"ドアを出る直前、肩にそっと乗ったほこりのひとすじ。畳んでおいたブラシを広げて一度なでれば、第一印象は再び端正になる。仕上げはいつもドアの前で起こり、端正さはそのひと撫でで完成する。"},"ICON-0545":{"nm":"洗濯ネットラベル","on":"ラベル","de":"混ざってはいけないものをネットに閉じこめ、ラベルがそっと名前を書く。洗濯にも居場所があり、居場所には小さな印が伴う。乱れやすい一日の秩序は、この小さな名札から育つ。"},"ICON-0546":{"nm":"シミ取りペン","on":"ペン","de":"コーヒー一滴がシャツの上に残した跡も、ちょんちょんと叩けばそっと退いていく。失敗を覆うのではなく静かに消してくれるペン。誰にでも、一日を再びきれいに始める一度が必要だ。"},"ICON-0547":{"nm":"靴磨き布","on":"靴磨き布","de":"布で一度なでてやれば、革が自分の輝きを取り戻す。長く履いた靴ほど、つやはより深く入る。輝きは共に歩んできた時間への返礼——靴はその歳月を甲の上に静かに刻んでいる。"},"ICON-0548":{"nm":"スニーカー紐キャップ","on":"キャップ","de":"ほどけた紐の端にかぶせた小さな帽子。ゴールまでよそ見しないように、端をしっかり封じておく。よく結ばれた紐ひとつが一歩を遠くへ運ぶ——ささやかな締めくくりが、最後まで走る勇気になる。"},"ICON-0549":{"nm":"ハンガーネームチップ","on":"チップ","de":"似たようなハンガーの間で、この小さなチップひとつが「自分の場所」をそっと示してくれる。慌ただしい朝の混乱を減らす静かな道しるべ——探す手間が減れば、一日の始まりも一段と軽やかになる。"},"ICON-0550":{"nm":"レンズピンセットケース","on":"ケース","de":"指先より正確な先が必要なときがある。小さなレンズを震えなくつまみ上げるピンセットがケースの中で順番を待つ。精密さはいつも静かに準備されたまま眠り、呼べばすぐに目覚める。"},"ICON-0551":{"nm":"コットンミニパック","on":"コットンミニパック","de":"ちょうど一度使うぶんだけ入れた小さな束。かばんの中のかさは減らしながらも、柔らかさはそのまま。少なく持つこともひとつの優しさ——減らした場所に軽やかな一日が入りこむ。"},"ICON-0552":{"nm":"あぶらとり紙ケース","on":"ケース","de":"真昼に鼻筋ににじんだ光を、薄い一枚でそっと押さえ拭く。ケースの中にきちんと眠る紙たち——一枚を取り出す瞬間だけは、誰もが少しの間、鏡の前に立つ自分を優しく見つめる。"},"ICON-0553":{"nm":"折りたたみコームミラー","on":"ミラー","de":"畳めば手のひら、開けば鏡とコーム。かばんの片隅で急な身だしなみを引き受ける小さな万能だ。端正さは大げさなものではなく、どこでも広げて一度整えられる心に近い。"},"ICON-0554":{"nm":"携帯シェーバーキャップ","on":"キャップ","de":"旅行かばんの中の鋭い刃を安全に眠らせておく。鈍いようで頑丈なこのふたのおかげで、慌ただしい朝に手探りする指先もけがをしない。心づかいとは、いつも一歩先に危険を覆っておくことだ。"},"ICON-0555":{"nm":"リップクリームリング","on":"リング","de":"かばんの紐に揺れる小さな保護膜。ポケットで転がって割れる心配なく、乾いた唇をいつも手の届くところに置く。備えるとは結局、必要なものを最も近い距離に置く心だ。"},"ICON-0556":{"nm":"手指消毒ジェルホルダー","on":"ホルダー","de":"片手で押せばひと握りの清潔が落ちる。ドアの前、机の上、どこでも掛けておけば、手を洗う心もそのぶん近くなる。よい習慣は大げさなことではなく、手の届く場所から始まる。"},"ICON-0557":{"nm":"ティッシュスリムポーチ","on":"ポーチ","de":"細身の体にひと握りのティッシュを抱えた。ポケットが膨らまずに、突然の鼻水や涙にもいつもそっと備えている。誰かにさっと差し出す一枚——備えはスリムなほど素敵だ。"},"ICON-0558":{"nm":"ミニマウスウォッシュ瓶","on":"瓶","de":"辛いラーメンを食べて誰かに会わなければならない日、この小さな瓶がさっと口直しを引き受ける。ひと口のさわやかさがときに大きな自信になって、ためらっていたあいさつを一段と軽くしてくれる。"},"ICON-0559":{"nm":"きらめきパウダーチップ","on":"チップ","de":"指先にちょんとつけて頬に乗せれば、照明の下に星くずが散るように広がる。平凡な頬が一瞬きらめくのはこの小さなチップひとつの魔法。光はいつもこうして、指先についた粉で訪れる。"},"ICON-0560":{"nm":"グリッター抑えシール","on":"シール","de":"あまりにきらめいて気後れする場には、このシールがそっと光を抑えてくれる。華やかさを一枚減らすことも飾りの一部——減らした場所に残るほのかさが、ときには別の感覚になる。"},"ICON-0561":{"nm":"ストーンピックアップペン","on":"ペン","de":"道を歩いてつま先に引っかかった小さな石ひとつ。わざわざ腰をかがめて拾い上げるペンだ。ただ通り過ぎることもできたものを指先でそっと拾う心——優しさはいつも立ち止まることから始まる。"},"ICON-0562":{"nm":"つけまつげ保管板","on":"板","de":"一本一本きちんと寝かせておく小さな板。外した後もその美しい曲線は乱れない。しばらく下ろしたものも自分の場所を覚えているという、静かで端正な保管の慰め。"},"ICON-0563":{"nm":"両面テープカッターキャップ","on":"キャップ","de":"二つの刃がかみ合って結び目を一度に切り落とす。切った跡がきれいなほど、次の結び目が端正になる。よく結びよく切る指先から、新しい始まりも一段と軽やかにほどけていく。"},"ICON-0564":{"nm":"フェイスラインテープ","on":"フェイスラインテープ","de":"あごのラインに沿って一筋、息をひそめて慎重に貼っていく。輪郭とは、なかった線を描くのではなく、すでに美しいところを示すこと。もともとそこにあった質を優しくたどって描く手つきだ。"},"ICON-0565":{"nm":"照明反射パウダー","on":"照明反射パウダー","de":"光をたっぷり含んできれいに返してくれる粉。自ら輝かなくても、受けた光を細かく振りまいて明るくなる。受け取った優しさをまた誰かに伝えるように、きらめきは分かち合うほど大きくなる。"},"ICON-0566":{"nm":"メイク固定ファン","on":"メイク固定ファン","de":"手をかけたメイクを一日の終わりまで支えるファンの風。崩れないように、流れ落ちないようにと、そっと冷やして固めてくれる。丁寧に整えた顔が、ステージの幕が下りるまではっきりしているように。"},"ICON-0567":{"nm":"カラー補正パレットチップ","on":"チップ","de":"ずれた色味を一枠ずつなだめて正す小さな欠片たち。ひとりでは浮いていた色も、そばに似合う色を置けばようやく明るくなる。色と色が手を取り合ってこそ、ようやく澄んだ一幅になる。"},"ICON-0568":{"nm":"ネックスカーフパック","on":"ネックスカーフパック","de":"首に巻けば、明け方の練習室の冷たい空気が一段と和らぐ。祖母が孫の首に巻いてくれたあの手つきのように温かく。寒さはいつも最も細いところから、だから首筋から包みこむ。"},"ICON-0569":{"nm":"ホットアイマスク袋","on":"袋","de":"温めたアイマスクを入れておく小さな袋。口を開ける瞬間、まぶたの上にとろりとした温もりがするりと広がる。疲れた一日をしばらく封じておいてほどく、眠る前の優しい儀式。"},"ICON-0570":{"nm":"携帯加湿フィルター","on":"フィルター","de":"からからに乾いた部屋に水気を取り戻す小さな濾し膜。見えない内側で濁ったものを黙々とこし取る。部屋いっぱいの潤いは、誰かの見えない手間が守ってくれた澄みだ。"},"ICON-0571":{"nm":"ビタミン整理ケース","on":"ケース","de":"一日ぶんの錠剤を仕切りごとに分けて入れるケース。きちんきちんと飲むことは、明日もステージに立つという決意だ。小さな仕切りひとつひとつに、自分をいとおしむ心がはっきり整っている。"},"ICON-0572":{"nm":"睡眠用耳栓ケース","on":"ケース","de":"世界の音をしばらく閉じてくれる耳栓の家。静けさにも世話が必要で、ケースの中にきれいに寝そべる。ぐっすり眠った夜があってこそ、次の日の声が澄んで目覚めることを、休息は知っている。"},"ICON-0573":{"nm":"クールタオルクリップ","on":"クリップ","de":"冷やしたタオルがずり落ちないように肩にしっかりくわえる留め具。蒸し暑い日に首筋に触れるひんやりした一筋が、長い午後を耐えさせてくれる。小さな涼しさも留めておけば長く留まる。"},"ICON-0574":{"nm":"ストレッチボール袋","on":"袋","de":"体をほぐしてくれたボールをまた入れておく袋。思いきり伸ばしてまた小さく収めることは、吸う息と吐く息に似ている。広げと収めのその間で、体も心もゆっくり強くなる。"},"ICON-0575":{"nm":"圧迫バンドロール","on":"圧迫バンドロール","de":"ひねった足首をひと巻きずつ包みこむ帯。締めつけるのではなく、そっと支えること。無理した場所ほど、そばで黙々と耐えてくれる手が必要だと、くるくる巻かれながらささやく。"},"ICON-0576":{"nm":"コンディションチェックタグ","on":"タグ","de":"今日のコンディションを一行で書いて掛ける札。よし悪しを正直に下げることは、小さな勇気だ。平気なふりの代わりに今日の自分を書いておけば、誰かはその一行を見てそっと気づかってくれる。"},"ICON-0577":{"nm":"靴用芳香剤カプセル","on":"靴用芳香剤カプセル","de":"靴の中にちょんと入れておく香りのカプセル。一日中ステージを駆け回った足に差し出す、小さくほのかな慰めだ。最も苦労した場所に最もよい香りを——優しさは足先まで余すところなく届く。"},"ICON-0578":{"nm":"インソールサイズ表","on":"表","de":"インソールひとつにも足の大きさをはっきり刻んでおいた表。ぴったり合う一足が、ステージの上の足どりを軽くする。それぞれ異なる歩幅を察すること——フィットとは結局、相手を深く見つめる心だ。"},"ICON-0579":{"nm":"靴べらキーリング","on":"リング","de":"靴べらを手のひらほどに縮めて下げたキーホルダー。靴を履くそのひとときをなめらかに助ける小さな心づかいだ。道を出る足には、いつも誰かの優しい手助けがそっと一緒に掛かっている。"},"ICON-0580":{"nm":"バッグほこりカバー","on":"カバー","de":"いとおしむバッグをほこりからそっと覆っておく布。使われない間もきれいに眠らせて質を守る。頻繁に手が伸びなくても心が留まるものには、こうして静かな世話が宿る。"},"ICON-0581":{"nm":"ストラップ調節ピン","on":"ピン","de":"緩んだ紐を体にぴったり合わせて押さえるピン。緩ければ肩がずり落ち、締めれば息が上がる。ちょうどよさを探す小さな一目盛りの調節で、ステージ衣装も心もようやく楽になる。"},"ICON-0582":{"nm":"ファスナー潤滑ペン","on":"ペン","de":"渋っていたファスナーに一度引けば、再びなめらかに滑る。詰まっていたものがするりとほどけるその音が、なんとも心地よい。止まった場所を再び流れさせるのは、一筋のなめらかさだ。"},"ICON-0583":{"nm":"スニーカークリーナーチップ","on":"スニーカークリーナーチップ","de":"土ぼこりのついたスニーカーを一点一点拭きとる筆先。ステージの外、見えなかった練習の跡を丁寧に消す。再び真っ白になったつま先を見れば、明日はまた新しい気持ちで走れそうだ。"},"ICON-0584":{"nm":"防水スプレーキャップ","on":"キャップ","de":"雨粒を丸く転がして落とす防水のふた。濡れないようにと一枚あらかじめ重ねておくことは、遠くを見すえる優しさだ。雨の日を知るから、晴れた今日に一枚の膜を巻いておく。"},"ICON-0585":{"nm":"革保護布","on":"革保護布","de":"革の上にそっとかぶせてしわを防ぐ布。韓紙で屏風を包んでおいた昔の手つきのように質を守る。長くそばに置くものほどゆっくり——なじませることとは、世話する時間の別の名だ。"},"ICON-0586":{"nm":"キャリーネームベルト","on":"キャリーネームベルト","de":"数多くのバッグの間で、自分のものを一発で見分けさせる名前の帯。コンベヤーをぐるぐる回る荷物の中で、一文字で手を挙げる。どんなに遠くへ旅しても、名前ひとつあれば再び出会えるという安心。"},"ICON-0587":{"nm":"圧縮袋クリップ","on":"クリップ","de":"膨らんだ荷物をぺたんと押さえて閉じる留め具。空けたというより、きちんと畳んだのだ。暮らしを整えて減らす指先から、欲も一緒に小さくなると、しっかり押された荷物が静かに教えてくれる。"},"ICON-0588":{"nm":"旅行用洗剤シート","on":"シート","de":"一枚あれば洗面台で洗濯ができる洗剤シート。遠い道の上でも服を手洗いして着た旅先の知恵に似ている。身軽に出かけても、端正さだけは持っていく、道の上の旅人の古い心構え。"},"ICON-0589":{"nm":"ネックピローカバー","on":"カバー","de":"首を支えてくれた枕に新しく付け替える清潔な覆い。寄りかかる場所はいつもきれいでこそ、心が安らぐ。誰かが楽に寄りかかれるように、場所をふんわり空けておくこと——もてなしはそこから始まる。"},"ICON-0590":{"nm":"手荷物はかり紐","on":"紐","de":"バッグをぐっと持ち上げて重さを量る紐。発つ前に、荷物の重さを手であらかじめ抱いてみる。持っていくものと置いていくものの間で、心の重さまで一緒にそっと量ってみる瞬間だ。"},"ICON-0591":{"nm":"シューズポーチペア","on":"シューズポーチペア","de":"左と右、靴二足を並べて入れる一対のポーチ。別々に置けば失いやすいものも、ペアにしておけば心強い。いつも一緒に行くものには、互いをそっと守る力がある。"},"ICON-0592":{"nm":"サブバッグフック","on":"フック","de":"片手が足りない日に、バッグをさっと掛けておく小さなフック。とても全部は持てないほど荷物が多い日のためのゆとりの一枠だ。しばらく掛けておく場所があるというだけで、肩が一段と軽くなる。"},"ICON-0593":{"nm":"旅行スケジュールチップ","on":"チップ","de":"一日の動線を一枚のチップにはっきり刻んでおく。どこで会ってどこへ流れるか、道に不慣れな足どりにあらかじめ引いておいた案内線。共に出かける道は一枠ずつ分けて書いておけば、めったに迷わない。"},"ICON-0594":{"nm":"マルチアダプターキャップ","on":"キャップ","de":"見知らぬ国のコンセントにもぴったりかみ合うふた。形が違っても結局ひとつにつながる。違う場所から来たものをつなぐこと——調和とは、小さな変換ひとつからそっと始まる。"},"ICON-0595":{"nm":"交通カードスリーブ","on":"交通カードスリーブ","de":"改札を通るたびにカードを守る透明な一枚。毎日の通勤、すり減るほど刻まれた跡まできれいに包む。平凡な道もいとおしんでおけば思い出になることを、この薄い一枚が証明する。"},"ICON-0596":{"nm":"乗車券クリップ","on":"クリップ","de":"すぐにくしゃくしゃになる切符一枚を端正にくわえる留め具。道の上で切符をなくせば、心まで揺らぐ。小さな紙ほどしっかり押さえておくこと——旅の安心は、まさにその一枠から来る。"},"ICON-0597":{"nm":"乗り換えメモチップ","on":"チップ","de":"どこで乗り換えるか一行で書いておいた小さなチップ。迷う分かれ道ごとに、あらかじめ書いておいたひと言が道を明るく開く。メモとは、道に迷う未来の自分にさっと差し出しておく優しいひと声だ。"},"ICON-0598":{"nm":"ゲート通過タグ","on":"タグ","de":"門を通るときにそっと認識される通過の印。ふさがれたような道も、自分の資格を持てばするりと開く。堂々と渡るとは、ためらいなく次の枠へ軽やかに進むことだ。"},"ICON-0599":{"nm":"タクシー領収書ホルダー","on":"ホルダー","de":"小さな紙ごとに、その日たどった道の跡がはっきり刻まれている。四方に転がっていた領収書をひとところにきちんと挟んで集めれば、何でもなかった一日も少しずつ積み重なって、立派な旅程になる。"},"ICON-0600":{"nm":"自転車反射バンド","on":"バンド","de":"薄暗い道の上で、通り過ぎる明かりを受けてそっときらめくバンド。自ら照らさなくても、誰かの光で明るくなる。見えるようにするとは、どうか無事に帰ってきてという夜道の優しい言づてだ。"},"ICON-0601":{"nm":"キャリーホイールカバー","on":"カバー","de":"空港のコンベアの上を何千回転がっても角が無事なのは、車輪を包むこの小さなカバーのおかげ。一番険しい道に真っ先に触れていく場所——誰かをそっと守る仕事は、いつもこうして目立たないところにある。"},"ICON-0602":{"nm":"ヘッドレストカバー","on":"カバー","de":"長距離バス、ヘッドレストに一枚かぶせて窓にもたれる。前の人の香りも昨日の疲れも、ここまでは届かないように。もたれる場所が清潔だというのは、見知らぬ道の上で受け取る意外と大きな慰めだ。"},"ICON-0603":{"nm":"駐車位置ピン","on":"ピン","de":"「何階の何番だったっけ。」がらんとした駐車場でしばらくさまよった人なら、このピンがどれほど頼もしいか分かる。薄れる記憶の代わりにそっと刺しておく目印一つが、戻る場所をあらかじめ決めておく。"},"ICON-0604":{"nm":"ルームキーホルダーストラップ","on":"ストラップ","de":"客室の鍵はどうしてあんなに簡単に消えるのだろう。ストラップに通して手首にかければ、今夜帰る部屋一つだけは忘れることがない。見知らぬ街でも自分の居場所が決まっているという小さな安心が、手首に下がる。"},"ICON-0605":{"nm":"ドアサインチップ","on":"チップ","de":"リハーサルが始まるとドアにチップを一つかける。邪魔禁止——今はひたすら集中する時間という意味。舞台裏のあの深い静けさは、こんな小さな合図たちが言葉なく守ってくれている。"},"ICON-0606":{"nm":"洗面ポーチ","on":"ポーチ","de":"歯ブラシ、洗顔フォーム、手のひらほどのタオル。どこへ発っても、このポーチさえあれば一日の終わりと始まりはいつも同じ手つきで整う。見知らぬ寝床をいつのまにか慣れたものに変える、小さな暮らしの一掴み。"},"ICON-0607":{"nm":"予備タオルクリップ","on":"クリップ","de":"洗面台の横、置き場がなくていつも湿っていた予備のタオル。クリップでつまんでかければ、ようやく居場所を見つける。乾く場所を用意してあげること——優しさはたいてい、これくらいの大きさをしている。"},"ICON-0608":{"nm":"電源タッププポーチ","on":"ポーチ","de":"鞄を開けるたびに一塊に絡まっていた充電器たち。電源タップごとくるくる巻いて入れると、中がぐっと整う。コードがほどけるというのは、発つ前の心の一筋もそっとほどけるという意味。"},"ICON-0609":{"nm":"ベッド番号ラベル","on":"ラベル","de":"合宿所の二段ベッドごとに貼られた番号札。どこが自分の場所かを教えてくれるラベル一枚で、初めて来た見知らぬ部屋もその夜にはいつのまにか我が家になる。始まりはいつもこうして小さい。"},"ICON-0610":{"nm":"ミニ物干しロープ","on":"ロープ","de":"窓枠の間に両端をかければ、それが物干しになる。日差しのいい日、手洗いした靴下が数足、風にふわふわ揺れる。遠く離れた場所でも、日常はこうしてロープの上で乾いていく。"},"ICON-0611":{"nm":"スリッパ識別タグ","on":"識別タグ","de":"玄関にスリッパが山積みになると、誰のものかさっぱり分からない。小さなタグを一つつけておけば、履き物も自分の主を見分ける。大勢でひしめいて暮らすことには、こんな優しい目印が必ず要る。"},"ICON-0612":{"nm":"朝食クーポンホルダー","on":"ホルダー","de":"朝食券を挟んでおくホルダー。小腹のすいた明け方、この一枚があれば湯気の立つスープ一杯が約束されたようなもの。旅先の一日は、いつも温かい一食からゆっくり開かれる。"},"ICON-0613":{"nm":"足首反射バンド","on":"バンド","de":"足首に巻けば暗闇の中で光を跳ね返す。夜の散歩道、遠くから近づく車に「ここに人がいますよ」と言葉なく手を振ってくれる小さな帯。安全はこうして素朴に煌めく。"},"ICON-0614":{"nm":"携帯ウェットティッシュキャップ","on":"キャップ","de":"ウェットティッシュの口にぴったり合わせてはめるキャップ。一枚ずつ柔らかく引き出せて、残りは乾かない。些細に見えても毎日のように手が伸びる物には、それなりの理由が隠れている。"},"ICON-0615":{"nm":"小さなレジャーシートストラップ","on":"ストラップ","de":"レジャーシートを丸く巻いてストラップで結ぶ。漢江の河川敷、桜の木陰、どこでも広げた瞬間そこが私たちの場所になる。草の上の手のひらほどの領土をまるごと連れて歩くストラップ。"},"ICON-0616":{"nm":"虫刺されパッチケース","on":"ケース","de":"夏の夜の必需品、虫刺されパッチを入れるケース。痒くなる前にあらかじめ用意しておく心が、この一区画に入っている。野外ステージの裏方は、いつもこんな小さな備えで頼もしくなる。"},"ICON-0617":{"nm":"散歩用水筒フック","on":"フック","de":"散歩に出るとき水筒を鞄にかけるフック。喉が渇くころ手の届く場所に水があるというのは、それだけ遠くまで歩けるという意味。歩く人を止めさせない小さなつながり。"},"ICON-0618":{"nm":"折りたたみエコバッグ","on":"バッグ","de":"広げればエコバッグ、たためば手のひら。市場の路地を巡って情のわいた野菜一束を入れるのにちょうどいい。暮らしの知恵はいつも、かさを減らす方へ、軽く持ち歩ける方へと育ってきた。"},"ICON-0619":{"nm":"風よけクリップ","on":"クリップ","de":"風の吹く日、はためく天幕の裾をつまんでしっかり押さえる。クリップ一つが、しきりに揺れていたものを元の場所に押しとどめる。野外で一番頼もしいのは、意外とこんな指ほどの物だ。"},"ICON-0620":{"nm":"日差し遮りピン","on":"ピン","de":"窓に刺して日差しを斜めに遮るピン。真昼の光が強すぎるとき、木陰一掴みをそっと差しかけてくれる。眩しさを和らげることも、誰かにとってはこの上なく優しい手つきになる。"},"ICON-0621":{"nm":"非常用ホイッスルキャップ","on":"キャップ","de":"非常用ホイッスルの口を覆うキャップ。埃が入らないように、いざ必要な瞬間には一発で鳴るように。結局使うことがないよう願いながらも、そばにあるだけで心が安らぐ物もある。"},"ICON-0622":{"nm":"傘先キャップ","on":"キャップ","de":"傘の先にかぶせる小さなキャップ。尖った先が鈍くなれば、隣の人も自分の鞄も傷つかない。雨の日のマナーとは、こうして鋭い先を丸く包むところから静かに始まる。"},"ICON-0623":{"nm":"レインコート収納パック","on":"収納パック","de":"たたんだレインコートをくるくる巻いて入れるパック。次のにわか雨が降るまで、鞄の片隅で静かに待つ。備えとは結局、最後まで使わないかもしれないものをあらかじめ用意しておく心の一筋だ。"},"ICON-0624":{"nm":"防水シューズカバー","on":"カバー","de":"靴の上にかぶせれば雨水がもう染み込まない。梅雨の降りしきる通学路でも靴下はさらさら。爪先まで濡れなかった一日は、思ったよりずっと大きく気分を変えてくれる。"},"ICON-0625":{"nm":"雪道すべり止めパッド","on":"パッド","de":"靴の裏に貼れば氷の道もぐっと怖くなくなる。雪の積もった路地を小走りで渡ったあの冬、滑らないようにそっと支えてくれたパッド。慎重な足取りの下に隠れた頼もしさ。"},"ICON-0626":{"nm":"クーリングネックリング","on":"リング","de":"首に巻けばひんやりした気配がそっと巡る。うだるような真夏の暑さの中でも、一筋の涼しさを首筋にかけて歩く夏の知恵。暑さを耐える術も、年ごとに少しずつ細やかになっていく。"},"ICON-0627":{"nm":"ハンディファンスタンド","on":"ハンディファンスタンド","de":"ハンディファンを立てておく台。両手が自由になればページもめくれるし、扇ぐ代わりに文章も書ける。小さな風一筋が、机の前の長い夏をどうにか耐えられるものにしてくれる。"},"ICON-0628":{"nm":"カイロポーチ","on":"ポーチ","de":"カイロを入れて持ち歩くポーチ。冷えきった指先を温めようとポケットに手を入れると、そこに小さなぬくもりが先に来て待っている。冬の外出はこの一掴みの温かさで乗りきる。"},"ICON-0629":{"nm":"防寒イヤーマフケース","on":"ケース","de":"耳当てを入れておくケース。次の寒さが訪れるまで、大切にしまっておく場所だ。季節が変わっても捨てきれない物には、また会う冬への静かな信頼が込められている。"},"ICON-0630":{"nm":"紫外線測定チップ","on":"チップ","de":"光に軽くかざすと今日の紫外線の強さを色で教えてくれるチップ。見えなかった日差しの強度を、ようやく目に見えるものにする。空を読む小さな目を一つ、手首にそっと留めておくようなもの。"},"ICON-0631":{"nm":"路地スタンプ台紙","on":"台紙","de":"路地の入り口の店ごとにスタンプをもらって埋めていく台紙。一マスずつ押されるたびに、町の地図が心の中にくっきり描かれる。二本の足で歩いて集めた思い出は、こうしてスタンプの跡として残る。"},"ICON-0632":{"nm":"訪問地ピンボード","on":"ピンボード","de":"行ってきた場所ごとにピンをぷすっと刺しておく小さなボード。点が一つ二つ増えるほど、自分の世界の周りも一緒に広がっていく。ピン一つ一つが「私、ここにいたよ」とそっと語りかける痕跡だ。"},"ICON-0633":{"nm":"ミニコンパスストラップ","on":"ストラップ","de":"しばらくさまよっても、北だけはいつでもその場所に変わらずある。胸元に下がる小さなコンパスは、どこへ行けばいいのか皆目分からないとき、揺れる心からまずそっと整えてくれる。"},"ICON-0634":{"nm":"道案内メモリング","on":"リング","de":"道を探して書きとめたメモをリングに通しておく。「赤いポストで左折。」誰かの拙い手書きが見知らぬ路地をそっと案内する。紙の上に残った道は、なかなか薄れない。"},"ICON-0635":{"nm":"ランドマークステッカーブック","on":"ステッカーブック","de":"旅先ごとに一枚ずつ買ったステッカーで埋めていく本。塔、橋、古い城壁が一面一面積もる。行ってきた場所を集めるというのは、過ぎてきた時間を指先でもう一度なぞることに似ている。"},"ICON-0636":{"nm":"地下鉄乗換チップ","on":"チップ","de":"路線が分かれる乗換駅で手にぎゅっと握るチップ。どこで乗り換えるか決めるその短い瞬間が、ときに一日の方向をまるごと変えることもある。小さな選択一つで、街は違う顔を見せる。"},"ICON-0637":{"nm":"町探検カード","on":"カード","de":"「今日はこの町のパン屋まで。」カードを一枚引けば今日の探検地が決まる。いつも通る慣れた路地も、ミッションができれば新しい道になる。冒険は遠くにないと教えてくれる一枚。"},"ICON-0638":{"nm":"店名刺ホルダー","on":"ホルダー","de":"行きつけの店でもらった名刺を挿しておくホルダー。美味しかった店、挨拶が優しかった店主が一区画ずつちゃんと集まる。一つの街と情がわくというのは、こんな小さな紙きれから始まること。"},"ICON-0639":{"nm":"コース完走バッジ台紙","on":"台紙","de":"散歩コースを最後まで全部回ると、バッジが一つ埋まる台紙。完走のやりがいが丸い金属になって手に残る。最後まで歩いた人だけが知るあの誇らしさが、ここにくっきり刻まれる。"},"ICON-0640":{"nm":"バッグ南京錠キーリング","on":"リング","de":"鞄のファスナーにかける小さな南京錠兼キーリング。大切なものをしっかり守りながらも、鞄の端でしゃらしゃら揺れる。防犯と装飾が一身になった、旅人のなかなか賢い相棒。"},"ICON-0641":{"nm":"紛失防止タグ","on":"タグ","de":"鞄の一番深い闇の中にうずくまっていて、皆が諦めたその瞬間に小さく点滅する。「ここですよ。」失くしたと思った心が指先に戻ってくる音。小さくても最後まで主のそばを守る。"},"ICON-0642":{"nm":"ファスナーロック","on":"ロック","de":"カチッ、一度かかればちょっとやそっとの手では開かない。急いた爪も、そっと近づいてきた指も等しく阻む粘り強さ。安全はたまに少々渋くてもいいのだと、ずっしりした重みで教えてくれる。"},"ICON-0643":{"nm":"盗難防止ベルストラップ","on":"ストラップ","de":"会計を済ませる前まで、陳列台の上の品々が勝手に外出できないように守る、見えない門番。正直な手が触れるときには、最後まで沈黙する。鳴らない鐘が、一番平和な鐘だ。"},"ICON-0644":{"nm":"連絡先目隠しラベル","on":"ラベル","de":"宅配の箱に書かれた名前と番号の上に、そっと一枚重なる。誰が住んでいてどこへ行くのかは、受け取る人だけが知っていればいいこと。うまく隠してあげることも優しさの一種だと、静かに居場所を守る。"},"ICON-0645":{"nm":"パスポートカバーバンド","on":"バンド","de":"見知らぬ空港、同じ表紙が何十個もコンベアを巡る明け方。その中で自分だけが知る色で「こっちだよ」と手招きする。遠い旅路へ発つ証明書に着せてあげる小さな上着。表紙が擦れても旅は明るい。"},"ICON-0646":{"nm":"現金分けポーチ","on":"ポーチ","de":"お札は左、小銭は右、へそくりは誰も知らない区画。市場帰りの手が真っ先に探る場所だ。乱れた一日も、この中ではきちんと、しゃらしゃらと元の場所を見つける。"},"ICON-0647":{"nm":"セキュリティステッカーシール","on":"セキュリティステッカーシール","de":"一度はがすと跡が残る。「誰かが開けました」を最後まで隠しきれない、小さく正直な良心。封印されたまま無事に届いた箱の底には、みなこの子の変わらぬ沈黙が敷かれている。"},"ICON-0648":{"nm":"非常連絡チップ","on":"チップ","de":"迷子の子のポケット、ノートパソコンの鞄の内側、犬のリードの端。話せない瞬間が来ても、代わりに番号をはっきりと唱えてくれる。小さなチップ一つに「家まで連れて行ってください」がまるごと込められている。"},"ICON-0649":{"nm":"自撮り棒リモコンキャップ","on":"キャップ","de":"腕が足りなくていつも誰かが切れていた集合写真。今は端でボタンをちょいと押せば、家族みんなが一つのフレームに収まる。みんなで笑うその一瞬、私はそっとシャッターを押してその中に飛び込む。"},"ICON-0650":{"nm":"レンズポーチストラップ","on":"ストラップ","de":"予備のレンズが鞄の中でぶつからないようにストラップでしっかり抱きしめておく。ガラス玉一つがそのまま風景一つだから、その重みをむやみに揺らさない。写真を撮る人の慎重さが結び目ごとに括られている。"},"ICON-0651":{"nm":"フィルターケースリング","on":"リング","de":"薄い一枚が同じ空を違う光に変える。その小さな魔法たちを丸い巣にきちんと収めておく場所。ケースを開ける瞬間ごとに、今日はどんな夕焼けを収めようかと、指先がしばし弾む。"},"ICON-0652":{"nm":"三脚ポーチ","on":"ポーチ","de":"たためば一握り、広げれば揺るぎない三本の脚。震える手の代わりに風景を捉えてくれる相棒をそっと巻いて入れる。重い機材ほど、より柔らかい布の上に寝かせてあげるのが道理だ。"},"ICON-0653":{"nm":"カメラストラップパッチ","on":"カメラストラップパッチ","de":"一日中歩いていると、カメラが肩を押しつぶす時間が来る。そのときパッチ一つがその重みをそっと分かち合う。いい一枚のために遠い道を歩く肩に乗せてあげる、小さくふかふかの慰めだ。"},"ICON-0654":{"nm":"メモリー分類カード","on":"カード","de":"数百枚の思い出がどのカードに眠っているのか紛らわしい夜。色とりどりの目印が道を指し示す。春の旅は青、初舞台は黄色。記憶にも区画を分けてくれる、小さく優しい司書だ。"},"ICON-0655":{"nm":"充電ケーブルロール","on":"充電ケーブルロール","de":"鞄の中でケーブルが結び目ショーを繰り広げる前に、丸く巻いてきちんと寝かせておく。コード一本を整えると、なぜか心の一本も一緒にほどける。くるくる巻かれた姿は、見ていると平和だ。"},"ICON-0656":{"nm":"写真バックアップラベル","on":"ラベル","de":"「この写真、バックアップしたっけ?」夜更けにふと込み上げるその不安に、あらかじめ答えておく小さなメモ。大切な瞬間ほど二箇所以上に生きていなければと、ラベルははっきり書きとめておく。"},"ICON-0657":{"nm":"構図フレーム板","on":"板","de":"四角い窓の向こうに世界を見れば、何を収めて何を空けるか一目で分かる。いい写真は足すのではなくうまく削るものだと、空っぽのフレームが真っ先に教えてくれる。"},"ICON-0658":{"nm":"小銭入れチャーム","on":"小銭入れチャーム","de":"鞄の端にぶらぶら下がって小銭を数枚抱える。自販機の前で、湯気の立つたい焼きの屋台の前で、真っ先に開く小さな宝庫。しゃらしゃら鳴るその音が、ささやかな幸せの効果音だ。"},"ICON-0659":{"nm":"レシート集め串","on":"串","de":"捨てようとしてやめた紙きれが一つ二つ刺さる。今日何を食べて何を買ったか、レシートは家計簿より正直な日記。一ヶ月分を集めると、なかなか分厚い生活の記録になる。"},"ICON-0660":{"nm":"マーケットバッグタグ","on":"マーケットバッグタグ","de":"買い物に出た手首にかかって市場通りを一緒に巡る。豆腐一丁、長ネギ一束、おまけに乗せてもらった情まで。そのすべての重みを文句なく受け止める。空けるときより満たすときのほうが嬉しい相棒だ。"},"ICON-0661":{"nm":"記念マグネット板","on":"板","de":"旅先ごとに一つずつ選んで冷蔵庫の扉に貼れば、台所が小さな世界地図になる。行ってきた街々が並んで下がり「また行こう」とささやく。ありふれた鉄板にも、思い出をとどめる力がある。"},"ICON-0662":{"nm":"地域スタンプブック","on":"地域スタンプブック","de":"一ページにスタンプ一つずつ、歩いた路地がインクで再び蘇る。全国を巡って集めた赤い跡が、そのまま足跡の地図だ。空欄が減るほど、次の旅路がそっと手招きする。"},"ICON-0663":{"nm":"包装ひもリール","on":"包装ひもリール","de":"贈り物の箱一つを結ぼうと果てしなくほどけ出てくる、長い長い忍耐心。ほどよく切れる手にだけ、きれいな結び目を許す。くるくる巻かれたまま、次の出番が来るのを黙って待つ。"},"ICON-0664":{"nm":"ギフト緩衝パック","on":"ギフト緩衝パック","de":"壊れやすい心をふかふかに包み込む。揺れる宅配の荷台の中でも「大丈夫、僕が支えるよ」とふかっと耐える。箱を開ける受け手の明るい笑顔まで、あらかじめ守っておくようなもの。"},"ICON-0665":{"nm":"値札目隠しシール","on":"値札目隠しシール","de":"贈る品の値段をそっと覆ってあげる、優しい嘘一枚。「いくらかは知らなくていい、気持ちだけ受け取って」と値札の上にふわりと座る。隠すのではなく、その気持ちをより輝かせること。"},"ICON-0666":{"nm":"ミニショッピングカートチップ","on":"チップ","de":"本物のカートは引けなくても、指先でぶらぶら揺れるこの小さな相棒には、スーパーへのお出かけのときめきが全部詰まっている。小さくても「今日は何を買おう?」とわくわくしたあの胸の高鳴りだけは、本物に劣らずずっしり重い。"},"ICON-0667":{"nm":"夜光シューズクリップ","on":"クリップ","de":"夜の散歩に出たスニーカーの先できらり、通り過ぎる車に「ここに人がいますよ」と合図を送る。暗い路地で真っ先に出迎えてくれる小さな光。安全はいつも足先から静かに始まる。"},"ICON-0668":{"nm":"ミニ懐中電灯キャップ","on":"キャップ","de":"懐中電灯の頭にかぶせると、光がより遠く、より美しく広がる。真っ暗なテントの天井に星の群れを描く小さな手品師。闇が少し怖い夜には、これほどの相棒はいない。"},"ICON-0669":{"nm":"帰宅お知らせボタン","on":"ボタン","de":"ぐっと押すと「無事に到着しました」の一行が、遠くにいる家族へ飛んでいく。夜更けの玄関の音の代わりに、小さなボタン一つが無事を伝える。誰かはこの合図を待ちながら眠りにつく。"},"ICON-0670":{"nm":"反射ステッカーロール","on":"反射ステッカーロール","de":"一区画切って鞄に、自転車に、傘にぺたっと貼れば、夜道がぐっと危なくなくなる。ヘッドライトに出会えば明るく目覚める寝ぼすけ。くるくる巻かれたまま、次の闇が来るのを待つ。"},"ICON-0671":{"nm":"非常タクシーカード","on":"カード","de":"財布の一区画に挿しておけば、夜更けのがらんとしたバス停も心細さが和らぐ。番号一つ、住所一行が「家まで送るよ」という約束のように書かれている。非常という言葉が、これほど頼もしいとは。"},"ICON-0672":{"nm":"夜道マップバンド","on":"バンド","de":"街灯のまばらな道を手首に巻いて歩く。どの路地が明るくてどこが真っ暗か、夜だけが知る近道をそっと教えてくれる。闇の中でも方向を見失わないように、そばを括っておくバンドだ。"},"ICON-0673":{"nm":"防犯ベルポーチ","on":"ポーチ","de":"危急のとき引っ張れば、路地中が驚くほど大きく叫ぶ。普段はポーチの中におとなしく隠れ、たった一度の瞬間のために声を温存しておく。小さな鞄に入った、一番大きな叫びだ。"},"ICON-0674":{"nm":"玄関灯キーリング","on":"リング","de":"暗い廊下の先、手探りで鍵穴を探した夜はもうさよなら。ドアの前に下がって帰宅する手を丸い灯りで出迎える。「お疲れさま、もう着いたよ」とキーリングが先に挨拶をかける。"},"ICON-0675":{"nm":"宿復帰メモ","on":"メモ","de":"「傘を持って、電気を消して出てね。」冷蔵庫に貼られた短い言いつけが、がらんとした宿を守る。戻ってくる人へ向けた小さなメモ。紙一枚に込められた優しさが、玄関までそっとついて出る。"},"ICON-0676":{"nm":"ケーブル整理コーム","on":"コーム","de":"絡まった配線を髪をとかすようにそっときれいにとかし下ろす。机の裏のジャングルのようだったケーブルの森が、数回のとかしで整う。乱れているのは髪の毛だけではないと、コームがそっと教えてくれる。"},"ICON-0677":{"nm":"ペン立て仕切り","on":"ペン立て仕切り","de":"鉛筆はこっち、蛍光ペンはあっち、ハサミは端の区画。一つの筒の中に小さな村を分けて、ペンたちの場所を決めてあげる。区画ができれば手ももう迷わない。机の上の小さな秩序の始まりだ。"},"ICON-0678":{"nm":"モニターメモクリップ","on":"クリップ","de":"モニターの脇に下がって「今日やること」をちょうど目の高さに突きつける。うっかりする間もなく正面に見える小さな掲示板。クリップ一つが、しきりに先延ばししようとする心をそっと引きとめる。"},"ICON-0679":{"nm":"引き出し分類トレイ","on":"トレイ","de":"クリップと輪ゴム、画鋲と消しゴム。引き出しの中の小さな部族たちに、それぞれの部屋を与える。区画ごとに分かれた場所へ手が届けば、探す時間が減り、心の片隅が軽くなる。"},"ICON-0680":{"nm":"ほこり払い筒","on":"筒","de":"レンズの上に乗った埃一粒も、写真の中では巨大な染みになる。だからブラシは筒の中でいつも、すっきり身支度を整えて待つ。目につかない清潔を守る、勤勉な指先だ。"},"ICON-0681":{"nm":"デスクマットコーナー","on":"デスクマットコーナー","de":"机の片隅に敷かれた一握りの柔らかさ。ペンが転がり落ちず、冷たいガラスの代わりに温かい木目が手首を支える。長い夜の文字が揺れないように、真っ先に場所を譲る優しい床だ。"},"ICON-0682":{"nm":"マウスコードホルダー","on":"ホルダー","de":"コードが絡まると、心もどこか絡まってしまう。乱れそうな一筋をあらかじめつかんできちんと寝かせておく手つき。目立ちもしないのに、机の佇まいを静かに整える、小さく勤勉な身づくろいだ。"},"ICON-0683":{"nm":"充電ドック台","on":"台","de":"寝ていた機器を斜めに起こすと、画面がようやく目を合わせる。充電される間の待ち時間さえ整然となる時間。支えてあげるというのは、しばし休むものにも姿勢を整えてあげること。"},"ICON-0684":{"nm":"ミニごみ箱ラベル","on":"ラベル","de":"一番小さな箱にも自分の名前がつく。「ここに捨ててください」の一行が、雑然とした机の上に静かな秩序を呼ぶ。ラベルとは結局、物に「お前の役目はここだよ」と教えてあげる小さな挨拶だ。"},"ICON-0685":{"nm":"パーティションボードピン","on":"ピン","de":"ボードの上に紙一枚をぷすっと押さえておく。忘れたくない気持ちを壁にしばし預けておくこと。ピンの先に下がる今日の誓いが風にそっと揺れ、通るたびにあなたを引きとめる。"},"ICON-0686":{"nm":"ラベルフレームチップ","on":"チップ","de":"四角い縁取り一つが、平凡な文字をはっきりした一文に変える。散らばりやすいメモに整った格を巡らせてあげるチップ。閉じ込めるのではなく、大切な言葉を失わないように包み込むこと。"},"ICON-0687":{"nm":"透明引き出し取っ手","on":"取っ手","de":"中が透ける引き出しに取っ手をつければ、何が入っているか見ながらもむやみに開けなくなる。見えても近づかない一握りの距離。透明さにも礼儀が必要だと、引き出しはそうささやく。"},"ICON-0688":{"nm":"蓋ロッククリップ","on":"クリップ","de":"開けたまま置くと香りも色合いもそっと逃げていく。蓋をしっかり挟んでおく小さな挟み一つで、昨日の色が明日までそっくり残る。閉じることは実は、大切にするものを守り抜くことだ。"},"ICON-0689":{"nm":"乾燥剤ホルダー","on":"ホルダー","de":"じめじめを憎み、黙々と持ち場を守る小さな番人。乾いた空気をそばに置くことが長く保管する第一の条件だと、この整然としたホルダーが静かに教えてくれる。さらさらはそうして守られる。"},"ICON-0690":{"nm":"整理かごタグ","on":"整理かごタグ","de":"かごごとに小さな名札一つ。どの区画に何が住むか決めておけば、探すのにかかっていた時間がそのまま休む時間になる。整理とは、未来の自分にあらかじめ渡しておく優しいメモだ。"},"ICON-0691":{"nm":"ミニパーティション板","on":"板","de":"机の上にこぢんまりとした部屋を一つ、ぱっと建て上げる小さな仕切り。この板一つで世界とちょっと背を向けた静かな角ができる。集中が宿りそうな、ひたすら自分だけの居心地のいい場所一つ。"},"ICON-0692":{"nm":"収納袋スタンド","on":"収納袋スタンド","de":"ぱたぱた倒れていた袋たちの背をそっと支えて立てておく台。きちんと並んで立っているだけで、選んで使うのがぐっと楽になる。まっすぐ立てておくというのは、次の手をあらかじめ気遣うことだ。"},"ICON-0693":{"nm":"空欄表示チップ","on":"チップ","de":"空いていることをわざわざ表示しておくチップ。満たすべき場所を残しておくのも、れっきとした計画だ。空欄は怠けではなく、まもなく訪れる何かのために丁重に空けておいた一握りの余白だ。"},"ICON-0694":{"nm":"歯ブラシカバーキャップ","on":"キャップ","de":"口に触れるブラシには、より気難しい気を使うようになる。埃一粒まで防ぐ小さな帽子一つ。見えない清潔を気遣うことこそ、毎朝をすっきり開く些細な真心だ。"},"ICON-0695":{"nm":"石鹸受けネット","on":"石鹸受けネット","de":"石鹸が水に浸かってふやけないようにそっと浮かせてあげるネット。水気を流せばより長くそばに残るという道理を、浴室の一番低く小さな場所で毎日静かに証明してみせる。"},"ICON-0696":{"nm":"シャンプーポンプクリップ","on":"クリップ","de":"ポンプの頭をそっと押さえ、一度押せばちょうどいい量だけ流れ出るようにする。節約する手癖は、長く続く暮らしの基礎。小さなクリップ一つが、無駄遣いを優しく取り締まってくれる。"},"ICON-0697":{"nm":"髭剃り掛けキャップ","on":"キャップ","de":"刃の鋭いものには、別に小さな家を用意してあげる。髭剃りをキャップにはめて掛けておけば、水気も危険も一緒に流れ落ちる。鋭さを慎重に扱う術は、すなわち自分を大切にする術でもある。"},"ICON-0698":{"nm":"シャワータオルリング","on":"リング","de":"長く垂れたタオルが輪をなし、手の届かなかった背中まで連れて行く。泡が滑る一筋の流れに沿って、一人でも背中を洗った優しいぬくもりが、浴室いっぱいに温かく広がる。"},"ICON-0699":{"nm":"排水口ストレーナーパック","on":"排水口ストレーナーパック","de":"水は流して、かすは捕まえる小さな網一つ。見えないところで詰まりを静かに防ぐ。一番低い場所で働くものたちが家の流れを守るのだと、排水口は言葉なく教えてくれる。"},"ICON-0700":{"nm":"吸盤フック板","on":"板","de":"釘一つ打たなくても壁に新しい場所を作る。ぐっと押して貼ったあとはがせば、跡さえ残らない。跡を残さずしばし留まって去る術——吸盤板は、その軽やかな礼儀をよく知っている。"},"ICON-0701":{"nm":"浴室スリッパタグ","on":"浴室スリッパタグ","de":"敷居の前にきちんと並んだ一足。靴を脱いで上がる家の真心が、浴室のドアの前までこまやかに続く。冷たい爪先を温める小さなもてなしを、名札がその場所をそっと指定してくれる。"},"ICON-0702":{"nm":"ミニ洗面コップ","on":"コップ","de":"うがい一口を入れる小さく丸いコップ。口をすすぐ短い瞬間で、一日の始まりと終わりを静かに受け止める。華やかでなくても毎日そばにあるもの——素朴さが一番長く続く暮らしだ。"},"ICON-0703":{"nm":"ほこり払いスリーブ","on":"ほこり払いスリーブ","de":"埃を撫でるようにそっと払い取るブラシ、その羽毛にスリーブをかぶせる。使わないとき羽をきれいに寝かせておく鳥のように、休む場所を知る道具が長くそばに残るものだ。"},"ICON-0704":{"nm":"粘着クリーナーリフィル","on":"粘着クリーナーリフィル","de":"一枚はがせばその下に新しい面がさらりと現れる。毛玉と髪の毛を取り去る粘っこい中身の重なり。使いきればまた満たされる丸いリフィルの中に、勤勉な反復の美徳が巻かれている。"},"ICON-0705":{"nm":"雑巾挟み","on":"挟み","de":"雑巾を手の代わりにしっかりくわえてくれる挟み。冷たい床と指の間に一握りの距離を置く。汚れ仕事を代わりに受け止める取っ手一つが、骨の折れる掃除をぐっと身軽にしてくれる。"},"ICON-0706":{"nm":"隙間ブラシキャップ","on":"キャップ","de":"狭い隙間を狙って入り込む細いブラシ、そのか弱い先を守る小さな帽子。手の届かない隅まで気にかける心一つ。見えないところを拭く人が、家の懐を一握り広げる。"},"ICON-0707":{"nm":"スプレーボトルラベルリング","on":"リング","de":"スプレーボトルの肩にそっとついた小さな名札。中身が澄んだ水か洗剤か、たった一行ではっきり教えてくれる。紛らわしさをあらかじめ消しておくラベルは、手早い暮らし上手の長年の習慣だ。"},"ICON-0708":{"nm":"トイレットペーパーリフィルバンド","on":"バンド","de":"使いきった場所に新しいロールをはめてしっかり結ぶバンド。切れたものを再びつなぐ最も単純な手つきだ。なくなる前にあらかじめ満たしておく誰かの心が、この小さな輪に丸く巡っている。"},"ICON-0709":{"nm":"掃除手袋フック","on":"フック","de":"水仕事を終えたばかりの濡れた手袋を掛けて乾かすフック。苦労した手にしばし休む場所を譲る。水気がゆっくり乾く間、次の仕事のためにそっと息を整える、短い休息の時間だ。"},"ICON-0710":{"nm":"ほうき掛けピン","on":"ピン","de":"ほうきを逆さに立てて掛けておけば、穂が曲がらずまっすぐ生きる。まっすぐ下がったまま次の庭を待つ姿勢。役目を終えたあとも自分の形を保てるよう助ける、小さくてもしっかりした場所一つだ。"},"ICON-0711":{"nm":"ごみ袋クリップ","on":"クリップ","de":"袋の口をしっかりくわえて、漏れ出るもの一つなくきっちり封じてくれる。先をきゅっと締める一度の手つきで、後片付けがぐっときれいになる。仕上げとは結局、よく閉じることから始まる。"},"ICON-0712":{"nm":"洗濯ばさみケース","on":"ケース","de":"散らばると失くしやすい洗濯ばさみたちが、一つに集まって暮らすケース。小さなものたちに、一緒に留まる共同の家を譲る。指先の小さな兵隊たちを一箇所に集めておけば、必要なとき一目で見つけられる。"},"ICON-0713":{"nm":"靴下分類リング","on":"リング","de":"片割れを失くした靴下は、いつもどこかへそっと消える。洗う前に一組ずつリングで結んでおけば、さらさらに乾いたあとも二つは別れない。分類とは、消失をあらかじめ防いでおく小さな約束だ。"},"ICON-0714":{"nm":"洗濯ボール袋","on":"袋","de":"洗濯機の中をころころ転がり回って、服に染みた汚れをとんとん叩いて起こす。丸い体で洗濯物を撫でるリズム。激しい水流の間で、叩くという洗濯の古い本能を袋に詰めて転がす。"},"ICON-0715":{"nm":"ウール洗剤計量キャップ","on":"キャップ","de":"繊細な服には繊細なだけの量を。ウール洗剤をちょうど一蓋分だけきれいに量ってくれる計量キャップ。小さな目盛り一つに、毛織物を扱う慎重な手つきが込められている。過ぎたるを減らすのも真心だ。"},"ICON-0716":{"nm":"生地補強パッチ","on":"生地補強パッチ","de":"ほつれた場所にそっと当ててあげる小さなパッチ。擦り切れた所をむやみに捨てず、そっといたわる指先の心。繕って着た跡ごとに、その服とともに過ごしてきた歳月の模様がきれいに残る。"},"ICON-0717":{"nm":"物干し固定ピン","on":"ピン","de":"風で洗濯物がひょいと飛んでいかないように、物干しをそっと押さえるピン。日差しの下で洗濯物が波打つ日も、揺れの中で元の場所を保てるよう助ける。小さくても頼もしい重しの一役だ。"},"ICON-0718":{"nm":"下着洗濯ネットタグ","on":"下着洗濯ネットタグ","de":"か弱い下着は網の中に別に入れて洗う。激しい水流から柔らかいものをすっぽり包み込む網。名札のついた小さな袋一つが、弱いものを慎重に守ることも暮らしだと教えてくれる。"},"ICON-0719":{"nm":"洗剤スプーンフック","on":"洗剤スプーンフック","de":"粉洗剤をすくうスプーンを壁にきちんと掛けておく。筒の中に落として手を濡らす煩わしさなく。いつも同じ場所に同じ道具を置く整然とした習慣が、この小さなフックにしっかり込められている。"},"ICON-0720":{"nm":"物干しロープストッパー","on":"物干しロープストッパー","de":"物干しロープの端をぎゅっとくわえ、重い洗濯物が乗ってもするりとほどけないようにしっかり押さえておく。ぴんと張った一筋がたるまないよう最後まで耐える、最後の結び目。しっかりした仕上げがここにかかっている。"},"ICON-0721":{"nm":"枕カバーラベル","on":"ラベル","de":"毎晩、頬が真っ先に触れる場所、その内側に縫いつけられた爪ほどのラベル。洗濯温度を書いた小さな文字を誰が読みきるだろう。それでも眠った顔のそばを守る、一番近い案内文だ。"},"ICON-0722":{"nm":"布団クリップ","on":"クリップ","de":"窓を開けた夜、風が入ってきても布団は逃げない。二つの口をしっかり閉じたクリップが角をくわえているから。眠る人の代わりに端を握ってくれる、言葉のない手だ。"},"ICON-0723":{"nm":"ナイトライト遮り板","on":"板","de":"「灯りが目に触れると眠りが遠ざかるんです。」誰かがそっと立てておいた遮り板一枚に光が後ろへ退き、足元だけをぼんやり濡らす。闇を一握り貸してくれる小さな仕切り。"},"ICON-0724":{"nm":"ベッド隙間ポケット","on":"ベッド隙間ポケット","de":"マットレスと壁の間、手の届かなかったあの隙間を思い浮かべて。転がり落ちたリモコンも眼鏡も、これからはここに集まる。失くすところだったものを受け止める、ベッドがそっと広げたポケット。"},"ICON-0725":{"nm":"眼鏡保管トレイ","on":"トレイ","de":"レンズを外せば世界は柔らかくにじみ、その束の間の無防備を浅い皿が受け止めておく。朝になれば指先が探らなくても、眼鏡はいつも同じ場所で待っている。"},"ICON-0726":{"nm":"目覚まし時計受け","on":"受け","de":"明け方六時、一番憎まれる音が鳴る、固い足場の上。揺るぎなく時計を支え、結局誰かの一日を開く。目覚めという無愛想な約束を、黙々と支える。"},"ICON-0727":{"nm":"枕元ケーブルホルダー","on":"ホルダー","de":"枕元へ滑り落ちていた充電ケーブルが、もう床に落ちない。小さなホルダーがコードの端をそっとつかむから。手を伸ばせば届く距離、夜の動線を整えた手つき。"},"ICON-0728":{"nm":"パジャマ収納バンド","on":"バンド","de":"きれいにたたんだパジャマを一周巻いて結ぶバンド。乱れやすい柔らかさにも佇まいが必要だ。明日の夜の自分のために、今日の自分がきちんと巻いておく小さな準備。"},"ICON-0729":{"nm":"香りカードホルダー","on":"ホルダー","de":"香りをまとったカード一枚を斜めに立てておけば、ページをめくるように鼻先で季節をめくる。ラベンダーからシトラスへ——匂いで綴った、その日の日記帳になる。"},"ICON-0730":{"nm":"鍵皿パッド","on":"パッド","de":"玄関の片隅、鍵たちががしゃんと落ちていた場所。柔らかいパッドを敷いた皿が、その鋭い音を飲み込む。帰ってきた人の最初の動作を、小さな受けが静かに受け止める。"},"ICON-0731":{"nm":"傘水受けキャップ","on":"キャップ","de":"持って入ってきた傘の先から雨水がぽたぽた落ちる。キャップ一つがその雫をしっかり受け止めるので、床にそっと広がっていた小さな水たまりを、誰かがあらかじめ察して防いでおいたようなもの。"},"ICON-0732":{"nm":"マスク掛けチップ","on":"チップ","de":"玄関の横の壁についた爪ほどのチップ。外出の最後の儀式のようにマスクがここに掛かる。持っていくものを忘れないように、ドアの前で目の高さを守る小さな記憶装置。"},"ICON-0733":{"nm":"宅配カッター刃カバー","on":"カバー","de":"宅配の箱を切り裂いていた刃の上にはめる保護カバー。ほどける高揚の裏に隠れた切れる危険をそっと覆っておく。待ちの終わりを安全に開いてくれる、目立たない気遣い。"},"ICON-0734":{"nm":"靴ブラシ受け","on":"受け","de":"ブラッシングを終えた靴ブラシが濡れたまま置かれる場所。水気を含んでも床はさらさらに乾く。きれいさを作る道具にも休む場所が必要だと、小さな受けが教えてくれる。"},"ICON-0735":{"nm":"来訪者メモ板","on":"板","de":"「ちょっと寄っていきます。」玄関のメモ板に残った短い文字一行。すれ違った人々が時間を越えて交わす小さな広場だ。紙一区画に、安否とお願いとハート一つが重なって積もる。"},"ICON-0736":{"nm":"ドア隙間ふさぎロール","on":"ドア隙間ふさぎロール","de":"ドアの下、指ほどの隙間から染みていたすきま風。くるくる巻いたふさぎがその通り道をそっと阻む。見えずに漏れ出ていたぬくもりを、部屋の中にもう一枚引きとめておく。"},"ICON-0737":{"nm":"ドアストッパーチャーム","on":"ドアストッパーチャーム","de":"ぱっと開けておいたドアが再び閉まらないように足元を支える小さなチャーム。出入りする風と足音のために、どっしり持ち場を守る。開けておくことを持続させる、優しい意地一つ。"},"ICON-0738":{"nm":"玄関灯スイッチカバー","on":"カバー","de":"夜更けに手探りで探した玄関のスイッチ。夜光カバーが闇の中でほのかに居場所を知らせる。手が迷わないように、灯りがつく前に先に光る小さな案内者。"},"ICON-0739":{"nm":"コップホルダーパッド","on":"パッド","de":"食卓に下ろしたコップがするりと滑った瞬間、パッド一枚がその足をそっとつかむ。水滴がついても跡一つ残さない、落ち着いて持ち場を守る受け。"},"ICON-0740":{"nm":"車用芳香クリップ","on":"クリップ","de":"車内に下がった小さな芳香クリップ。送風口の風に乗ってほのかな香りが狭い空間をゆっくり満たす。信号待ちの退屈ささえ香りで温める、運転席の優しい慰め。"},"ICON-0741":{"nm":"シートベルトカバー","on":"カバー","de":"肩を横切るベルトの上にはめる柔らかいカバー。首筋に触れていたごわつきがするりと消える。安全のための紐にも優しさを添えられるのだと、一握りの布が言う。"},"ICON-0742":{"nm":"駐車番号目隠し板","on":"板","de":"地下駐車場で自分の区画を知らせてくれた番号板を、写真を撮る前にそっと隠す板。残したくない情報は誰にでもある。日常の一場面で慎重に消しておく一枚。"},"ICON-0743":{"nm":"自転車ベルキャップ","on":"キャップ","de":"ちりりん。路地の角で自転車が交わす澄んだ挨拶。ベルの上にかぶせたキャップが、雨にもその音を守り抜く。小さな鈴の音一つに、人々は笑いながら一歩よけて立つ。"},"ICON-0744":{"nm":"ハンドルグリップリング","on":"リング","de":"手のひらに触れるハンドルの感触を柔らかく包むリング。長く握って走っても手がしびれない。遠くまで行く道ほど、握る場所の心地よさがその距離を縮めてくれる。"},"ICON-0745":{"nm":"ヘルメットラベルステッカー","on":"ステッカー","de":"ヘルメットの内側に貼った名前ステッカー。同じ姿の安全帽の中で「これは私のもの」と小さく叫ぶ。頭を守る固さの上に刻んだ、最もプライベートな目印一つ。"},"ICON-0746":{"nm":"ホイール反射キャップ","on":"キャップ","de":"日が沈むとようやく自分の仕事を始めるキャップ。通り過ぎる灯りを受けて車輪をくっきり照り返す。闇の中で「ここに人がいますよ」と光で伝える小さな合図。"},"ICON-0747":{"nm":"車キー保護ポーチ","on":"ポーチ","de":"ポケットの中で他の鍵とぶつかって擦れていた車キー。柔らかいポーチがその表面をすっぽり包む。毎日握る物ほど傷なく長く持ってほしいという心が、そこに込められる。"},"ICON-0748":{"nm":"吸盤棚ピン","on":"ピン","de":"釘一つ打たずに壁にぽんとつく吸盤棚ピン。跡を残したくない壁にも収納が一区画できる。しばし留まる部屋に暮らしを掛ける、痕跡のない手際。"},"ICON-0749":{"nm":"穴あけ不要フック板","on":"板","de":"壁を開けなくても何かを掛けられるなんて。穴あけ不要のフック板が軽い荷物をそっと引き受ける。借りた空間を傷つけまいとする心が、小さなフック一つにきれいに込められる。"},"ICON-0750":{"nm":"マグネット整理バー","on":"マグネット整理バー","de":"金属がカチッと元の場所にくっつく音。あちこちに散らばった細々した道具をマグネットでさっと引き寄せれば、ごちゃごちゃしていた作業台が一列に整う小さな快感がついてくる。"},"ICON-0751":{"nm":"すきま収納ポール","on":"ポール","de":"冷蔵庫と壁のあいだ、見過ごされていた細いすきまを思い浮かべて。細いポールがその隙間を暮らしで満たす。役立たずと思われた空間から収納をすくい上げる、つましい発想。"},"ICON-0752":{"nm":"粘着パッドシート","on":"シート","de":"一度貼れば重いものもしっかり支える粘着パッドシート。剥がすと不思議なほど跡ひとつ残らない。見えないところで重さに耐える、静かでねばり強い力。"},"ICON-0753":{"nm":"ドア掛けフックキャップ","on":"キャップ","de":"ドアの上にちょっと引っ掛けるだけのフックキャップ。バッグもタオルも手の届く高さにぶら下がる。釘ひとつ打たずに生まれた掛け場が、狭い部屋にひと枠の余裕を加える。"},"ICON-0754":{"nm":"ケーブル壁クリップ","on":"クリップ","de":"壁を伝って垂れていたコードを一本にまとめるクリップ。机の裏で絡まった糸玉がすっきりした線に伸びる。見えない片づけが、部屋の空気まで一段と軽くする。"},"ICON-0755":{"nm":"スタンド受けパッド","on":"パッド","de":"スタンド照明の足元にそっと敷くパッド。机に傷を残さず、わずかな揺れまで鎮める。光を立てる仕事にも、ぐらつかない土台がまず先だ。"},"ICON-0756":{"nm":"滑り止め粘着板","on":"板","de":"足元でそろりとずれていたマットが、ようやく定位置に止まる。粘着板が床をぎゅっと噛むから。転びかけた瞬間を先に取り除く、目立たない安全網。"},"ICON-0757":{"nm":"精密ドライバーキャップ","on":"キャップ","de":"「この小さなネジ一本が外れないなあ。」精密ドライバーの先にかぶせたキャップが刃を守る。手のひらほどの機械の中の世界を開く、もっとも繊細な指先の道具。"},"ICON-0758":{"nm":"六角レンチリング","on":"リング","de":"六角レンチを何本もひとつの輪に通してまとめるリング。サイズ順に並んだ金属が扇のようにシャラリと広がる。必要な一本をひと目で選び出す、整った手のリズム。"},"ICON-0759":{"nm":"ミニメジャーリング","on":"リング","de":"手のひらにすっぽり収まるミニメジャーに付いたリング。キーホルダーにぶら下がってどこへでも付いてくる。ふと気になった長さを、その場で測って答えてくれる小さな友だち。"},"ICON-0760":{"nm":"ネジ分類ケース","on":"ケース","de":"ばらばらのネジが仕切りごとに居場所を見つける分類ケース。入り混じって転がっていた小さな部品にも秩序が生まれる。何かを直す前に、まず片づけから覚える手。"},"ICON-0761":{"nm":"接着剤ノズルキャップ","on":"キャップ","de":"閉じておけば固まらず、開けておけば乾いてしまう——私はその境目に生きる。一滴落ちるたび、どこかでは壊れたものがまた繋がっている最中だ。小さな蓋ひとつが、止まりと流れの境を静かに守る。"},"ICON-0762":{"nm":"水平器キーリング","on":"リング","de":"鍵束の先で揺れる手のひらほどの正直さ。傾いた棚を一番に見抜くのは、いつもこの小さな気泡だ。世界が少し歪んでいると静かに教えてくれる友だちを、ポケットに入れて持ち歩く。"},"ICON-0763":{"nm":"ピンセット保護キャップ","on":"保護キャップ","de":"尖ったものほど鎮める衣が要る。先をそっと包んでおけば、手も部品も傷つかない。鋭さを扱う最初の礼儀は、その先をそっと覆っておくこと——小さなキャップがその優しさを引き受ける。"},"ICON-0764":{"nm":"ミニカッターマット","on":"マット","de":"何千回刃が通っても傷が自ら癒えていく板。切られた跡に次の作業がまた重なり、また癒える。我が身を差し出して他のものをきれいに切らせる、黙々とした床の一日だ。"},"ICON-0765":{"nm":"修理部品袋","on":"袋","de":"ネジひとつ、バネひとつが永遠に消えないように口をすぼめた袋。直し終えたあとに残った小さなものが、ここで次の出番を静かに待つ。なくすことを防ぐのは、いつもこんな些細な区画だ。"},"ICON-0766":{"nm":"お菓子袋クリップ","on":"クリップ","de":"開けた袋のサクサクを守るのは、結局ひと度のきっぱりした挟み込みだ。湿気る隙を与えないという小さな約束。端をきっちり噛んでおく手癖が、明日のおやつを救う。"},"ICON-0767":{"nm":"ゼリー小分けカップ","on":"カップ","de":"ひと袋を皆で分けるには、まず公平に分けねばならない。小さなカップごとに同じ分量をすくい入れる心。分かち合いとは、誰も寂しくないように、きっかり同じ量から始まると信じている。"},"ICON-0768":{"nm":"チョコホイル片","on":"チョコホイル片","de":"甘さを包んでいた銀色は、指先でたやすくくしゃっとなる。伸ばせば一瞬きらめき、畳めば思い出になる。食べ終えてからこそ一番きれいになる、ひとひらの光——捨てる前にもう一度見つめてみる。"},"ICON-0769":{"nm":"スナックラベル帯","on":"帯","de":"何が入っているか、いつまで美味しいか——黙った袋の代わりに私が伝える。一本の帯が貼られた瞬間、おやつにも名前と約束が生まれる。分類とは実は、もっとも優しい記憶法だ。"},"ICON-0770":{"nm":"キャンディ分類ケース","on":"ケース","de":"すっぱいものと甘いものを同じ仕切りには置かない。手が迷わないよう、あらかじめ分けておくこと。小さなケースが列をなして並べば、選ぶ楽しみがそっと倍になる。"},"ICON-0771":{"nm":"クッキー緩衝紙","on":"クッキー緩衝紙","de":"クッキーが行く道で傷まないよう、あいだあいだに挟む薄い紙。壊れやすいものほど、もっと柔らかな道連れが要る。固さより、ぬくもりが時にもっとよく守る。"},"ICON-0772":{"nm":"ドーナツ箱ひも","on":"ひも","de":"十字に結ばれた結び目ひとつが、箱の中のケーキの無事を引き受ける。取っ手になり、封になり、ときめく待ち時間の印になる。このひもがほどける瞬間が、すなわち誰かの誕生日だ。"},"ICON-0773":{"nm":"パン袋クリップ","on":"クリップ","de":"ひとひねりして折り、私を挟めば、パンのしっとりが明日の朝まで封じられる。空気を阻む小さく頑固なこだわり。柔らかいものを長く守る仕事は、いつも固い何かの役目だ。"},"ICON-0774":{"nm":"おやつ交換タグ","on":"おやつ交換タグ","de":"君の分を私に、私の分を君に。小さなタグに名前を書いておやつを交換したあの日のときめき、覚えてる?分け合う心に付く紙には、いつも友だちの名前がきちんと書かれている。"},"ICON-0775":{"nm":"ストローキャップ","on":"キャップ","de":"ひと口休むときは私を閉じておく。こぼれないように、冷めないように、その場でじっと待てるように。また口をつけるその瞬間のために、入り口を守る小さな栓の仕事だ。"},"ICON-0776":{"nm":"タンブラーネームリング","on":"リング","de":"何本も並んだタンブラーのあいだで「これは私の」と教えてくれる小さな輪。色ひとつで取り違えがするりとほどける。私のものという印は、この輪ひとつで十分はっきりする。"},"ICON-0777":{"nm":"カップホルダースリーブ","on":"カップホルダースリーブ","de":"熱いカップと手のひらのあいだにそっと割り込む段ボール一枚。やけどしないよう、滑らないよう挟む心配り。あいだを守ることが、すなわち無事な一杯を仕上げる。"},"ICON-0778":{"nm":"製氷皿ラベル","on":"ラベル","de":"氷ごとに作った日付を書いておく人がいる。冷たさにも順番があるという信念で。小さなラベル一枚が、冷凍庫の時間を正直に、順を追って流れさせる。"},"ICON-0779":{"nm":"ティーバッグトング","on":"トング","de":"出てくる時間を見守り、ちょうどいい瞬間にすくい上げる。濃くなりすぎる前に止められる手加減。お茶の深さは、浸す時間より引くタイミングが決める。"},"ICON-0780":{"nm":"ドリップフィルター受け","on":"受け","de":"熱い湯がゆっくり落ちるようにフィルターを支え、黙々と立つ。急げば香りが浅くなると、よく知っている。待ちを支える仕事にも、ぐらつかない姿勢が要る。"},"ICON-0781":{"nm":"ボトルストラップ","on":"ストラップ","de":"水筒を手首に、肩にぶら下げて一緒に歩くひも。わざわざ持たなくても、いつもそばにあるようにする道連れの仕方だ。忘れないためには、そっと結んでおくのが、いちばん優しい方法のときがある。"},"ICON-0782":{"nm":"缶ふたカバー","on":"カバー","de":"飲みかけの缶の口を覆い、ほこりと気の抜けを防ぐ。次のひと口まで新鮮さを引き受ける小さな帽子。しばし開いたものをそっと覆っておく仕事にも、真心が宿る。"},"ICON-0783":{"nm":"ドリンククーポンホルダー","on":"ホルダー","de":"10杯目のただの一杯——その約束を失くさないようスタンプカードを抱く。一マスずつ埋めてきた日々がくしゃくしゃにならないように。このホルダーの中には、常連がせっせと通った足取りが積もる。"},"ICON-0784":{"nm":"弁当バンドひも","on":"ひも","de":"ふたが開かないよう弁当をぐるりとしっかり抱きしめるひも。鞄の中で汁がもれないという小さな安心だ。昼までの無事を引き受けるのは、このきっちりした一周り。"},"ICON-0785":{"nm":"おかずカップセット","on":"おかずカップセット","de":"おかずごとに居場所を与えれば、味が混ざらない。キムチはキムチで、ナムルはナムルではっきりと。小さなカップが作る仕切りが弁当の秩序であり、手料理に添える優しさだ。"},"ICON-0786":{"nm":"箸ケース","on":"ケース","de":"一日三食を共にした箸を清潔に抱いて持ち歩く小さな家。通学鞄の中でもきちんとさを保つ静かな道連れ。持ち歩くその心が、結局きれいな食事を作る。"},"ICON-0787":{"nm":"ソース容器ラベル","on":"ラベル","de":"醤油か酢か、迷っていた容器にはっきりを着せる。一本貼られた瞬間、指先の迷いが消える。慌ただしい台所の速さは、こんな小さな目印が静かに作り出す。"},"ICON-0788":{"nm":"のり巻きシート","on":"シート","de":"ご飯と具をひとつに巻き上げる薄い海苔一枚。しっかり包まないと切るとき崩れてしまう。遠足の朝のときめきは、まさにこの一枚から丸く巻き出される。"},"ICON-0789":{"nm":"ピック立てケース","on":"ケース","de":"串や爪楊枝を一か所に立てておけば、必要な瞬間に手が迷わない。尖ったものにも定められた家を与えること。片づけとは結局、次の手のための小さな親切だ。"},"ICON-0790":{"nm":"保冷パックカバー","on":"カバー","de":"冷たさを少しでも長く引き止めようと、保冷パックをもう一枚包む。結露で鞄が濡れないよう防ぐ役目も一緒に。涼しさを最後まで守るのは、いつもこの分厚い一枚だ。"},"ICON-0791":{"nm":"弁当仕切り","on":"弁当仕切り","de":"ご飯とおかずが互いの場所を侵さないよう立てた小さな垣根。汁が行き来しない一区画の平和。仕切りごとに分かれた弁当には、作る人の細やかな心がそのまま込められている。"},"ICON-0792":{"nm":"食事順番カード","on":"カード","de":"汁からか、ご飯からか、今日のコースをそっと教えてくれるカード。順に食べればもっと美味しいという優しい案内だ。食事にも物語のように流れがあると、静かに教えてくれる。"},"ICON-0793":{"nm":"計量カップシール","on":"シール","de":"目盛りの横に貼られた小さなシールが「ここまで」とちょんと指さす。毎度迷っていた量を一度で合わせてくれる目印。正確さとは、こんな小さな案内線ひとつから生まれる。"},"ICON-0794":{"nm":"シリコンふた取っ手","on":"取っ手","de":"熱いふたを指をやけどせず持ち上げさせる小さな取っ手。湯気の立つ鍋を開ける勇気をそっと貸してくれる。安全はいつも、つかむ場所を先に用意しておくところから来る。"},"ICON-0795":{"nm":"ミニ挟みフック","on":"ミニ挟みフック","de":"ふきんでも袋でも、掛ける場所のなかったものに居場所を与える小さな挟み。雑然とした壁の一画を整った風景に変える。掛けておく習慣ひとつが、台所を一段と軽くする。"},"ICON-0796":{"nm":"オイルブラシキャップ","on":"キャップ","de":"油を塗る刷毛の先を覆っておけば、ほこりも固まりも避けて通る。次の料理までその柔らかさを守る帽子。道具を大事にする小さな心が、結局味を長く守り抜く。"},"ICON-0797":{"nm":"塩スプーン容器","on":"容器","de":"塩入れの中にちょこんと刺さって暮らす小さなスプーン。ひとつまみの正確さを、毎度丁寧にすくい上げる。塩加減という手の感覚は、この小さなスプーンが覚えている分だけの心だ。"},"ICON-0798":{"nm":"タイマーマグネット板","on":"板","de":"冷蔵庫の扉に貼ってラーメン3分を数え、運動30秒を測る。マグネット一枚で流れゆく時間が目の前に留まる。過ぎゆくものをしばし壁に引き止めておく、せっせと働く丸だ。"},"ICON-0799":{"nm":"鍋取っ手カバー","on":"カバー","de":"熱くなった取っ手を素手でつかまないよう包み込む一枚。熱さと手のひらのあいだに立ちはだかる小さな盾だ。無事に運ぶ仕事はいつも、この柔らかな包みから始まる。"},"ICON-0800":{"nm":"まな板受けゴム","on":"まな板受けゴム","de":"私が床に敷かれると、まな板はもう滑らない。包丁がぶれるたび下で踏ん張るゴム一片。安定とは、見えないところでしっかり噛むことだ。"},"ICON-0801":{"nm":"キッチン手袋クリップ","on":"クリップ","de":"火の前で休みなく動いていた手が、しばし留まる場所。ひらひらしていた手袋一枚を壁に引き止めれば、次の食事までの短いひと息が始まる。片づけとは結局、優しさの別の名前。"},"ICON-0802":{"nm":"マドラーホルダー","on":"ホルダー","de":"カウンターの脇、細い棒たちが肩を寄せ合い、きちんと寄りかかって立つ場所。誰かの朝の一杯に円を描く支度をしたまま、列をなす姿はまるで口をそろえる直前の合唱団のようだ。"},"ICON-0803":{"nm":"コースターセット帯","on":"帯","de":"グラスが食卓に触れる、その小さなコトッという音をそっと受け止める帯。丸い受けをひとまとめに束ねておけば、客を迎える支度が整う。もてなしはいつもこんな些細な場所から先に始まる。"},"ICON-0804":{"nm":"シロップラベルチップ","on":"チップ","de":"瓶に貼られた一行の名前。甘い、濃い——その短い単語ひとつが、慌ただしい朝を一段ときちんと整える。ラベルは、小さな約束をあらかじめ書いておく紙だ。"},"ICON-0805":{"nm":"デザートピックケース","on":"ケース","de":"果物ひと切れをちょんとつまみ上げる尖った棒たちが集まって暮らすケース。デザート皿の上に旗のように刺さる前、ここで静かに自分の番を待つ。甘さにも順番があるものだ。"},"ICON-0806":{"nm":"マドラースリーブ","on":"マドラースリーブ","de":"かき混ぜる棒をひと握り、ぴったり包み込んだ紙の衣。冷たい飲み物がこぼした水気を代わりに含み、グラスを握る指先をさらりと守ってくれる。見えない心配りは、いつも端からやってくる。"},"ICON-0807":{"nm":"テイクアウトキャリアタグ","on":"テイクアウトキャリアタグ","de":"両手が足りない瞬間、カップを代わりに持ってくれる小さな取っ手。包まれたぬくもりを一滴もこぼさず引き止め、誰かの路地の入り口までその温かさを見送る。"},"ICON-0808":{"nm":"カフェ呼び出しベルカバー","on":"カバー","de":"振動が鳴るまでの待ち時間を、そっと包む衣。カフェの片隅で光る順番札を守りながら、もうすぐ私の番号が呼ばれるというそのときめきまで一緒に抱いておく。"},"ICON-0809":{"nm":"スタンプクーポンリング","on":"リング","de":"十マスを全部埋めれば一杯がおまけになる紙。スタンプがひとつ増えるたび、常連という名前も少しずつ育つ。小さな輪に通された、この上なく素朴な楽しみ。"},"ICON-0810":{"nm":"コーヒー豆サンプル袋","on":"袋","de":"豆をひと握り詰めて、香りから先に手渡す袋。鼻先をかすめる酸味と甘い香り、その第一印象が一杯の運命を決める。香りはどんな説明より速く届く。"},"ICON-0811":{"nm":"冷蔵ラベルマグネット","on":"マグネット","de":"冷蔵庫の扉にぴたっと貼り付く小さなマグネット名札。何がいつ入ったか書いておけば、忘れられかけたおかずも自分の番を取り戻す。暮らしとは、流れる記憶をつなぎ留めること。"},"ICON-0812":{"nm":"保存日付チップ","on":"チップ","de":"詰めた日をはっきり刻んでおくひと片。何日経ってもこれはまだ大丈夫と静かに教えてくれる小さな証人。新鮮さは、日付を覚えておく指先で守られる。"},"ICON-0813":{"nm":"小分け容器バンド","on":"バンド","de":"分け入れた容器の腰をぐるりと抱くバンド。浮き上がるふたをしっかり抱き寄せ、冷蔵庫の中の小さな秩序を守り抜く。何かを縛る仕事は、心を整える仕事と似ている。"},"ICON-0814":{"nm":"密封クリップ色帯","on":"帯","de":"袋の口をきっちりがぶっと噛む色とりどりの挟み。赤は辛いもの、黄色は甘いもの——色を見るだけで手が先に分かる。台所の信号は、こうして黙って道を案内する。"},"ICON-0815":{"nm":"冷凍パック名札","on":"札","de":"凍らせたものの上にそっと載せておく名札。霜のついた袋の中でも、自分が何だったか忘れないように労わってくれる。冬眠に入った材料へ送る、小さな安否の挨拶。"},"ICON-0816":{"nm":"野菜保存ネット","on":"野菜保存ネット","de":"土のついた野菜を寛容に受け止める粗い網。息をつく隙を与えてこそ長持ちすると、おばあちゃんの台所はとうに知っていた。風通しは、野菜に施す優しい余白。"},"ICON-0817":{"nm":"瓶ふた分類キャップ","on":"キャップ","de":"サイズごとのふたをひとつひとつ組み合わせる分類キャップ。失くした相方をまた見つけてあげる仕事は、思いのほか優しい。似合う一対を合わせておけば、台所も一段ときちんと整う。"},"ICON-0818":{"nm":"卵トレーラベル","on":"ラベル","de":"十個の小さな巣ごとにきちんと刻まれた目印。何日か経った卵から先に使えと教えてくれる暮らしの知恵。朝の目玉焼き一枚にも、順番を気にかける心が宿っている。"},"ICON-0819":{"nm":"残り物シール","on":"シール","de":"「これは私の!」一行書いて貼れば、冷蔵庫にもしばし平和が宿る。夜食の主をあらかじめ決めておく可愛い宣戦布告。家族とは、こんな些細な協定で今日も回っていく。"},"ICON-0820":{"nm":"箸置き片","on":"箸置き片","de":"スプーンと箸が食卓に直接触れないよう、そっと支えてあげるひと片。この小さなきちんとさが、ひと食の格をそっと上げる。食卓の作法は、こんな場所で静かに育つ。"},"ICON-0821":{"nm":"ナプキン固定リング","on":"リング","de":"風に舞い散るナプキンをそっと挟んで引き止める輪。広げられる番を待つ白い紙をきちんとかき集め、食卓の上に小さな秩序をきちんと刻んでおく。"},"ICON-0822":{"nm":"テーブルマットコーナー","on":"テーブルマットコーナー","de":"マットの浮いた角をそっと押さえて労わるひと片。一端がつかまれてこそ全体がまっすぐになると、食卓は毎日教える。角にも自分の分の責任がある。"},"ICON-0823":{"nm":"小さな薬味トレー","on":"トレー","de":"醤油ひと小皿、塩ひとつまみを並べて支えておく小さな盆。添え物ひとつにも居場所を与える食卓の広い懐。韓国料理は、添え物を気にかける心で深まる。"},"ICON-0824":{"nm":"テーブル番号チップ","on":"チップ","de":"慌ただしい食堂で「何番のお客様!」と呼ばれるあの数字。待ちに順番を付けて、皆に公平を守ってくれる。チップひとつに込められたのは、小さな約束と、もうすぐ出てくる温かな一膳。"},"ICON-0825":{"nm":"水コップ目印帯","on":"帯","de":"水のグラスに巻いて、誰のものかそっと教えてくれる帯。似たコップのあいだで自分の場所を示しておく小さな旗。一緒に囲む食卓では、こんな心配りが余計な誤解を防いでくれる。"},"ICON-0826":{"nm":"取り皿分類ピン","on":"ピン","de":"取り分けて食べる小皿を色で分けてくれるピン。私のものと君のものの境界を優しく引いて、分け合う楽しみを一段とすっきりさせる。情は分かち合っても、衛生はきっちり守る。"},"ICON-0827":{"nm":"メニュー隠し板","on":"板","de":"広げ持ったメニュー表の裏にそっと隠れる、悩みの時間。何を食べるか選ぶその短い迷いさえ、実は食事の一部だ。今日は何にしようか——そのときめきを静かに隠してくれる。"},"ICON-0828":{"nm":"席札ホルダー","on":"ホルダー","de":"名札をまっすぐ立てておく小さな受け。会場の席でも祝宴の膳でも、ここにあなたの席があるとはっきり知らせる。もてなしは、名前を呼ぶその瞬間にようやく完成する。"},"ICON-0829":{"nm":"マフィンカップスリーブ","on":"マフィンカップスリーブ","de":"焼きたてマフィンのふっくらした腰をすっぽり包んだ紙の衣。温かな体を手から落とさないよう支え、ひと口かじるその瞬間までぬくもりをそっと守る。デザートにも衣が要る。"},"ICON-0830":{"nm":"絞り袋キャップ","on":"キャップ","de":"クリームを絞り出す袋の先をしっかり閉じさせる栓。休むあいだ一滴も漏れないよう、口をきっちり塞いでおく。ケーキの上の小さな花一輪は、この節度から咲き出る。"},"ICON-0831":{"nm":"クッキー型リング","on":"リング","de":"星の形、熊の形に生地をくり抜く丸い型。同じ小麦粉が指先を経て何十もの表情で目覚める。何を焼くにせよ、生地にまず触れるのはいつだって真心だ。"},"ICON-0832":{"nm":"生地スクレーパーチャーム","on":"生地スクレーパーチャーム","de":"生地をきれいに掻き集め、すっきり切り分ける平たい手。ボウルにこびりついたひと握りまで気にかけるそのまめさが、パン一塊の膨らみを決める。ベイキングは、惜しむ手の仕事だ。"},"ICON-0833":{"nm":"計量スプーンボード","on":"計量スプーンボード","de":"小さじ一、大さじ半分——ぶれることなく計量スプーンをきちんと寝かせておく板。正確なひと匙が味の均衡をまっすぐ立てる。手の感覚という言葉の裏には、実は丁寧な計量が隠れている。"},"ICON-0834":{"nm":"オーブン手袋フック","on":"フック","de":"熱いオーブンの前を守っていた手袋を掛けておくフック。やけどを防いでくれた分厚い手は、休むあいだも手の届くところに静かに留まる。安全とはいつも、定位置にあるものから始まる。"},"ICON-0835":{"nm":"冷まし網クリップ","on":"クリップ","de":"焼きたてのお菓子が冷める網をきちんと挟んでおく挟み。湯気が抜けるあいだ崩れないよう引き止め、サクサクが仕上がるのを一緒に待ってくれる。冷ますことにも、ひと握りの忍耐が要る。"},"ICON-0836":{"nm":"ケーキトッパー差し","on":"ケーキトッパー差し","de":"「お誕生日おめでとう」の文字をケーキの上にそっと差して立てる差し。ろうそくが消える直前、この小さな旗が一人の一日をいちばん明るく照らす。祝いは高く立ててこそよく見える。"},"ICON-0837":{"nm":"粉砂糖ふり容器","on":"容器","de":"最後のひと度の軽い振りまきを詰めた容器。焼きたてのデザートの上に白い雪のようにこんもり降り積もり、平凡なひと切れを小さな贈り物に変える。仕上げとは、いちばん軽い手つきから来る。"},"ICON-0838":{"nm":"おにぎりラベル","on":"ラベル","de":"ビニールを1、2、3の順に剥がせば海苔がさらりと甦るあの三角形。コンビニの夜明けの頼もしい友だちをひと目で見分けさせる一行。塾帰りにお腹のすいた夜が、ここに貼られている。"},"ICON-0839":{"nm":"カップ麺ふたホルダー","on":"ホルダー","de":"3分の待ちのあいだ、ふたが持ち上がらないようそっと押さえる受け。湯気が抜けないようにと上に載せていた箸の場所を代わりに務める。麺が出来るその短い時間が、夜食のいちばんときめく瞬間。"},"ICON-0840":{"nm":"ホットバー串キャップ","on":"キャップ","de":"串の先をきっちり包んで握る小さなキャップ。ひと口かじりやすく、手にタレ一滴つかないよう守ってくれる。粉物屋の前の買い食いの楽しみは、いつもこんな些細さで完成する。"},"ICON-0841":{"nm":"ビニール袋取っ手","on":"取っ手","de":"指に掛けるとビニールがカサッと小さく鳴く。買い物の重さが片方に偏り、家まで歩く道が手のひらに赤い跡となって残る。軽い音の中に、今日一日分の暮らしがずっしり込められて揺れる。"},"ICON-0842":{"nm":"レシート折りクリップ","on":"クリップ","de":"長く繰り出されたレシートを半分に折ってちょんと挟めば、今日使ったお金がおとなしいひと束になる。インクの匂いの染みた紙が次々と積もるあいだ、些細な暮らしの記憶もきちんと整えられていく。"},"ICON-0843":{"nm":"電子レンジタグ","on":"タグ","de":"チン――と鳴る前、タグは温まる時間を静かに数える。何分何秒、温めるものの名前を書いておいた小さな案内板。温かくなる番を待つ心にも、こうして目盛りがある。"},"ICON-0844":{"nm":"割引シールロール","on":"割引シールロール","de":"一マスずつ剥がすたび、ぺりっと粘っこい音が指先をくすぐる。赤い数字が列をなして繰り出されれば、誰かの買い物かごが少し軽くなる。丸く巻いて待つ小さな親切ひとロール。"},"ICON-0845":{"nm":"ソースパウチリング","on":"リング","de":"すっぱいのがちょん、口元に広がって、平凡だった一日も少し甘くなる。丸いリングにぶら下がったパウチが歩くたび揺れれば、小さな甘さひとつがポケットの中で一日中私を追ってくる。"},"ICON-0846":{"nm":"コンビニかごチップ","on":"チップ","de":"手に握ればプラスチックが軽くしなる。明かりの煌々とした夜更けの店、おにぎり二、三個と飲み物ひとつが入るほどの深さ。一人でも寂しくない、ちょうどひと食分の優しい器。"},"ICON-0847":{"nm":"マカロン箱帯","on":"帯","de":"色とりどりのマカロンが崩れないよう、帯ひとつが箱をそっと抱きしめる。リボンをほどく直前のそのときめきが実はいちばん甘いのだと、贈り物をもらった人は指先で知っている。"},"ICON-0848":{"nm":"果物ネットクリップ","on":"クリップ","de":"網の口を集めてちょいとつまめば、りんごの香りが網のあいだからそっと漏れ出る。転がり落ちないよう引き止める小さな手ひとつ。傷む前に早く食べてという、声なき優しい言伝。"},"ICON-0849":{"nm":"ジャム瓶ふた布","on":"ジャム瓶ふた布","de":"丸い布をふたにかぶせて輪ゴムで結んでいた、母方の祖母の夏の台所が浮かぶ。格子柄の布一枚に、ジャムが熟す甘い時間と真心が一緒に封じられる。手料理はこうして覆って保存される。"},"ICON-0850":{"nm":"クッキータイリボン","on":"リボン","de":"焼きたてクッキーをセロファンに入れてタイをひねって結べば、バターの香りがリボンの先まで染み込む。手作りのものを誰かに手渡す手は、いつも少し震える。心まで一緒に結ばれる結び目。"},"ICON-0851":{"nm":"チョコ仕切り板","on":"板","de":"ひとマスひとマス、チョコが互いに触れないよう場所を決めてくれる。溶けないように、砕けないように。小さな仕切りが最後まで守り抜くのは、結局誰かに手渡す丸ごとひと粒の心だ。"},"ICON-0852":{"nm":"お茶ギフトラベル","on":"ラベル","de":"茶袋に巻いたラベルの上、手書きできちんと書かれた名前。淹れれば草の香りが湯気とともに立ち上ると、小さな紙があらかじめ耳打ちする。飲む前から手が先に温かくなる一杯。"},"ICON-0853":{"nm":"キャンディボトルネックレス","on":"キャンディボトルネックレス","de":"色とりどりのキャンディが入った瓶の首にひもを巻いて作ったネックレス。歩くたびコロコロと、中で小さなビー玉のような音が転がる。甘さを首に掛けて歩いた幼い日の誇らしい宝物。"},"ICON-0854":{"nm":"ギフトスプーンチャーム","on":"ギフトスプーンチャーム","de":"持ち手の先にぶら下がった小さなチャームひとつで、平凡だったスプーンがいつのまにか贈り物になる。すくうたびにシャラン、軽くぶつかる澄んだ音。手渡す心に小さな粋を添えるささやかな飾り。"},"ICON-0855":{"nm":"おやつお礼タグ","on":"おやつお礼タグ","de":"もらった分だけでも少し返したい心。おやつ袋にそっと付けたお礼タグ一枚。言い尽くせなかった「ありがとう」の代わりに、小さな挨拶が手から手へと静かに渡っていく。"},"ICON-0856":{"nm":"マスキングテープ見本リング","on":"リング","de":"ひと幅ずつ切って貼った模様が小さな帯になって列をなしている。どの色がいいか指先でゆっくり選ぶあいだ、飾る想像だけで一日が色とりどりに染まる。悩むことさえ楽しい見本ひと列。"},"ICON-0857":{"nm":"シールピンセットキャップ","on":"キャップ","de":"尖ったピンセットの先にキャップをかぶせれば、爪ほどのシールも傷つかない。指では届かない角をそっとつまみ上げる精密な手。好きなものを扱うには、いつも慎重さが伴う。"},"ICON-0858":{"nm":"ダイアリーコーナーシール","on":"ダイアリーコーナーシール","de":"ダイアリーの四隅にシールを貼れば、ひらひらしていたページが嘘のようにおとなしくなる。紙がそっと押される感触、今日一日をきれいに封じる小さな儀式。記録は角から固くなる。"},"ICON-0859":{"nm":"穴あけガイド板","on":"板","de":"穴を開ける場所をあらかじめ教えてくれる板。点線に沿ってそっと合わせれば狂いがない。急がずにもう一度見定める心、正確さはいつもその一拍の小さな余裕から静かにやってくる。"},"ICON-0860":{"nm":"紙くずトレー","on":"トレー","de":"はさみを入れて残った紙くずがトレーの中へさらさらと集まってくる。机が散らからないよう、小さなかけらのしばしの宿。ものづくりの後始末は、こうして音もなく整えられる。"},"ICON-0861":{"nm":"カラーインクパッド","on":"パッド","de":"パッドを軽く押して離せば、指先に色がしっとりにじむ。赤、黄、青、スタンプひとつににじみ出る小さな虹。白い紙の上にちょんちょんと、色を植え込むやわらかな一画。"},"ICON-0862":{"nm":"デコテープロール","on":"デコテープロール","de":"クルクルと繰り出される模様が果てしなく続く。一マス剥がして貼れば、地味だった場所に花が咲く。手の進むまま次第にきれいになっていく、丸く巻いて待つ小さな魔法ひとロール。"},"ICON-0863":{"nm":"テーマスタンプキャップ","on":"キャップ","de":"インクが乾かないようスタンプの頭をすっぽり包む小さな帽子。次に押す模様がはっきり残るよう、そっと守ってくれる。よく保管しておいた色は、次の紙の上でも変わらず鮮やかに咲き出る。"},"ICON-0864":{"nm":"デコパンチ片","on":"デコパンチ片","de":"パンチがぽとっと、落とした小さなかけらたち。星とハートと花びらにくり抜かれた色紙のくずが、手のひらにこんもり集まる。捨てるには可愛すぎて、またどこかに貼ってしまう小さな宝石。"},"ICON-0865":{"nm":"糸巻きラベルリング","on":"リング","de":"糸巻きごとに色糸の名前を書いて貼った小さなラベル一枚。絡まる前に居場所を教えてくれる優しい目印だ。もつれた糸も、心も、名札ひとつあればほどくのが一段とたやすくなる。"},"ICON-0866":{"nm":"ニードルブックカバー","on":"カバー","de":"針がびっしり刺さったフェルトの頁を覆う柔らかなカバー。開けば裁縫道具がきちんと横たわって私を迎える。指先が傷つかないよう、尖ったものを優しく寝かせておく小さな一冊。"},"ICON-0867":{"nm":"生地見本リング","on":"リング","de":"ざらりとか、すべすべとか、指先で布の風合いをひとつひとつ探って選ぶ遅い時間。色ごとにきちんと集まった布片の中で、一着の服になる前の布は、まず触れられるのを静かに待つ。"},"ICON-0868":{"nm":"刺繍フープ輪","on":"輪","de":"丸いフープに布を挟んで締めれば、張った太鼓の面のようにぴんとなる。ひと針ひと針刺繍する支度が整ったという小さな合図。輪がしっかりつかむのは布ではなく、集中する心だ。"},"ICON-0869":{"nm":"ボタン分類カプセル","on":"ボタン分類カプセル","de":"コロコロ転がっていたボタンが、カプセルの仕切りごとに色別におとなしく収まる。失くす心配がないよう小さく分けて入れる暮らしの知恵。散らばったものを集めるのにも、こうして真心がかかる。"},"ICON-0870":{"nm":"裁縫チャコホルダー","on":"ホルダー","de":"生地の上に線を引くチャコを握りやすく支えるホルダー。折れやすいものをしっかり受け止める。最初の一線がまっすぐでこそ服もまっすぐになるという、はさみを取る前の落ち着いた初心。"},"ICON-0871":{"nm":"まち針ボトル","on":"ボトル","de":"透明な瓶の中でまち針がぶつかってカチャカチャ鳴る。日に当てれば針の先ごとに小さな光が結ぶ。散らばると危ないものを一か所に集めてきれいに寝かせておく、きっちりした器ひとつ。"},"ICON-0872":{"nm":"補修テープロール","on":"補修テープロール","de":"破れた場所に当ててアイロンをかければそっと貼り付く魔法の帯。針ひと針もなく、ほつれた服が静かに癒える。捨てずに繕って着ていた心が、丸いロールの中にきちんと巻かれている。"},"ICON-0873":{"nm":"パッチ図案紙","on":"パッチ図案紙","de":"パッチの形をあらかじめ描いておいた図案紙一枚。はさみが通る道を点線が優しく案内する。作りたいものの輪郭をまず描いてみること、ときめきはいつもこの薄い下絵から始まる。"},"ICON-0874":{"nm":"水彩バケツキャップ","on":"キャップ","de":"バケツの口にかぶせれば、色水がどんなに揺れても一滴も漏れない。筆をすすいだ濁った水が机ににじむ心配まで覆ってくれる。絵を描く場所を黙々と守ってくれる静かな栓ひとつ。"},"ICON-0875":{"nm":"パステル保護帯","on":"帯","de":"粉が白くにじむパステルに帯を巻いてあげれば、指があまり汚れない。か弱い色が砕けないようそっと包む紙。柔らかいほど優しくつかんでこそ、紙の上でも美しく塗れる。"},"ICON-0876":{"nm":"色鉛筆延長キャップ","on":"キャップ","de":"ちびた色鉛筆の先にキャップを差せば、一本がまた長くなる。短くなったからとたやすく捨てない心。最後まで使い切る指先で、絵の色は最後のひとマスまでより濃く仕上がる。"},"ICON-0877":{"nm":"筆洗いカップフック","on":"フック","de":"洗いカップをフックに掛けておけば、筆から落ちた水滴がぽたぽた流れ落ちる。次の色を塗る前、筆をすすぐ短く澄んだ静けさ。きれいになるその音にも、静かなリズムが流れる。"},"ICON-0878":{"nm":"パレットナイフキャップ","on":"キャップ","de":"絵の具を広げて掻き取るナイフの刃にすっぽりかぶせる小さなキャップ。鋭い先が鈍らないようそっと守ってくれる。厚く塗られた色の質感は、この一本のよく手入れされた先から生まれる。"},"ICON-0879":{"nm":"キャンバスクリップ","on":"クリップ","de":"キャンバス布を枠に力いっぱい引っ張って固定するきっちりした挟み。ぎゅっと噛めば絵を描く面がぴんと伸びる。ぶれない下地があってこそ、その上を走る筆も思う存分自由になる。"},"ICON-0880":{"nm":"ドローイングボードひも","on":"ひも","de":"ひもを肩にそっと掛ければボードが背中の後ろに付いてくる。どこでも腰を下ろせばそこがもう私だけのアトリエ。描きたい風景を探して身軽に旅立つ、背に負う小さな画室ひとつ。"},"ICON-0881":{"nm":"アクリル絵の具キー","on":"アクリル絵の具キー","de":"水を一滴足せば夜明けが、減らせば真夜中になる。同じ青なのに指先で毎度違う空が開く。キーひとつを絞る瞬間、今日の心の色合いが紙の上ににじんでいく。"},"ICON-0882":{"nm":"グラデーション見本紙","on":"グラデーション見本紙","de":"夕焼けが一度に赤くならないことを、この紙がまず知っていた。淡いところから濃いところへ渡る小さな階段。目はそのあいだをゆっくり歩きながら、色が熟していく時間を静かに辿る。"},"ICON-0883":{"nm":"かぎ針キャップ","on":"キャップ","de":"糸が指に食い込む前に差す、指ぬきのように小さな保護膜。長く編み物をしてきた手ほど分かる。傷つかずにこそ、最後の目まで優しく連れていけるということを。"},"ICON-0884":{"nm":"編みリングマーカー","on":"編みリングマーカー","de":"どこまで来たか、目印ひとつあればまたはっきりする。同じ目を二度数えなくていい安堵感。心もそうやって、辿ってきた場所をそっと押さえてあげるとき、ようやく道に迷わない。"},"ICON-0885":{"nm":"段数チェックチャーム","on":"段数チェックチャーム","de":"一段を編み終えたという静かな証がマスごとに積もる。果てしなく見えた仕事も、ひとつずつ数えておけばいつのまにか半分を過ぎている。小さな勘定が、今日の心を最後まで耐えさせる。"},"ICON-0886":{"nm":"糸端整えピン","on":"ピン","de":"ほどけた糸の端をそのままにしておけば、次の結び目がどこで絡むか分からない。見えない場所をあらかじめ整える手つき。優しさとはたいてい、こうして目立たない場所から先に動く。"},"ICON-0887":{"nm":"結び練習ひも","on":"ひも","de":"本結び、蝶結び、指輪結び。手が形を覚えるまで同じひもを結んではまたほどいてみる。不慣れだった指先がある夜ふと滑らかになるとき、その一本がいちばん先に気づく。"},"ICON-0888":{"nm":"毛糸ラベルバンド","on":"バンド","de":"どの太さ、どの色か、糸玉ごとに書いておいた小さな帯。使い切ってから同じ糸が手に入らず探し回った夜があったからできた習慣だ。記録は、未来の私へ向けた優しいメモだ。"},"ICON-0889":{"nm":"ゲージ定規片","on":"ゲージ定規片","de":"10センチに目が何個入るか——その小さな数字が服一着の大きさを決める。手のひらほどの片が全体の寸法を握っているというのは、考えてみればなかなか重い仕事だ。"},"ICON-0890":{"nm":"ボタン穴目印","on":"ボタン穴目印","de":"ボタンを付ける前、どこを開けるか点ひとつ先に打っておく。じき消えるその目印のおかげで、服の前合わせが歪まない。真心はたいてい、結局見えない場所にそっと残る。"},"ICON-0891":{"nm":"小さな房飾りリング","on":"リング","de":"ノリゲの先の房のように、小さなリングひとつが揺れを生む。ぶら下がって静かに揺らめくものには、いつも人の視線が留まる。風が過ぎるたび静かに生き動く揺れ。"},"ICON-0892":{"nm":"ミニ塗料ボトル","on":"ボトル","de":"惜しむのではなく、正確に使うことが塗料を正しく扱う術だ。一滴で十分な色を、小さなボトルのそばに置いて見計らう手。節度は、欲を一度手放すところから来る。"},"ICON-0893":{"nm":"小型サンドスティック","on":"小型サンドスティック","de":"粗い面から始めて、次第に細かい面へ移っていく。一度で滑らかになる表面など、どこにもない。目を一段ずつ下げていく指先で、ざらついた場所がゆっくり柔らかくなる。"},"ICON-0894":{"nm":"模型クリップ受け","on":"受け","de":"糊をつけた部品を手で握っていると指紋が残る。クリップにそっと挟んでおけば手は自由になり、乾きは独りで静かに終わる。待ちも、誰かが支えてくれるとき軽くなる。"},"ICON-0895":{"nm":"接着剤受け板","on":"板","de":"接着剤一滴が机に落ちれば跡が長く残る。受け板を一枚先に敷いておく習慣。作業の半分はもしかすると、場所を汚さないようにというその心から始まる。"},"ICON-0896":{"nm":"部品分類仕切り","on":"部品分類仕切り","de":"同じ形の部品が数十個入り混じれば、組み立てはたちまち迷宮になる。仕切りごとに分けて入れる手つきが、やがて迷う時間をあらかじめ減らしておく。整頓は、未来の私へ手渡す親切だ。"},"ICON-0897":{"nm":"組み立て順番チップ","on":"チップ","de":"何番の部品から差すか書いておいた小さなチップひとつ。順番を守れば簡単には崩れない。模型も、こつこつ積み上げるどんな一日も、その静かな約束の上で固くなる。"},"ICON-0898":{"nm":"ミニ筆掛け","on":"ミニ筆掛け","de":"使い終わった筆を寝かせれば毛が押されて曲がってしまう。逆さに吊るして水気を切る場所。道具を長くそばに置く人は、仕事が終わってからがむしろ忙しく、優しい。"},"ICON-0899":{"nm":"プラ片ケース","on":"ケース","de":"型から外した端切れが静かに集まるケース。捨てられたようでも、いつか小さなディテールになって帰ってくる。残ったものにも自分の番があると、ケースは黙って待ちながら知っている。"},"ICON-0900":{"nm":"仕上げ剤スプレーキャップ","on":"キャップ","de":"最後の一層は、近すぎるところから吹くとそのまま垂れてしまう。ひと幅の距離から軽く、軽く。艶を着せる仕事は、もしかすると心の欲を一度手放す練習でもある。"},"ICON-0901":{"nm":"シャー芯ケース","on":"ケース","de":"細いシャー芯はポケットの中ですぐに折れてしまう。小さなケースにきちんと寝かせておけば、一本だって無駄にならない。整理とは結局、明日の自分をあらかじめ大切にしておく静かな心づかいだ。"},"ICON-0902":{"nm":"消しゴムスリーブ","on":"消しゴムスリーブ","de":"消しゴムにまとわせた小さな紙の衣。手垢がしみて黒ずむほど、それだけ直して使った跡が積もっていく。消すということは、最初に戻ってもいいという優しい許しでもある。"},"ICON-0903":{"nm":"ペン先保管ケース","on":"ケース","de":"ペン先は乾けば割れ、ぶつかれば曲がる。別に寝かせて保管する小さなケース一つが、字の流れを長く守ってくれる。丁寧に扱った道具は、最後まで丁寧に滑って応えてくれる。"},"ICON-0904":{"nm":"万年筆インクサンプル","on":"万年筆インクサンプル","de":"一滴ずつ試しに置いてみるインクたち。青緑だと思っていた色が、紙の上では深い海になる。色とはいつも直に出会ってみないと分からない――心で描いた色は、しばしば外れるものだから。"},"ICON-0905":{"nm":"ブックダーツケース","on":"ケース","de":"読みかけの場所にそっと挟んでおく小さな旗。次に本を開けば、昨日の自分が手招きして待っている。止めておいた場所さえ約束になる、その小さな印の優しい仕事。"},"ICON-0906":{"nm":"メモふせん旗パック","on":"メモふせん旗パック","de":"一枚はがして貼れば、すぐにそこから物語がまた始まる。小さな旗たちが本の横に並んで立てば、散らばっていた考えが一冊の地図へと少しずつ集まっていく。"},"ICON-0907":{"nm":"クリップ整理マグネット","on":"マグネット","de":"散らばったクリップを一度に集める小さな磁石。小さいものほど失くしやすいから、引き寄せる力一つが散らかった机を静かに救う。引き寄せることにも優しさがある。"},"ICON-0908":{"nm":"鉛筆キャップセット","on":"鉛筆キャップセット","de":"鉛筆の先を包み、かばんの中を守る小さな帽子たち。尖ったものはいつも何かを刺してしまうから、そっと覆ってあげる手が必要だ。鈍らないように、けれど傷つけないように。"},"ICON-0909":{"nm":"机ネームプレートシール","on":"シール","de":"名前を書いて机の前に貼った瞬間、その場所はようやく誰かのものになる。手のひらほどの空間にも主が生まれると、心を据える姿勢からずいぶん変わってくる。"},"ICON-0910":{"nm":"なわとびハンドルキャップ","on":"キャップ","de":"ハンドルの端がすり減って割れる前にかぶせておくキャップ。千回以上回した縄のリズムを、頭より手のひらが先に覚えている。体に刻まれた拍子は、なかなか忘れられない。"},"ICON-0911":{"nm":"ヨガリングストラップ","on":"ストラップ","de":"リングをつかんでゆっくり体を開く。紐がぴんと張るほど、こわばった肩が一枚ずつほどけていく。伸ばすとは無理に引っぱることではなく、体が開くまで静かに待つことに近い。"},"ICON-0912":{"nm":"卓球ボールケース","on":"ケース","de":"軽いから遠くへ転がり、踏めばそのまま潰れる白い球。小さなケース一つが、最も弱いその球を次の試合まで守り抜く。固さはしばしば、柔らかく包むことから生まれる。"},"ICON-0913":{"nm":"バドミントングリップテープ","on":"バドミントングリップテープ","de":"汗で滑るハンドルを一枚きれいに巻いてあげる。うまく巻かれたグリップの上では、ラケットが手の一部になる。力ではなく感覚で打つという秘訣が、この薄い一枚に隠れている。"},"ICON-0914":{"nm":"小さなスコアチップ","on":"チップ","de":"一点、また一点。小さなチップを動かしながら点数を少しずつ積み上げていく。数えが目に見えると試合はより鮮明になり、一点差を追いつく勇気もそっと湧き上がる。"},"ICON-0915":{"nm":"靴の向きクリップ","on":"クリップ","de":"きちんと並んだ靴先がいつも同じ方向を向いている。脱ぐとき一度そっと回しておく手つき。ささいな整えひとつが、明日の朝の足取りをずっと軽くしてくれる。"},"ICON-0916":{"nm":"ホイッスル首かけ紐","on":"紐","de":"笛を首にかければ、止まれと言う権限が生まれる。短い一吹きで運動場が一斉に止まる風景。その小さな音を信じてくれる心が集まって約束になる。"},"ICON-0917":{"nm":"ボールポンプ針ケース","on":"ケース","de":"空気の抜けたボールも細い針一本でまたぴんと張る。小さなケースに丁寧にしまったその針は、失くした瞬間ポンプ全体が役立たずになってしまう。最も小さなものが最も大切なとき。"},"ICON-0918":{"nm":"ミニコーン目印","on":"ミニコーン目印","de":"ここからあそこまで、小さなコーンが見えなかった境界を描いてくれる。線がなくても人々はその目印に沿って自然と並ぶ。秩序はこんな小さな合図から静かに育つ。"},"ICON-0919":{"nm":"トークンポーチ","on":"ポーチ","de":"ちゃりちゃり鳴るトークンを一つにまとめるポーチ。口を絞れば散らばることがない。小さくささいなものも、収まる場所があってこそ役目を果たすのだと、ポーチは黙って見せてくれる。"},"ICON-0920":{"nm":"カードシャッフルマット","on":"マット","de":"滑る机の上ではカードが手にうまくなじまない。敷物一枚あれば、混ぜるのも取るのもずっと滑らかになる。よく遊ぶことにも、まず土台を整える優しい準備がある。"},"ICON-0921":{"nm":"ボード角プロテクター","on":"ボード角プロテクター","de":"ボードゲームの夜が終わると、誰かは黙ってボードの四隅から片づける。折り目が深くなれば次の盤が歪むと知っているから。角を伸ばしておく指先に、明日も一緒に遊ぼうという心がこもっている。"},"ICON-0922":{"nm":"サイコロカップ蓋","on":"蓋","de":"振って、転がして、みんなで息を止めるその短い瞬間。サイコロが飛び出さないように覆う小さな天井だ。蓋の中で今日の運がしばし息を整えたあと、からんと転がり出てくる。"},"ICON-0923":{"nm":"タイル整列ボード","on":"ボード","de":"手応えに浮かれる人ほど列が歪む。タイルが斜めになったとき、そっと押してきれいに揃えてあげること。整列とは、誰かの浮き立つ焦りを優しく受け止める手だ。"},"ICON-0924":{"nm":"得点チップケース","on":"ケース","de":"チップが一つのケースに満ちるほど、盤も一緒に熱くなる。丸い点数が手のひらの中でからんとぶつかるとき、勝ち負けよりその音が先に楽しくなる。"},"ICON-0925":{"nm":"ターンマーカーリング","on":"リング","de":"もう君の番だと知らせる小さな指輪。一マス動かしてはめるその瞬間だけは、みんなの目が静かに私に集まる。待ちときめきの間をゆっくり回る輪だ。"},"ICON-0926":{"nm":"コマ台座","on":"台座","de":"倒れやすいコマほど足元がしっかりしていなければならない。台座一つが、少し揺れる盤の上でも定位置を支えてくれる。小さいものが踏ん張ってこそ、その上の大きいものがすっと立つ。"},"ICON-0927":{"nm":"説明書クリップ","on":"クリップ","de":"説明書はいつも開いたまま、いつの間にかめくれていく。風にページが逃げる前に、一ページをそっとくわえてくれる挟みだ。ルールを押さえておいてこそ、遊びは最後まで続く。"},"ICON-0928":{"nm":"ピックケース紐","on":"紐","de":"ギターのピックは決まって一番盛り上がるところで指から抜け出す。ケースにぶら下がった紐一つが、その小さな脱走を防いでくれる。音楽が止まった夜を経験した人だけが、この紐をありがたく思う。"},"ICON-0929":{"nm":"リード保管ケース","on":"ケース","de":"リードは乾く瞬間に自分の音を失う。湿ったケースの中で、細い葦の一片が次の演奏を待っている。息を吹き込む前に、まず息を寝かせておく場所だ。"},"ICON-0930":{"nm":"弦交換ワインダー","on":"ワインダー","de":"弦がたるめば音もそっと垂れる。ハンドルをゆっくり回して張りを取り戻すこと――真心はいつも手首の先から来る。整った音は、こんなささいな整えから始まる。"},"ICON-0931":{"nm":"楽器拭き布","on":"楽器拭き布","de":"演奏が終わると楽器にも薄い汗が残る。柔らかい布で一度撫でれば、つやとともに今日の音が落ち着いて沈んでいく。大切に思う心は、いつも仕上げに表れる。"},"ICON-0932":{"nm":"チューニングピンカバー","on":"カバー","de":"チューニングピンは素肌のままだといつの間にか錆びる。小さなカバー一つが、金物の季節を一拍遅らせてくれる。見えない隅を先に気づかう人が、長く演奏する。"},"ICON-0933":{"nm":"譜面台クリップライト","on":"譜面台クリップライト","de":"暗い舞台裏、楽譜だけが明るくあるべき瞬間がある。譜面台に挟んで光をそっと降ろす小さな灯火だ。音符が道に迷わないよう、足元を照らす一握りの明かり。"},"ICON-0934":{"nm":"練習ミュートキャップ","on":"キャップ","de":"早朝の練習はいつも隣人の眠りと静かに争う。キャップ一つはめれば、響き渡る音がささやきに変わる。誰かの安眠を守りながら育つ音楽もあるものだ。"},"ICON-0935":{"nm":"ドラムパッドシール","on":"シール","de":"ドラムパッドの上に貼られた小さな印たち。どこを打てばどんな音が出るか、手が覚える前に目が先に道を覚える。拍子はこうしてゆっくり体に刻まれていく。"},"ICON-0936":{"nm":"メロディーメモチップ","on":"チップ","de":"口ずさんでいたメロディーは、つかまえないとすぐ消える。チップに急いで書いた数小節が、のちに一曲へと育つこともある。霊感はいつも、まめにメモする手をまた訪れてくる。"},"ICON-0937":{"nm":"ブックカバーバンド","on":"バンド","de":"読みかけの本がかばんの中で勝手にめくれると困る。バンド一つでページをそっと縛っておけば、本が大人しくなる。次のページのために、きちんと閉じておく約束だ。"},"ICON-0938":{"nm":"ページホルダーリング","on":"リング","de":"片手で本を開いたまま、温かいコーヒーを飲みたい日。指にはめる輪が、ページを代わりに押さえてくれる。小さな余裕は、こんなささいな発明から始まる。"},"ICON-0939":{"nm":"読書タイマーチップ","on":"チップ","de":"あと一章だけ、と座ればいつの間にか夜が深まる。チップを押して時間を決めておけば、読書にも休符が生まれる。好きなことほど、止まることを知る優しい勇気が必要だ。"},"ICON-0940":{"nm":"本の角ガードキャップ","on":"ガードキャップ","de":"大切な本ほど角からそっとすり減る。キャップ一つかぶせれば、表紙の耳が丸く守られる。いつまでもそばに置きたい気持ちを、そっと挟んでおく小さな鎧だ。"},"ICON-0941":{"nm":"感想メモ帯","on":"帯","de":"一文に胸がふと落ちる瞬間がある。帯に書き写した感想が、しおりのようにそのページに留まる。読んだ人だけが知る、傍線の温かな温度だ。"},"ICON-0942":{"nm":"図書館返却タグ","on":"図書館返却タグ","de":"返却日はいつも一日くらい早くやってくる。タグに書かれた日付が静かに背を押せば、借りた本にも締めくくりの礼儀が生まれる。次の人の手のために、図書館はそうして待っている。"},"ICON-0943":{"nm":"ブックライトクリップ","on":"クリップ","de":"眠った家族のそばで一人起きて読む夜。本の端に挟んだ小さな光一つで十分だ。闇をすべて押しのけなくても、一ページあれば足りる静かな時間だ。"},"ICON-0944":{"nm":"本の香りカード","on":"カード","de":"古い本からは日差しと紙が混ざった匂いがする。その香りを一枚に込めたというカード、開けば古本屋の路地がしばし鼻先によみがえる。記憶は匂いでもしおりを挟む。"},"ICON-0945":{"nm":"既読ページ印ピン","on":"ピン","de":"どこまで読んだっけ、というその漠とした問いを消してくれる小さなピン。最後の文に挟んでおけば、明日の自分はもう迷わない。止まった場所を代わりに覚えてくれる優しい印だ。"},"ICON-0946":{"nm":"スマホストラップ金具","on":"金具","de":"スマホの紐につけた金具一つで、人が少し違って見える。好きな色、好きな形。手に握った小さな好みが、その日の気分をそっと揺らしてくれる。"},"ICON-0947":{"nm":"カメラレンズ保護キャップ","on":"保護キャップ","de":"旅の写真の運命はレンズ一枚にかかっている。保護キャップを外すその瞬間が、すなわちシャッターを押す心の準備。風景を収める前に、まず目を開く小さな儀式だ。"},"ICON-0948":{"nm":"充電端子キャップ","on":"充電端子キャップ","de":"かばんの中のほこりは、いつも充電口から狙う。キャップ一つで小さな入り口を塞いでおけば、端子が長くきれいに保たれる。見えない隙間まで気づかう、まめさがここにある。"},"ICON-0949":{"nm":"スマホ立てポップリング","on":"リング","de":"動画一つ気楽に見ようと、スマホを斜めに立てること。後ろについたポップリングを広げれば、手も画面もずっとゆとりが生まれる。小さく突き出た支え一つが、夕べのひとときをゆったり延ばしてくれる。"},"ICON-0950":{"nm":"画面拭きパッチ","on":"画面拭きパッチ","de":"指紋だらけの画面は、心までなんだかぼやけさせる。パッチでさっと拭けば、世界がまた鮮明になる。きれいさとは、時に指一本の短い仕事だ。"},"ICON-0951":{"nm":"SIMピンケース","on":"ケース","de":"SIMピンは、ちょうど必要な瞬間にだけ姿を消す妖精だ。ケースの一区画に入れておけば、もうヘアピンを探して家中をさまよわなくていい。小さな整理が、急な瞬間を静かに救う。"},"ICON-0952":{"nm":"ワイヤレス充電パッドシール","on":"シール","de":"パッドの上にそっと置けば、勝手に満ちていく夜。貼っておいたシールが、スマホの寝る場所をそっと示してくれる。見えない電流が音もなく一日分の力を満たす。"},"ICON-0953":{"nm":"通知隠しシール","on":"シール","de":"見たくない通知は、隠しておくほうが気が楽だ。シール一枚で早朝の小さな灯りを眠らせる。時には見ないことも、自分を守る優しい方法だ。"},"ICON-0954":{"nm":"レンズ保護リング","on":"リング","de":"カメラレンズが床に触れるその刹那、心臓がひやりと落ちる。巡らせたリング一つが、小さな墜落をさっと防いでくれる。思い出を収める目を、一番先に包んでくれる縁取りだ。"},"ICON-0955":{"nm":"ケーブル名札","on":"名札","de":"もつれて絡まったケーブルの山から、なんとか自分のものを見分けること。名札一つあれば、充電線にもようやく自分の名前が生まれる。散らかった紐の間で道を教えてくれる小さな旗だ。"},"ICON-0956":{"nm":"充電器ポーチ","on":"ポーチ","de":"旅行かばんの中の充電器たちは、いつも互いに絡んで争う。ポーチの一区画にきちんとまとめておけば、ようやく仲直りする。片づけの技は、散らばったものを一か所へ優しく呼ぶことにある。"},"ICON-0957":{"nm":"マルチポートラベル","on":"ラベル","de":"電源タップの口はどれも同じ形で毎回まぎらわしい。ラベルを貼って誰の場所か決めておけば、忙しい朝がずっと楽になる。小さな名札が、日常のこまかな争いを減らす。"},"ICON-0958":{"nm":"コード巻き取りリール","on":"コード巻き取りリール","de":"ほどいて使い、また巻いておく、紐のきちんとした一日。リール一つに少しずつ巻けば、絡まりがすっきり消える。使い終わって定位置に戻す手が、明日を軽くする。"},"ICON-0959":{"nm":"マグネット端子キャップ","on":"キャップ","de":"磁石端子はいつの間にか細かい鉄粉を集める。キャップで覆っておけば、ねばつくほこりがつかない。もう一度気づかう手が触れた機器が、より長くそばで生きる。"},"ICON-0960":{"nm":"モバイルバッテリーバンド","on":"バンド","de":"モバイルバッテリーとケーブルは別々にすると、決まって片方が消える。バンドで縛っておけば、二つがようやく一対になる。外出直前、一緒に連れ立てと、そっと結ぶ小さな結び目だ。"},"ICON-0961":{"nm":"プラグほこりキャップ","on":"キャップ","de":"空いたコンセントの口は、数日経つだけでほこりがそっと所帯を構える。この小さなキャップがその場所を代わりに守れば、次に挿される充電器がきれいな初めの一息を吸える。空いている間を丁寧に守る門番。"},"ICON-0962":{"nm":"ケーブルカラーリング","on":"リング","de":"絡んだ紐の中で自分のものを手探りした夜、誰かが色をつけておこうと言った。青は君、黄色は私。小さな輪一つで、私たちはもう互いをまぎらわせなくなった。合奏室の片隅に残った、優しい約束の跡。"},"ICON-0963":{"nm":"アダプター分類チップ","on":"チップ","de":"丸い足と平たい足、110と220。国ごとに違うコンセントの顔を、そっと覚えておいたチップだ。初めて海を越え舞台へ発った荷物の片隅には、この小さな分類表が一つ、いつも挟まっていたものだ。"},"ICON-0964":{"nm":"イヤーチップ分類ボード","on":"ボード","de":"耳の穴は人それぞれ深さも広さも違うという。大・中・小の三組を並べて寝かせ、自分の耳にぴったり合う一対を選ぶこと。音を聴く前に、まず体から合わせておく優しい手順だ。"},"ICON-0965":{"nm":"ケースシリコンリング","on":"リング","de":"舞台衣装は縫い目一針まで手をかけながら、肝心のケースの角はいつも素肌でぶつかる。この薄いシリコンの輪が周りをそっと包めば、手から滑った早朝でも画面は無事に朝を迎える。"},"ICON-0966":{"nm":"ノイズキャンセルシール","on":"シール","de":"世の中の音をしばし消しておきたい日がある。ヘッドホンの耳に貼ったこの小さなシールは、静寂をつける印。客席の歓声も地下鉄の騒音も、一曲が終わるまでだけ遠くへ連れて置く御守りだ。"},"ICON-0967":{"nm":"イヤーフックセット","on":"イヤーフックセット","de":"踊っているとイヤホンは決まって片方が先に逃げ出す。耳介をそっと抱き寄せるこの輪を掛けておけば、激しい振付の中でも音楽だけは最後まで耳に留まる。練習室の人たちが交わした小さな発見だった。"},"ICON-0968":{"nm":"掃除ブラシキャップ","on":"キャップ","de":"ブラシの先についたほこりがまた舞い散らないようかぶせておく小さな帽子だ。掃除する道具にも掃除が必要だということを、掃き終わりにほうきを逆さに立てておいた手つきが、ずっと昔から知っていた。"},"ICON-0969":{"nm":"充電ドック底パッド","on":"パッド","de":"充電ドックが机の上でしきりに滑っていたのは、足がなかったからだ。底に敷いたこの薄いパッド一枚が足の役を代われば、機器は定位置にじっと留まり、一晩じゅう静かに力を満たす。"},"ICON-0970":{"nm":"左右区別マーカー","on":"左右区別マーカー","de":"左はL、右はR。暗闇で手探りしても気づけるよう、点を一つ足して打っておく。舞台の左足と右足をただの一度も間違えまいとする心が、この小さな印の上にそっくり刻まれている。"},"ICON-0971":{"nm":"オーディオ分配ジャックキャップ","on":"キャップ","de":"一本の音を何人かで分けて聴いたあのジャック、休む間は先を塞いでおかねばならない。ほこりが回路にしみ込まないように。一緒に聴いた歌を次も澄んだまま流そうとする、小さく慎ましい手つきだ。"},"ICON-0972":{"nm":"イヤーケーブル巻き取り","on":"イヤーケーブル巻き取り","de":"糸玉を巻いた昔の手つきのように、イヤホンの紐もここに丸く巻けばきれいになる。絡んだままかばんの中を転がっていた音楽が、整然と片づく瞬間。ほどく明日がずっと軽くなる。"},"ICON-0973":{"nm":"レンズキャップホルダー紐","on":"紐","de":"レンズを開けるたびにキャップはいつも行き場を失った。紐に結んでカメラのそばに留めておくと、もうポケットを虚しく探らなくてよくなった。失くさないにはそばに結んでおけばいいと、手が先に覚えた。"},"ICON-0974":{"nm":"ホットシューカバーチャーム","on":"ホットシューカバーチャーム","de":"カメラの上の空いたホットシューの場所に、小さな飾り一つをそっと挿す。何の機能もないそのチャーム一つが、重くそっけなかった機材を、いつの間にか自分のものらしく愛おしく見せてくれる。道具に情を抱く仕事。"},"ICON-0975":{"nm":"ストラップ調節バックル","on":"ストラップ調節バックル","de":"かばんの紐が肩に食い込むたびに、このバックルを少しずつゆるめ締める。自分の体に合わせて長さを選ぶ指の一手。荷を背負うことも結局は自分をいたわることだと、バックルはそっと教えてくれる。"},"ICON-0976":{"nm":"フィルタースタックケース","on":"ケース","de":"光を分けるガラスの欠片を少しずつ寝かせておく小さな家だ。曇りと晴れ、夕焼けと夜。天気をあらかじめ選んでしまった引き出しのようで、写真家は旅に出る前いつもこのケースから開けてみる。"},"ICON-0977":{"nm":"ブロワーほこりキャップ","on":"キャップ","de":"風を吹いてほこりを追うゴム玉、その口もほこりには弱いのは同じだ。休む間はこのキャップをかぶせておく。他人を拭ってあげる道具が自分の口からそっと塞いでおく姿が、なんだか優しい。"},"ICON-0978":{"nm":"シャッターボタンカバー","on":"カバー","de":"かばんの中でシャッターが勝手に押され、空の写真ばかり百枚撮れていたこと、誰しも一度は経験する。ボタンの上にかぶせたこの小さなカバーが、その無駄骨を防ぐ。本当に残したい瞬間だけ残そうとする、ささいなロックだ。"},"ICON-0979":{"nm":"バッテリー区別シール","on":"シール","de":"使い切ったものと満タンのものが一つのポケットで混ざると、いつも困る。バッテリーごとに貼った色シールが、その混乱を静かに整理する。赤は空で緑は頼もしい。撮影現場に灯した、言葉なき信号機。"},"ICON-0980":{"nm":"カメラバッグ仕切り","on":"カメラバッグ仕切り","de":"レンズとボディ、予備のバッテリーが互いにぶつからないよう、かばんの中に区画を分ける。一つの荷の中に小さな部屋をいくつも設ける仕事。場所ごとに主が決まっていて、揺れても定位置を失うことがない。"},"ICON-0981":{"nm":"撮影グローブパッド","on":"パッド","de":"冬の屋外撮影、シャッターを押す指先だけは凍えてはならない。手のひらには厚めのパッドを、指先には感覚を残した手袋。温かさと精密さを一つの手にともに握ろうとする、現場の優しい折衷案だ。"},"ICON-0982":{"nm":"タブレットペン先ケース","on":"ケース","de":"ペン先も鉛筆の芯のようにすり減るということを、タブレットを長く握った人は知っている。予備の先をころころ集めたこの小さなケースは、切れてはならない線をあらかじめ満たしておく指先の非常金のようなものだ。"},"ICON-0983":{"nm":"キーボードキーキャップトレイ","on":"トレイ","de":"キーキャップを一つ一つ抜いて洗いまた挿した日、このトレイが小さな干潟になってくれた。子音と母音が区画ごとに寝そべって水気を乾かす風景。一度分解してこそようやく見える真心もある。"},"ICON-0984":{"nm":"マウスソールパック","on":"マウスソールパック","de":"マウスが机の上を滑るように走る秘訣は、底についたこの小さな足たちにある。すり減れば取り替える一束。見えない場所で滑らかさを黙々と支えるものたちの労苦。"},"ICON-0985":{"nm":"ノートパソコン台ゴム","on":"ノートパソコン台ゴム","de":"ノートに似ているが、実はノートパソコンを支えるゴムの台だ。画面を目線へそっと持ち上げ、曲がった首を伸ばしてあげること。長く書き長く見つめる人のための、姿勢を正す心づかいだ。"},"ICON-0986":{"nm":"ウェブカメラ隠しスライダー","on":"ウェブカメラ隠しスライダー","de":"レンズを指で押して隠し、また押して開く。見たいときだけ見られたいという心。この小さなスライダー一つに、プライバシーという大きな安心が宿る。閉まる音がなんだか頼もしい。"},"ICON-0987":{"nm":"USB分類ラベル","on":"ラベル","de":"似たような黒い棒が五つ、どれに何が入っているのかまるで分からない。小さなラベルを貼って名前をつけてやれば、そこでようやく自分の家族になる。呼ぶ名前があってこそ、探すのも楽になる。"},"ICON-0988":{"nm":"デスクパッドコーナー","on":"デスクパッドコーナー","de":"デスクパッドの角がしきりにめくれ上がると、手書きの字まで歪む。四隅をそっと押さえておくこの小さな部品が、机の上の平らな平和を守る。土台が静かでこそ手先も落ち着く。"},"ICON-0989":{"nm":"ハブスタンドクリップ","on":"クリップ","de":"幾本もの線が一つに集まるハブを机の端に斜めに立てておく挟みだ。散らかっていた紐が一点に集まって整う姿。もつれたものを一筋にまとめ上げる手応えが、ここにも生きている。"},"ICON-0990":{"nm":"画面クリーナースプレーキャップ","on":"キャップ","de":"画面についた手の跡を消すスプレー、その口を塞ぐ小さな栓だ。液が漏れたり乾いたりしないよういつもしっかり閉めておく。澄んで見るには、まず拭くものから大切にしておくべきだという、暮らしの素朴な順序。"},"ICON-0991":{"nm":"メモリーカード財布","on":"メモリーカード財布","de":"数日分の舞台映像が爪ほどのカード一枚に静かに眠っている。失くせばその一日が丸ごと消えるから、小さな財布に大切にまとめて抱く。最も小さく、そして最も大きな記憶を収める家。"},"ICON-0992":{"nm":"外付けハードラベルリング","on":"リング","de":"黒い外付けハードが五つ、引き出しの中で同じ顔で眠っている。ラベルを貼って「あの夏」「未公開クリップ」と名づける仕事。ぼやけた記憶に鮮明な索引をつける作業だ。"},"ICON-0993":{"nm":"バックアップチェックチップ","on":"チップ","de":"バックアップを終えたか否か、その紙一重の差に心がやきもきする。終えた場所にそっと挟んでおくこの小さなチップが「ここまでは安全だ」と教えてくれる。安心は、印を残しておくことから来る。"},"ICON-0994":{"nm":"クラウドメモトークン","on":"トークン","de":"空のどこかに浮かぶ保管庫へメモ一行を飛ばして送るトークンだ。どこでつけてもその文が迎えに出る小さな魔法。凧を上げて願いを書いた夜空が、今や手のひらの上へそっと降りてきたようだ。"},"ICON-0995":{"nm":"USB保護キャップセット","on":"USB保護キャップセット","de":"端子がむき出しのままかばんの中を転がれば、接点が傷むものだ。先ごとに小さな帽子をかぶせて一セットでまとめる。使わない間を丁寧に寝かせておくこと。次の接続のための、最も静かな準備だ。"},"ICON-0996":{"nm":"データケースバンド","on":"バンド","de":"大切なデータを収めた機器をすっぽり包んで締めるバンドだ。揺れるかばんの中でぶつからないよう、一周巻いてしっかり結ぶ。風呂敷を丁寧に結んだ手つきが、デジタルにもそのまま生きている。"},"ICON-0997":{"nm":"ファイル整理タグ","on":"タグ","de":"何百ものファイルが名前もなく積もれば、探すことがすなわち迷いになる。色とりどりのタグをつけて分かれ道を開く瞬間、散らかった山の間に道ができる。整理とは結局、道を開くことだった。"},"ICON-0998":{"nm":"パスワードヒントカード","on":"カード","de":"パスワードを丸ごと書けば危ないし、全く書かなければ忘れる。だから自分だけが分かる糸口だけそっと残す。「初舞台のあの街」のように。答えではなく道を書いておく、賢く優しい記憶法。"},"ICON-0999":{"nm":"保管日付シール","on":"シール","de":"しまった日を書かなければ、保管はすぐ忘却になる。箱ごとに貼った日付シールが「いつから」を鮮明に刻んでおく。漬け物を漬けた日を書いておいた昔の蔵の心が、この小さな紙の上へ受け継がれる。"},"ICON-1000":{"nm":"ミニリングライトキャップ","on":"キャップ","de":"丸い光を出す小さな照明、その光の口を覆うキャップだ。かばんの中でレンズが傷つかないよう、しばし光を寝かせておく。つける前の闇を丁寧にしまっておくことも、明るさを大切にする一つの方法だ。"},"ICON-1001":{"nm":"スタンド締めネジ","on":"スタンド締めネジ","de":"あと一回りだけ。ゆるんだ隙間が消え、手のひらの下にずっしりと安心が降りてくる。揺れない舞台の裏には、いつも誰かの確かな手首の一ひねりが隠れている。小さなネジが支えるのは、見えない確かさだ。"},"ICON-1002":{"nm":"放送中表示チップ","on":"チップ","de":"赤いランプがつく瞬間、廊下の足音がそっと忍び足になる。放送中――その一言の前で皆が息を殺す。ドアの向こうの静寂までもが誰かへの心だということを、この小さなチップは静かに知らせている。"},"ICON-1003":{"nm":"チャットメモパッド","on":"パッド","de":"画面を流れ過ぎる応援を指先でつかまえておく。流れ去ってしまう一言一言が紙の上にきちんと留まる時間。記録とは、遅くなってもきっと届きたい優しさが留まる場所だ。"},"ICON-1004":{"nm":"無音キーボードカバー","on":"カバー","de":"夜中の二時、キーを打つ音だけが嘘のように消える。ぐっすり眠るルームメイトの寝息を起こさないための薄い膜一枚。最も静かな心づかいは、いつも音のない場所から始まる。"},"ICON-1005":{"nm":"マイクアームクリップ","on":"クリップ","de":"唇とマイクの間、歌が揺れないちょうどそのぶんの距離。この小さなクリップがその約束を押さえてくれる。舞台の裏にはいつも、こうしてしっかり支えてくれる手が先に来ている。"},"ICON-1006":{"nm":"背景布クリップ","on":"クリップ","de":"風が吹いても背景布は微動だにしない。角をしっかりくわえた小さな顎一つが、場面全体を支えているから。揺れない風景の裏には、見えない場所で歯を食いしばった誰かがいる。"},"ICON-1007":{"nm":"ストリームデッキラベル","on":"ラベル","de":"数十のボタンの上、小さな名札のおかげで手が道に迷わない。ラベル一行が生放送のミス一つをあらかじめ消してくれる。冷静さとは、震える前に書いておいた文字から来る。"},"ICON-1008":{"nm":"タイムスタンプボタン","on":"ボタン","de":"ぐっと押せば、流れていく時間の上に小さな旗が立つ。二度と戻らない今に印を押すこと。ずっと後で振り返れば、その印が思い出へ入る扉になっている。"},"ICON-1009":{"nm":"タグリーダーキーリング","on":"リング","de":"かざせばピッ、と情報が目覚める。鍵の輪にぶら下がってポケットの中でからから鳴る小さな道連れ。平凡な一日は、こんなささいな信号音で無事につながっていく。"},"ICON-1010":{"nm":"スマートプラグラベル","on":"ラベル","de":"コンセントごとに名前をつけておけば、どの線が何なのかもう迷わない。見えない電気にまで名前を渡す心。整頓とは、優しさがしばし借りてまとった別の顔だ。"},"ICON-1011":{"nm":"温湿度センサースタンド","on":"温湿度センサースタンド","de":"部屋の中の温度と湿気を黙って見守る手のひらほどの番人。快適さは口を開かないが、このスタンドは毎瞬、君のコンディションをそっと気づかっている。安らぎはこうして静かに守られる。"},"ICON-1012":{"nm":"ドア開閉センサーキャップ","on":"キャップ","de":"ドアがそっと開くその刹那を逃さない小さな目。誰かが帰ってきたという合図を音もなく伝える。留守の家を守ってくれるのは、いつもこうして言葉なきものたちだ。"},"ICON-1013":{"nm":"リモコンホルダー","on":"ホルダー","de":"あちこち転がっていたリモコンたちが、ついにそれぞれの定位置を見つける。失くしかけたものをそっと押さえておく小さな場所、また会おうという約束をあらかじめ刻んでおく手つきだ。"},"ICON-1014":{"nm":"睡眠アプリトークン","on":"トークン","de":"ぐっすり眠った夜ごとに、丸いやりがいが一つころころ積もる。眠りも練習のように少しずつ集まると、アプリが優しく教えてくれる。よく休んだ君に贈る、世界で一番小さな賞だ。"},"ICON-1015":{"nm":"タイマーキューブ台座","on":"台座","de":"三分がきちんと流れる間、キューブは揺るぎなく自分の時間を数える。その下をそっと支える手のひらほどの場所一つ。待つことにも、安心して踏める床が必要なものだ。"},"ICON-1016":{"nm":"通知ライトカバー","on":"カバー","de":"明るすぎないよう、光を一枚柔らかく包み込む。通知は急いでも目だけは安らかであれと。心づかいとは、光の強さまでそっと汲み取る心だ。"},"ICON-1017":{"nm":"バッテリー交換カード","on":"カード","de":"このカードが見えたら、機器の中の小さな心臓を替えてやる時が来たという意味だ。止まる前にあらかじめ用意しなさいという優しい耳打ち。長く共にする秘訣は、いつも一拍早い気づかいにある。"},"ICON-1018":{"nm":"ジョイスティックキャップセット","on":"ジョイスティックキャップセット","de":"親指が滑らないようそっとはめる小さな帽子たち。指先の感覚が一段と鮮明になる。この小さなキャップ一つが、手に汗のにじんだ一戦の勝敗を分けることもある。"},"ICON-1019":{"nm":"スイッチドックカバー","on":"カバー","de":"コンソールが休む場所をほこりからそっと覆ってくれる。しばし眠った機器にも布団一枚は必要だから。大切に思う心は、使わないときにこそ一層はっきりと表れる。"},"ICON-1020":{"nm":"携帯コンソールポーチ","on":"ポーチ","de":"移動するときは必ずこの中に。携帯用コンソールをふんわり包み込むポーチ。かばんの中であちこちぶつかっても平気なように、大切なものはもう一度包んでおくのがいい。"},"ICON-1021":{"nm":"ボタンシールリング","on":"リング","de":"のっぺりしたボタンの上に小さな絵一つ載せるだけで、その瞬間まるごと自分のものになる。同じ機器の上に自分だけの印を残すこと。個性はいつもこんなささいな場所でそっと咲く。"},"ICON-1022":{"nm":"ゲームソフトケース","on":"ケース","de":"夜通し夢中になったゲーム一戦が、この小さなケースの中ですやすや眠る。蓋をまた開ければ、あのときのあの夜がそっくり目覚める。思い出は意外と、手のひらほどの箱に収まったりする。"},"ICON-1023":{"nm":"冷却ファン台座","on":"台座","de":"風が熱を冷ます間、少し傾けて機器を支える場所。熱くなった体がひと息つく隙を作る。遠くまで走るには、しばし止まって冷ます術も知らねばならないものだ。"},"ICON-1024":{"nm":"手首ストラップピン","on":"ピン","de":"手首に巻いてピンを留めれば、どんなに激しい動きでもコントローラーがそばを離れない。煩わしく見えるこの紐が、実は安心して跳ね回らせてくれる安らぎだ。"},"ICON-1025":{"nm":"アナログスティックグリップキャップ","on":"キャップ","de":"長く握ってつるつるになったグリップの上に新しい衣を着せる。手に馴染んだ感覚はそのままに、表面だけ新品のように。馴染みとときめきが一つの手の中に並んで留まる瞬間だ。"},"ICON-1026":{"nm":"セーブスロットラベル","on":"ラベル","de":"セーブの枠ごとに誰の冒険かをきちんと書いておく。ラベル一行が、過ぎた数日の旅路を黙々と守ってくれる。大切な記憶は、上書きされないよう名前を刻んでおくのがいい。"},"ICON-1027":{"nm":"レコーダーポーチ","on":"ポーチ","de":"音を収める機械は、その中に入った何かのために一層尊くなる。衝撃から守ってくれるふんわりしたポーチに丁寧に入れて持ち歩く。誰かの声が眠っているかもしれないから、より慎重に。"},"ICON-1028":{"nm":"ウィンドスクリーンキャップ","on":"キャップ","de":"風の音を払いのけ、ただ声だけを残す。屋外録音でマイクにそっとかぶせるふわふわの傘。乱れた雑音の間から真心だけを選んで収める、小さな漉し器だ。"},"ICON-1029":{"nm":"音声メモラベル","on":"ラベル","de":"これは歌詞が浮かんだもの、これは口ずさんだメロディー。音声メモごとに色とりどりの名札をつけてやる。あちこちに散らばっていた霊感の欠片が、ようやく定位置を見つけて列をなす。"},"ICON-1030":{"nm":"サンプリングボタンチップ","on":"チップ","de":"ぐっと押せば、あらかじめ収めておいた音一片がぽんと飛び出す。雨粒、拍手、誰かの笑い――世界の断片が指先で目覚める。音楽はこんな小さなチップたちの優しい合唱だ。"},"ICON-1031":{"nm":"音集め封筒","on":"封筒","de":"道を歩いていてふと拾った音を、この封筒にそっと収める。風の流れ、明け方の路地の静寂までも。いつか歌になる素材は、いつもこうして素朴に集まってくる。"},"ICON-1032":{"nm":"ミニ三脚の足","on":"ミニ三脚の足","de":"三本の脚が机の上に小さな舞台を広げる。揺れる手の代わりにしっかり立って場面を支えてくれる。鮮明な一カットは、黙々と止まり立つ三本の脚からようやく生まれる。"},"ICON-1033":{"nm":"録音ファイルタグ","on":"タグ","de":"何百もの録音ファイルに短い名札を一つずつつける。ある日初めて流れ出た最初の一節か、一目で分かるように。散らばった声をまた探し出してくれる、小さな道しるべ一つだ。"},"ICON-1034":{"nm":"波形シール帯","on":"帯","de":"音の形をそのまま写した波模様の帯。ノートやケースに巻いてやれば、まるで音楽が目の前に見えるようだ。聞こえるものを見えるようにする、優しいだまし絵だ。"},"ICON-1035":{"nm":"ヘッドセット掛けピン","on":"ピン","de":"練習が終わると、疲れたヘッドセットが休む場所をそっと用意してくれる。机の角にこつんと差した小さなかぎ一つ。整った机は、明日の意欲をあらかじめ掛けておく場所だ。"},"ICON-1036":{"nm":"ミニギフトボックス帯","on":"帯","de":"ギフトボックスの胴に巻く最後の一周。この帯一つで心がようやく仕上がる。真心は中身よりも、その上を整える手つきから先に伝わるものだ。"},"ICON-1037":{"nm":"リボン端キャップ","on":"キャップ","de":"リボンの端がほどけないようそっと包んで仕上げる。目立たないディテール一つが、贈り物の第一印象をそっと変える。締めくくりが美しければ、心も美しく届く。"},"ICON-1038":{"nm":"包装シーリングワックス","on":"包装シーリングワックス","de":"熱い一滴をぽとりと落として封筒を封じる。昔の手紙のように、みだりに開けるなという重い約束一つ。格式は時にこうして、温かな重みを抱くこともある。"},"ICON-1039":{"nm":"感謝カードホルダー","on":"ホルダー","de":"ありがとうの言葉を込めたカードがしわにならないよう、まっすぐ支えてくれる。心が真っ直ぐに立って伝わるように。感謝はその姿まで端正なとき、より長く心に残る。"},"ICON-1040":{"nm":"緩衝スター紙","on":"緩衝スター紙","de":"星の形に切った紙が箱の隙間をふんわり埋める。揺れてもどうか傷つかないでという心の綿。包みの中の闇にも、小さな星が一つ浮かんでいるわけだ。"},"ICON-1041":{"nm":"ギフトリストタグ","on":"タグ","de":"贈る相手の欄の前でペンがしばし止まる。名前を書く間に浮かぶ顔、共に過ごした季節。結ばれる瞬間、この小さな紙はほどく前まで誰も読めない秘密になる。"},"ICON-1042":{"nm":"お祝いスタンプリング","on":"リング","de":"ぐっと押せば丸いお祝いがくっきり捺されて出る。インクが乾くしばしを待つ間、誰に渡そうかと思い浮かべる心が一番温かい。もう一度捺したくなるのが、難といえば難。"},"ICON-1043":{"nm":"包装紐ボビン","on":"包装紐ボビン","de":"丁寧に巻かれていたかと思えば、誰かのときめく指先で楽しげにほどけていく。巻かれてほどける、そのわずかな間に、糸に結ばれていた心一つがようやく贈り物になる。"},"ICON-1044":{"nm":"花ではない結びチャーム","on":"花ではない結びチャーム","de":"花を真似たのではなく、糸一筋が自分の体を何度も抱きしめて、自ずと咲いた形。夜通し結び目を整えた指先の忍耐が、こうして小さな蕾一つとして残った。"},"ICON-1045":{"nm":"幸運コイン袋","on":"袋","de":"遠い旅に出る人のポケットにコイン数枚をそっと入れてやった心。重さではなく優しさを満たすことだ。一歩ごとにちゃりんと鳴る音が、無事に行ってきてという挨拶の代わりになる。"},"ICON-1046":{"nm":"願いカプセルチャーム","on":"願いカプセルチャーム","de":"丸い殻の中に、折りたたまれた願い一つがすやすや眠っている。開ければ叶うという言葉は嘘だが、開けずに抱けばその願いが永遠に生きているというのは本当だ。"},"ICON-1047":{"nm":"守り結び紐","on":"紐","de":"五方色の糸でしっかり編み、悪い気を背中の後ろへ向き直らせる紐。幼い頃手首に結び目を結んでくれた祖母の手つきのように、結ばれた場所ごとに誰かの祈りが丁寧に刻まれている。"},"ICON-1048":{"nm":"小さな折り鶴ケース","on":"ケース","de":"千回折ってこそ願いになるという折り鶴を、ただ一羽だけは傷つかないよう収めておく小さな家。羽の片方でもしわになれば、その夜こめた真心まですっとほどけてしまうから。"},"ICON-1049":{"nm":"きらきら石ポーチ","on":"ポーチ","de":"舞台衣装から落ちた小さな光の粒、捨てるに捨てられず掃き集める場所。一度つけば一週間追いかけてきたきらめきも、ここでは手のひらの上のように大人しく眠る。"},"ICON-1050":{"nm":"吉日スタンプチップ","on":"チップ","de":"良い日を選ぶときそっと添える小さな札。占いの敷居ではなく自分の机の上で、今日一日だけは良いことだけ起これと、そっと捺しておく優しい迷信一片だ。"},"ICON-1051":{"nm":"祈りブレスレットカード","on":"カード","de":"ブレスレットの形に印刷された一枚の紙に、誰かの静かな祈りが込められている。手首に巻けなくても、財布の奥にしまっておけば、その想いだけはいつもそばに結ばれて一緒に歩いてくれる。"},"ICON-1052":{"nm":"戸口の塩瓶","on":"瓶","de":"粗塩を小さな瓶に入れて戸口にそっと置く。悪い気は追い返し、嬉しい客だけを迎え入れようとした昔ながらの知恵。しょっぱい粒のひとつひとつが、わが家を守る小さな門番だ。"},"ICON-1053":{"nm":"ラッキーナンバー隠しタグ","on":"ラッキーナンバー隠しタグ","de":"削る直前、誰もがほんの一瞬は一等だ。幸運の数字をそっと隠したこのタグは、期待が最もふくらむ最後の1秒を守ってくれる。削る指先が震えても、知らないふりして目をつぶってくれる。"},"ICON-1054":{"nm":"誕生日キャンドル保管キャップ","on":"キャップ","de":"一度火を灯したろうそくも次の誕生日まで大切にしまっておく、しっかり者の心。去年願った夢がまだ叶っていなかったら、今年そこから続けて願えばいいという優しい計らいだ。"},"ICON-1055":{"nm":"記念日カウントリング","on":"リング","de":"Dデイを指にはめる大胆な品。残りの日数が一マスずつ回るたびに、心臓もそのぶん前へ引き寄せられる。0になる日には勝手に輝くのだと、ひとりで言い張る。"},"ICON-1056":{"nm":"パーティー帽ひも","on":"ひも","de":"とんがり帽子を頭にそっと固定する細いひも。当の主役は窮屈だとすぐ脱いでしまうけれど、写真の中ではその一枚に永遠にかぶせられている。任務はそれで十分だ。"},"ICON-1057":{"nm":"小さなケーキピック","on":"小さなケーキピック","de":"指二節ほどの小さなケーキに刺さった小さな目印。一口で消える甘さの上でも、お祝いはぴんと背筋を伸ばして立つ。小さくても誕生日は誕生日、今日の主役は君だから。"},"ICON-1058":{"nm":"お祝いクラッカーラベル","on":"ラベル","de":"パンと鳴らなくても見た目は一番華やかな紙のクラッカー。封筒に貼られた瞬間、ありふれた郵便物が祝いの席から届いた手紙に変身する。はがすのが惜しくてそのままにする人が多い。"},"ICON-1059":{"nm":"写真吊りクリップ","on":"クリップ","de":"ひもに吊るした思い出を落とさないよう、わたしはいつも口をきゅっと結んでいる。写真を一枚ずつくわえている間だけは、窓の隙間から吹く風にもあの日々は落ちない。"},"ICON-1060":{"nm":"日付風船パッチ","on":"日付風船パッチ","de":"数字の書かれた風船の形のパッチ。服に貼れば、今日が何日目の特別な日なのか町じゅうに知れわたる。はがすと跡が残るけれど、その薄い跡さえもうひとつの記念になる。"},"ICON-1061":{"nm":"プレゼント交換マーク","on":"プレゼント交換マーク","de":"受け取った手と渡した手をちょっと混乱させるいたずらな目印。誰がくれたかよりも何が行き交ったかを覚えていてという、贈り物を交わす席の小さくて優しいルールだ。"},"ICON-1062":{"nm":"記念テーブルナンバー","on":"記念テーブルナンバー","de":"祝いの席ごとに小さく立てておく番号ひとつ。どの席に誰が座るか前もって決めておけば気まずい思いをしなくて済むという、祝い事を何度も催した人々の優しい知恵が込められている。"},"ICON-1063":{"nm":"ドアノブギフトバッグ","on":"ドアノブギフトバッグ","de":"呼び鈴を押さずに気持ちを届ける方法。ドアノブにそっと掛けて逃げるように去れば、それを見つけた人の驚いた顔が、贈り主への一番大きなプレゼントになる。"},"ICON-1064":{"nm":"秘密配達ラベル","on":"ラベル","de":"表面には何も書かれていない。誰が送ったか最後まで隠すのがこのラベルの小さな矜持。受け取る人がしばらく首をかしげて笑うほど、その秘密の任務は完璧になる。"},"ICON-1065":{"nm":"呼び鈴メモチップ","on":"チップ","de":"戸を叩く勇気が出ないとき代わりに貼っておく小さなメモ。「ちょっと寄っていきます」のような短い一行が、呼び鈴の音より長く残る。たどたどしい手書き文字には表情があるから。"},"ICON-1066":{"nm":"開封カッター安全キャップ","on":"キャップ","de":"開封カッターの刃がうっかり指を狙うとき、そっと前に立ちはだかる小さな英雄。新しい品への高鳴りで急いた指先を、最後の一マスまで無事に守りぬく。"},"ICON-1067":{"nm":"緩衝プチプチの欠片","on":"緩衝プチプチの欠片","de":"わたしは押されるために生まれた。プチッとはじけるその音に、なぜか一日の緊張がするりとほどける。中に包んでいた品物より、わたしのほうが長く愛される日も、ときどきある。"},"ICON-1068":{"nm":"受取時間ピン","on":"ピン","de":"何時に届くのかをぴたりと指して刺しておくピン。漠然とした待ち時間にも座標がひとつできれば、ずいぶん耐えやすくなる。その時刻まで玄関を何度のぞくかは、まるまる本人次第。"},"ICON-1069":{"nm":"宅配ボックスキーリング","on":"リング","de":"宅配ボックスの暗証番号をしょっちゅう忘れる人のための小さな相棒。キーホルダーにぶら下がって揺れていて、決定的な瞬間に「あ、そうだ」のひと言を引き出すのがこの子のさりげない特技だ。"},"ICON-1070":{"nm":"玄関かごタグ","on":"玄関かごタグ","de":"玄関の片隅のかごに付いた名札。「ここに置いていってください」という無言の約束が記されている。空っぽでも、誰かの気持ちを待つ席は決して寂しくない。"},"ICON-1071":{"nm":"住所隠しシール","on":"シール","de":"捨てる箱の上、名前は残して住所だけをすっと消す。全部知られても平気なのは名前まで、住んでいる所はわたしだけの秘密に。一枚はがして貼った瞬間に小さな安心が生まれる。"},"ICON-1072":{"nm":"おやつ缶ラベル","on":"ラベル","de":"缶の中に何が入っているか一目で教えてくれるラベル。でも「おやつ」と書いておくと、ふたを開けなくてもなぜか心強いのが落とし穴。ラベルは食欲までは責任を持たない。"},"ICON-1073":{"nm":"小さなネックレスペンダント","on":"小さなネックレスペンダント","de":"服の中で静かに体温を分け合う小さな粒ひとつ。誰の目にも見えない場所にいつも触れていて、かえっていっそういとおしい。胸元を共に歩く一番近い友。"},"ICON-1074":{"nm":"足跡スタンプマット","on":"マット","de":"肉球にぽんと押すと小さな足跡が列をなして残る。誰がどこへ歩いたか、紙の上にきちんと記した一日分の散歩日記。インクのついた最初の一歩がいつも一番くっきりしている。"},"ICON-1075":{"nm":"毛づくろいブラシキャップ","on":"キャップ","de":"ブラシに絡んだ毛をきれいに引き受ける小さなふた。一回のブラッシングでひと握り集まる季節の変わり目、このキャップがなければ家じゅうがふわふわの雪原になってしまう。目立たずまめな掃除人。"},"ICON-1076":{"nm":"散歩袋ケース","on":"ケース","de":"散歩道に持っていく袋をきちんと抱えて歩く小さな家。前もって用意した人だけがゆとりを持って歩けることを、このケースが毎日静かに証明する。忘れると困るその一枚。"},"ICON-1077":{"nm":"名前隠しタグ","on":"タグ","de":"本当の名前はそっと隠して愛称だけを残したタグ。世の中には誰にでも見せたくない優しさもあるものだ。知る人だけが知るその呼び名が、ここにそっと隠れている。"},"ICON-1078":{"nm":"水入れ受けパッド","on":"パッド","de":"水入れの下に敷かれたわたしはいつも湿っている。四方に飛び散る水滴を代わりに受け止めて、床がさらりと乾くよう守る。誰も褒めてくれないけれど、わたしもまた不平を言わない。"},"ICON-1079":{"nm":"おもちゃ修繕糸","on":"糸","de":"縫い目のほつれた人形は捨てるものではなく、また縫い直すものだ。一針ずつ埋める場所ごとに、その子と過ごした時間がまた固くなる。修繕とは結局、別れを静かに先送りすること。"},"ICON-1080":{"nm":"記念写真ネックレス","on":"記念写真ネックレス","de":"一番明るく笑っていた一枚を首に掛けて歩く心。写真の中のあの日は剥製にされる代わりに、一歩ごとに一緒に揺れて今日まで続く。よかったあの瞬間は止まらない。"},"ICON-1081":{"nm":"気分カラーチップ","on":"チップ","de":"心にも色があるなら、今日の君の色は何だろう。チップをひとつ選んで机に置いた瞬間、言葉にしきれなかった気分が静かに広がってくる。夕焼け色も夜明け色もいい――その日のわたしをそっと映してくれる小さな鏡だから。"},"ICON-1082":{"nm":"今日の記録ビー玉","on":"今日の記録ビー玉","de":"一日が暮れるとビー玉の中に今日がまるく結ばれる。うまくいったことも不器用だったことも、ころんと収まって転がっていく。手のひらにのせると昨日のわたしがほんのり温かくて、今日もよく生きたと背中をぽんと叩いてくれる。"},"ICON-1083":{"nm":"ほめ言葉メモ瓶","on":"瓶","de":"いい言葉はあまりに簡単に散ってしまうから、この瓶に一枚ずつ折って入れておく。ほめ言葉が香りのように溜まると、心がうつろな夜にふたを開ける。誰かがくれた優しさひとつをまた取り出して読めば、その日のぬくもりがよみがえる。"},"ICON-1084":{"nm":"仲直りリボンひも","on":"ひも","de":"もつれた心は結び目に似ていて、ほどくときも手間がいる。二人がひもの両端を持ってゆっくり引けば、いつのまにかきれいなリボンひとつ。仲直りとは切ることではなくまた結ぶことだと、このひもが静かに教えてくれる。"},"ICON-1085":{"nm":"感謝トークン","on":"トークン","de":"ありがとうの言葉が口からなかなか出てこない日、代わりにトークンをひとつそっと手渡す。受け取った手はその小さな重みで気持ちをすっかり読み取る。言葉より先に届く真心――まるい一粒に情が込められて渡っていく。"},"ICON-1086":{"nm":"休憩時間マーク","on":"休憩時間マーク","de":"一日じゅう走ってきた練習室にも、息を整える一拍が必要だ。このマークを扉に掛けると時間がしばし遅くなる。休符があってこそ歌が息をするのだと、息せき切った一日を生きてみた人はみな知っている。"},"ICON-1087":{"nm":"秘密の感情ひきだし","on":"秘密の感情ひきだし","de":"胸のうちを全部出して見せられない日がある。そんなときは心の中の小さなひきだしひとつに、悲しみもときめきもそっと入れて閉じておく。今は置いておいても大丈夫――いつかゆっくり開いて整理する日が来るから。"},"ICON-1088":{"nm":"笑顔シールロール","on":"笑顔シールロール","de":"一マスずつはがすと笑顔マークがひとつ指先につく。ノートの隅に、友だちのロッカーにそっと貼っておく小さな明るさ。紙の上に小さな太陽が昇れば、それを見つけた誰かの一日が少し明るくなる。"},"ICON-1089":{"nm":"おたよりベルチャーム","on":"おたよりベルチャーム","de":"遠くにいる君に届きたい気持ちが鈴ひとつに結ばれた。振ると澄んだ音が便りを代わりに伝える。元気かと言えなかった日――この小さな響きが風に乗って先に届く。"},"ICON-1090":{"nm":"春雨カバーピン","on":"ピン","de":"春雨の降る日は大事なものほど濡れやすい。このピンで表紙をとめれば雨粒がそれて流れる。大切な一冊を懐に包む心――小さなピンひとつがその優しさを代わってくれる。"},"ICON-1091":{"nm":"夏のクーリングシール","on":"シール","de":"真夏の暑さに疲れた手の甲にぽんと一枚。ひんやりした冷気がハッカのように広がって汗が一段引く。縁側に寝そべってうちわをあおいだあの涼しさを、手のひらほどの紙がけなげに真似てみせる。"},"ICON-1092":{"nm":"秋チェックの布切れ","on":"秋チェックの布切れ","de":"秋の野原に似た格子模様の布一切れ。すり切れた所を誰かが丁寧に当てた跡だ。捨てずに繕って使う心――小さな布が集まって、すり減ったものをまた温かくよみがえらせる。"},"ICON-1093":{"nm":"冬の手袋クリップ","on":"クリップ","de":"冬の手袋はなぜかしょっちゅう片方ずつ逃げていく。このクリップで二つをつないでおけば、かじかんだ手が道に迷わない。なくしたくない気持ちが小さな金具に宿って、両方を並んで守る。"},"ICON-1094":{"nm":"梅雨の防水タグ","on":"梅雨の防水タグ","de":"梅雨どきは名札さえ雨水ににじむ。防水加工を施したこのタグは、降りしきる雨の中でも文字を守りぬく。雨上がりにもくっきり残る一行――これが誰のものか、最後まで忘れないために。"},"ICON-1095":{"nm":"初雪保管瓶","on":"瓶","de":"初雪は手に触れた瞬間に消えてしまうから、そのときめきだけでも瓶に詰めておいた。ガラスの中に閉じ込めたのは雪ではなく、あの日ときめいた心。振れば冬がひとつまた舞い散って、あの朝へ連れていってくれる。"},"ICON-1096":{"nm":"祝日袋の帯","on":"帯","de":"祝日の袋を巻く赤い帯一本。中身よりも手渡す手の情のほうが大きいことを、みな知っている。元気でという言葉と福を一緒に包む心が、この細い帯の中にきれいに結ばれている。"},"ICON-1097":{"nm":"ピクニック食器バンド","on":"バンド","de":"敷物を広げてお弁当を開けると、風がしきりにふたをめくる。このバンドで食器をしっかりとめれば、ピクニックが乱れない。持ってきた一食を最後まで守ろうとする心が、小さな帯ひとつに込められている。"},"ICON-1098":{"nm":"季節の香りサンプルカード","on":"カード","de":"開けてみなくても季節がわかるように、カード一枚にその季節の香りを込めた。春には花、秋には枯れ葉の匂い。鼻先をかすめた瞬間その季節がまるごと浮かぶ――「これが四月の空気」。"},"ICON-1099":{"nm":"値札クリップボード","on":"値札クリップボード","de":"値札がしょっちゅう飛んでいった露店の悩みの種を、このクリップボードひとつが鎮めた。数字をしっかりくわえて客の前にまっすぐ差し出す。商いの最初の挨拶は、乱れのない正直な一行から始まる。"},"ICON-1100":{"nm":"営業中ひっくり返し板","on":"板","de":"戸口にこの板を裏返して掛けると、店がようやく目を覚ます。「準備中」から「いらっしゃいませ」へ。一日の始まりを告げる小さな合図――店主の手が毎朝一番に触れる場所だ。"},"ICON-1101":{"nm":"クーポンスタンプパッド","on":"パッド","de":"十マスを全部埋めると、なぜかいいことが起こる。スタンプのひとつひとつが常連の足取りであり、積み重なってきた情だ。パッドにインクが乾くほど押された跡ごとに、また来るという小さな約束が生きて息づく。"},"ICON-1102":{"nm":"紙袋取っ手キャップ","on":"キャップ","de":"紙袋の取っ手は重さの前でいつも弱い。このキャップをはめると、切れそうだったひもが頼もしくなる。中身を無事に家まで連れて帰ろうとする心――小さな部品ひとつがその道を最後まで支えてくれる。"},"ICON-1103":{"nm":"レジの小銭皿","on":"皿","de":"おつりを手から手へ渡すときのためらいを、この皿が静かに和らげてくれる。小銭がちゃりんと鳴って居場所を見つける音。やりとりがいっそう温かくなるのは、こんなまるい心遣いのおかげだ。"},"ICON-1104":{"nm":"ポイント積立チップ","on":"チップ","de":"今日踏みしめた足取りがチップひとつにこつこつ積もる。溜まるほど心が軽くなる不思議な計算。少しずつ満たしていく楽しさは、空っぽの甕がいつのまにか満ちていくのを見守る喜びに似ている。"},"ICON-1105":{"nm":"陳列棚ナンバーピン","on":"ピン","de":"陳列棚ごとに小さな番号ひとつが優しく刺さっている。どこに何があるか教えてくれる静かな道しるべ。迷わないよう前もって場所を教えておく心――秩序にもこうして温かさが宿る。"},"ICON-1106":{"nm":"試食串カップ","on":"カップ","de":"試食ひと口を刺して差し出す小さなカップ。ためらっていた客もこのひと切れにそっと心を開く。「ひとつどうぞ」と勧める人情が串の先にぶら下がって、初めて来た人の足を引きとめる。"},"ICON-1107":{"nm":"予約名簿ホルダー","on":"ホルダー","de":"今日来る客の名前がこのホルダーにきちんと立っている。待つことにも順番があるという優しい約束。紙一枚をまっすぐ立てておくことが、誰かの一日を心をこめて迎える最初の準備になる。"},"ICON-1108":{"nm":"壁写真クリップひも","on":"クリップ","de":"壁にひもを張って写真をクリップでひとつずつ掛ける。笑っていた瞬間たちが洗濯物のように並んで吊るされて乾く。日差しの差す場所に思い出を干しておけば、通りかかるたびにあの日の笑顔がまたはためく。"},"ICON-1109":{"nm":"ミニラグコーナー","on":"ミニラグコーナー","de":"部屋の隅に敷かれる小さなラグ一枚。冷たい床に真っ先にぬくもりを広げてくれる場所だ。素足が一番に触れる一尺――家に帰ってきた足先が、ここでようやく安心してくつろぐ。"},"ICON-1110":{"nm":"表札隠し布","on":"表札隠し布","de":"表札をそっと隠す布一幅。名前をしばし隠しておくのも暮らしの粋だ。内と外の境をきれいに垂らす一すじ――今日は静かに休みたいという気持ちが柔らかく掛かる。"},"ICON-1111":{"nm":"照明コードクリップ","on":"クリップ","de":"垂れ下がった照明コードをこのクリップがきちんと押さえてくれる。光が乱れないよう、道をまっすぐ伸ばしてくれる手。夕暮れが訪れるころ散らかった線一本を整えると、部屋の光も心も一段落ち着く。"},"ICON-1112":{"nm":"ポスター磁石キャップ","on":"キャップ","de":"ポスターを壁に貼る小さな磁石キャップ。画びょうの穴ひとつ開けずに紙が居場所を守る。大切なものを扱う手はいつも優しいもの――傷めずに置いておく心がここに込められている。"},"ICON-1113":{"nm":"カーテンタッセルひも","on":"ひも","de":"カーテンの裾を片側に結んでおくタッセルひも。朝の日差しが入る道をきれいに開けてくれる。房のついたひもをひと引きすると、部屋の中へ明るい一日がぐっと押し寄せてとどまる。"},"ICON-1114":{"nm":"アロマキャンドル受けラベル","on":"ラベル","de":"アロマキャンドルの受けに貼る小さなラベル一枚。どんな香りが燃えているか、いつ初めて灯したか、きちんと書いておく。好きな匂いに名前を付けておくこと――そのきちんとさが部屋の空気をいっそう優しくする。"},"ICON-1115":{"nm":"飾り棚ゴム足","on":"飾り棚ゴム足","de":"棚が揺れないよう支えるゴム足が四つ。見えない場所で黙々と重さに耐える。小さく低くて目立たないけれど、一番下で踏ん張るものが結局一番長くもつ。"},"ICON-1116":{"nm":"方向標識矢印チャーム","on":"方向標識矢印チャーム","de":"どこへ行けばいいか迷う人のために、矢印ひとつが静かに方向を指す。道に迷うなという優しい手招き。分かれ道ごとに誰かが先に立てておいた心のおかげで、今日も迷わず進める。"},"ICON-1117":{"nm":"島招待キーホルダー","on":"ひも","de":"島へ招く人の手に握らせるキーホルダー。これを受け取ればもう君もこの土地の家族だ。見知らぬ客を温かい内へ迎え入れるもてなしが、ひもの先にぶら下がった小さな約束にしっかり込められている。"},"ICON-1118":{"nm":"関係温度チップ","on":"チップ","de":"二人の間の温度をチップひとつがそっと教えてくれる。まだよそよそしい青なのか、いつのまにか温かい緋色なのか。情が深まる速さは測りにくいけれど、手のひらはそのぬくもりを先に感じ取る。"},"ICON-1119":{"nm":"好み見本箱","on":"箱","de":"何が好きかまだわからないときは、小さな見本をひと箱に詰めて手渡す。選んでみる楽しさの中で好みがゆっくり育つ。どれが君のものになるか――箱の中にはわくわくする可能性がいっぱいだ。"},"ICON-1120":{"nm":"お世話予約ピン","on":"ピン","de":"誰かをお世話するという約束が、このピンひとつにくっきり刺さる。名前と時間を書いておけば心が道に迷わない。互いの子を代わるがわる見てあげたあの優しい助け合いが、ここに生きて息づく。"},"ICON-1121":{"nm":"成長記録カプセル","on":"成長記録カプセル","de":"戸枠に背を測った跡が一すじずつ積もるように、このカプセルは昨日の君をそっと封じておく。遠い未来にふたを開ければわかるだろう。小さかった足取りがどれほど遠くまで歩いてきたかを。"},"ICON-1122":{"nm":"初対面保管帯","on":"帯","de":"初めて手を取り合ったあのときめきを、帯ひとつにそっと結んでおく。結び目はほどくためにあるのではなく、その日のぬくもりを手首にずっと生かしておくためにそこにとどまる。"},"ICON-1123":{"nm":"マイルーム小物ラベル","on":"ラベル","de":"「ここがわたしの場所」。小さなラベル一枚が机の角に貼られた瞬間、見知らぬ部屋がようやく息をついてマイルームになる。名札は心が初めて降り立つ場所だ。"},"ICON-1124":{"nm":"親密度ビー玉缶","on":"缶","de":"振るところころ、二人の間が一マス近づく音が転がる。缶がいっぱいに満ちるころには、名前を呼ぶだけで笑顔が先に迎えに出ているはず。"},"ICON-1125":{"nm":"デビュー準備封印シール","on":"デビュー準備封印シール","de":"封筒を閉じる最後の一枚。ここまでが準備、次のページをめくれば舞台だ。指先でぎゅっと押しながら練習生は息を整える。ついに、始まりだ。"},"ICON-1126":{"nm":"水","on":"水","de":"一番ありふれているから一番貴い。火の消えた明け方の練習室、たった一口がへたり込んだ人をまた立ち上がらせる。決まった形を持たず、どんな器にもしみ込む優しさ。"},"ICON-1127":{"nm":"澄んだ水","on":"澄んだ水","de":"底の小石まで明るく映す透明さ。山あいの湧き水は自分の澄みを一度も自慢しない。隠すもののない心は、いつもこうして底まで見通せる。"},"ICON-1128":{"nm":"海水","on":"海水","de":"舌先に触れた瞬間、遠い波が押し寄せる。塩辛いひと口の中に水平線とカモメ、離れてきた港がまるごと溶けている。海はいつも、しょっぱく記憶に残る。"},"ICON-1129":{"nm":"氷","on":"氷","de":"手のひらの上でするすると小さくなり、握ったぶんだけ消えていく。固く見えても結局は水に戻ることを知っているもの。氷はしばし息を止めた川だ。"},"ICON-1130":{"nm":"雪玉","on":"雪玉","de":"ぎゅっと固めたひと塊が路地を切り裂いて真っ白に飛んでいく。けらけら笑う声と赤く凍えた頬。冬が子どもたちにそっと握らせる、一番真っ白なおもちゃ。"},"ICON-1131":{"nm":"土","on":"土","de":"種を抱き、雨水を飲み、通り過ぎる足跡を黙って受け止める。すべてを抱きしめる黒い肌。育つものすべての最初の場所には、このひと握りがある。"},"ICON-1132":{"nm":"肥沃な土","on":"肥沃な土","de":"指をぐっと入れるとふかふかと巻きついてくる黒い脂。おばあちゃんの畑が毎年青々としていた秘密が、まさにここにあった。よく寝かせた土は堆肥の匂いで豊作をささやく。"},"ICON-1133":{"nm":"粘土","on":"粘土","de":"水気を含んだ瞬間、どんな形でも素直に受け入れる。手のままに鳥になり器になる優しい肌。ろくろが回る間、ひと握りの土がようやく夢を見る。"},"ICON-1134":{"nm":"砂","on":"砂","de":"指の間からするすると抜けていく細かな粒たち。つかむほど早くこぼれ落ちて、しきりに時間に似てくる。浜辺のひと握りには、数えきれない昨日が眠っている。"},"ICON-1135":{"nm":"小石","on":"小石","de":"小川のほとりで丸く削れた石たち。とがった角が消えるまで水が長い時間をかけて撫でた跡だ。遠くまで転がってきたものほど、手の中にきれいに収まってくる。"},"ICON-1136":{"nm":"石","on":"石","de":"道端に何気なく置かれたひと塊。ある人はぽんと蹴って通り過ぎ、ある人はそっと拾って塔を積む。同じ石が心しだいで荷にもなり願いにもなる。"},"ICON-1137":{"nm":"敷石","on":"敷石","de":"古い宮殿の庭を横切る平たい石。何百年もの靴が踏んで通り、真ん中がくぼんでいる。一歩ずつ踏みしめる人ごとに、そこに時間を一層加えていく。"},"ICON-1138":{"nm":"石灰石","on":"石灰石","de":"海だったころの貝が幾層にも固まって白い石になった。窯に入れば石灰にほどけて塀を真っ白に塗る。静かに見えても、ひと時代をまるごと抱えた石だ。"},"ICON-1139":{"nm":"石炭","on":"石炭","de":"黒く眠ってしまった昔の森。何億年も前のシダ植物が地中深くで固く凝った塊だ。火をつければ、長く埋めておいた陽の光がめらめらとまた目を覚ます。"},"ICON-1140":{"nm":"炭","on":"炭","de":"火は含むが煙は静かに飲み込む。窯の中で黒く締まった木が、火鉢の上で黙って赤く咲き上がる。寡黙なものほど、長く温かい。"},"ICON-1141":{"nm":"小枝","on":"小枝","de":"折れまいと黙々と曲がってきた枝は、しなる術を知っている。きつい風に耐えた所ごとに節ができ、本当の硬さとは結局うまくしなった跡だ。"},"ICON-1142":{"nm":"丸太","on":"丸太","de":"切られた年輪の中に百回の春と冬がまるく重なっている。一本が生き抜いた歳月がまるごと横たわり、いま家の柱になる番を静かに待っている。"},"ICON-1143":{"nm":"木材","on":"木材","de":"かんなが通るたびに香しい木目が一層ずつ現れる。粗かった木が滑らかになる間、おがくずが床に黄色い雪のように積もる。整える手が用途を呼び覚ます。"},"ICON-1144":{"nm":"板","on":"板","de":"床を張り、縁台を組み、塀を巡らす。まっすぐ挽いた一枚一枚が集まれば、ようやく人の住む場所が立つ。ありふれたものが積み重なって住みかになる。"},"ICON-1145":{"nm":"竹","on":"竹","de":"中は空っぽでも風の前にまっすぐだ。節ごとに区切ってまた新しく伸びるその気概を、昔の学者たちは似たいと願った。空いているからかえってより凛とまっすぐなものが、ここにある。"},"ICON-1146":{"nm":"コルク","on":"コルク","de":"ぎゅっと押して離せばまた元の厚さにふくらむ。軽いのに粘り強いこの質感を見ると、柔らかいことが決して弱さではないとわかる。瓶の栓から掲示板まで、静かに支えてくれる。"},"ICON-1147":{"nm":"草","on":"草","de":"踏まれても次の雨が降ればまた立ち上がる。名前ひとつなく野原をまるごと覆っていく緑の粘り。小さいと侮ってはいけない、春を一番先に告げるのはいつもこの低い場所だ。"},"ICON-1148":{"nm":"わら","on":"わら","de":"秋の収穫が終わった野に黄色く残ったもの。編めば屋根になり、敷けば温かい寝床になった。実を全部差し出してもなお、最後まで人を覆ってくれる心だ。"},"ICON-1149":{"nm":"葦","on":"葦","de":"風がかすめるとさらさらと、川辺がまるごと歌う。中が空いているからより遠くまで鳴る茎。揺れるその姿こそが自分の歌だと、葦は少しも恥じない。"},"ICON-1150":{"nm":"綿花","on":"綿花","de":"実ったさやがぱちんとはじけると小さな雲ひと房が咲く。軽く柔らかなこの綿が糸になり服になって、凍える冬の夜、誰かの肩をそっと温める。"},"ICON-1151":{"nm":"羊毛","on":"羊毛","de":"手につくと脂が回り、ぬくもりが静かに残る。寒い山に耐えるようにと羊が自分の身にまとっていた外套。刈り取ったそのぬくもりが、いま人の冬へ移ってくる。"},"ICON-1152":{"nm":"糸","on":"糸","de":"見えるか見えないか細くても、離れた二筋をまたつなぐのはいつもこれだ。一本では弱くても、編めば一幅の布になる。つなぐことに、太さは重要じゃない。"},"ICON-1153":{"nm":"布","on":"布","de":"横糸と縦糸が幾度も交わって一幅をなす。ひとりでは解けてしまう糸たちが互いをぎゅっとつかんだ結果だ。密なほど温かいのは、人と人の間もまったく同じ。"},"ICON-1154":{"nm":"革","on":"革","de":"使うほど手垢がしみて持ち主に少しずつ似ていく。最初の硬さがなじむ間に色は深まり、肌は柔らかくなる。時間が刻んだその艶は、何をもっても真似できない。"},"ICON-1155":{"nm":"羽根","on":"羽根","de":"手のひらにのせても重さを感じないほど軽い。空を飛んだ記憶がそのまま宿った一筋。一番軽いものが一番高く昇ったことを、どうか忘れないで。"},"ICON-1156":{"nm":"貝殻","on":"貝殻","de":"耳に当ててごらんと言ったおばあちゃんの言葉がふと浮かぶ。内側の虹色には離れてきた海がまるごと刻まれていて、空の殻からもひと時代の揺らめきが聞こえてくる。"},"ICON-1157":{"nm":"サンゴ","on":"サンゴ","de":"石のように固まったけれど、かつては確かに息づいていた群れだった。ゆっくりした海の中で何百年もかけて枝を伸ばしていく。一番固い枝は、一番長く待った末にようやく育つ。"},"ICON-1158":{"nm":"真珠","on":"真珠","de":"砂一粒のさわりに耐えきれず、貝はそれを光でそっと包んでしまった。痛みを丸く抱けばこんなにきらめくのだと、海が差し出す小さな慰めだ。"},"ICON-1159":{"nm":"海藻","on":"海藻","de":"引き潮になった磯の岩につるりと垂れた緑の帯。手に握ると生臭い潮の香りがふっと押し寄せる。根もなく潮の流れに身を任せたまま、海は静かに自分の庭を育てる。"},"ICON-1160":{"nm":"海苔","on":"海苔","de":"黒い一枚を火に少しあぶると青々となって香ばしい匂いが広がる。炊きたてのご飯にくるくる巻いたあの朝。薄っぺらくても一食の幸せをゆうゆうと包み込む。"},"ICON-1161":{"nm":"塩","on":"塩","de":"海が陽光に置いていった白い結晶だよ。ひとつまみで薄かった汁が深まり、手が滑ればすべての味を覆ってしまう。ほどよさを知る指先だけがわたしを上手に使いこなせるんだ。"},"ICON-1162":{"nm":"ガラスの欠片","on":"ガラスの欠片","de":"割れたその場所でようやく光を曲げて虹を咲かせる。無傷のときには知らなかった芸当だ。砕けたものにも陽の光を分け与える役目が残っていると、窓辺に横たわる欠片が静かに教えてくれる。"},"ICON-1163":{"nm":"ガラス","on":"ガラス","de":"透明だということは、隠すものがないという意味だけじゃない。光をまるごと通すために自分の姿を消したんだ。見えずにそこにとどまることにも、手が触れればひんやりした端正さがある。"},"ICON-1164":{"nm":"ガラス瓶","on":"瓶","de":"中が空っぽでこそ何かを入れられる。ジャムでも野の花ひと握りでも折った手紙でも、入ってくるものによって名前が変わる。空けることを恐れない器が一番おおらかなんだ。"},"ICON-1165":{"nm":"空き瓶","on":"瓶","de":"飲み終えた後に訪れる静けさが好きだ。誰かはわたしを捨て、誰かはすすいで窓辺に置いて陽の光を満たしてくれる。終わった場所でまた役目を得ること、それが空けられたものの二度目の生だ。"},"ICON-1166":{"nm":"紙","on":"紙","de":"何でも受け取って書く構えで真っ白に広がっている。最初の一行をためらう人の心を一番長く見つめるのは、いつもわたしだ。白紙の忍耐はインクより一尺深い。"},"ICON-1167":{"nm":"古い紙","on":"古い紙","de":"黄ばんだのは老いではなく耐えたこと。折り目ごとに広げて読んだ手のぬくもりがしみている。古い紙は忘れられまいと、自分の色で流れた時間を記しておくんだ。"},"ICON-1168":{"nm":"インク","on":"インク","de":"一滴から始まって文章になり、乾けば約束のように残る。にじめばにじんだままその日の痕跡だ。取り返せなくするのがわたしの仕事だから、人はわたしをもう一度慎重に押す。"},"ICON-1169":{"nm":"鉄鉱石","on":"鉄鉱石","de":"地中で赤い眠りについていた石だ。火の中を一度通ってこそ、ようやく内に秘めた鉄を差し出す。硬さは初めから硬いのではなく、熱さを通り抜けた後に受けた名前だ。"},"ICON-1170":{"nm":"鉄塊","on":"鉄塊","de":"鉱石が火に耐えてからようやく一塊に冷えた。冷たく重いこの形が橋にもなり刀にもなり鋤にもなる。用途がまだ決まっていないから、わたしは何にでもなれる。"},"ICON-1171":{"nm":"銅鉱石","on":"銅鉱石","de":"青りんご色の緑青をまとって土から抜け出てきた。溶かせば鐘が鳴り銅像が立ち電線が流れる。真っ暗な地に眠っている間も、わたしはいつも何かに呼ばれる番を待っていたんだ。"},"ICON-1172":{"nm":"銅塊","on":"銅塊","de":"長くそばに置くと青い衣を自分の手で仕立てて着る。その色を傷と呼ぶ人も、歳月の模様だと撫でる人もいる。変わりゆく自分の色を恥じない金属が、一番長く愛される。"},"ICON-1173":{"nm":"金鉱石","on":"金鉱石","de":"川砂をすくってまたすくって出会った一点だ。ありふれていないから貴いのではなく、変わらないから貴い。錆びない心に似なさいと、昔の人はこれを手に握らせて証として渡した。"},"ICON-1174":{"nm":"金塊","on":"金塊","de":"くもりも錆びもせず一塊で横たわっている。人々の欲を一番多く聞いてきたのに、当のわたしは何も欲しがらない。ただ輝くことだけに忠実な重々しい沈黙だ。"},"ICON-1175":{"nm":"くず鉄","on":"くず鉄","de":"用途を終えたのではなく、次の用途を待っている最中だ。折れた釘とへこんだ缶が一か所に集まって、また熱い火と出会う。捨てられたという言葉は、わたしにはしばし休んでいる最中という意味だ。"},"ICON-1176":{"nm":"ねじ","on":"ねじ","de":"ひとりでは何もできない。回し込んで二枚の板をぎゅっとかみ合わせるときにこそ、ようやく役目を果たす。小さな体で大きなものを支える芸、締めるその力にも誠がこもる。"},"ICON-1177":{"nm":"釘","on":"釘","de":"一度刺さるとなかなか退かない。金づちが打ちつけるたびに深まるのは傷ではなく約束だ。何かをしっかりつなぐことなら、わたしは喜んで頭を差し出す。"},"ICON-1178":{"nm":"歯車","on":"歯車","de":"隣の歯を押して一緒に回る。ひとりで速く行こうとせず、そばの速さに合わせる術を知っている。かみ合ってこそ時間が流れる時計のように、調和こそが動きだとわたしは信じる。"},"ICON-1179":{"nm":"ばね","on":"ばね","de":"押されれば押されるほど、戻る力を内に集める。曲がるのは諦めではなく、また伸びるための備え。衝撃を受け止めたぶんだけ跳ね返す、しなやかさがそのまま硬さである小さならせんだ。"},"ICON-1180":{"nm":"電線","on":"電線","de":"外はおとなしい被覆、内は絶え間なく流れる道だ。見えない所で光と音を運んでいく。舞台裏を黙々とつなぐ手のように、表に出ないからいっそう頼もしい通路だ。"},"ICON-1181":{"nm":"電池","on":"電池","de":"半日の明るい光を小さな体の中にこつこつと収める。使い切ればまた満たせばいいと、空っぽを決して終わりとは思わない。誰かの長い夜を照らす小さな夕べを抱いている。"},"ICON-1182":{"nm":"電球","on":"電球","de":"細い糸一筋が赤く熱を帯びて闇を押しのける。自分の身を燃やして部屋を温めるのではなく、明るくする仕事だ。点くときが一番熱く、だから一番明るい一瞬の小さな太陽だ。"},"ICON-1183":{"nm":"レンズ","on":"レンズ","de":"散らばっていた光を集めて一点にくっきり立てる。はるか遠くの星も、手のひらの上の小さな文字も静かに呼び寄せる。見ることを助けながら当の自分の姿は隠す、澄んだ丸い仲人だ。"},"ICON-1184":{"nm":"ゴム","on":"ゴム","de":"押しても伸ばしても結局元の場所に戻る。柔らかいとけなした人も雨の日にはわたしを選んで履く。きつい衝撃を柔らかく受け止めること、この柔らかさの中にも粘りが生きている。"},"ICON-1185":{"nm":"プラスチックの欠片","on":"プラスチックの欠片","de":"本体から離れて出てきた小さな欠片だ。捨てられかけたけれど、たくさん集まればまた新しいものになる。小さいから軽いのではなく、軽いから遠くまで行ける何かの一部分だよ。"},"ICON-1186":{"nm":"縄","on":"縄","de":"何本もよじってこそようやく一本になる。ひとりではたやすくほどけるけれど、編めば船も引き荷も縛る。一緒にねじれたぶんだけ丈夫になる、手のひらにざらつく協力の古い結び目だ。"},"ICON-1187":{"nm":"帆布","on":"帆布","de":"風を憎まず胸いっぱいに抱く。ぴんとふくらんでこそ船を遠くへ送るから、向かい風さえわたしには力になる。激しいものに逆らわず抱きしめて進む術を、海で学んだ。"},"ICON-1188":{"nm":"錨の欠片","on":"錨の欠片","de":"錨の一隅だけれど、その重みだけは丸ごと覚えている。深い底をつかんで船を止めていたあの時代を。離れて出てきた今も、とどまることの重みを知る重々しい欠片だ。"},"ICON-1189":{"nm":"船釘","on":"船釘","de":"波に揺れる甲板を一点一点つなぎとめていた釘だ。潮気に赤く錆びても、最後まで自分の場所を放さなかった。漂うものをしっかりつかむことにも、ねばり強さがいる。"},"ICON-1190":{"nm":"防水布","on":"防水布","de":"雨を防ぐことに文句がない。上から降りそそぐものを黙々と受け止め、下のものを乾いたまま守る。華やかでなくても誰かの荷を濡らさず覆ってくれる、頼もしい一層だ。"},"ICON-1191":{"nm":"染料","on":"染料","de":"木綿の布にそっとしみ込んでこそ、ようやく色になる。藍でも茜でも、昔の母たちは指先を染めながら布に色を着せた。沈んでしみ込むことにも、なかなか抜けない深さがある。"},"ICON-1192":{"nm":"香料オイル","on":"香料オイル","de":"たった一滴で部屋いっぱいに広々とした野原がぐっと開ける。目に見えなくても一番先に到着する客。眠った記憶の裾をそっと引っぱる、鼻先に先に触れる風景だ。"},"ICON-1193":{"nm":"ろう","on":"ろう","de":"熱を受けると流れ、冷めると固まってその形を保つ。柔らかさと硬さの間を行き来して何でも静かに型取る。閉じ、封じ、艶を出す、温度によって表情を変える優しい素材だ。"},"ICON-1194":{"nm":"ろうそく","on":"ろうそく","de":"自分の身をゆっくり溶かして闇のひと区画を照らす。燃え尽きれば短くなった背丈だけが残るけれど、誰かの夜を温めたその時間は消えない。小さくなりながら輝く術を知るまっすぐな芯だ。"},"ICON-1195":{"nm":"堆肥","on":"堆肥","de":"腐っていくものが一か所に集まって、一番肥えた土になる。捨てられた皮と乾いた落ち葉が春の新芽のご飯になるわけだ。終わったと思ったその場所で、次の命が静かに最初の息を整える。"},"ICON-1196":{"nm":"米","on":"米","de":"一粒を手にするまで八十八回手がかかるという。田植えから脱穀まで、農夫の一年がこの小さな粒に余すところなく込められる。湯気の立つご飯一杯が、そのまま誰かの四季だ。"},"ICON-1197":{"nm":"玄米","on":"玄米","de":"外皮だけそっとむいたまま、本来の色をそのまま保った。噛むほど香ばしくなるのは、急がなかった正直さの味だ。きれいに削られるのを拒んで粗い肌を残した、穀粒の固い意地だ。"},"ICON-1198":{"nm":"小麦","on":"小麦","de":"風にいっせいに頭を垂れた黄金の野原を覚えている。パンになり麺になりすいとんになって、世界のあちこちの食卓を温める。ありふれているからかえってより深く、人の暮らしの中にしみ込んだ穀物だ。"},"ICON-1199":{"nm":"小麦粉","on":"小麦粉","de":"きめ細かな白い粉になってこそ、ようやく何にでもなる構えを整える。水に出会えばふくらみ、火に出会えば焼ける。定まった形がないから、手が練るままに形を得る素直な土台だ。"},"ICON-1200":{"nm":"生地","on":"生地","de":"粉と水が手のひらの下でひと塊に溶け合う。こねたぶんだけもちもちになり、待ったぶんだけぷっくりふくらむ。急げばかたくなるから、発酵の時間だけは急かせないと、古いパン屋は言う。"},"ICON-1201":{"nm":"パン粉","on":"パン粉","de":"指先についた白い粉を払っていると、いつのまにか袖口まで真っ白。衣になればサクサク、こんもり積もれば初雪のよう。パン一塊が焼けて残した一番軽い痕跡だけれど、小さなものにも使い道は育っていく。"},"ICON-1202":{"nm":"パスタ麺","on":"パスタ麺","de":"煮立つ湯にひとつかみを扇のように広げる瞬間、台所に遠い日差しが渡ってくる。長い麺は手首の仕事、アルデンテは少し火が通りきらないまま待つことを知る心。フォークにくるくる巻きつくその艶を見て。"},"ICON-1203":{"nm":"ラーメン","on":"ラーメン","de":"舞台の化粧をすっかり落とした明け方、こっそり鍋にかける一袋。麺がほぐれる3分が一日で一番プライベートな時間。ふうふうと吹く息と一緒に緊張も冷め、湯気で曇った眼鏡の向こうで今日が静かに終わる。"},"ICON-1204":{"nm":"餅","on":"餅","de":"米が臼の打擲に耐えてはじめて餅になる。白餅に、きな粉餅に、松餅に——同じ穀物が手の味によって百もの名を得る。祝いの膳に上れば口より情が先に呼ぶ、分け合ってこそ本領の食べ物。"},"ICON-1205":{"nm":"雑煮餅","on":"雑煮餅","de":"細長い餅を斜めに切れば小さな硬貨のように丸い。白いだしに浮かぶのは餅だろうか、丸い願いだろうか。新年最初の朝に一椀を空ければ年が一つ増えるのが、優しくもこの国の数え方だ。"},"ICON-1206":{"nm":"じゃがいも","on":"いも","de":"土をぽんぽん払えば丸い顔が現れる。江原道の斜面の風にも黙々と太った塊根、蒸せばほくほく、焼けば香ばしい。懐の軽い日にも家族の腹をしっかり満たしてくれた正直な根だ。"},"ICON-1207":{"nm":"さつまいも","on":"さつまいも","de":"路地の入り口に焼き芋の釜が立てば、それがすぐ冬の始まりだった。ホイルをむけば黄色い湯気が指から温め、その甘さは寒さに耐えた根の報い。ふうふう吹きながら半分に割って分け合うのにちょうどいい温もり。"},"ICON-1208":{"nm":"にんじん","on":"にんじん","de":"土の中からまっすぐ伸びたオレンジ一本。うさぎだけが好きかと思いきや、炒めれば隠れた甘みが目覚め、汁物に入れば彩りまで添える。目にいいという昔の年寄りの言葉は、だいたい正しかった。"},"ICON-1209":{"nm":"大根","on":"大根","de":"白く重いこの根一つで冬の食卓が頼もしい。トンチミでひんやり、大根汁でさっぱり、カクテキでシャキッと。捨てるところがなく、青い葉まで軒に干してシレギに残す、つましい野菜だ。"},"ICON-1210":{"nm":"玉ねぎ","on":"玉ねぎ","de":"皮をむいていると涙がひと筋つるり。辛くてつんとする身も、熱した油に出会えば嘘のように甘くなる。ほとんどすべての韓国料理の一行目に記される名、黙々と香りの土台を敷く静かな主役だ。"},"ICON-1211":{"nm":"長ねぎ","on":"長ねぎ","de":"細かく刻んだ白い根元と青い葉を汁の上に散らせば、ようやく一椀が完成したかのよう。食べ残した根元を水コップに挿しておけばまたぐんぐん伸びてくる、暮らし上手の小さな窓辺の菜園だ。"},"ICON-1212":{"nm":"にんにく","on":"にんにく","de":"六片が丸く集まって一玉をなす。熊を人に変えたというその辛い根。包丁の背でとんとん刻めば香りがぱっと目覚め、キムチもチゲもこれひとつかみなしには到底話にならない。"},"ICON-1213":{"nm":"しょうが","on":"しょうが","de":"ごつごつと結び目のような形の小さな根。一切れ入れるだけで生臭さを鎮め、冷えた体を内側から温める。風邪でうんうん唸る夜、蜂蜜と一緒に煮出して飲んだあの温かい一杯が、このぴりりとした辛さから始まる。"},"ICON-1214":{"nm":"白菜","on":"白菜","de":"ぎっしり詰まった葉を塩に漬ければ、ようやくキムチの最初の章が開く。晩秋の庭ごとに山のように積まれたそれ。家族みんなで囲んで一玉を漬ける仕事は、長い冬を共に過ごそうという約束だった。"},"ICON-1215":{"nm":"キャベツ","on":"キャベツ","de":"幾重にも丸く巻かれた葉を一枚ずつむいていくと終わりがなく、いつのまにか心がゆったりする。茹でればやわらか、炒めれば甘め。素朴な見た目の中に意外な優しさを隠した野菜だ。"},"ICON-1216":{"nm":"レタス","on":"レタス","de":"くぼんだ葉に肉を一切れぽんと載せ、サムジャンまで添えて口いっぱいに頬張る。丸く囲んで包んで食べる席では誰もが格式をそっと下ろすから、これはほかでもない緑のもてなしだ。"},"ICON-1217":{"nm":"サンチュ","on":"サンチュ","de":"菜園の片隅で一番先に芽を出す葉。摘んでもまた生えて夏じゅう食卓を埋める。冷水でゆすいで手でさっと包んで食べたあの瑞々しい青臭さが、誰かには丸ごと故郷の味だ。"},"ICON-1218":{"nm":"ほうれん草","on":"ほうれん草","de":"缶詰を空ければ力が湧いてきた漫画の中のあの緑。茹でればひとつかみにきゅっと縮んでも香りと精気はそのまま。さっと和えても、味噌汁にひとつかみ溶いても良い——ありふれていると軽く見てはいけない野菜だ。"},"ICON-1219":{"nm":"ワラビ","on":"ワラビ","de":"春の山が差し出した柔らかな芽を折り、茹でてまた干す。その長い手間を経てはじめて祭祀膳にもビビンバにも上る。手がかかるだけ真心が幾重にも染みた、山が一季かけて育てた貴い山菜だ。"},"ICON-1220":{"nm":"山菜","on":"山菜","de":"名もなさそうでそれぞれ違う香りを抱いた春の贈り物。おばあちゃんの手は山道でどの葉が食べられるか一目で見分ける。山菜ひと籠に、その季節一つが香りごと包まれてついてくる。"},"ICON-1221":{"nm":"ヨモギ","on":"ヨモギ","de":"凍った地を一番先に突き破って伸びる、苦いような香しい草。餅にこねれば春の色がそのまま口に入る。正月にはこれで汁を炊いて一年の厄を防ぐと信じたから、春はいつもこの香りから来た。"},"ICON-1222":{"nm":"エゴマの葉","on":"エゴマの葉","de":"たった一枚でも口の中を濃く染める香り。こんがり焼けたサムギョプサルに添えたり醤油にきちんと漬けておけば、ご飯一膳があっという間だ。この独特な香りは、ただこの地の食卓でのみ親しい。"},"ICON-1223":{"nm":"ピーマン","on":"ピーマン","de":"中が空っぽのままシャキッと砕ける緑の実。ほんのり残る苦みが鈍った味覚を目覚めさせ、油で炒めれば色合いがいっそう鮮やかになる。細かく刻んで散らすだけで、どんな料理も一気にさっぱりする。"},"ICON-1224":{"nm":"パプリカ","on":"パプリカ","de":"赤、黄、オレンジ、信号機のような色合いがひと籠いっぱい。生でかじれば甘い汁がつるりと流れ、色だけで食卓が明るくなる。見た目の良い野菜が食欲もそそるという言葉がここにぴったり当てはまる。"},"ICON-1225":{"nm":"トマト","on":"トマト","de":"果物か野菜かいつも争われた丸い赤。じっくり煮れば味が深まり、生で食べればこの上なくさわやか。真夏の日差しを一番正直に集めた実だから、一口かじれば真昼が丸ごとはじける。"},"ICON-1226":{"nm":"きゅうり","on":"きゅうり","de":"夏の暑さを一番涼しく冷ましてくれる緑。冷たい汁にぷかぷか浮かべれば口の中がひんやりし、ソバキで漬ければシャキッとよみがえる。蒸し暑い日には薄く切って目の上に載せても良い、内も外も涼しい野菜だ。"},"ICON-1227":{"nm":"かぼちゃ","on":"かぼちゃ","de":"つるの先に丸くぶら下がり、晩秋までゆっくり甘みを満たす。じっくり煮れば黄色い粥になって腹を楽にし、焼けばこんがりしたチヂミになる。軒下に吊るしておけば冬じゅう頼もしい蔵の役目を果たす。"},"ICON-1228":{"nm":"ズッキーニ","on":"ズッキーニ","de":"夏の菜園で日ごとに太っていく若緑色。味噌チゲにざくざく、チヂミにこんがり——やわらかくて幼い子の口にも優しい。ありふれているからこそありがたい、真夏の食卓の常連だ。"},"ICON-1229":{"nm":"なす","on":"なす","de":"紫の艶がつやつやと光る細長い実。油を含めば限りなくやわらかくなり、じっくり蒸せば肌理が絹のように美しい。地味に見えても何と組み合わせてもよく馴染む、食卓の優しい脇役だ。"},"ICON-1230":{"nm":"とうもろこし","on":"とうもろこし","de":"一粒一粒きちんと列をなした黄色い粒。鍋で蒸してふうふう吹きながらかじった夏のおやつであり、野原が熟したという嬉しい合図だ。ふわふわのひげひと束の中に甘みがたっぷり入っている。"},"ICON-1231":{"nm":"豆","on":"豆","de":"小さく硬い粒が一晩水を含んでぷっくりふくらむ。細かく挽けば豆乳に、じっくり発酵させれば醤に——この地の食卓のたんぱく質は大抵ここから始まった。土に一粒埋めればまた一本に戻ってくる。"},"ICON-1232":{"nm":"豆腐","on":"豆腐","de":"豆が水を含み挽かれて固まれば、角の四角い白い塊になる。やわらかく素直で、どんな汁に入っても自分の色を押し通さない。スプーンですくってもさらりと崩れる、淡白さがそのまま美徳の食べ物だ。"},"ICON-1233":{"nm":"小豆","on":"小豆","de":"赤く小さな粒をじっくり煮れば、黒っぽい赤の甘みが濃く滲み出る。一番長い夜、温かい小豆粥一椀で寒さと邪鬼を共に追い払った心がここに宿る。蒸し餅に幾重にも重なるその赤い色は、すなわち真心だった。"},"ICON-1234":{"nm":"餡子","on":"餡子","de":"茹でた小豆を細かく潰して煮詰めてまた煮詰めて作ったやわらかな餡。パンの間に、餅の中に、かき氷の上にひとさじ——甘み一筋が昔の記憶まで温める。漉して煮詰めたその長い時間がそのまま甘みになる。"},"ICON-1235":{"nm":"きのこ","on":"きのこ","de":"雨上がりの薄暗い森の陰で音もなく顔をのぞかせる。日差しひとつなくても自分の香りを育てる土の腕前。汁にひとつかみ入れるだけで肉なしでも深い旨みが滲み出る、森が隠しておいた秘密だ。"},"ICON-1236":{"nm":"しいたけ","on":"しいたけ","de":"傘をぱっと広げた茶色い傘。日にしっかり干せば香りが何倍も濃くなり、乾いた一輪が汁一鍋を十分に引き受ける。菜食の食卓の頼もしい柱であり、深い味を知る者の長年の常連だ。"},"ICON-1237":{"nm":"松茸","on":"松茸","de":"秋の松林の奥深く、松のそばでだけそっと頭をもたげる。人が育てられず、ただ足で探し出すしかない香りだから一層貴い。さっと焼いて塩だけちょんとつけても、森の一片が口に入る。"},"ICON-1238":{"nm":"エリンギ","on":"エリンギ","de":"分厚い柄を繊維に沿ってざくざく裂けば歯ごたえが手に取れる。四季を通じて頼もしく育ってくれて、食卓から遠ざかる日がない。焼きに、炒めに——たっぷりした身の中に負担のない頼もしさがぎっしり詰まっている。"},"ICON-1239":{"nm":"いちご","on":"いちご","de":"冬を耐えたビニールハウスの端で一番先に赤く熟す。一口かじれば甘酸っぱく、まるで早春の最初の挨拶のよう。ケーキの上に丸くひと粒載せれば、なんでもない今日もすぐ記念日になる。"},"ICON-1240":{"nm":"ブルーベリー","on":"ブルーベリー","de":"ぷちっとはじければ口いっぱいに酸味が明るく広がる。紫の小さな玉をひと粒ずつつまんでいるといつのまにか容器が空になり、白い牛乳の上に散らせばそのまま小さな夜空が一つ広がる。"},"ICON-1241":{"nm":"りんご","on":"りんご","de":"一口かじればサクッと、秋が砕ける。果樹園のおばあちゃんがふきんでさっと拭いて手渡したあの赤は、日差しを長く抱いてはじめて入る色。硬いほど最後まで甘いすべを知っている。"},"ICON-1242":{"nm":"梨","on":"梨","de":"皮をむけば指先がまず冷んやりする。秋夕の祭祀膳の一番前列、ひんやりした甘い汁が口いっぱいに満ちる瞬間、秋の夜風がひと間、そっとそばに来て座る。"},"ICON-1243":{"nm":"桃","on":"桃","de":"桃の花が散った跡ごとにうぶ毛ふわふわの夏が実る。そっと押せば香りがまず広がり、一口かじる瞬間、季節まるごとが口の中へついて入る。"},"ICON-1244":{"nm":"ぶどう","on":"ぶどう","de":"紫の粒がひと房にぶら下がり互いの肩を寄せ合う。ぷちっとはじければ酸味が先で甘みは半拍遅れて——夏の終わりが呼ぶ端正な合唱のようだ。"},"ICON-1245":{"nm":"マスカット","on":"マスカット","de":"若緑色が日差しをそのまま通して粒ごとに灯がともる。種なしで爽やかな清涼感、たった今つむいだ最初のひと節のように無駄ひとつない甘みだ。"},"ICON-1246":{"nm":"レモン","on":"レモン","de":"黄色い皮を爪で引っかけば香りがつんと鼻先を目覚めさせる。一滴で口元が自然にすぼまっても、その酸味の終わりには妙に一日が明るくなるところがある。"},"ICON-1247":{"nm":"ライム","on":"ライム","de":"レモンより小さくもっと濃い青のこの実は、つんと刺す香りでまず挨拶を交わす。一切れあれば生ぬるい水も一気に目覚める——小さくてもしっかりしたひとつかみの清涼。"},"ICON-1248":{"nm":"オレンジ","on":"オレンジ","de":"皮をむく瞬間、指に日差しの匂いがつく。ひと房ずつ口に入れればぷち、ぷち、小さな甘い汁の風船がはじけて——丸いものは気分まで丸く転がしておく。"},"ICON-1249":{"nm":"みかん","on":"みかん","de":"冬のオンドルの暖かい床、布団に足を埋めてむいて食べたあの味覚えてる?爪の間に広がった香りが部屋じゅうを黄色く染めたよね。一袋あれば家族が囲んで座る口実になる。"},"ICON-1250":{"nm":"バナナ","on":"バナナ","de":"腹を空かせた明け方の練習室の隅、鞄から転がり出た黄色い一本で食事を済ませた日があった。やわらかく甘く頼もしい——一番優しい間に合わせ。"},"ICON-1251":{"nm":"パイナップル","on":"パイナップル","de":"棘の生えた外側を一枚通り過ぎてはじめて黄色い果肉が現れる。一切れ口に含めば甘酸っぱさが舌をつんと刺し、口元にはいつのまにか南の海の匂いが漂う。"},"ICON-1252":{"nm":"マンゴー","on":"マンゴー","de":"よく熟した果肉を手で割れば粘り気のある甘い香りが指を濡らす。濃い黄色が口の中でとろりと溶けて消えるとき、短い夏の昼寝のような甘い夢がよぎる。"},"ICON-1253":{"nm":"ココナッツ","on":"ココナッツ","de":"硬い殻を振れば中でちゃぷん、水の音がする。割れば白い果肉と涼しい汁——遠い海が丸ごと入って揺れる小さな甕だ。"},"ICON-1254":{"nm":"ドラゴンフルーツ","on":"ドラゴンフルーツ","de":"ピンクの鱗のような見た目に最初はたじろぐけれど、割ってみれば白い果肉に黒い粒が点々。味は素朴で装いは派手な、表と裏が正反対のおとぼけ者だ。"},"ICON-1255":{"nm":"キウイ","on":"キウイ","de":"うぶ毛をまとった茶色を半分に割れば緑の宝石が現れる。黒い種が星のように散った断面をひとさじすくって入れれば、酸っぱいひとさじが眠りを揺り起こす。"},"ICON-1256":{"nm":"鶏肉","on":"鶏肉","de":"油を引いたフライパンに載せればじゅう、こんがりした音がまず焼ける。淡白でやわらかく、誰の食卓にも無難に加わって座る——優しい一食の常連。"},"ICON-1257":{"nm":"豚肉","on":"豚肉","de":"焼き板の上でじゅうじゅう、油がぱちぱちはねてこんがり焼けていく。サンチュ一枚にサムジャンをちょんと載せて口いっぱいに頬張った会食の夜、香ばしさが場を温める。"},"ICON-1258":{"nm":"牛肉","on":"牛肉","de":"赤い繊維ごとに脂がきれいに入って光る。熱した石板に載せれば香りからその場を満たし、一切れ口に入れる瞬間、一日の疲れがそっとほどける。"},"ICON-1259":{"nm":"ベーコン","on":"ベーコン","de":"朝のフライパンの上でサクッと、脂が踊る。その塩辛い匂いひとつで寝坊していた家族も目をこすりながら台所に集まってくる——匂いがまず呼ぶ食事。"},"ICON-1260":{"nm":"ソーセージ","on":"ソーセージ","de":"切り込みを入れた所がぱっと開いてぷちっとはじける肉汁。弁当の一マスを引き受けた赤いタコの形、幼い昼休みが享受したささやかな贅沢だった。"},"ICON-1261":{"nm":"ペパロニ","on":"ペパロニ","de":"丸くてピリ辛なひと切れが熱いチーズの上で縁からくるんと丸まる。油が少したまればそれがまさに一枚の絶頂——小さくても存在感だけは丸く濃い。"},"ICON-1262":{"nm":"パティ","on":"パティ","de":"分厚くこねて焼き板に載せれば縁から茶色に焼けていく。押して焼いた一枚の間に野菜を挟めば、片手にすっぽり収まる頼もしさが完成する。"},"ICON-1263":{"nm":"卵","on":"卵","de":"こつんと割れば黄身が丸い太陽のように滑り出る。炊きたてのご飯に混ぜてもよし、キンパの中の黄色い筋になってもよし——一番ありふれていて一番優しいたんぱく質。"},"ICON-1264":{"nm":"牛乳","on":"牛乳","de":"明け方ドアの前に置かれた冷たい一本、手のひらに触れるそのひんやりで一日が開いたものだ。温めれば湯気が立ち冷やせば香ばしい——いつでもそばを守る白。"},"ICON-1265":{"nm":"チーズ","on":"チーズ","de":"黄色い一枚が温かいパンの上でゆっくり崩れていく。びよーんと伸びるその一瞬を待つ心——溶けるほど香ばしさはより深く濃くなる。"},"ICON-1266":{"nm":"チェダーチーズ","on":"チェダーチーズ","de":"濃いオレンジ色がひと目で塩辛い味を予告する。薄く切ってトーストに挟めば旨みが口いっぱいに広がり——色がはっきりしているだけ風味もはっきりしている。"},"ICON-1267":{"nm":"バター","on":"バター","de":"熱したフライパンにひと切れ落とせばとろりと溶けて香ばしい湯気が立ちのぼる。パンに塗り、ご飯に混ぜ、何に触れても一層やわらかくする黄色い魔法。"},"ICON-1268":{"nm":"生クリーム","on":"生クリーム","de":"泡立て器を回すほどゆるかった白が次第に固い雲にふくらんでいく。ケーキの上にひとさじ載せる瞬間、ありふれた午後が小さな誕生日のように明るくなる。"},"ICON-1269":{"nm":"ヨーグルト","on":"ヨーグルト","de":"スプーンを入れればなめらかにすくえる酸っぱい白。果物を一切れ混ぜれば朝が軽くなり、一カップあれば胃が穏やかに整う——やわらかな始まりの味。"},"ICON-1270":{"nm":"さば","on":"さば","de":"網に載せれば脂がぱちぱちはねて生臭いような香ばしい煙が台所を満たす。骨を取ってご飯の上に載せてくれたあの手——ありふれた食卓に宿る一番深い真心。"},"ICON-1271":{"nm":"サーモン","on":"サーモン","de":"ピンク色の繊維がきちんと重なって横たわっている。冷たくして食べれば口の中でやわらかくほどけ、焼けば脂が滲んで香ばしい——遠い海をさかのぼってきた確かな味。"},"ICON-1272":{"nm":"ツナ","on":"ツナ","de":"缶詰のふたを開ければ塩辛い香りがふわっと立ちのぼる。ご飯に混ぜて海苔に包んで食べた一人暮らしの夜、一缶が頼もしい一食になってくれた時代があった。"},"ICON-1273":{"nm":"たら","on":"たら","de":"澄んだ身が淡白で、煮ればだしから涼しく滲み出る。冬の港の刃のような風を耐えた白い魚、温かい汁一椀あれば冷えた手もゆっくり溶ける。"},"ICON-1274":{"nm":"えび","on":"えび","de":"背を丸く曲げて火が通れば灰色が赤らんで染まる。ぷちっとはじける弾力と香ばしい香り、一匹ずつむいて食べているといつのまにか皿が空になっている。"},"ICON-1275":{"nm":"カニ","on":"カニ","de":"硬い殻の中の白い身をほぐす仕事は小さな忍耐の時間。その苦労の末に口に入れるひと切れは甘く、秋の海が丸ごと口の中に入る。"},"ICON-1276":{"nm":"イカ","on":"イカ","de":"焼き板の上で丸く縮みながら香ばしい匂いを立ちのぼらせる。こりこり噛めるひと切れ、酢コチュジャンにちょんとつけて口に入れれば塩辛い海がついてくる。"},"ICON-1277":{"nm":"貝","on":"貝","de":"澄んだだしの中で口を開けて自分の香りをそっと差し出す。じゅくじゅく煮立つ音に海の匂いが広がり、一口ずるりとすすれば冷えた腹が温かくほどける。"},"ICON-1278":{"nm":"おでん","on":"おでん","de":"温かいだしに串ごと浸せば湯気がもくもく立ちのぼる。寒い日の屋台の前、紙コップにだしを受けてふうふう吹いたあの手——路地が差し出す小さな慰めだ。"},"ICON-1279":{"nm":"キムチ","on":"キムチ","de":"甕の中でゆっくり熟しながら酸っぱく深い香りを育てる。手でびりっと裂いて炊きたてのご飯に載せればよし、家ごとに違う味がすなわちその家の来歴だ。"},"ICON-1280":{"nm":"たくあん","on":"たくあん","de":"黄色いひと切れがシャキッと、口の中で軽快に砕ける。キンパ一本、粉食一皿のそばを守る相棒——甘酸っぱさが脂っこい口の中をさっぱりすすぎ流す。"},"ICON-1281":{"nm":"ピクルス","on":"ピクルス","de":"きゅうりが塩にしばし息をひそめてから酢の中で目を覚ます。シャキッとが戻るその瞬間を逃すまいと、ガラス瓶は日の差す窓辺を離れない。ゆっくり漬かる時間が味を連れてくる。"},"ICON-1282":{"nm":"コチュジャン","on":"コチュジャン","de":"甕の中で一年を耐えた赤。辛さの終わりに豆の甘みがそっと隠れていて、ひとさじ溶けばチゲがようやくわが家の顔になる。庭の甕台が日差しで育てた深みだ。"},"ICON-1283":{"nm":"テンジャン","on":"テンジャン","de":"メジュがかびを抱きしめて一冬を越した。香ばしさは熟れと熟れすぎの間の危うい綱渡り——おばあちゃんはその境を指先の匂いひとつで見分けた。待った分だけ深まる味。"},"ICON-1284":{"nm":"醤油","on":"醤油","de":"豆が黒くなるほど中身が深くなる。一滴あればナムルが生き返り、煮物が艶を得るから、台所のすべての色合いは結局この温かい茶色から始まる。塩味の向こうの旨み。"},"ICON-1285":{"nm":"チュンジャン","on":"チュンジャン","de":"同じ黒でも肌理が違う。カラメルでもう一度炒めた甘辛の後味、麺に混ぜればその黒い艶が食欲を揺り起こす。中華の鍋肌の味が始まる最初のボタン。"},"ICON-1286":{"nm":"カレー粉","on":"カレー粉","de":"いくつもの香辛料がひとさじの中で仲良く溶け合った黄色い粉。水に溶けばぐつぐつ煮立って家じゅうを温めるから、雨の降る夕方の一番頼もしい一椀の予告編になる。"},"ICON-1287":{"nm":"こしょう","on":"こしょう","de":"丸ごと挽いてこそ香りが生き、先に挽いておけば香りがこっそり逃げる。最後のひと回しはいつも火を止める直前に——料理する手が惜しんで打っておく小さな終止符だ。"},"ICON-1288":{"nm":"唐辛子粉","on":"唐辛子粉","de":"秋の日差しの下で干した太陽草がようやく赤を完成する。細かく挽くか粗く挽くかによってキムチの性格が分かれるから、手の味とは結局この粉の粒子を選ぶことから来る。"},"ICON-1289":{"nm":"塩","on":"塩","de":"塩加減を合わせるとは足りない方へひとつまみずつ近づくこと。一度入った塩味は戻せないから、熟練の手はいつも最後に少し控えめに入れて味を見る。控えておいた分が余裕だ。"},"ICON-1290":{"nm":"砂糖","on":"砂糖","de":"苦みをなだめ、酸味の角を丸める。けれど甘みは自分の存在を悟られてはいけないから、良い味付けほど砂糖は終わりにこっそり姿を消す。隠れるすべを知る甘み。"},"ICON-1291":{"nm":"蜂蜜","on":"蜂蜜","de":"蜂が花畑を何千回も行き来して集めた一瓶。固まれば温かい湯で湯煎してよみがえらせ、茶に溶けば喉をやわらかく包む。季節一季が丸ごと煮詰められた黄金色のひとさじ。"},"ICON-1292":{"nm":"食用油","on":"食用油","de":"熱したフライパンにひと回しすれば材料がくっつくことを忘れる。早すぎれば焦げ遅すぎればくっつくから、煙がちょうど立ちのぼるその一拍が焼き物の定石だ。音で頃合いを計る。"},"ICON-1293":{"nm":"オリーブオイル","on":"オリーブオイル","de":"一番搾りの緑色には草の香りと少しの辛さが共に住む。火にかけるより最後に回しかけてこそその香りが最後まで生き残るから、火を通さないほうが一番正直な使い方だ。"},"ICON-1294":{"nm":"ごま油","on":"ごま油","de":"最後にひと滴ちょんと落とせばナムルがようやく完成を宣言する。香ばしさは火の上で簡単に逃げる性質だから、いつもすべての調理が終わった後にそっと加えられる終止符になる。"},"ICON-1295":{"nm":"バニラビーンズ","on":"バニラビーンズ","de":"ひとさやを割って黒い種をかき出せばデザートが香りで衣替えする。使い終わったさやも捨てずに砂糖に埋めておくこと——パティシエが受け継いだ古いつましさだ。"},"ICON-1296":{"nm":"カカオ","on":"カカオ","de":"実の中の白い果肉と苦い種。発酵と日干しを経てはじめて私たちの知る甘さに翻訳される。チョコレートになる前、一番野生に近い最初の顔を持っている。"},"ICON-1297":{"nm":"チョコレート","on":"チョコレート","de":"手のひらの温もりだけでもとろりと溶けてしまう気難しい性質。28度あたりで固めてこそぱきっと折れる光沢が生きるから、甘さの裏には意外と気難しい温度の規則が隠れている。"},"ICON-1298":{"nm":"コーヒー豆","on":"コーヒー豆","de":"挽かれる前のひと粒は固い沈黙に近い。けれど熱い湯に出会えばぷっくりふくらんで香りを吐き出すから、朝を目覚めさせる最初の合図はいつもこの小さな粒から始まる。"},"ICON-1299":{"nm":"茶葉","on":"茶葉","de":"熱い湯に長くとどまりすぎれば渋く、短ければ味気ない。葉がゆっくり開く時間をじっと数える仕事——茶を淹れるとは待つことを指先で計る仕事だ。"},"ICON-1300":{"nm":"ミント","on":"ミント","de":"潰せば苦みが滲み出るからいつもそっと扱うべき柔らかな葉。軽くぽんと叩いて眠った香りを目覚めさせ、蒸し暑い日にグラスにぷかぷか浮かべれば、真夏がワントーンほど涼しく落ち着く。"},"ICON-1301":{"nm":"ハーブ","on":"ハーブ","de":"茎ごと入れれば香りが深く、葉だけ使えば澄む。干せば濃くなり生で使えばさわやかだから、ひと束が抱く香りの幅だけ台所の表情も共に広がる。"},"ICON-1302":{"nm":"栗","on":"栗","de":"棘の生えた殻の中に艶のある実が隠れている。切り込みを入れて焼けばぱっと開いて甘い香りを放つから、冷たい風の吹く路地の焼き栗の袋の温もりが手に取れそうだ。"},"ICON-1303":{"nm":"ピーナッツ","on":"ピーナッツ","de":"香ばしさは炒める火で完成する。ひと粒ずつむいて食べていると時の経つのも忘れる小さな実——縁側に囲んで座って分け合えば、話までほのぼのと一緒にむかれる。"},"ICON-1304":{"nm":"アーモンド","on":"アーモンド","de":"さっと湯がいて皮をむけば中身がもっと白くやわらかくなる。潰して挽けば牛乳のように、丸ごと焼けばサクサクに——ひと粒が抱く変身の幅が製菓人の想像を存分に広げる。"},"ICON-1305":{"nm":"ごま","on":"ごま","de":"弱火でそっと揺らしているとある瞬間ぱちぱちはじけ上がる。その音が止まる直前が一番香ばしいとき——ごまを炒める仕事は結局、耳で聞く仕事になる。"},"ICON-1306":{"nm":"さとうきび","on":"さとうきび","de":"ひと節を噛めば草の香りと共に甘い汁が滲み出る。煮詰めてまた煮詰めてこそ私たちの知る甘さになる茎——砂糖の始まりは意外とこんなに青く背が高い。"},"ICON-1307":{"nm":"原糖","on":"原糖","de":"精製を控えめにして自分の色をそのまま抱いた粗い甘み。土の匂いのような深みがほのかに残っていて、きれいに整える前の率直さを好む手がわざわざ探し出す。"},"ICON-1308":{"nm":"カカオ豆","on":"カカオ豆","de":"さやから取り出したばかりの種は苦く渋い。発酵の数日を黙々と耐えてこそ香りが咲くから、甘さとはこの豆が長く我慢し抜いた末に受け取った小さな褒美だ。"},"ICON-1309":{"nm":"カカオニブ","on":"カカオニブ","de":"炒めた豆を細かく砕いた欠片には砂糖が一粒もない。口に入れれば苦みがまず来て遅れて香ばしさが続くから、甘さ以前のカカオに一番正直に出会う。"},"ICON-1310":{"nm":"コーヒー生豆","on":"コーヒー生豆","de":"まだ青臭さの残る緑の粒。このままでは香りがぐっすり眠っていて、火の洗礼を受けるまでは自分が何になるか分からない可能性のままじっと残っている。"},"ICON-1311":{"nm":"焙煎コーヒー豆","on":"焙煎コーヒー豆","de":"脂が少し滲み出た茶色い表面に香りがたっぷりたまった。冷める前に挽いてこそその香りが完全だから、一杯の運命は焙煎してから数日のうちに静かに決まる。"},"ICON-1312":{"nm":"バニラビーンズ","on":"バニラビーンズ","de":"ひと筋の香りが牛乳一鍋を丸ごと染める。使い終わったさやさえ砂糖瓶に挿しておけば数日後に砂糖じゅうが香しくなるから、捨てるところなど一つもない贅沢だ。"},"ICON-1313":{"nm":"こしょう","on":"こしょう","de":"粒こしょうひと粒の香りは挽かれる瞬間から減っていく。だから食卓の上に丸ごと置いてその都度砕くこと——新鮮さとは先延ばしにしない心から咲く。"},"ICON-1314":{"nm":"白こしょう","on":"白こしょう","de":"皮をむいて一層なめらかになった粒は辛いよりほのかだ。白いソースに黒い点ひとつ残すまいとする心遣いから生まれた、見えない場所の繊細さだ。"},"ICON-1315":{"nm":"シナモン","on":"シナモン","de":"ひと切れ煮出せば茶に温かい辛さがゆっくり広がる。粉より丸ごと入れてこそ香りが長持ちするから、冬の飲み物の深みはこの干した皮の粘りから来る。"},"ICON-1316":{"nm":"クローブ","on":"クローブ","de":"小さな釘のような形の蕾ひとつに香りがぎっしり凝縮された。入れすぎれば料理を丸ごと飲み込むから、たったひと粒の節制が風味の均衡をそっと守る。"},"ICON-1317":{"nm":"ナツメグ","on":"ナツメグ","de":"丸ごと置いた種をその都度さっと挽いて使う。先に挽けば香りがすぐ散る性質だから、一度さっとかき出す最後の手つきが牛乳の香りを一層深くする。"},"ICON-1318":{"nm":"カルダモン","on":"カルダモン","de":"緑のさやをぽんとはじけさせれば中からすっとする香りがあふれる。茶に一つ二つ潰して入れるだけで、ありふれた一杯がふと遠い国の香りを得る。"},"ICON-1319":{"nm":"サフラン","on":"サフラン","de":"花一輪からわずか三筋しか採れない赤い糸。温かい湯に溶けば黄色い光がゆっくり広がるから、貴さとは手で一つ一つ選り分けた時間の重みでもある。"},"ICON-1320":{"nm":"ウコン","on":"ウコン","de":"土の中の根を挽けば指先まで黄色く染まる。油でさっと炒めてこそ香りが目覚める性質だから、カレーの黄金色はこの小さな根が火の上で咲かせた色だ。"},"ICON-1321":{"nm":"月桂樹の葉","on":"月桂樹の葉","de":"勝者の額に載せられたという葉。煮立つ湯に一枚浮かべれば湯気の間から昔の競技場の歓声がしばし咲きのぼる。勝てなかった日にも香りを吸い込めば、今日の君を静かに抱きしめる青い慰めになる。"},"ICON-1322":{"nm":"ココナッツミルク","on":"ココナッツミルク","de":"硬い殻を割ってはじめて流れ出る白い汁。暑い国の市場の片隅、ストロー一本挿してひと口あおれば真昼の渇きが丸ごと冷める。口いっぱいに広がる涼しい甘い香りが熱帯の木陰を連れてくる。"},"ICON-1323":{"nm":"ココナッツオイル","on":"ココナッツオイル","de":"固まれば初雪のように白く、手のひらで温めれば香りがするすると広がる。頭の先からつま先までひと瓶あれば十分だと手渡してくれた、島のおばあちゃんの優しい暮らしの知恵が丸い瓶の中にそのまま込められている。"},"ICON-1324":{"nm":"ドライバナナ","on":"ドライバナナ","de":"日差しの下で数日寝かせれば黄色い身がもちもちになる。ひと切れずつ惜しんでかじっていると、雨の降った収穫期の粘っこい甘い香りが口の中でそっとよみがえる。ゆっくり熟した甘さはそうして季節を抱く。"},"ICON-1325":{"nm":"ドライマンゴー","on":"ドライマンゴー","de":"やわらかな果肉が日差しの下で凝縮され琥珀色のゼリーに生まれ変わった。酸っぱくて甘くてもちもちの三つの味がひと切れに全部入っていて、口の中でゆっくり転がしていると一袋で午後が長くなる。"},"ICON-1326":{"nm":"ドライパイナップル","on":"ドライパイナップル","de":"棘の生えた見た目と違って果肉はこの上なく黄色く明るい。日に干しておけば酸味が凝縮され、ひと切れかじるだけで口元が自然に上がる。ひと切れの終わりに残るさわやかな余韻が長くとどまる。"},"ICON-1327":{"nm":"南国フルーツの籠","on":"籠","de":"つみたての色合いがひと籠に調和する。マンゴーのオレンジ、バナナの黄色、パイナップルの黄金色——手を伸ばして選ぶ前に鼻先でまず夏が押し寄せる。見るだけで心が明るくなるひと抱え。"},"ICON-1328":{"nm":"海藻の包み","on":"海藻の包み","de":"潮の引いた磯岩で採った海の髪の毛。塩辛い磯の匂いの中に波の音が絡んでいて、冷水にじっと戻せば生臭い海の香りが台所までゆっくり押し寄せる。ひとつかみが食卓に小さな干潟を広げる。"},"ICON-1329":{"nm":"乾物","on":"乾物","de":"こっくり乾いた海をひとつかみ。手で繊維に沿って裂けば塩気と共に昔の港の塩辛い風がほどける。マッコリ一杯が自然と思い浮かぶ、情の深い食卓のそばの古い友だ。"},"ICON-1330":{"nm":"するめ","on":"するめ","de":"足十本をきちんと広げて日に干した。火にさっと焼いて香ばしい匂いが立てば繊維に沿ってざっと裂く。こりこり噛めるその味に、夜更けの夜食一皿の品格がひと段階上がる。"},"ICON-1331":{"nm":"塩漬け魚","on":"塩漬け魚","de":"粗塩に埋めておけば魚は時間を耐える術を学ぶ。塩味の深い身ひと切れあればご飯一膳があっという間に空になる、海辺のおばあちゃんが指先で受け継いでくれた優しい秘策だ。"},"ICON-1332":{"nm":"アミの塩辛","on":"アミの塩辛","de":"小さなえびたちが塩の中でゆっくり熟して旨みに生まれ変わる。キムジャンの白菜の中にひとさじ入れる瞬間、庭じゅうに広がった塩辛い匂い。そのひとさじが一年のキムチの味を分ける。"},"ICON-1333":{"nm":"煮干し","on":"煮干し","de":"指ほどの体が汁一鍋の深みを引き受ける。頭とはらわたを取りながらほのぼの話を交わした幼い頃の台所、小さくても暮らしの真ん中にしっかり立っていたありがたい魚だ。"},"ICON-1334":{"nm":"昆布","on":"昆布","de":"海の底で長く育った黒い帯。冷水に入れて煮立つ直前にそっと引き上げるのが、だしをとる手が代々守ってきた約束だ。深い旨みは決して急ぐことがない。"},"ICON-1335":{"nm":"ひじき","on":"ひじき","de":"ぷちぷちした食感が口の中でぷちぷちはじける。春には磯岩を緑に染めた海藻、さっと和えておけば食卓の片隅に小さく瑞々しい海が広がる。春を噛む味だ。"},"ICON-1336":{"nm":"真珠貝","on":"真珠貝","de":"硬い二枚の間に長く抱いて作り上げた丸い光。砂一粒の不快を宝石に変えるまで、海は一度も急かさなかった。手のひらに載せればその長い忍耐の重みが共に載る。"},"ICON-1337":{"nm":"珊瑚の飾り","on":"珊瑚の飾り","de":"波が数百年をかけて磨いた海の枝。日差しが触れればピンクとオレンジに広がり、棚の上にそっと置くだけで部屋ひと間が温かい島に染まる。指先に触れる粗い肌理さえ愛おしい。"},"ICON-1338":{"nm":"貝ボタン","on":"ボタン","de":"貝の身が去った跡、玲瓏な内側を丸く切り抜いた。襟元につければ留めるたびに小さな虹が指先できらめく。すべて差し出して去りながら海が残した、最後の優しい贈り物だ。"},"ICON-1339":{"nm":"ガラス玉","on":"ガラス玉","de":"手のひらに転がせば中に閉じ込められた光がころころ一緒についてくる。路地にしゃがんで日が暮れるのも忘れてビー玉遊びをしたあの頃、一つ多く取った子のポケットはことのほか重く誇らしかった。"},"ICON-1340":{"nm":"香木の欠片","on":"香木の欠片","de":"削り出した肌理ごとにほのかな香りが滲み出る。昔の人はこの木を焚いて乱れた心を整えた。ひと欠片そっと握っていると、指先から落ち着きがゆっくり満ちてくる。"},"ICON-1341":{"nm":"お香","on":"お香","de":"細いひと筋がゆっくり燃えながら上へと道を作る。煙が描く曲線を目で追っていると、一日じゅう急いでいた心もいつのまにか歩みを緩めてその場にじっととどまる。"},"ICON-1342":{"nm":"染料の花","on":"染料の花","de":"花びらの中に隠れた色合いを煮立つ釜に溶かし出せば、清らかな布が次第にその色に染まる。自然があらかじめ塗っておいた色をしばし借りてくること——染色とは本来、花に交わす優しい挨拶だった。"},"ICON-1343":{"nm":"藍染料","on":"藍染料","de":"藍草を発酵させてまた発酵させて得た深く奥ゆかしい青。一度浸けて取り出すたびに布は空色から海色へとゆっくり色を移していく。焦りを下ろしてこそはじめて咲く、待ちの色だ。"},"ICON-1344":{"nm":"紅染料","on":"紅染料","de":"あかね草の根を煮出せば土の中に眠っていた夕焼けが釜の中で目を覚ます。祝いの日の花嫁の裾を美しく染めた、村で一番おめでたく明るかった色合いだった。"},"ICON-1345":{"nm":"金糸","on":"糸","de":"髪の毛より細い金を引き出してひと筋ずつ真心で紡ぐ。刺繍された所ごとに光を含み、灯の消えた暗い部屋でもその模様だけは自らほのかに明るく浮かび上がる。"},"ICON-1346":{"nm":"絹","on":"絹","de":"蚕が吐いた糸を織ってまた織ってようやくひと幅になる。手の甲に触れれば春の水のように滑る感触、昔の人が季節ひとつを丸ごと抱いてゆっくり育てた肌理の細やかな布だ。"},"ICON-1347":{"nm":"真珠ボタン","on":"ボタン","de":"真珠の内側の光だけを選んで丸く整えた。チョゴリの襟元に一つずつ留めるたびに指先がしばし優雅になる。小さくても装いの格をそっと引き上げる、端正なひと粒だ。"},"ICON-1348":{"nm":"航海図の断片","on":"航海図の断片","de":"ちぎれた縁の向こうで未知の海岸線がぷつりと途切れている。残りの欠片を集めた者だけが宝のそばに辿り着けるというが——もしかすると風に従ってそれを探し回った旅路自体が、すでに宝だったのかもしれない。"},"ICON-1349":{"nm":"古い海図","on":"古い海図","de":"海水に滲んだ航路と色あせた羅針盤の絵。ある船乗りが真っ暗な夜に星だけを見て引いた線を指先でたどれば、遠い昔に消えた島一つが古い紙の上にまたゆっくり浮かび上がる。"},"ICON-1350":{"nm":"瓶の中の手紙","on":"瓶の中の手紙","de":"波に押し流されてきたガラス瓶の中、くるくる巻かれた紙一枚。誰がいつ流したか分からない便りがついに誰かの手に届いた。海も心さえあれば、こうして遅い郵便配達夫になる。"},"ICON-1351":{"nm":"漂流の箱","on":"箱","de":"潮水でふやけて固くなった蓋を開ける瞬間までが冒険だ。中身が宝でも空っぽの砂でも、遠く漂ってきた箱には、いつも顔も知らぬ誰かの物語が一緒に流れ着いている。"},"ICON-1352":{"nm":"小さな鍵","on":"小さな鍵","de":"手のひらにすっぽり収まる古びた鉄のかけら。どの扉を開けるのかはすっかり忘れられても、閉める術より開ける術を先に思い起こさせる優しい重みが、指先にずっしりと残っている。"},"ICON-1353":{"nm":"銀貨","on":"銀貨","de":"手垢で模様の薄れた丸い銀。誰かの船賃であり、疲れた一夜の寝床でもあっただろう一枚、冷たく冷えた表面を撫でると、遠い昔の取引のぬくもりがかすかに指先によみがえる。"},"ICON-1354":{"nm":"金貨","on":"金貨","de":"手のひらに載せると、ずっしりした重みからまず心が揺れる。陽を受けて黄色く輝く一枚、持てば金持ちになれそうだが——本当に最も明るく輝くのは、手に握る直前のときめきだ。"},"ICON-1355":{"nm":"船長の印章","on":"船長の印章","de":"赤い蝋の上にぐっと押し当てた船長の約束。模様一つで命令が立ち、荒れた航路が定まった。権威とは結局、同じ船に乗る皆が共に信じようと決めた、小さく固い印章一つだった。"},"ICON-1356":{"nm":"ハンドマイク","on":"マイク","de":"手に握った瞬間、妙に頼もしい重みが手のひらを満たす。震える最初の挨拶を交わすときも、ついに高音を張り上げる瞬間にも——この小さな棒一本が、君の声にそっと翼をつけてくれる。"},"ICON-1357":{"nm":"ワイヤレスマイク","on":"マイク","de":"線が消えると、舞台が丸ごと広がった。客席の端まで駆け出しても声は一度も途切れないから、思う存分走り回って歌えと、誰かがそっと背中を押してくれているようなものだ。"},"ICON-1358":{"nm":"スタンドマイク","on":"マイク","de":"足元にしっかり立ったまま、黙々と歌い手を待つ。両手が自由になれば、歌は指先の代わりに全身へ広がっていく。一つの場所を最後まで守ることにも確かな格好良さがあると、この棒は静かに語る。"},"ICON-1359":{"nm":"ポップフィルター","on":"フィルター","de":"マイクの前を丸く遮る布一枚。激しい息遣いはやわらかく濾し取り、澄んだ声だけを通す。よく聞こえるようにするとは、最後まで見えない場所で黙々と守ることなのだ。"},"ICON-1360":{"nm":"インイヤー","on":"インイヤー","de":"耳の中にすっぽり収まれば、数万の歓声の向こうに自分の歌がはっきりとよみがえる。光も音も降り注ぐ舞台の上で、拍を逃さないよう支えてくれる、最も小さく密やかな道連れだ。"},"ICON-1361":{"nm":"ヘッドホン","on":"ヘッドホン","de":"耳を覆った瞬間、世界が一回り小さくなり、歌だけが大きく残る。誰も割り込めない丸い部屋一つ。一人でつけたヘッドホンの中で、不思議と一人ではない。"},"ICON-1362":{"nm":"楽譜","on":"楽譜","de":"黒い点たちが線の上にそっと降り立つと、沈黙していた紙が音を含む。読むのではなく聴く文字。広げた瞬間、止まっていた歌がまた息をする。"},"ICON-1363":{"nm":"ボーカル楽譜","on":"ボーカル楽譜","de":"息を吸う場所ごとに小さく丸をつける。ここで吸い込み、あそこでそっと放て。声が傷つかないよう道を開いてくれる、優しい地図一枚。"},"ICON-1364":{"nm":"ピアノ楽譜","on":"ピアノ楽譜","de":"十本の指が同時に道を尋ねるページ。左手は根を押さえ、右手は歌を描く。別の物語を語っていた両手が、最後の小節でついに一つに重なる。"},"ICON-1365":{"nm":"ギターコード表","on":"表","de":"指が初めて学ぶ外国語、その最初の単語がここに書かれている。六つの点が丸に集まると、ようやく一つの音が鳴く。押して、また押す夜ごとに、指先にタコが育つ。"},"ICON-1366":{"nm":"メトロノーム","on":"メトロノーム","de":"コツ、コツ——揺るがぬ足取り一つが傍らで刻む。心が先に駆け出すとき、背後からゆっくり、ゆっくりと引き止めてくれる。拍子とは結局、一緒に歩こうという約束だから。"},"ICON-1367":{"nm":"チューナー","on":"チューナー","de":"針が真ん中へ滑り込んでくると、ようやく音が定位置を見つける。高くも低くもないその一点。合うとはこういうこと、もう震えず静かに止まることなのだなと。"},"ICON-1368":{"nm":"ピアノ鍵盤カード","on":"カード","de":"一枚ずつめくるたびに、鍵盤が手のひらの中へ歩み入ってくる。ドからシまで、七つのマスの小さな宇宙。本物のピアノがない夜にも、歌はここでそっと育つ。"},"ICON-1369":{"nm":"ギターピック","on":"ギターピック","de":"親指と人差し指の間に挟む、小さく硬いかけら。落とせば椅子の下で永遠に姿を消すが、手に握った瞬間、六本の弦が一斉に鳴り響く。"},"ICON-1370":{"nm":"ドラムスティック","on":"ドラムスティック","de":"二本が宙でぶつかれば、その場に合図が落ちる。1、2、3、4。散らばっていた皆の心臓が、その四拍に合わせて同じ速さで打ち始める。"},"ICON-1371":{"nm":"タンバリン","on":"タンバリン","de":"一度叩けば、陽射しが細かく砕けるように澄んだ音が四方へ散る。軽そうに見えても、盛り上がりが冷めかけたとき真っ先に手が伸びる一拍。小さいからと誰も侮れない。"},"ICON-1372":{"nm":"ダンススニーカー","on":"ダンススニーカー","de":"床を滑るように回る足には、摩擦こそが武器になる。すり減った靴底ごとに、回って回った回転が刻まれる。最も格好いい動きはいつも、頑丈な一足から始まる。"},"ICON-1373":{"nm":"膝サポーター","on":"膝サポーター","de":"数えきれぬほど膝をつき、また立ち上がった者だけが知る、この薄い布一枚のありがたさを。床がもう怖くなくなるもの——勇気は時にこうして膝に巻かれている。"},"ICON-1374":{"nm":"手首サポーター","on":"手首サポーター","de":"曲がる場所をあらかじめ包んでおけば、無理な動きも幾分寛容になる。手首は言葉がなく、痛むまで一人で耐える。その長い沈黙を、一枚が代わりに守ってくれる。"},"ICON-1375":{"nm":"足首サポーター","on":"足首サポーター","de":"高く跳ぶジャンプの果てには着地があり、その着地の果てには足首がある。最も低い場所で全身の重みを受け止めるところ。この小さな帯が、明日の練習を静かに守ってくれる。"},"ICON-1376":{"nm":"ストレッチバンド","on":"バンド","de":"引っ張れば引っ張った分だけ、元へ戻ろうと踏ん張る。その抵抗に耐える間に、体は知らぬ間に少しずつ伸びていく。伸びるとは結局、耐えた時間が残した跡だ。"},"ICON-1377":{"nm":"ヨガマット","on":"マット","de":"広げた瞬間、床の上に自分一人分の土地ができる。うつ伏せになり、横たわり、呼吸を整える小さな領土。一日の始まりと終わりが、この一枚の上で静かに収まる。"},"ICON-1378":{"nm":"フォームローラー","on":"フォームローラー","de":"凝った場所をじっと押すと、初めは痛く、やがて気持ちよくなる。固まったものをほぐすことには、いつも少しの痛みが伴う。体も心も、ほぐれるには一度は押さねばならないから。"},"ICON-1379":{"nm":"ダンベル","on":"ベル","de":"同じ重さを持ち、また持つ。昨日よりちょうど一回多く、それがすべてだ。華やかさなど何一つない反復の中で、腕は黙って太くなる。ただ正直なだけの鉄の塊一つ。"},"ICON-1380":{"nm":"ケトルベル","on":"ベル","de":"取っ手一つに全身が丸ごと振り回される。丸い重みが円を描いて回るとき、踏ん張る者の均衡が試される。揺るがぬためには、まず自分の中心を知らねばならない。"},"ICON-1381":{"nm":"縄跳び","on":"縄跳び","de":"足元をさっと過ぎていく一本の縄を跳び、また跳ぶ。庭で仲間たちと数えたあの遊びのように、数が積もるほど息は切れ、笑いは増えていく。"},"ICON-1382":{"nm":"ランニングシューズ","on":"ランニングシューズ","de":"道の上に立ってこそ真価がわかる一足。明け方の空気を切って同じ道をまた走れば、昨日は遠かった曲がり角が、今日は目の前に来ている。距離は足が覚えている。"},"ICON-1383":{"nm":"運動タオル","on":"運動タオル","de":"額の汗を拭うと、そこに今日の努力が一筋にじんでいる。洗えば跡は消えても、流した分はどこかにきちんと積もっていく。最も素直な応援は、いつも傍らで乾く。"},"ICON-1384":{"nm":"水筒","on":"ボトル","de":"空けば満たし、乾けば一口飲む。その単純な往復が一日を黙々と支える。井戸端でつるべが上り下りしたように、満たすことからまた一日が始まる。"},"ICON-1385":{"nm":"プロテインシェイク","on":"プロテインシェイク","de":"よく振って一口飲めば、今日壊した筋肉が明日また満ちていく。華やかな味ではなくとも体は知っている、これが回復の言葉だと。成長はいつも静かに飲み込まれる。"},"ICON-1386":{"nm":"エナジーバー","on":"エナジーバー","de":"ポケットの中で平たく押しつぶされた一本。食事と食事の合間、空っぽの時間を埋める非常食。大げさなものではなくとも、この小さな一口が、午後のひと動きをもう少し支えてくれる。"},"ICON-1387":{"nm":"のど飴","on":"のど飴","de":"口の中で転がすと、すっとしたミントが荒れた喉をそっと撫でてくれる。たくさん話した日、たくさん歌った夜——小さな飴玉一つが、ざらついた道をなだめる。甘さにも確かな役目がある。"},"ICON-1388":{"nm":"ボーカルティー","on":"ボーカルティー","de":"温かい湯気が喉を温め、一口で肩の緊張がするりとほどける。おばあちゃんが煮てくれた生姜茶のような古い処方。歌う前に、声へ交わす優しい挨拶。"},"ICON-1389":{"nm":"はちみつ水","on":"はちみつ水","de":"ぬるい水にはちみつを一さじ、ゆっくり溶かす。喉がいがらっぽいとき、大人たちが決まって作ってくれたあの一杯。薬でも飲み物でもなく、ただ内側から体をそっと撫でる甘さ。"},"ICON-1390":{"nm":"加湿器タンク","on":"タンク","de":"部屋の中に小さな霧を放つ器。乾いた空気が喉を引っかく冬の夜、見えないところで潤いを分けてくれる。誰かを世話することは、たいていこうして音もなく流れる。"},"ICON-1391":{"nm":"休息クーポン","on":"休息クーポン","de":"休んでいいと書かれた紙一枚。手に受け取った瞬間、心の荷が一段軽くなる。止まることも練習だと——この小さな券が代わりに許してくれる。"},"ICON-1392":{"nm":"練習スケジュール表","on":"表","de":"マスごとに記された時間の上へ、一日がきちんと降りていく。朝は発声、午後は振付、夕方は休息。途方もなかった明日も線を引いて分ければ、いつしか歩いてみる気になる。"},"ICON-1393":{"nm":"出席スタンプ","on":"出席スタンプ","de":"今日も来たという印を一つ、ぐっと押す。インクが少しにじんだ丸がマスごとに増えていくほど、大したことのなかった誠実さが、いつしか道になっている。毎日の小さな証拠。"},"ICON-1394":{"nm":"ほめシール","on":"シール","de":"よくやったという言葉の代わりに、星一つをそっと貼ってあげる。爪ほどのきらめきなのに、ノートの隅に座った瞬間、一日が明るくなる。ほめ言葉は小さくても、不思議と長く輝く。"},"ICON-1395":{"nm":"メンタルノート","on":"ノート","de":"舞台裏で震えた心を、文字に解いて書きとめた面。うまくいかなかった日も正直に書いておけば、どこか幾分軽くなる。心は覗き込んだ分だけ強くなる。"},"ICON-1396":{"nm":"イメージトレーニングカード","on":"カード","de":"目を閉じて手に握れば、頭の中にそっと舞台が広がる。まだ立ったことのない場所をあらかじめ一周歩いてみること。想像で描いた動線は、実際の足先より一歩先に到着する。"},"ICON-1397":{"nm":"表情練習鏡","on":"鏡","de":"鏡の前で笑ったり、こわばらせたり、同じ顔を百回以上も作る。喜びも悲しみも練習が要ると、ここで学ぶ。表情とは、心を外に書き写すことだから。"},"ICON-1398":{"nm":"振付ノート","on":"ノート","de":"足と腕が通り過ぎる道を、絵に写して書きとめた面。8拍ごとに体がどこへ行くべきか、矢印が静かに教えてくれる。なかなか覚えられなかった動きも、この上でゆっくり馴染んでいく。"},"ICON-1399":{"nm":"振付映像チップ","on":"チップ","de":"小さなチップ一つに数百回の動きがそのまま収まる。眠る前にもう一度回して見れば、指先がひとりでにその道をたどって動く。反復は、体で書き写すもう一つの記録。"},"ICON-1400":{"nm":"舞台動線表","on":"表","de":"舞台をあの上から見下ろした一枚の地図。誰がどこで出会い、どこへ散らばるか、線と点であらかじめ約束されている。大勢で一つの絵を描くには、まず道から分けねばならない。"},"ICON-1401":{"nm":"リハーサルパス","on":"リハーサルパス","de":"客席は空っぽで、照明はまだ眠っている。このパス一枚が、その静寂の中へ君を入れてくれる。誰も見ていないときの舞台——だから最も正直な君に出会う時間が、ここから始まる。"},"ICON-1402":{"nm":"スタイルブック","on":"スタイルブック","de":"今日はどんな気持ちで着ようか。シャツ一枚にも似合う気分があると、この本はそっと教えてくれる。ページをめくるほど、鏡の前でためらった指先に、小さな目利きがきちんと積もっていく。"},"ICON-1403":{"nm":"ヘアスプレー","on":"ヘアスプレー","de":"シュッと一吹きすれば、風もみだりに乱せない。舞台の上のわずか数分を隙なく押さえておこうとする小さな欲。完璧な瞬間はいつも、こんな些細なこだわりの上で完成する。"},"ICON-1404":{"nm":"メイクパレット","on":"メイクパレット","de":"十二マスの色は十二種類の気分だ。今日はどんな表情で歌うか、指先が先に選び、心がその後に従う。空いていくマスごとに、舞台に置いてきた日々が静かににじんでいる。"},"ICON-1405":{"nm":"衣装ピン","on":"ピン","de":"最も華やかな瞬間、肝心の見えない場所で布を留める小さなピンがある。ずり落ちないように、乱れないように。舞台の上の輝きはいつも、誰かの堅実さを踏みしめて立つ。"},"ICON-1406":{"nm":"ネームボード","on":"ネームボード","de":"空欄だったボードに名前が満ちる瞬間、ぼやけていた約束一つがはっきりする。誰がこの場に立つか——文字一行が決める。名前とは、最も短く固い誓いだ。"},"ICON-1407":{"nm":"ファンサービスカード","on":"カード","de":"受け取る人はたった一人、その一人には世界のすべてだ。短い挨拶一行に、幾晩もの感謝をぎゅっと押し込めること。心は手のひらほどの紙の上でも、こうしてあふれ出る。"},"ICON-1408":{"nm":"サイン練習紙","on":"サイン練習紙","de":"初めは自分の名前さえ見慣れず描かれる。百回引いて千回整える明け方、手が心より先にその流れを覚えるまで。そうして名前一つが、ようやくサインになる。"},"ICON-1409":{"nm":"インタビュー質問紙","on":"インタビュー質問紙","de":"「この質問には何と答えよう。」紙を握った指先がわずかに震える。答えを暗記するのではなく、本心を順に立てておく時間——面接も告白も、結局は心の順序を問うことだから。"},"ICON-1410":{"nm":"外国語単語帳","on":"外国語単語帳","de":"最も擦り切れた角が、いちばん長く見つめた単語を教えてくれる。慣れない発音一つが口に馴染むまでの時間だけ、一度も行ったことのない世界との距離も、一寸ずつ近づく。"},"ICON-1411":{"nm":"発音矯正カード","on":"カード","de":"転がる「ラ」、漏れていく「サ」。カードを一枚ずつめくりながら舌を馴らす明け方がある。言葉がはっきりするほど、その言葉で届きたい誰かの顔も、はっきりしていく。"},"ICON-1412":{"nm":"ライブチェックリスト","on":"ライブチェックリスト","de":"マイクオン、インイヤー確認、動線点検。四角いマスが一つずつ埋まるたび、胸の不安が一段ずつ空いていく。舞台に上がる前、入念さは最も静かな勇気だ。"},"ICON-1413":{"nm":"コンディションパッチ","on":"コンディションパッチ","de":"貼った瞬間、温かく広がる場所がある。無理した肩、固まったふくらはぎ——体が送る小さな信号にそっと答えてくれる手のひらほどの慰め。よく休むことも練習の一部だ。"},"ICON-1414":{"nm":"アイスパック","on":"アイスパック","de":"腫れた足首にそっと載せる。冷たさがゆっくり染み込む間にようやく、今日どれだけ走ったか気づく。舞台裏の回復はいつもこうして、音もなく訪れる。"},"ICON-1415":{"nm":"応急ポーチ","on":"ポーチ","de":"絆創膏、痛み止め、手鏡。大したことのないものが詰まったこの小さな袋が、最も頼もしくなる瞬間が来る。あらかじめ用意しておいた優しさは、思わぬ危機の前で最も明るく輝く。"},"ICON-1416":{"nm":"キューカード","on":"カード","de":"カメラの向こうで誰かがそっと掲げる。忘れかけた一言が、そこにきちんと書かれている。よどみなく流れる進行の裏には、いつもこうして画面に映らない手がある。"},"ICON-1417":{"nm":"ミッション封筒","on":"封筒","de":"封筒を破る直前がいちばんときめく。中に何が入っていようと、まだ知らぬままにわくわくするその短い隙間。バラエティの妙味は、封じられたその一瞬の中に丸ごと生きている。"},"ICON-1418":{"nm":"名札","on":"札","de":"胸元についた小さな名前が、最初の挨拶を代わりにする。まだ互いを知らぬ人々の間で、名札一つが気まずさの氷をコツンと割る。名前を呼ぶその瞬間から関係が始まる。"},"ICON-1419":{"nm":"罰ゲームシール","on":"シール","de":"負けた人の額にぺたっと貼られる一枚が、笑いをどっと弾けさせる。罰というには情が深すぎて、負けたことさえいつまでも思い出になる。一緒に笑おうと作られた、小さく優しい印だ。"},"ICON-1420":{"nm":"ランダム罰ゲームカード","on":"カード","de":"引く前まで誰も知らない。象の鼻十周か、愛嬌一回か。紙一枚に運命を丸ごと委ねる瞬間、かえって笑いの壺から先にするりとほどけてしまう。"},"ICON-1421":{"nm":"ヒントカード","on":"カード","de":"行き詰まった場所にそっと差し出す手のようなもの。答えをすべて与えはしないが、道は教えてくれる。よいヒントとは正解ではなく、もう一度考えてみる勇気をそっと差し出すことだ。"},"ICON-1422":{"nm":"チャンスカード","on":"カード","de":"傾いた盤面を一度にひっくり返す、ただ一度の機会。このカードをいつ出すかが勝負を分ける。惜しみに惜しんだ幸運は、最も決定的な瞬間にこそ、ようやく真価を発揮する。"},"ICON-1423":{"nm":"タイムアウトカード","on":"カード","de":"ちょっと止まっても大丈夫だと、このカードが代わりに言ってくれる。息を整える隙が必要なとき堂々と手を挙げること——止まることも立派な戦略であり、よく休むこともまた実力の一つだ。"},"ICON-1424":{"nm":"笑いボタン","on":"ボタン","de":"パッと押した瞬間、けらけらと明るい笑い声がいっぱいに溢れ出す。本当に面白い場面には、こんな効果音までそっと加わるもの。場のぬくもりは、こんな小さないたずら一つから温まる。"},"ICON-1425":{"nm":"効果音リモコン","on":"効果音リモコン","de":"ボタン一つで拍手、もう一つでブーイング。指先だけで雰囲気を作り出す魔法使いが、調整室に静かに座っている。画面に映らない演出が、その場面を生き生きと息づかせる。"},"ICON-1426":{"nm":"カチンコ","on":"カチンコ","de":"カチッ、軽快な音とともに一カットが始まる。何十回のNGとただ一度のOKの間、この黒い板がすべての瞬間をきちんと数えてくれる。記録が踏み出す最初の拍子だ。"},"ICON-1427":{"nm":"撮影テープ","on":"撮影テープ","de":"足先がその線にそっと触れた瞬間、待っていたように照明がふわりと降りてくる。擦り切れるほど覚えたただ一マス——舞台は床に引かれた小さな色帯一つで、ようやく完成する。"},"ICON-1428":{"nm":"照明フィルター","on":"フィルター","de":"同じ顔でも光の色が丸ごと変える。青いフィルターには明け方が、赤いフィルターには夕焼けが宿る。雰囲気は決して遠くにない——薄い色紙一枚の中にそっと折りたたまれている。"},"ICON-1429":{"nm":"カメラバッテリー","on":"カメラバッテリー","de":"赤い灯が点滅し始めると、まず心が焦る。よりによって最高の場面はいつも残量1パーセントで訪れるから。ポケットの中の予備一つが、たちまちひと息つける安心になる。"},"ICON-1430":{"nm":"メモリーカード","on":"カード","de":"一日分の笑いと汗の粒が、爪ほどのチップの中にびっしり詰まる。小さすぎて失くしやすく、またその分この上なく大切だ。抱えた思い出の重さは、決して大きさで測れない。"},"ICON-1431":{"nm":"ポラロイドフィルム","on":"ポラロイドフィルム","de":"カシャッ、そして静かな待ち時間。白かった面の上にゆっくり顔が浮かび上がる、その数秒が妙にときめく。手に握った即席写真にも、忍耐がきっと一さじは入っているものだ。"},"ICON-1432":{"nm":"フォトカードフィルム","on":"フォトカードフィルム","de":"この一枚にどんな表情が現像されるかは、印刷される直前まで秘密だ。誰かの推しになる顔が、まさにここで生まれる。小さな紙一枚が、それほど大きな心を抱く。"},"ICON-1433":{"nm":"フォトカードスリーブ","on":"フォトカードスリーブ","de":"フォトカードは素手で触らない。角が一度押されれば、その日の微笑みまで痛むから。透明な一枚に推しを大事に包むこと——大切にすることにも、これだけの真心がいる。"},"ICON-1434":{"nm":"トップローダー","on":"トップローダー","de":"硬い二枚の間に挟み込めば、時間さえみだりに皺にできない。曲がるな、折れるなと。何かを大切に守ることは、いつも堅さを一層借りてくる。"},"ICON-1435":{"nm":"シールパック","on":"シールパック","de":"一枚ずつ剥がして手帳の角に、ノートパソコンの裏にぺたっと貼る。小さな絵一つで、無彩色だった一日が色とりどりに染まる。傍らを飾りたい気持ちに、年齢など関係ない。"},"ICON-1436":{"nm":"サインペン","on":"ペン","de":"インクが紙をさらさらこする音に、列がどんどん長くなる。ときめく手で差し出したアルバムの上、わずか数秒の出会いが長く残る。ペン先を伝って心が渡っていく。"},"ICON-1437":{"nm":"サインアルバム","on":"サインアルバム","de":"表紙を開けば、見慣れた曲線の署名がまず挨拶を交わす。音楽で出会った仲が、紙の上で一寸さらに近づく。とっておくとは、その瞬間をそっと止めておくことだ。"},"ICON-1438":{"nm":"ペンライト電池","on":"ペンライト電池","de":"「点いてくれ、頼む。」入場直前に電池を入れ替える手がせわしない。数万の光の中で自分の一つが消えないように——小さな電池が、その大きな夜を明るく照らす。"},"ICON-1439":{"nm":"ペンライトポーチ","on":"ポーチ","de":"傷一つなくきれいに、次の夜の歓声まで大事に。熱かった場がすっかり冷めても、大切にしまって家へ連れて帰る。応援の道具にも自分の居場所があり、その場所を守る心がある。"},"ICON-1440":{"nm":"スローガン","on":"スローガン","de":"長い布の上に書かれた文章が、客席を横切って広がる。言葉にできなかった応援がぱっと開く瞬間、一人の本心がたちまち皆の叫びになる。その布がそのまま声になる。"},"ICON-1441":{"nm":"ミニバナー","on":"ミニバナー","de":"手のひらにすっぽり収まる小さな応援。遠くに掲げられた横断幕は皆のものだが、これはただ君の机の端でだけはためく。小さいからと心まで小さいはずがないと、そっと揺れながら証明する。"},"ICON-1442":{"nm":"ファンレター","on":"ファンレター","de":"宛名を三度書き直し、最初の一文は七回消したよ。封筒を閉じる直前に指先が震えるのは、心があまりに正直だから。切手一枚より重い本心が、その中に折りたたまれている。"},"ICON-1443":{"nm":"贈り物の包装紙","on":"包装紙","de":"開ける直前のその1秒が一番ときめくと、包装紙は誰よりよく知っている。じきに破られる運命と知りながら、渡す人の心に似て、最も美しい風合いで身を包む。"},"ICON-1444":{"nm":"リボン","on":"リボン","de":"きつく結びすぎれば窮屈、緩ければほどける、ちょうどその間を探すのが真心だ。指先で選んだ結び目一つに、心の形が込もる。贈り物の最後の一行は、いつもリボンが代わりに書いてくれる。"},"ICON-1445":{"nm":"感謝カード","on":"カード","de":"口で言うありがとうは風に散るが、手書きで記せば長くとどまる。受けた優しさにもう少し添えて返すこと。一文字ずつ押し書きする間に、心が二倍に深まる。"},"ICON-1446":{"nm":"お弁当クーポン","on":"お弁当クーポン","de":"この紙一枚で昼の心配がするりとほどける。炊きたてのご飯に湯気がもうもう、おかずのマスごとに満ちた一食が約束されているから。空腹の午後を頼もしく守ってくれる小さなお守り。"},"ICON-1447":{"nm":"おやつクーポン","on":"おやつクーポン","de":"午後三時、小腹がそっと信号を送るとき出せと生まれた。小さな甘いもの一つで気分が半寸ほど上がるのを知るクーポン。大きな報酬ではなくとも、必要な瞬間にそっと届く。"},"ICON-1448":{"nm":"カフェクーポン","on":"カフェクーポン","de":"温かい一杯と窓辺の席一つ、このクーポンが約束するのはそれだけだ。大したことなさそうでも、誰かには一日を耐えた小さな褒美になる。香りが一歩先に届く、優しい招待状。"},"ICON-1449":{"nm":"宿舎清掃券","on":"券","de":"窓を大きく開けて布団をぱたぱた、埃一粒まで逃げ出す一日。自分の手でやらなくていいというのが、こんな贅沢だったとは。部屋がきらめけば、心までそっと整う。"},"ICON-1450":{"nm":"修理キット","on":"修理キット","de":"ドライバーにテープ、得体の知れない部品いくつか。全部揃えば直せないものはなさそうなのに、開けてみるといつも一つ足りない。それでも手に握れば、なぜか頼もしくなる自信の箱。"},"ICON-1451":{"nm":"幸運チケット","on":"幸運チケット","de":"座席も番号もない空っぽのチケット一枚。今日どんないいことが来るか書かれていないのが肝心だ。その空欄を埋めるのは、ポケットに入れて持ち歩く人の役目だから。"},"ICON-1452":{"nm":"サイコロ","on":"サイコロ","de":"公平という言葉を最もよく知る友。誰の味方もせず、六つの面を等しく愛する。手のひらを離れてころころ転がるその瞬間だけは、実力も人脈もしばし運に席を譲る。"},"ICON-1453":{"nm":"移動券","on":"券","de":"ここからあそこまで、一歩で十分だという約束。遠い道を小さく折ってポケットに入れておく、魔法のような紙。出かけるのをためらう日、これほどの言い訳遮断機もない。"},"ICON-1454":{"nm":"再挑戦券","on":"券","de":"転んだ人に手を差し伸べる代わりに、もう一度やってみろとそっと背中を押す券。失敗は終わりではなく、しばしの休符だと最も静かに教えてくれる。もう一度の勇気は、ここから満ちる。"},"ICON-1455":{"nm":"早期完了券","on":"券","de":"待ち時間をそっと飛び越える優しいチートキー。3分も待てない心を誰が責められよう。砂時計の砂を指でちょいと押しのける、少し反則じみた楽しみがここにある。"},"ICON-1456":{"nm":"生産ブースター","on":"生産ブースター","de":"同じ手、同じ時間なのに、成果物が二倍。秘訣は聞くなとばかりに作業台の上でウィーンと、楽しげに回る。せっせと動く両手にそっと翼をつけてくれる小さな装置。"},"ICON-1457":{"nm":"親密度キャンディ","on":"親密度キャンディ","de":"言葉ではほぐしにくい気まずさも、甘いものの前ではするりと溶ける。一緒に頬張った飴一つで、昨日より一寸近づく仲。甘さがそのまま仲良くなる速さだという、かわいい発見一つ。"},"ICON-1458":{"nm":"気分回復ゼリー","on":"気分回復ゼリー","de":"悔しい日には冷たくぷるぷるしたものが一番効く。一口かじれば、曇っていた表情がそっとほどける。心を直すことはもともと貴いから、R等級が付いているのは伊達ではない。"},"ICON-1459":{"nm":"きらきら粉","on":"きらきら粉","de":"平凡なものの上にそっと振りかければ、急に特別になる。正体はただきらめく粉なのに、付いた瞬間、世界が少し浮き立って見えるから不思議。日常にちょいと効かせる幸せの薬味のような存在。"},"ICON-1460":{"nm":"ステージテープ","on":"ステージテープ","de":"舞台に立てば、数多の照明が一斉に君を探し出す。その場所を床の小さなXが黙って印しておく。見えない場所で最も正確なものが、結局は最も大きな舞台を支える。"},"ICON-1461":{"nm":"結束バンド","on":"結束バンド","de":"絡まった線を一度にきれいに整える小さな英雄。一度締めると元に戻せないのが欠点であり魅力だ。すっきりに本気な者たちが、静かに用意しておく必需品。"},"ICON-1462":{"nm":"予備ケーブル","on":"ケーブル","de":"あるときは存在感がなく、ないときにこそ切実になる品。舞台裏のかばんの奥深くで眠っていて、決定的な瞬間にぱっと目覚める。備えという言葉を、身をもって証明してみせる。"},"ICON-1463":{"nm":"リハーサルチェック表","on":"表","de":"動線にキュー、衣装替えまでマスごとにびっしりの紙。ここのチェックが一つでも空けば、誰かの心臓がひやりと下がる。完璧な舞台は、この表がすべて埋まったその後に、ようやく幕を開ける。"},"ICON-1464":{"nm":"セット看板","on":"看板","de":"ここはカフェ、あそこは路地、矢印をたどれば全く別の世界。合板に描いた嘘なのに、カメラの前では本物になる。方向を指し示すことに生涯を捧げた正直な案内人。"},"ICON-1465":{"nm":"ミニトロフィー","on":"トロフィー","de":"受け取った瞬間、なぜか背丈が一寸伸びた気がする金色のかけら。一等でなくとも本当に大丈夫だと、今日君が頑張ったのを全部知っていると、机の上で輝く。小さな褒美が差し出す大きな慰め。"},"ICON-1466":{"nm":"リュック","on":"リュック","de":"背負った瞬間、どこへでも旅立てそうな気がする。中に入っているのは大したものでなくとも、可能性だけはいっぱい。冒険はいつも、この肩紐をしっかり締めることから始まる。"},"ICON-1467":{"nm":"コンパス","on":"コンパス","de":"道に迷っても慌てないのは、針の先がいつも北を指すからだ。さんざん揺れた末にようやく定位置を見つける姿が、まるで人の心のよう。迷っても大丈夫だと、震える先で語ってくれる。"},"ICON-1468":{"nm":"ノート","on":"ノート","de":"最初の一枚はいつも白い。何を書くかはペンを持った人だけが知る。私はただ待つ、今日の思いが文字になって私の上にそっと降り立つのを。R等級は、じきに満ちる可能性の重みだ。"},"ICON-1469":{"nm":"鉛筆","on":"鉛筆","de":"間違えても大丈夫という点が、この道具の最も優しいところだ。消しゴムの友さえ傍らにいれば、何度でもやり直せるから。削れるほど短くなるが、短くなった分だけ長く愛された証だ。"},"ICON-1470":{"nm":"フィルム","on":"フィルム","de":"光が通り抜ける瞬間、その日の色がそのまま刻まれる。一カットが過ぎれば永遠に戻せないのが緊張であり魅力。速い時代に、わざと一拍遅く記憶しようとする人々の選択。"},"ICON-1471":{"nm":"インスタントカメラ","on":"インスタントカメラ","de":"カシャッ、そしてしばしの待ち時間。手に握ってひらひら振れば、ぼやけていた瞬間がだんだんはっきりしていく。今この場を紙一枚にそのまま捕まえておく、少し魔法のような機械。"},"ICON-1472":{"nm":"古い写真","on":"写真","de":"色が褪せた分だけ時間が流れたという意味だ。角がすり減った場所ごとに、誰かの手が触れてとどまった。最も古い写真が最も鮮明な記憶を抱くのは、たぶんその手のせいだろう。"},"ICON-1473":{"nm":"スクラップブック","on":"スクラップブック","de":"捨てるには惜しいかけらが集まりに集まって一冊になる。色褪せた映画チケット、乾いた花びら、短いメモ一枚。他人の目には雑多な品でも、開いた人にはひと時代が丸ごとよみがえる。"},"ICON-1474":{"nm":"航海日誌","on":"航海日誌","de":"今日の風と波、そして心の一行。何事もない日もきちんと書いておくのが航海の規則だ。無事に着いたという証拠は、いつもこの分厚い記録の中のどこかに記されている。"},"ICON-1475":{"nm":"地図のかけら","on":"地図のかけら","de":"全体のほんの一隅なのに、これがなければついに道を見つけられない。破れた断面が別のかけらとぴたりと噛み合うときのあの快感ときたら。R等級は、パズルの最後の一マスのような存在感だ。"},"ICON-1476":{"nm":"ボトルメール","on":"ボトルメール","de":"誰が読むかわからぬまま、波にそっと身を委ねる。返事は期待しない、ただこの心がどこかへ届くことを願うだけ。最も遅いが、最もロマンチックな郵便の方式だ。"},"ICON-1477":{"nm":"サイコロ","on":"サイコロ","de":"またお前かとばかりに丸く笑う六つの面。同じ形なのに、転がるたび毎回違う答えを出すのがこの友の変わらぬ気まぐれだ。手を離れる瞬間、選択をしばし運命に委ねてみる。"},"ICON-1478":{"nm":"風車","on":"風車","de":"風が吹いてこそ、ようやく生きる。じっとしておけばただの紙の羽だが、誰かがふっと吹いてくれれば楽しげに回り始める。助けてもらうことを恥じらわないのが、この小さな花の知恵だ。"},"ICON-1479":{"nm":"ピクニックバスケット","on":"バスケット","de":"蓋を開ければ海苔巻きの匂いがまず挨拶を交わす。青い芝生、広げたレジャーシート、そして分け合って食べる手と手。このバスケットが満ちる日は不思議といつも空が晴れていた。"},"ICON-1480":{"nm":"花瓶","on":"瓶","de":"一輪挿すだけで部屋の空気が変わる。空っぽのときはただ黙々と待つのが本分だ。花をより輝かせようとそっと自分の存在を低くする、部屋の中で最も謙虚な舞台装置。"},"ICON-1481":{"nm":"花びら","on":"花びら","de":"風が一枚連れ去れば、春はその分軽くなる。庭の老木は毎年同じ挨拶を交わす——散ることも咲くことの一片だと。舞い散りは終わりではなく、次の春へあらかじめ出す手紙だ。"},"ICON-1482":{"nm":"バラ","on":"バラ","de":"棘を先に立てるのは、みだりに触れるなという約束。その内側には最も赤い心が隠れている。誰かは一輪を足元にそっと置いて、名前の代わりに色だけで心を記して去った。"},"ICON-1483":{"nm":"ユリ","on":"ユリ","de":"端正な白磁の傍らには、いつもこの白い花が置かれた。香りは遠くへ行っても、姿は乱れないようにと。華やかさの代わりに潔白を選んだその場所で、ユリは黙って一段の品位を守り抜く。"},"ICON-1484":{"nm":"チューリップ","on":"チューリップ","de":"少しうなだれたまま列をなして立つ姿が、どこか端正だ。春の花壇の最初の列を一手に引き受ける花。一斉に咲いて一斉に散るその正直さが、短い季節を最も濃く染める。"},"ICON-1485":{"nm":"ヒヤシンス","on":"ヒヤシンス","de":"一本の茎に小さな鐘をびっしり吊るした。揺らしても音はないが、香りが代わりに部屋の中を鳴らす。春の初め、花瓶一つで部屋の空気を丸ごと入れ替える優しい贅沢だ。"},"ICON-1486":{"nm":"カエルの標本","on":"カエルの標本","de":"ガラスの箱の中で時間が止まった小さな体。ラベルにはこう書かれている——「田んぼと貯水池、雨の翌日に最も活気づく。」止まった後でこそ、一つの生き物が暮らした水辺の温度まで記録に残る。"},"ICON-1487":{"nm":"トカゲの標本","on":"トカゲの標本","de":"尻尾を切って逃げる利発さだけは、標本になっても消えない。日当たりのいい石垣を好んだ小さな客。傍らのメモには、彼が好んで登った日向の方向がきちんと記されている。"},"ICON-1488":{"nm":"モグラの記録","on":"モグラの記録","de":"地中を行く者の日記は、土の筋で書かれる。どこを掘り、どこで止まったか、見えない道の地図。光を背にして生きた時間も、誰かにはこの上なく誠実な記録になる。"},"ICON-1489":{"nm":"貝の標本","on":"貝の標本","de":"波が幾千度も磨いて送った固い模様。干潟の人々は貝殻の筋だけを見て、どの海のものか分かった。かつて生きて息づいていた海の形が、手のひらほどの標本にそのまま収まる。"},"ICON-1490":{"nm":"サンゴの標本","on":"サンゴの標本","de":"海の深いところで数百年かけて、ようやく一寸を育つ。枝のように見えても、実は数多の小さな命が共に建てた家。遅いものほど長く残ると、サンゴは沈黙で証明する。"},"ICON-1491":{"nm":"アイドンの手がかり","on":"アイドンの手がかり","de":"島のどこかに散らばった物語の一片。小さな紙きれ一つが、次の一歩をそっと指し示す。すべての冒険は結局、こんな些細な痕跡を拾うことから始まると、古い道しるべは語る。"},"ICON-1492":{"nm":"シグネチャーのかけら","on":"シグネチャーのかけら","de":"散らばった模様が定位置を見つければ、ようやく一つの印が完成する。誰かの固有の筋が刻まれたかけら。揃うまでは意味を隠し、揃う瞬間にようやく名前になる。"},"ICON-1493":{"nm":"舞台の記憶のかけら","on":"舞台の記憶のかけら","de":"一曲が終わっても、客席には余熱が残る。そのぬくもりを剥がして固めれば、こんな小さなかけらになる。散らばった拍手と歓声の破片、そっと集めれば、その夜が丸ごとよみがえる。"},"ICON-1494":{"nm":"デビュースタンプ","on":"デビュースタンプ","de":"初めて自分の名前が呼ばれた日、手の甲に押されたあのインクの跡。にじまないよう慎重に乾かす心までが、出発線だった。小さな印一つが、ある一日を永遠に消えないものにする。"},"ICON-1495":{"nm":"トップアイドルメダル","on":"メダル","de":"最も高い場所に上った者にだけ許される重み。だがこのメダルが重いのは金属のせいではない。舞台を共に満たした数多の手の重みが、一点にそのまま集まってのことだ。"},"ICON-1496":{"nm":"小さな鍵","on":"小さな鍵","de":"宿舎の最初の鍵は、いつも最も奥の部屋のものだった。閉める術より開ける術を先に覚えた場所。去る日、冷たい鉄の上には、手のひらが残したぬくもりがしばらくとどまる。"},"ICON-1497":{"nm":"宝箱","on":"箱","de":"開ける前まで中に何が入っているか誰も知らない。その知らなさこそが宝箱の本当の宝だ。蓋を持ち上げる短い瞬間、誰もがしばし幼い日のときめきへと戻る。"},"ICON-1498":{"nm":"設計図","on":"設計図","de":"一マス一マス引かれた線の上に、まだ建てられていない建物が住む。図面を広げることは、明日をあらかじめ一度歩いてみること。よく引かれた線一つが、崩れない明日を支える。"},"ICON-1499":{"nm":"レシピカード","on":"カード","de":"手垢のついたカード一枚に、おばあちゃんの手の味が分量で記されている。「塩ひとつまみ」のような曖昧な言葉が、最も正確な秘訣。文字が薄れるほど、その料理を煮ていた台所がよりはっきり浮かぶ。"},"ICON-1500":{"nm":"施設許可証","on":"施設許可証","de":"一枚の紙が空き地を「使える場所」に変える。新しい建物には決まって村の印がまず必要だった。許しとは結局、ここで何かを始めてもいいという、温かい印章だ。"},"ICON-1501":{"nm":"港の入港許可証","on":"入港許可証","de":"船が錨を下ろすには、まずこの一枚が必要だった。港の色あせた印章は、遠くから来た者を迎える最初の挨拶。発つことと着くことのあいだ、港はいつも一枚の紙で心を開く。"},"ICON-1502":{"nm":"島の編入証","on":"証","de":"この島の一員になったという小さな証書。昔の村は新しい隣人が加わると名を書き添え、温かい餅を配った。たった一枚の紙だが、そこには「これでお前も仲間だ」という明るい歓迎が記されている。"},"ICON-1503":{"nm":"宿の表札","on":"宿の表札","de":"扉の脇に掛けられたひとつの名で、空き部屋はようやく誰かの家になる。昔の客間にも、主の号を刻んだ額がまず掛けられた。表札は小さくとも、その中には「ここに人が住んでいる」という温もりが満ちている。"},"ICON-1504":{"nm":"ファンダム切手","on":"切手","de":"唾をつけてぎゅっと押し貼る、その手間までが一通の完全な手紙だった。小さな紙に好きという気持ちを貼って遠くへ飛ばすこと。デジタルの時代でも、誰かはあえて手で心を送り出す。"},"ICON-1505":{"nm":"きらめき島バッジ","on":"きらめき島バッジ","de":"襟につければ、小さな光が行く道々についてくる。同じバッジをつけた人と道で出会えば、言葉がなくても通じ合う。きらめきは自慢ではなく、「私たちは同じ島を愛している」という静かな合図だ。"},"ICON-1506":{"nm":"作業台","on":"作業台","de":"傷だらけの天板が、最も多くを作ってきた手の証となる。何かを直し、繋ぎ、整えてきた場所。きれいな机より散らかった作業台のほうが、実はもっと多くの物語を抱えている。"},"ICON-1507":{"nm":"保管箱","on":"箱","de":"大切なものほど、まず居場所を決めておく。昔の人も貴い文書は桐の箱に別に納めた。よく保管するとは結局、未来の誰かのために今日をきちんと畳んでおくことだ。"},"ICON-1508":{"nm":"資源箱","on":"箱","de":"あふれる時はためておき、足りない時は取り出して使う。蔵が豊かでこそ心も豊かだった時代の知恵がここに詰まっている。備蓄とは、未来の自分にあらかじめ差し出す優しい一食だ。"},"ICON-1509":{"nm":"冷蔵箱","on":"箱","de":"氷を詰めた箱は、真夏でも涼しさを留めた。石氷庫の昔の知恵が手のひらサイズに移ってきたわけだ。冷たさを守るとは、最も新鮮な一瞬を長く留めておくことだ。"},"ICON-1510":{"nm":"手押しポンプ","on":"手押しポンプ","de":"取っ手を上下に振ると、地中深くの水が湧き上がる。呼び水一杯があってこそ、ようやくどっと流れ出す正直な機械。先に注いでやらねば受け取れないという道理を、井戸端は早くから知っていた。"},"ICON-1511":{"nm":"浄水器","on":"浄水器","de":"濁った水が一層ずつ澄んで出てくる小さな奇跡。昔の人は甕に砂と炭を幾重にも敷いて水を漉した。澄むとはただで得られるものではなく、ゆっくり漉していく真心だ。"},"ICON-1512":{"nm":"じょうろ掛け台","on":"掛け台","de":"じょうろが休む場所を持った瞬間、花壇の一日がきちんと整う。道具を掛ける場所を決めるのは、仕事を愛する人の癖。居場所がひとつ決まれば、庭全体がいっそう整って見える。"},"ICON-1513":{"nm":"竿掛け台","on":"掛け台","de":"手応えが来るまで、人は離れても竿はその場を守る。川辺で歳月を釣っていた、あの待ちの姿勢がここにそのまま刻まれている。掛け台とは結局、焦りをしばし下ろしておく支えだ。"},"ICON-1514":{"nm":"採集かご","on":"かご","de":"山菜ひと握り、野花一輪を入れて持ち帰った母の手荷物。竹ひごを編んだ隙間から、土の匂いがそっと漏れ出す。何を入れるかによって、空のかごは春にも秋にもなれる。"},"ICON-1515":{"nm":"臼","on":"臼","de":"ドン、ドンと、一定の拍子で穀物を搗けば村の一日が目覚めた。節句になれば餅つきの音が路地を満たした道具。固いものを柔らかくするには、絶え間ない手のリズムが要る。"},"ICON-1516":{"nm":"まな板","on":"まな板","de":"包丁が通った跡ごとに、一食の歴史が刻まれる。傷だらけの木の板は、最も働き者の手を持つ台所の勲章。何かを切ることは、それを心を込めてもてなそうとする気持ちから始まる。"},"ICON-1517":{"nm":"鍋","on":"鍋","de":"ぐつぐつ煮える音は、どんな音楽よりも優しい。小腹のすいた夜明け、麺が茹で上がるのを待つあの3分が、最も私的な慰めだ。丸い底いっぱいに、誰かを食べさせようとする温もりが温められる。"},"ICON-1518":{"nm":"フライパン","on":"フライパン","de":"火の上で一瞬にして焼き上げる腕前が、この一枚にかかっている。よく馴染んだ表面ほど焦げつかず艶が流れる。長く使った鉄パンは、それ自体が台所の過ごした歳月の証だ。"},"ICON-1519":{"nm":"オーブン","on":"オーブン","de":"扉を閉めて待つあいだ、中では静かに魔法が起きている。生地が膨らみ、色づいていく時間。見えなくても信じて待てば、温かな結果が扉を開けて出てくる。"},"ICON-1520":{"nm":"ミキサー","on":"ミキサー","de":"固いものもここに入れれば、一瞬で柔らかな一杯になる。異なる素材が混ざり、新しい味が生まれる小さな渦。調和とは結局、それぞれの角を少しずつ譲り合うことだ。"},"ICON-1521":{"nm":"泡立て器","on":"泡立て器","de":"手首ひと振りで空気が閉じ込められ、かき混ぜる速さの分だけ、ゆるかったものがしっかり立ち上がる。泡が山のように盛り上がるあいだ、膨らむのは生地だけではない。今日誰かを食べさせようとする気持ちも一緒に膨らむ。"},"ICON-1522":{"nm":"コーヒーミル","on":"コーヒーミル","de":"豆ひと握りに取っ手を回せば、歯のあいだから香りが先に砕ける。腕が疲れてくる頃、粉はようやく細かくなり、その苦労の分だけ最初の一口が深くなる。真心はいつも手首から始まるものだ。"},"ICON-1523":{"nm":"製粉機","on":"製粉機","de":"粒が石の隙間に入り、白い粉になって出てくる。一度で細かくならなくても大丈夫、もう二度搗けばいいから。粗いものを細かくするのにも順序があると、製粉機は黙々と教えてくれる。"},"ICON-1524":{"nm":"製材台","on":"製材台","de":"丸太が載れば、鋸がまず木目を読む。節は避け、まっすぐな道だけで挽いてこそ板は反らない。木を切ることは結局、一本が生き抜いた時間をきちんと広げることだ。"},"ICON-1525":{"nm":"ミシン","on":"ミシン","de":"ガガガッ——針が布を咥えて走る音が夜更けを満たす。一本の縫い目が二枚の布を一つの体に繋ぎ、舞台衣装の内側の見えない縫い目ごとに、誰かの眠れなかった時間がしっかりと縫い込まれる。"},"ICON-1526":{"nm":"染色台","on":"染色台","de":"白い布を浸して引き上げれば、初めは黄緑、空気に触れてようやく青くなる。藍草を三度は煮出してこそ出るという、あの色。待つことがそのまま色になると、私はこの染色台の前で初めて学んだ。"},"ICON-1527":{"nm":"撮影三脚","on":"撮影三脚","de":"三本の脚を広げて地を踏む瞬間、揺れていた世界が止まる。手で持っていたら震えたであろう一枚が、この三点の約束の上ではっきりとする。何かを長く見つめるには、まず立ち止まることを知らねばならない。"},"ICON-1528":{"nm":"照明スタンド","on":"照明スタンド","de":"柱ひとつに光を載せれば、部屋のどこでも小さな舞台になる。角度を少し傾けると影が伸び、表情が生きてくる。闇を消すのではなく、闇さえも優しく置いてやる道具だ。"},"ICON-1529":{"nm":"マイクスタンド","on":"マイクスタンド","de":"高さを合わせる瞬間、口と歌のあいだの距離が決まる。手を離しても声はその場に留まる。両手が自由になった舞台の上でこそ、ようやく全身で歌う歌が始まる。"},"ICON-1530":{"nm":"譜面台","on":"譜面台","de":"広げた紙が斜めに寄りかかれば、音符たちが奏者の目の高さに並ぶ。手ぶり一つで次の小節が来ても、台は揺るがない。誰かの演奏の後ろには、いつも言葉なき支えがある。"},"ICON-1531":{"nm":"家庭菜園","on":"家庭菜園","de":"土を耕して畝を立てれば、地の上に小さな約束の線ができる。種を埋めた数日は何事もないように見えても、ある朝、柔らかな双葉が土を押して上がってくる。待った人にだけ見える風景だ。"},"ICON-1532":{"nm":"肥沃な菜園","on":"肥沃な菜園","de":"同じ種なのに、この土では葉が二倍に大きい。指を突き入れれば、黒く柔らかな土が爪の下までついてくる。よく育つこととは結局、見えない足元が静かにやり遂げたことだった。"},"ICON-1533":{"nm":"温室","on":"室","de":"ガラスの天井の下では、季節がひと拍遅れて流れる。外に霜が降りても、内側は真夏の湿り気でしっとりしている。寒さに弱いもののために、誰かが日差しを屋根にそっと閉じ込めておいた。"},"ICON-1534":{"nm":"ハーブ花壇","on":"ハーブ花壇","de":"指先で葉をかすめれば、香りが先に挨拶をくれる。バジル、ローズマリー、ミント——名を呼ぶたびに違う匂いが指に移る。小さな花壇ひとつが、台所まるごとを優しく変えてしまう。"},"ICON-1535":{"nm":"果樹園","on":"果樹園","de":"春は花の陰で、秋は実の重さで枝がしなる。梯子を上って一つもいでかじれば、一年中、日差しがためてきた甘みが口の中で弾ける。木が人に渡す返事のようだ。"},"ICON-1536":{"nm":"きのこ原木","on":"きのこ原木","de":"切っておいた原木に穴を開けて種菌を植えれば、死んだ木が再び何かを育てる。数日後、傘がふさふさと生える朝、終わりだと思っていた場所で、新しい暮らしが静かに始まる。"},"ICON-1537":{"nm":"巣箱","on":"箱","de":"耳を近づければ、中から低く勤勉な振動が聞こえる。何千回もの羽ばたきが集まって、ようやく一さじの甘さになる。花畑を行き来した一日分の苦労が、ねばつく黄金色のまま、ここに溜まっている。"},"ICON-1538":{"nm":"鶏小屋","on":"鶏小屋","de":"夜が明ける前、止まり木に座ったものたちが先にざわめく。温かい藁の中に手を入れれば、まだ温もりの残る卵がひとつ掴める。朝を最も先に告げる場所が、最も先に朝餉を整える。"},"ICON-1539":{"nm":"牧場","on":"牧場","de":"草の匂いと日差しの匂いが混ざる広い野。柵の中でのんびり反芻する背中の上を、雲の影が通り過ぎる。急ぐことのないこの場所では、時間さえ草を食むようにゆっくり流れる。"},"ICON-1540":{"nm":"チーズ工房","on":"チーズ工房","de":"搾りたての乳が凝固と熟成を経て、ゆっくり固まっていく。洞窟のように涼しい棚で何ヶ月か待てば、白い塊に深い風味が染み込む。チーズは、急がなかった牛乳にだけ与えられる名だ。"},"ICON-1541":{"nm":"豆腐工房","on":"豆腐工房","de":"豆をふやかして挽き、煮れば、生臭かった豆乳が香ばしくなる。にがり一滴で散らばっていたものが集まっておぼろ豆腐になり、そっと押しておけば角が立つ。散らばった心をなだめて形を整える手が、ここにある。"},"ICON-1542":{"nm":"甕置き場","on":"甕置き場","de":"陽当たりのよい庭の片隅、背の低い甕たちが寄り集まって日を浴びる。蓋を開ければ、寝かせた時間の匂いがふわりと立つ。祖母が仕込んだ醤の味は、実は歳月を一さじずつすくって食べることだ。"},"ICON-1543":{"nm":"搗き屋","on":"搗き屋","de":"ガタンガタンと石が回れば、穀物が粉にほどける。白い埃が日差しの中を漂い、餅ひと桶こしらえようとする人々が順番を待つ。村の祝いの日は、いつもこの敷居から始まったものだ。"},"ICON-1544":{"nm":"パン工房","on":"パン工房","de":"オーブンの扉の隙間から、バターと砂糖の匂いが漏れ出す。膨らんだ生地がきつね色になる頃、店の前を通る足取りが思わず遅くなる。焼きたてのパンひとつには、誰にも勝てない優しさがある。"},"ICON-1545":{"nm":"粉食屋台","on":"粉食屋台","de":"ビニールの天幕が風にはためき、トッポッキの汁がぐつぐつ煮詰まる。おでん串ひとつに紙コップの汁を流し込む夕暮れ、寒さと空腹を一度に溶かす場所。路地の端に置かれた小さな慰めだ。"},"ICON-1546":{"nm":"洋食キッチン","on":"洋食キッチン","de":"パンが熱され、オリーブオイルがジュージューと音を立てる。火加減ひとつでソースは絡みもし、焦げもする。皿の上の色の均衡まで配慮するこの場所では、一食が丁寧に整えられた一編の演出になる。"},"ICON-1547":{"nm":"中華キッチン","on":"中華キッチン","de":"強火の上で中華鍋が舞うようにくるくる回る。炎が噴き上がる短い瞬間に、素材の香りがそっくり閉じ込められる。速く、熱く、ためらえば逃すその一呼吸に、中華料理の秘密が隠れている。"},"ICON-1548":{"nm":"カフェ","on":"カフェ","de":"扉を押せば、豆の香りと穏やかな音楽がまず迎えてくれる。窓辺の席、冷めていくラテ一杯と広げたノート。忙しい一日の中でしばし息を整えてと、街はこんな小さな部屋をあちこちに隠しておいた。"},"ICON-1549":{"nm":"デザート店","on":"デザート店","de":"ガラスの陳列棚の中、色とりどりのケーキが並んで客を待つ。フォークの先がクリームを切る瞬間、口角が先に上がる。悲しい日でも一切れあれば耐えられる、小さくて甘い処方箋。"},"ICON-1550":{"nm":"精肉店","on":"精肉店","de":"赤い灯りの下、肉が筋目に沿ってきちんと並ぶ。「今日はこれがいいですよ」のひと言に、包丁が正確な厚さで滑る。夕餉の心強さは、毎日同じ場所を守るこの手から静かに始まる。"},"ICON-1551":{"nm":"鮮魚作業台","on":"鮮魚作業台","de":"夜明けの生臭さと氷の冷たさが混ざる作業台。鱗が飛び、手がかじかんでも、最も新鮮なものを選び出す目は止まらない。海から上がったばかりのものが、ここから食卓へ向かう道を得る。"},"ICON-1552":{"nm":"塩田","on":"塩田","de":"海水を閉じ込めておけば、日差しと風が残りをやる。数日待って水が乾けば、底に白い結晶が星のように立つ。塩ひと握りは実は、海と空がゆっくり共同で作り上げた贈り物だ。"},"ICON-1553":{"nm":"海藻干し台","on":"海藻干し台","de":"長い綱にわかめと昆布が並んで広げられ、風に揺れる。海水を含んだものが乾きながら濃い緑へと深まる。日差しと潮風が共に醸し出した、海の最も質素な味がここに掛かっている。"},"ICON-1554":{"nm":"小さな船着き場","on":"小さな船着き場","de":"水に半ば浸かった木の板が足元で軽く揺れる。小舟一艘を繋ぐのにちょうどよい場所。遠くへ発つことも、無事に戻ることも、すべてこの一区画で始まり、また終わる。"},"ICON-1555":{"nm":"港の倉庫","on":"港の倉庫","de":"潮風に染みた木の扉を開ければ、網と樽と縄が天井まで積まれている。遠い航海へ発つ荷と着いたばかりの荷が、しばし一つ屋根の下に留まる。発つことと戻ることがひととき行き交う乗り換え駅のような場所。"},"ICON-1556":{"nm":"灯台","on":"灯台","de":"夜の海が最も真っ暗になる時、ようやく自分の仕事を始める。くるりと回る光が霧を裂いて「ここに道がある」と告げる。誰かの無事な帰りのために、最後まで眠らない背の高い見張り。"},"ICON-1557":{"nm":"造船作業場","on":"造船作業場","de":"竜骨を立て、肋材をつければ、船一艘の骨組みが形を整える。槌の音が一日中響く庭で、まだ水の味を知らない船が初航海を夢見る。発つために、まず固くなる場所だ。"},"ICON-1558":{"nm":"録音ブース","on":"録音ブース","de":"扉が閉まれば、外のすべての音が一瞬で消える。ヘッドホン越しに聞こえるのは自分の息と拍子だけ。この小さな部屋の静寂の中で、思いきり震えてもいい声がようやく生まれる。"},"ICON-1559":{"nm":"音楽室","on":"室","de":"扉の隙間から漏れ出た和音が廊下を満たす。誰かは音階を押さえ、誰かは拍子を数える。たどたどしい音と熟れた音が入り混じってもいい場所、すべての歌が初めて足を踏み出す優しい教室。"},"ICON-1560":{"nm":"ピアノルーム","on":"ピアノルーム","de":"鍵盤の蓋を開ければ、白い鍵にうっすら埃が積もっている。指が触れる瞬間、部屋いっぱいに澄んだ響きが広がる。一人でも寂しくない夕べがあるなら、それはきっとこの一台のピアノのせいだろう。"},"ICON-1561":{"nm":"ダンスルーム","on":"ダンスルーム","de":"つま先を押せば、床が押し返してくる。四面の鏡が同じ動きを四度写すあいだ、体は拍子より半拍先に振り付けを覚える。汗と息が最も長く留まる部屋、ここで育った動きが舞台へ歩み出る。"},"ICON-1562":{"nm":"ジム","on":"ジム","de":"重さは嘘をつかない。持ち上げた分だけ正確に肩に積み立てられる、その正直さが好きで、人々は夜明けごとに私を訪ねる。鏡にゆっくり刻まれていくのは筋肉ではなく、諦めずに耐えた時間たちだ。"},"ICON-1563":{"nm":"ヨガルーム","on":"ヨガルーム","de":"息を深く吸い込めば、床板も一緒に膨らむ気がする。速く駆けてきた一日をゆっくり畳んでおく部屋、マット一枚の上では誰もが自分の呼吸の速さに戻る。急いでいた心も、ここではしばし下ろす。"},"ICON-1564":{"nm":"楽屋","on":"室","de":"舞台へ出る直前、人々はここでしばし別の人になる。鏡を囲む電球が顔をまんべんなく温めれば、震えはパフの先について襟の後ろにそっと隠れる。変身が始まり、また終わる場所。"},"ICON-1565":{"nm":"衣装室","on":"室","de":"舞台の一着が完成するまで、ここに掛かった服は何十回も着せられ脱がされる。仕付け針を刺したまま回るマネキン、チョークで引いた縫い代の線。きらめきの裏側にはいつも、誰かの針仕事の跡が残っている。"},"ICON-1566":{"nm":"放送局セット","on":"放送局セット","de":"カメラが映す一面だけを本物らしく飾ればいいと、私は早くから学んだ。合板の裏に回れば、がらんとした骨組みだけ。正面の華やかさを黙々と支えるのは、いつも見えない角材たちの役目だ。"},"ICON-1567":{"nm":"フォトスタジオ","on":"フォトスタジオ","de":"光を三方向から投げて影を消すのが第一の秘訣。主光は顔を、補助光は陰を、後光は髪の先を生かす。シャッターが落ちる刹那、白い背景一枚が今日の最もいい笑顔を閉じ込める。"},"ICON-1568":{"nm":"公演会場","on":"公演会場","de":"天井の高い闇の中で、私はいつも同じ約束を抱く。幕が上がれば、空っぽの客席さえ一人の人のように息をひそめると。最初の一拍が落ちるその一瞬のために、私は一年中静かに空いている。"},"ICON-1569":{"nm":"ファンミーティングブース","on":"ファンミーティングブース","de":"手と手のあいだの距離は、ちょうど机ひとつ分。短い挨拶、震えるサイン、ついに言えなかったひと言が列をなして通り過ぎる。この小さな区画の中で、長く育てた好きという気持ちが初めて顔を合わせる。"},"ICON-1570":{"nm":"ベッド","on":"ベッド","de":"一日の終わりを最も先に受け止めるのは、いつも私だった。練習で重くなった脚、舞台裏に残った震えまで全部沈めてやれば、朝はまた軽いつま先で始まる。おやすみと、言葉なく抱きしめる。"},"ICON-1571":{"nm":"二段ベッド","on":"二段ベッド","de":"上の段と下の段のあいだ、梯子五段が二人を繋ぐ。灯りを消して交わす小さな声、天井に貼った夜光の星。狭い宿が最も広くなるのは、毎晩梯子を上り下りする話のおかげだ。"},"ICON-1572":{"nm":"棚","on":"棚","de":"何を載せておくかに、その人が見える。もらった手紙、初めてのトロフィー、色あせた入場券が並んで列をなす。私は自慢を並べる家具ではなく、捨てられなかった記憶をそっと陳列する場所だ。"},"ICON-1573":{"nm":"机","on":"机","de":"歌詞ノートが広げられたまま、消した跡の上に再び新しい線が引かれる。一晩中積もった紙コップと、ようやく拾い上げた一行のメロディー。心を文字に移す遅い仕事は、いつもこの平らな面の上で静かに繰り広げられる。"},"ICON-1574":{"nm":"椅子","on":"子","de":"ちょっと座ってという言葉は、意外と優しい。会議が長引き、練習が延びても、背もたれは黙々と人の重さを受け止める。長く立っていた人ほど私を喜ぶことを、私は知っている。"},"ICON-1575":{"nm":"ソファ","on":"ソファ","de":"夜遅く宿を居間に変えるには、私一つで十分だ。みんなでぎゅっと座ってバラエティを見ていれば、一人はいつの間にか肘掛けにもたれて眠る。深く沈んだ真ん中の席が、その家の温もりを証明する。"},"ICON-1576":{"nm":"テーブル","on":"テーブル","de":"囲んで座れば、誰も上座でなくなる。煮立てたばかりのチゲと匙のぶつかる音、今日あったことが真ん中に集まる。丸い面ひとつが広がれば、散らばっていた一日も再び一所に集まって座る。"},"ICON-1577":{"nm":"クローゼット","on":"クローゼット","de":"季節が変わるたびに、奥から寝かせた話があふれ出す。舞台衣装と普段着が肩を並べたまま、閉じた扉の後ろで服たちは次の番を待つ。扉を開けてこそ、ようやく今日着る一日が決まる。"},"ICON-1578":{"nm":"鏡","on":"鏡","de":"褒め言葉も欠点も、私は同じ正直さで返す。舞台へ出る前の最後の点検を受ける場所、人々は私の前で表情を整え、姿勢を正す。最も率直な友は、いつもひと言も言わない。"},"ICON-1579":{"nm":"ドレッサー","on":"ドレッサー","de":"小さな引き出しごとに違う顔が眠っている。舞台用ひとつ、普段用ひとつ、大事にとっておいた限定版ひとつ。鏡の前に座れば、今日はどんな人になって扉を出るかからゆっくり決めることになる。"},"ICON-1580":{"nm":"ラグ","on":"ラグ","de":"素足が最初に触れる感触が、その部屋の温度を決める。囲んで座っておやつを食べ、転がった跡が毛羽として残る。冷たい床をひと回り温かく温めておく、最も低い場所で働く家具。"},"ICON-1581":{"nm":"カーテン","on":"カーテン","de":"朝をどれだけ入れるかは私が決める。少し開ければ日差しが長く入り、ぴたりと閉じれば朝寝坊さえ寛容になる。窓と部屋のあいだに立って光の量をそっと調節するのは、いつも私に任された役目だ。"},"ICON-1582":{"nm":"照明","on":"照明","de":"同じ部屋も光の色によって全く違う時間になる。黄色い光は夕べを長く延ばし、白い光は夜明けをくっきり目覚めさせる。スイッチひとつで一日の雰囲気をそっと変えてしまう、手のひらほどの魔法使い。"},"ICON-1583":{"nm":"掛け時計","on":"時計","de":"秒針の音は静かな部屋でだけ聞こえる。練習が深まるほど私を忘れていて、ふと見上げればいつの間にか窓の外が夜明けだ。流れた時間を責めることなく、ただ次の目盛りを黙々と指し示す仕事。"},"ICON-1584":{"nm":"花瓶","on":"瓶","de":"花が枯れても、私はその場所を空けておかない。もらった気持ちをしばし入れておく器、水を替えてくれる手がある限り食卓は明るくなる。空っぽの時さえ、誰かを待つ形で立っている。"},"ICON-1585":{"nm":"ポスター額","on":"額","de":"好きな顔を壁に掛けることにも真心がいる。日差しが直接当たらない場所、水平がぴたりと合った釘ひとつ。ガラスの中に大切に寝かせた紙一枚は、毎朝部屋に入る私に最も先に挨拶をくれる。"},"ICON-1586":{"nm":"フォトカードボード","on":"フォトカードボード","de":"五十音順に挿すか発売順に挿すか、その幸せな悩みからがオタ活の始まりだ。空いている一マスは、まだ出会えていない推しの席。一枚ずつ埋まるほど、ボードは私だけの小さな年代記になる。"},"ICON-1587":{"nm":"ペンライト掛け台","on":"掛け台","de":"電池は抜いて、持ち手は上へ。斜めに傾けて立てる角度にもそれなりのコツがある。来たる次の歓声を待ちながら、ライトはまさにここで光を消し、きちんと身を横たえる。よく休んでこそ、より明るく灯る。"},"ICON-1588":{"nm":"トロフィー棚","on":"トロフィー棚","de":"一番前の列には最も古いものを置く。小さな大会の銅像から大きな舞台の杯まで、背の順ではなく心の順に並ぶ。磨くたびに、その日舞台の上の震えが指先に再ににじみ出る。"},"ICON-1589":{"nm":"ピクニックバスケット","on":"バスケット","de":"蓋を開ければ、春の陽の匂いがまず漏れ出す。海苔巻きと水筒、レジャーシート一枚がきちんと重なって野へ行く支度をする。私を持つ人の足取りは、なぜかいつもより一回り軽くなる。"},"ICON-1590":{"nm":"小さな鉢","on":"小さな鉢","de":"窓枠ひと幅あれば私は十分だ。水やりをしょっちゅう忘れても寛容に耐えてくれる小さな緑。忙しい人の机の片隅で、私は毎日葉を一枚ずつ広げ、静かに今日の安否を伝える。"},"ICON-1591":{"nm":"大きな鉢","on":"大きな鉢","de":"私の背が伸びるあいだ、人も一緒に育つ。居間の片隅を占めた広い葉が日差しを受けて陰を落とせば、部屋の中にもそっと季節が入る。水やりを忘れない人だけが知る手応え。"},"ICON-1592":{"nm":"アロマキャンドルセット","on":"アロマキャンドルセット","de":"芯に火を灯す瞬間、部屋の空気がひと段階沈む。香りがゆっくり広がりながら、昨日残った疲れを温めて送り出す。小さな炎ひとつで、慌ただしかった一日の終わりを静かな儀式のように締めくくること。"},"ICON-1593":{"nm":"ミニ冷蔵庫","on":"ミニ冷蔵庫","de":"夜遅く扉を開ければ、冷たい飲み物一缶が私を迎える。ウィーンという小さな振動音が、空っぽの宿を少し寂しくなくする。大きな所帯は持てなくても、小腹のすいた夜明けを引き受けるなら私の右に出るものはない。"},"ICON-1594":{"nm":"虫取り網ヘッド飾り","on":"虫取り網ヘッド飾り","de":"頭に載せる瞬間、夏の野原が肩の上についてくる。丸い網が日差しを細やかに漉し、歩くたびに草の匂いがそよそよ揺れる。トンボを一匹も捕れなくてもいい、季節をまるごとかぶる帽子。"},"ICON-1595":{"nm":"採集網ポーチ","on":"ポーチ","de":"腰にぶら下がって採集の友になる。入り口を少し締めておけば捕ったものが逆に逃げないというのが、野原で学んだ最初のコツ。軽い布のポーチひとつが、一日分の収穫をしっかり抱きしめる。"},"ICON-1596":{"nm":"昆虫観察瓶","on":"瓶","de":"しばし留まる客には空気穴が最も大切だと、私は知っている。蓋に開けた小さな息の道、底に敷いた草の葉一枚。観察が終われば再び草むらへ返してやることまでが一対だ。"},"ICON-1597":{"nm":"標本ピンケース","on":"ケース","de":"ピンを斜めに刺す角度ひとつにも技が生きる。深すぎれば壊れ、浅ければ揺れるので、指先の力を精密に分け与えねばならない。小さな生をじっくり見つめようとする人の真心が、そっと収まるケース。"},"ICON-1598":{"nm":"飼育箱の蓋","on":"蓋","de":"内と外の境を引き受けるのが私の仕事だ。きつく閉めすぎれば息が詰まり、緩すぎれば道に迷うので、斜線のような隙間を必ず残しておく。守るということは、閉じ込めておくこととは確かに違う。"},"ICON-1599":{"nm":"蝶の餌皿","on":"皿","de":"砂糖水を含ませた綿を真ん中に置けば、翼たちが集まってくる。浅く広く、小さな脚が落ちない深さで盛るのが秘訣。皿ひとつが、日当たりのよい庭にしばし留まって去る客たちをそっと呼び集める。"},"ICON-1600":{"nm":"誘虫灯","on":"誘虫灯","de":"暗闇の中でうっすら灯しておけば、小さな翼たちが光を追って集まってくる。明るさはほのかに、場所は人から遠く。ぶんぶん鳴っていた夏の夜をいっそう静かに沈める、この上なく優しい客引き。"},"ICON-1601":{"nm":"昆虫シールラベル","on":"ラベル","de":"六本の脚に一対の触角、爪ほどの紙の中に小さな生涯が眠っている。ノートの隅にそっと貼れば、本のページのあいだに草地ひと幅が静かに広がる。"},"ICON-1602":{"nm":"採集許可タグ","on":"タグ","de":"虫取り網を持つ前に、大人がまず尋ねる言葉。何匹まで、どこまで。この小さなタグ一枚が、はしゃぐ好奇心と守るべき約束のあいだに優しい線を引いてくれる。"},"ICON-1603":{"nm":"餌入れ","on":"入れ物","de":"蓋を開ければ、生臭く涼やかな夜明けの匂いが立ち上る。魚を呼ぶのは餌ではなく、浮きが揺れるまでじっと待てる心かもしれない。"},"ICON-1604":{"nm":"浮き保管箱","on":"浮き保管箱","de":"色とりどりの浮きが仕切りごとに横たわって眠る小さなタンス。あるものは穏やかな湖の朝、あるものは激しい流れの真昼。水の表情ごとにふさわしい相棒をきれいに畳んでおく。"},"ICON-1605":{"nm":"釣り糸巻き","on":"釣り糸巻き","de":"ほどけた糸は指に巻かないこと。この丸い道具にきちんと巻き戻せば、もつれもそっとほどける。だらけてしまった一日を再び整える手つきに似ている。"},"ICON-1606":{"nm":"針外し","on":"針外し","de":"刺さった針を素手で外そうとしてちくりとした人だけが、この道具を見分ける。小さな命にも、私の指先にも、より痛くない道。思いやりはいつもこんな些細な先から始まる。"},"ICON-1607":{"nm":"潮干狩りスコップカバー","on":"カバー","de":"干潟で掘り出したばかりのスコップの刃を包む一枚。泥と塩水が刃を蝕まないよう、海と道具のあいだに薄く柔らかな休息をそっと挟んでおく。"},"ICON-1608":{"nm":"潮見表カード","on":"カード","de":"水がいつ満ち、いつ引くのか、手のひらほどのカードがそっと教えてくれる。月と海が交わした古い約束を、人が書き写しておいた小さな暦一枚。"},"ICON-1609":{"nm":"水槽掃除ブラシ","on":"ブラシ","de":"ガラス壁についた緑の苔をそっと払えば、水中の小さな世界に再び光が差し込む。誰かの一日を澄ませてやることは、たいていこんなふうに静かに流れる。"},"ICON-1610":{"nm":"水槽温度チップ","on":"チップ","de":"数字ひとつが点滅、ちょうどよい温度で止まれば、魚たちがようやく安心する。冷たすぎも熱すぎもしない一マスの温もり。世話は見えないところまで届く。"},"ICON-1611":{"nm":"海洋生物観察容器","on":"容器","de":"透明な容器の中にしばし留まる小さな客。背びれをそっと数えてみて、再び海へ返してやる。観察とは持つことではなく、しばし借りて見ることだ。"},"ICON-1612":{"nm":"化石ブラシ","on":"ブラシ","de":"数千万年眠った石の目を覚ますのは槌ではなく、柔らかな刷毛の先だ。急げば砕けてしまう時間の前で、慎重さが最も深い礼となる。"},"ICON-1613":{"nm":"発掘筆キャップ","on":"キャップ","de":"筆先がからからに乾けば、土もきれいに落ちない。小さな帽子ひとつが刷毛の息遣いをしっとり守ってくれる。道具を大切にする手が、発掘の第一歩を踏み出す。"},"ICON-1614":{"nm":"地層サンプル板","on":"板","de":"ひと幅の土の中に数百年が幾層にも重なっている。この板にそっとすくい取れば、これまで見えなかった時間の模様が線を引き、ゆっくり浮かび上がる。"},"ICON-1615":{"nm":"骨片トレイ","on":"トレイ","de":"散らばった破片を仕切りごとに横たえれば、風に舞っていた一つの生涯が、ゆっくり元の場所を手探りで探し当てる。復元とは、失われた順序を優しく問い直すことだ。"},"ICON-1616":{"nm":"復元接着テープ","on":"テープ","de":"割れた箇所を繋ぐ細い一筋。傷跡をあえて隠さず、優しく抱きしめて留めておく。壊れたものも再び完全になれると、そっと証明する。"},"ICON-1617":{"nm":"展示銘板カバー","on":"カバー","de":"ガラス越しの名札があせないよう、そっと覆う一枚。誰が、どこで生きてきたのか、その短い文章が遠い未来までくっきり読まれるようにという気持ちが込められている。"},"ICON-1618":{"nm":"収蔵庫タグ","on":"タグ","de":"灯りに出ない宝物たちが眠る深い部屋。その中のすべてのものには小さな名札がぶら下がっている。明るい場所に立たなくても決して忘れられないように。"},"ICON-1619":{"nm":"博物館寄贈封筒","on":"封筒","de":"誰かが一生かけて集めたものを言葉なく差し出す。この封筒に込められたのは物ではなく、長く抱いてきた心。分かち合いは最も長く残る展示となり、誰かを照らす。"},"ICON-1620":{"nm":"標本番号チップ","on":"チップ","de":"採集したその場で、小さな数字ひとつをそっとつける。いつ、どこで初めて出会ったのか。書き留めなかった発見は、ほどなく朝霧のように散ってしまうから。"},"ICON-1621":{"nm":"流れ星のかけら瓶","on":"瓶","de":"夜空を裂いて落ちたかけらがガラス瓶の中に閉じ込められた。願いを言う間もなく消えていった光ひと筋が、今や手の中でそっとそっと再び輝く。"},"ICON-1622":{"nm":"貝殻風鈴の紐","on":"紐","de":"海辺で一つずつ拾った貝を糸に通して軒に吊るす。風が過ぎるたびにしゃらしゃらと、その年の夏の海が家の中までそっとついて入ってくる。"},"ICON-1623":{"nm":"虹のしずく","on":"しずく","de":"雨上がりに葉先にころりと結んだひとしずく。その丸い中に空のすべてと七色が丸く収まる。最も小さなものが最も広い風景を抱くことがある。"},"ICON-1624":{"nm":"霧採集瓶","on":"瓶","de":"夜明けの山裾の霧を一瓶いっぱいに詰めてきた。手に握れば冷んやりと白く曇る。掴めないものをしばし傍に置こうとする、優しく小さな欲ひとつ。"},"ICON-1625":{"nm":"露受けカップ","on":"カップ","de":"草の葉が一晩中ひとしずくずつ集めた露を受ける小さな杯。一口にも満たないが、朝の最も澄んで清らかな部分が、そこに静かに溜まっている。"},"ICON-1626":{"nm":"そよ風リボンピン","on":"ピン","de":"風が過ぎていった筋をそのまま模して結んだリボン。髪に挿せば、歩くたびにそよ風がさらさらついてくる。春の日の軽やかさを、ピンひとつにそっと結んでおいた。"},"ICON-1627":{"nm":"波音カプセル","on":"波音カプセル","de":"耳にそっと当てれば、遠い海の波が押し寄せる。幼い頃、巻貝の殻に込めておいたあの音を、誰かが小さなひと粒に大切に封印しておいたかのよう。"},"ICON-1628":{"nm":"砂星のかけら","on":"砂星のかけら","de":"夜の浜辺で砂をひと握り掴めば、その中に星のかけらが混じってきらめく。空から落ちたのか、波が細やかに磨いたのかは、誰もあえて尋ねない。"},"ICON-1629":{"nm":"島天気記録チップ","on":"チップ","de":"島の空は一日に何度も気を変える。晴れ、霧、にわか雨を小さなチップにきちんと記しておけば、昨日の空を今日また広げて見られる。"},"ICON-1630":{"nm":"崖の階段キット","on":"崖の階段キット","de":"急な坂を上り下りする一段、また一段。散らばった部品を組めば、崖ものんびりした散歩道になる。道を作るとは、誰かの次の一歩をあらかじめ置いておくことだ。"},"ICON-1631":{"nm":"土の道パターンロール","on":"土の道パターンロール","de":"柔らかな土の道の目をそのまま写し取った巻物。するすると広げれば、裸足で歩きたくなる田舎の小道ひとつが、足元にそっと敷かれる。"},"ICON-1632":{"nm":"石畳パターンチップ","on":"チップ","de":"昔の路地を埋めていた敷石の模様が、小さなチップの中にそっくり収まっている。踏むたびにカツカツと、古い村の足音が足先で蘇る。"},"ICON-1633":{"nm":"浜辺の柵のかけら","on":"浜辺の柵のかけら","de":"波が越えてこないよう砂浜に立てた低い柵、そのひと切れ。海と砂のあいだに優しい線を引いて立つ、小さく寡黙な境の番人だ。"},"ICON-1634":{"nm":"芝生復元パッチ","on":"芝生復元パッチ","de":"踏まれて剥げた場所にそっと被せてやる緑のひと切れ。数日すれば草たちが互いに手を取り合って空き地を埋める。自然はいつも自ら癒える術を知っている。"},"ICON-1635":{"nm":"水路標識杭","on":"水路標識杭","de":"水が流れていく道をあらかじめ示しておく杭。雨水がどこへ行くべきか迷わないよう、地に刺さった小さな道しるべが、雨の日にも黙々と立っている。"},"ICON-1636":{"nm":"小さな橋の部品","on":"小さな橋の部品","de":"小川の両岸を繋ぐ小さな橋のひと切れ。こちらとあちらのあいだ、いつでも渡れるという約束が、この小さな部品ひとつから静かに始まる。"},"ICON-1637":{"nm":"展望台手すりキャップ","on":"キャップ","de":"島で最も高い所、その手すりの先を包む仕上げのひと点。遠くを見渡そうと集まった人々の手が最も頻繁に触れる場所を、そっと支えて守ってくれる。"},"ICON-1638":{"nm":"キャンプファイヤー台","on":"台","de":"薪を載せる前、火種が散らばらないよう支えてやる場所。その上で星を見上げて語り合った夜々が、いつまでも温かく燃え上がる。"},"ICON-1639":{"nm":"壁紙サンプルロール","on":"壁紙サンプルロール","de":"部屋の雰囲気は壁一面から始まる。小さな巻物を広げて色を選ぶことは、これからどんな一日を生きたいかをあらかじめそっと思い描くことだ。"},"ICON-1640":{"nm":"床材サンプルチップ","on":"チップ","de":"裸足が触れる床の感触を、指先でまず推し量ってみる。温かいか涼しいか、この小さなチップ一枚に、これから生きていく日々の心地よさがそっとかかっている。"},"ICON-1641":{"nm":"天井フックセット","on":"天井フックセット","de":"梁にフックひとつを掛ける瞬間、空っぽだった天井が誰かを待つ場所になる。風鈴を掛けるか、鉢を掛けるか。吊るす重さはこの小さな鉄のフックが耐えても、何を掛けておくかは住む人の心が決める。"},"ICON-1642":{"nm":"窓目隠しフィルム","on":"窓目隠しフィルム","de":"真昼の光があまりに率直なので、窓に薄い膜を一枚かぶせる。日差しはそのまま入るが角は柔らかくほどけ、部屋の中のすべてが杏色に和らぐ。目隠しではなく、光を優しくにじませることだ。"},"ICON-1643":{"nm":"ドアベルカバー","on":"ドアベルカバー","de":"客が押すベルにも服が要るからと、誰かが丸いカバーをかぶせた。雨を防ぎ埃を防ぎ、何より「ここに人が住んでいる」という最初の挨拶を一番先に伝える、小さく丸い口だ。"},"ICON-1644":{"nm":"芳名録スタンド","on":"芳名録スタンド","de":"来る人ごとに名を記して行けと立てておいた台。インクが乾く前、ペン先から安否のひと行が流れる。訪れた足取りが一行ずつ積もれば、空のノートはいつしかこの家の最も分厚いアルバムになる。"},"ICON-1645":{"nm":"家具配置ピン","on":"ピン","de":"移そうか迷っていた机の位置を、ピンひとつが床にコッと刺して決める。家具の足先をそっと押さえる小さな釘。居場所とは一度決めれば情が湧くものだと、床板が静かにうなずいてくれる。"},"ICON-1646":{"nm":"収納ラベルフレーム","on":"収納ラベルフレーム","de":"何がどこに入っているか、引き出しは結局口に出せない。だから四角い枠に名札を挟んで代わりに語らせた。ラベル一枚が居場所を得る瞬間、雑然としていた仕切りが自分の名を取り戻して落ち着く。"},"ICON-1647":{"nm":"ルームフレグランススティック","on":"ルームフレグランススティック","de":"棒の先を浸した香りがゆっくり上へ広がる。ラベンダーだったり、雨上がりの草地だったり。見えない糸のような匂いが部屋の空気を入れ替えれば、帰ってきた人の肩から一日分の疲れがするりとほどける。"},"ICON-1648":{"nm":"種袋クリップ","on":"クリップ","de":"春に買って植えきれなかった種たちを、袋ごとクリップでしっかり挟んでおく。一粒でも漏れれば次の季節がひと行減るから。小さな留め具の中に、来年の菜園がまるごと眠っている。"},"ICON-1649":{"nm":"苗トレイ","on":"トレイ","de":"仕切りごとに土を詰めて、幼い芽の最初の部屋を作る。一穴にひとつの命ずつ、並んで列を揃えて育つ新入生たち。覗き込めば緑が寄り集まって出席を取る朝が、トレイの上で毎日新しく始まる。"},"ICON-1650":{"nm":"水やり目印ピン","on":"ピン","de":"「私、喉が渇いてます。」鉢は口に出せないので、小さな札が土に刺さって代わりに合図を送る。色が変われば水やりの時間。植物と人のあいだの最も小さな通訳が、このひと幅の棒に全部詰まっている。"}};
